insert into subjects(id,slug,name,sort) values (1,'civ-proc','민사소송법',1) on conflict (slug) do nothing;
insert into articles(subject_id,article_no,title,body,pyeon,jang) values
(1,'제1조','민사소송의 이상과 신의성실의 원칙','①법원은 소송절차가 공정하고 신속하며 경제적으로 진행되도록 노력하여야 한다.
insert into articles(subject_id,article_no,title,body,pyeon,jang) values
(1,'제382조','증거보전의 기록','증거보전에 관한 기록은 본안소송의 기록이 있는 법원에 보내야 한다.','제2편 제1심의 소송절차','제3장 증거'),
(1,'제383조','증거보전의 비용','증거보전에 관한 비용은 소송비용의 일부로 한다.','제2편 제1심의 소송절차','제3장 증거'),
(1,'제384조','변론에서의 재신문','증거보전절차에서 신문한 증인을 당사자가 변론에서 다시 신문하고자 신청한 때에는 법원은 그 증인을 신문하여야 한다.','제2편 제1심의 소송절차','제3장 증거'),
(1,'제385조','화해신청의 방식','①민사상 다툼에 관하여 당사자는 청구의 취지ㆍ원인과 다투는 사정을 밝혀 상대방의 보통재판적이 있는 곳의 지방법원에 화해를 신청할 수 있다.
insert into atoms(id,subject_id,article_no,pyeon,ans,statement,ref,freq,verified) values
(1,1,'제1조','제1편 총칙','O','민사소송법상의 소송행위에는 특별한 규정이나 특별한 사정이 없는 한 민법상의 법률행위에 관한 규정이 적용될 수 없다.','대판(소송행위 성질)',1,false),
(2,1,'제1조','제1편 총칙','O','소송행위의 해석은 실체법상 법률행위와 달리 내심의 의사가 아닌 표시를 기준으로 하여야 하고, 표시된 내용과 저촉되거나 모순되어서는 안 된다.','대판(소송행위 해석)',1,false),
(3,1,'제1조','제1편 총칙','O','법원사무관등은 대법원과 각급법원에 배치되어 재판의 부수사무를 처리하는 단독제 기관이다.','법원조직법',1,false),
(4,1,'제1조','제1편 총칙','O','법원사무관등은 법관이라 하여도 대행할 수 없는 고유의 권한을 갖는다.','통설',1,false),
(5,1,'제1조','제1편 총칙','O','법원사무관등이 주로 행하는 사무에는 심판의 참여, 송달사무, 소송상 사항의 공증, 집행문 부여 등이 있다.','법원조직법',1,false),
(6,1,'제1조','제1편 총칙','O','신의성실의 원칙 또는 권리남용은 직권조사사항이다.','대판(신의칙 직권)',1,false),
(7,1,'제1조','제1편 총칙','O','공정증서가 집행권원으로서 집행력을 갖도록 하는 집행인낙의 표시는 공증인에 대한 소송행위로서, 이러한 소송행위에는 민법상의 표현대리 규정이 적용·준용될 수 없다.','대판(집행인낙)',1,false),
(8,1,'제1조','제1편 총칙','O','재판권의 존재 여부는 직권조사사항이다.','대판(재판권 직권)',1,false),
(9,1,'제2조','제1편 총칙','O','소액사건은 원칙적으로 제소 당시 소송목적의 값이 일정액(당시 2,000만 원) 이하인 금전 기타 대체물·유가증권의 일정 수량 지급을 목적으로 하는 제1심 민사사건을 말한다.','소액사건심판법 §2',1,false),
(10,1,'제2조','제1편 총칙','O','소액사건은 소가 2,000만 원 이하의 금전 그 밖의 대체물이나 유가증권의 일정 수량의 지급을 구하는 사건으로, 특정물에 관한 청구는 포함되지 않는다.','소액사건심판법 §2',1,false),
(11,1,'제3조','제1편 총칙','O','피고의 보통재판적 소재지(주소지) 법원에 관할이 있고, 피고가 국내에 주소를 둔 경우 그 소유 부동산 소재지(재산소재지, §11)는 이 사건 청구의 특별재판적이 되지 않는다.','민소 §3·§11',1,false),
(12,1,'제3조','제1편 총칙','O','피고(을)의 주소지를 관할하는 법원(보통재판적)에 소를 제기할 수 있다.','민소 §2·§3',1,false),
(13,1,'제3조','제1편 총칙','O','사람의 보통재판적은 주소에 따라 정하되, 주소가 없거나 알 수 없으면 거소, 거소가 일정하지 아니하거나 알 수 없으면 마지막 주소에 따라 정한다.','민소 §3',1,false),
(14,1,'제5조','제1편 총칙','O','소액사건에 대하여 법원이 변론에 의한 소송절차에의 회부에 앞서 반드시 이행권고결정을 하여야 하는 것은 아니다.','소액사건심판법 §5의3',1,false),
(15,1,'제5조','제1편 총칙','O','확정된 이행권고결정에는 기판력은 없으나 집행력은 있다.','소액사건심판법 §5의7·5의8',1,false),
(16,1,'제5조','제1편 총칙','O','법인 등의 보통재판적은 주된 사무소·영업소가 있는 곳에 따라 정하고, 사무소·영업소가 없으면 주된 업무담당자의 주소에 따라 정한다.','민소 §5①',1,false),
(17,1,'제6조','제1편 총칙','O','국가의 보통재판적은 그 소송에서 국가를 대표하는 관청 또는 대법원이 있는 곳으로 한다.','민소 §6',1,false),
(18,1,'제8조','제1편 총칙','O','사해행위취소에 따른 원상회복으로서의 소유권이전등기 말소등기의무의 이행지는 그 등기관서 소재지이다.','판례(의무이행지 관할)',1,false),
(19,1,'제8조','제1편 총칙','O','금전지급채무(대여금)는 지참채무이므로 그 의무이행지인 채권자(원고)의 주소지 법원에 관할이 있다.','민소 §8',1,false),
(20,1,'제8조','제1편 총칙','O','계약으로 이행지를 정하지 않았으면 특정물 인도청구 이외의 채무에 대해서는 채권자의 주소지가 특별재판적인 의무이행지가 된다(지참채무).','민소 §8',1,false),
(21,1,'제8조','제1편 총칙','O','대여금반환청구는 지참채무이므로 채권자(갑)의 주소지를 관할하는 법원(의무이행지)에 소를 제기할 수 있다.','민소 §8',1,false),
(22,1,'제8조','제1편 총칙','O','대여금채무는 지참채무이므로 의무이행지 특별재판적은 채권자의 주소지이고, 단지 돈을 건네준 장소가 관할이 되는 것은 아니다.','민소 §8',1,false),
(23,1,'제9조','제1편 총칙','O','어음·수표에 관한 소는 지급지의 법원에 제기할 수 있다(특별재판적이고 전속관할이 아니다).','민소 §9',1,false),
(24,1,'제11조','제1편 총칙','O','대한민국에 주소가 없거나 알 수 없는 사람에 대하여 재산권에 관한 소를 제기하는 경우에는 청구의 목적·담보의 목적이나 압류할 수 있는 피고의 재산이 있는 곳의 법원에 제기할 수 있다.','민소 §11',1,false),
(25,1,'제18조','제1편 총칙','O','불법행위에 관한 소는 그 행위지의 법원에 제기할 수 있다.','민소 §18',1,false),
(26,1,'제18조','제1편 총칙','O','불법행위로 인한 손해배상청구는 불법행위지(가해행위지) 법원에 관할이 있다.','민소 §18',1,false),
(27,1,'제20조','제1편 총칙','O','부동산에 관한 소를 제기하는 경우에는 부동산이 있는 곳의 법원에 관할이 있다.','민소 §20',2,false),
(28,1,'제21조','제1편 총칙','O','등기·등록에 관한 소를 제기하는 경우에는 등기 또는 등록할 공공기관이 있는 곳의 법원에 관할이 있다.','민소 §21',1,false),
(29,1,'제24조','제1편 총칙','O','특허권 등 지식재산권에 관한 소는 고등법원이 있는 곳의 지방법원(서울은 서울중앙지방법원)의 전속관할에 따른다.','민소 §24',1,false),
(30,1,'제25조','제1편 총칙','O','공동소송에서 한 피고에 대하여 관할권이 있으면 관련재판적(§25②)에 따라 다른 피고에 대하여도 관할이 인정될 수 있다.','민소 §25',1,false),
(31,1,'제25조','제1편 총칙','O','주채무자와 연대보증인을 공동피고로 소송을 제기하는 경우, 관련재판적에 따라 연대보증인의 주소지 관할법원에 제기할 수 있다.','민소 §25②',1,false),
(32,1,'제27조','제1편 총칙','O','하나의 소로 여러 청구를 하는 경우 그 가액을 합산하여 사물관할을 정하므로, 합산 가액이 합의부 관할 기준을 초과하면 합의부 사건이 된다.','민소 §27',1,false),
(33,1,'제27조','제1편 총칙','O','주채무자와 보증인에 대한 청구는 경제적 이익이 같으므로 그 소송목적의 값을 합산하지 않고 흡수된다(다액을 기준으로 한다).','민소 §27',1,false),
(34,1,'제27조','제1편 총칙','O','과실·손해배상·위약금 또는 비용의 청구가 소송의 부대목적이 되는 때에는 그 값을 소가에 합산하지 아니한다.','민소 §27②',2,false),
(35,1,'제27조','제1편 총칙','O','1개의 소로써 수인의 연대채무자에 대하여 청구하는 경우, 그 중 가장 다액인 청구의 가액을 소송목적의 값으로 한다.','인지규칙',1,false),
(36,1,'제27조','제1편 총칙','O','1개의 소로써 주장하는 수개 청구의 경제적 이익이 동일하거나 중복되는 때에는 중복되는 범위에서 흡수되고, 그 중 가장 다액인 청구의 가액을 소송목적의 값으로 한다.','인지규칙',1,false),
(37,1,'제27조','제1편 총칙','O','1개의 소로 여러 비재산권을 목적으로 하는 청구를 하는 경우 그 값을 합산한다(가장 다액으로 하는 것이 아니다).','민소 §27①',1,false),
(38,1,'제27조','제1편 총칙','O','소송목적의 값은 사실심 변론종결시가 아니라 소를 제기한 때를 기준으로 산정한다.','인지규칙',1,false),
(39,1,'제27조','제1편 총칙','O','지연손해금이 소송의 부대목적이 되는 경우 그 값은 소송목적의 값에 합산하지 아니한다.','민소 §27②',1,false),
(40,1,'제27조','제1편 총칙','O','단순병합의 경우 소가를 산정함에 있어서는 병합된 청구의 가액을 합산함이 원칙이다.','민소 §27①',1,false),
(41,1,'제27조','제1편 총칙','O','1개의 소로써 여러 개의 청구를 하는 경우 그 여러 청구의 경제적 이익이 독립한 별개의 것인 때에는 합산하여 소송목적의 값을 산정한다.','민소 §27①',1,false),
(42,1,'제27조','제1편 총칙','O','선택적 병합·예비적 병합 모두 합산하지 않고 그 중 다액인 청구가액을 소송목적의 값으로 한다.','인지규칙',1,false),
(43,1,'제27조','제1편 총칙','O','여러 사람의 연대채무자에 대한 청구의 경우에는 합산하지 않고 그 중 액수가 많은 청구의 값이 소송목적의 값으로 된다.','인지규칙(흡수)',1,false),
(44,1,'제28조','제1편 총칙','O','소송목적의 값이 제소 당시 또는 청구취지 확장 당시 일정액(당시 1억 원)을 초과한 민사사건 판결에 대한 항소사건은 원칙적으로 고등법원이 심판한다.','법원조직법',1,false),
(45,1,'제28조','제1편 총칙','O','서울중앙지방법원 단독판사가 제1심으로 판결한 소가 9,000만 원의 소유권이전등기청구소송의 항소사건은 서울중앙지방법원 합의부가 심판한다.','법원조직법',1,true),
(46,1,'제29조','제1편 총칙','O','당사자는 합의로 제1심 관할법원을 정할 수 있는데, 이 합의는 소송법상의 합의이며 반드시 서면에 의하여야 한다.','민소 §29②',1,false),
(47,1,'제29조','제1편 총칙','O','관할합의의 효력은 특정승계인에게도 미칠 수 있다.','판례',1,false),
(48,1,'제29조','제1편 총칙','O','관할합의의 효력은 그 권리의 특정승계인에게도 미칠 수 있고, 소송물이 채권인지 물권인지에 따라 달라지는 것은 아니다.','대판(관할합의 승계)',1,false),
(49,1,'제29조','제1편 총칙','O','갑과 을이 소비대차에 관하여 합의로 정한 법원에 소를 제기할 수 있으나, 그 관할합의는 서면으로 한 경우에 한한다.','민소 §29②',1,false),
(50,1,'제30조','제1편 총칙','O','관할의 합의가 있으면 관할이 변경되지만, 전속적 합의관할을 정한 경우에도 그 성질은 임의관할이므로 변론관할이 생길 여지가 있다.','판례',1,false),
(51,1,'제30조','제1편 총칙','O','피고가 제1심 법원에서 관할위반이라고 항변하지 아니하고 본안에 대하여 변론하거나 변론준비기일에서 진술하면 그 법원은 관할권을 가진다.','민소 §30',1,false),
(52,1,'제30조','제1편 총칙','O','변론관할은 피고가 현실적으로 본안에 관하여 변론하거나 진술하여야 생기고, 답변서의 진술간주만으로는 변론관할이 생기지 않는다.','판례',2,false),
(53,1,'제30조','제1편 총칙','O','피고가 본안에 관한 준비서면을 제출하고 변론기일에 불출석하여 그 준비서면이 진술간주되더라도 변론관할은 생기지 않는다.','대판(변론관할 진술간주)',1,false),
(54,1,'제30조','제1편 총칙','O','임의관할 위반·담보제공 위반·중재합의의 항변(방소항변)은 본안에 관하여 변론하기 전에 제출하여야 하고, 변론종결시까지 할 수 있는 것이 아니다.','민소 §30·§118',1,false),
(55,1,'제30조','제1편 총칙','O','관할권이 없는 제1심법원에 소가 제기된 경우에도 피고가 관할위반의 항변을 하지 아니하고 본안에 관하여 변론하면 그 법원은 (변론)관할권을 가진다.','민소 §30',1,false),
(56,1,'제31조','제1편 총칙','O','법정 전속관할로 정하여진 소에는 합의관할(및 변론관할) 규정이 적용되지 않는다.','민소 §31',1,false),
(57,1,'제31조','제1편 총칙','O','전속관할로 정하여진 소에 대하여는 관련재판적의 규정을 적용할 수 없다.','민소 §31·§25',1,false),
(58,1,'제31조','제1편 총칙','O','전속관할의 정함이 있는 소에서는 합의관할이나 변론관할 규정의 적용이 배제된다.','민소 §31',1,false),
(59,1,'제31조','제1편 총칙','O','전속관할에 대하여는 합의관할이나 변론관할이 인정되지 아니하고, 관할위반의 경우를 제외하고는 소송이송이 허용되지 아니한다.','민소 §31',1,false),
(60,1,'제31조','제1편 총칙','O','전속관할로 정하여진 소에는 합의관할에 관한 규정이 적용되지 않으므로, 전속관할을 배제하는 관할합의는 효력이 없다.','민소 §31',1,false),
(61,1,'제31조','제1편 총칙','O','전속관할로 정하여진 소에는 변론관할에 관한 규정이 적용되지 않으므로, 피고가 본안에 변론하여도 관할권이 생기지 않는다.','민소 §31',1,false),
(62,1,'제32조','제1편 총칙','O','소송목적의 값이 2억 원을 초과하는 민사사건이 원칙적으로 합의부의 제1심 관할에 속한다(2억 원 이상이 아니라 초과).','사물관할규칙',1,false),
(63,1,'제32조','제1편 총칙','O','수표금·약속어음금 청구사건의 제1심은 소송목적의 값과 상관없이 단독판사가 심판한다.','사물관할규칙',1,false),
(64,1,'제32조','제1편 총칙','O','소송목적의 값이 1억 원인 사건은 (합의부가 아니라) 단독판사의 관할에 속한다.','사물관할규칙',1,false),
(65,1,'제32조','제1편 총칙','O','낙찰자지위확인의 소의 사물관할은 그 소가 산정에 따라 정해진다(재확인 필요).','사물관할규칙',1,true),
(66,1,'제32조','제1편 총칙','O','새마을금고 등 사물관할규칙 §2 단서 2호의 금융기관이 원고가 되어 제기하는 대여금·구상금·보증금 청구사건은 소송목적의 값과 관계없이 단독판사가 제1심으로 심판한다.','사물관할규칙',1,true),
(67,1,'제32조','제1편 총칙','O','관할에 관한 사항은 법원의 직권조사사항이다.','대판(관할 직권조사)',1,false),
(68,1,'제32조','제1편 총칙','O','수표금·약속어음금 청구사건은 소가와 상관없이 단독판사가 심판하므로 합의부 사물관할이 아니다.','사물관할규칙',1,false),
(69,1,'제32조','제1편 총칙','O','해당 채무부존재확인사건은 소가에 따라 사물관할이 정해질 뿐 당연히 합의부 사건이 되는 것은 아니다.','사물관할규칙',1,false),
(70,1,'제32조','제1편 총칙','O','해고무효확인소송은 지방법원 합의부의 사물관할에 해당한다.','사물관할규칙',1,true),
(71,1,'제32조','제1편 총칙','O','신용보증기금이 원고가 되어 5억 원의 구상금 지급을 구하는 사건은 사물관할규칙 §2단서2호에 따라 소가와 무관하게 단독판사가 심판한다.','사물관할규칙',1,true),
(72,1,'제33조','제1편 총칙','O','법원의 관할은 소를 제기한 때를 표준으로 하여 정한다.','민소 §33',2,false),
(73,1,'제33조','제1편 총칙','O','소가는 소를 제기한 때를 기준으로 산정한다.','민소 §33·인지규칙',1,false),
(74,1,'제34조','제1편 총칙','O','지방법원 합의부는 소송에 대하여 관할권이 없는 경우라도 상당하다고 인정하면 직권으로 소송의 전부 또는 일부를 스스로 심리·재판할 수 있다.','민소 §34③',1,false),
(75,1,'제34조','제1편 총칙','O','지방법원 단독판사는 소송에 대하여 관할권이 있는 경우라도 소송의 전부 또는 일부를 같은 지방법원 합의부에 이송할 수 있다.','민소 §34②',1,false),
(76,1,'제34조','제1편 총칙','O','이송은 법원이 직권 또는 당사자의 신청에 의하여 할 수 있으나, 관할위반을 이유로 하는 경우에는 당사자의 신청권이 인정되지 않는다.','대결(전합) 93마524',1,false),
(77,1,'제34조','제1편 총칙','O','원고가 고의·중과실 없이 행정소송으로 제기할 사건을 민사소송으로 잘못 제기한 경우, 수소법원이 그 행정소송 관할도 가지면 행정소송으로 심리·판단하고, 관할이 없으면 관할법원에 이송하여야 한다.','판례',1,false),
(78,1,'제34조','제1편 총칙','O','소액사건은 고유의 사물관할이 있는 것이 아니라 민사단독사건 중 소가에 따라 특례로 처리하는 것이므로, 간이·신속하게 처리될 수 없는 사건은 민사소송법 제34조 제2항에 의하여 지방법원·지원 합의부에 이송할 수 있다.','판례',1,false),
(79,1,'제34조','제1편 총칙','O','지방법원 본원 합의부가 단독판사 판결에 대한 항소사건을 심판하던 중 합의부 관할에 속하는 소송이 새로 추가되거나 그러한 소송으로 청구가 변경되어도, 추가·변경된 청구에 대하여도 그대로 심판할 수 있다.','대판(본원합의부 항소심)',1,false),
(80,1,'제34조','제1편 총칙','O','가정법원과 민사법원 사이에도 관할위반에 따른 이송이 인정되므로, 가정법원 전속관할 소를 민사법원에 제기한 경우 민사법원은 각하할 것이 아니라 관할법원으로 이송하여야 한다.','대판(가정-민사 이송)',1,false),
(81,1,'제34조','제1편 총칙','O','손해나 지연을 피하기 위한 이송에 관하여는 당사자의 이송신청권이 인정되지만, 관할위반을 이유로 한 이송에 관하여는 당사자의 이송신청권이 인정되지 않는다.','대결(전합) 93마524',1,false),
(82,1,'제34조','제1편 총칙','O','합의부 사건으로 심리하는 도중에 청구의 감축으로 단독사건으로 된 경우에도 합의부에서 단독판사로 이송하지 아니한다.','대판(합의부 계속심판)',1,false),
(83,1,'제34조','제1편 총칙','O','병합된 청구 중 어느 하나가 다른 법원의 전속관할에 속하는 때에는 결정으로 이를 이송하여야 한다.','민소 §34',1,false),
(84,1,'제34조','제1편 총칙','O','관할위반의 경우 당사자에게 이송신청권은 없고, 당사자의 이송신청은 직권발동을 촉구하는 의미 이상은 없으며 그에 대한 재판을 필요로 하지 않는다.','대판(이송신청권)',1,false),
(85,1,'제35조','제1편 총칙','O','전속적 관할합의가 있어도 그 관할은 임의관할이므로, 법원은 손해나 지연을 피하기 위한 필요(§35)로 사건을 다른 관할법원에 이송할 수 있다.','대판(전속적 합의관할 이송)',1,false),
(86,1,'제35조','제1편 총칙','O','법원은 소송에 대하여 관할권이 있는 경우라도 현저한 손해·지연을 피하기 위하여 직권으로 소송의 전부를 다른 관할법원에 이송할 수 있다.','민소 §35',1,false),
(87,1,'제35조','제1편 총칙','O','관할위반 외의 사유라도 법(§35 등)이 당사자의 신청을 인정하는 경우에는 이송신청권이 있고, 그 신청에 대한 재판과 즉시항고가 인정된다.','민소 §35',1,false),
(88,1,'제37조','제1편 총칙','O','법원은 소송의 이송결정이 확정된 뒤라도 급박한 사정이 있는 때에는 직권 또는 당사자의 신청에 따라 필요한 처분을 할 수 있으나, 기록을 보낸 뒤에는 그러하지 아니하다.','민소 §37',1,false),
(89,1,'제38조','제1편 총칙','O','소송을 이송받은 법원은 사건을 다시 다른 법원에 이송하지 못하고, 이송결정이 확정된 이상 원칙적으로 전속관할을 위배하여 이송한 경우에도 이송결정의 기속력이 미친다.','판례(이송결정 기속력)',1,false),
(90,1,'제38조','제1편 총칙','O','전속관할 위배 이송에도 기속력이 미치지만, 심급관할을 위배한 이송결정의 기속력은 이송받은 상급심 법원에는 미치지 않는다.','대판 95마1088',4,false),
(91,1,'제38조','제1편 총칙','O','소송을 이송받은 법원은 이송결정에 따라야 하고 사건을 다시 다른 법원에 이송하지 못한다.','민소 §38②',2,false),
(92,1,'제38조','제1편 총칙','O','전속관할을 위배한 이송결정에 대하여 당사자가 즉시항고를 하지 아니하여 확정된 이상 원칙적으로 이송결정의 기속력이 인정된다.','대판 95마1088',1,false),
(93,1,'제38조','제1편 총칙','O','전속관할 규정을 위배한 이송결정이라도 즉시항고 없이 확정되면 원칙적으로 기속력이 인정된다.','대판 95마1088',1,false),
(94,1,'제38조','제1편 총칙','O','심급관할을 위배한 이송결정의 기속력은 이송받은 같은 심급의 법원과 하급심 법원에만 미치고 상급심 법원에는 미치지 아니한다고 해석함이 타당하다.','대판 95마1088',1,false),
(95,1,'제39조','제1편 총칙','O','당사자에게 관할위반을 이유로 하는 이송신청권은 없으나, 법원이 이송결정을 한 경우 그 이송결정에 대하여는 민사소송법 제39조에 따라 즉시항고를 할 수 있다.','대결(전합) 93마524; 민소 §39',1,false),
(96,1,'제39조','제1편 총칙','O','관할위반을 이유로 한 당사자의 이송신청을 기각하는 결정에 대하여는 즉시항고는 물론 특별항고도 허용되지 않는다.','대결(전합) 93마524',1,false),
(97,1,'제39조','제1편 총칙','O','당사자에게는 관할위반을 이유로 한 이송신청권이 없으므로 그 신청을 배척한 데 대하여는 항고가 허용되지 않는다.','대결(전합) 93마524',1,false),
(98,1,'제39조','제1편 총칙','O','이송결정과 이송신청의 기각결정에 대하여는 재판이 고지된 날부터 1주 이내에 즉시항고를 할 수 있다.','민소 §39',1,false),
(99,1,'제40조','제1편 총칙','O','이송결정이 확정된 때에는 소송은 처음부터 이송받은 법원에 계속된 것으로 본다.','민소 §40',2,false),
(100,1,'제40조','제1편 총칙','O','재심의 소가 재심제기기간 내에 제1심법원에 제기되었으나 항소심판결을 대상으로 한 것으로 인정되어 항소심법원에 이송된 경우, 재심제기기간의 준수 여부는 제1심법원에 제기된 때를 기준으로 한다.','대판(재심 이송 기간)',1,false),
(101,1,'제40조','제1편 총칙','O','소송이송이 있는 경우에도 소제기에 따른 시효중단의 시점은 관할법원이 이송받은 때가 아니라 이송한 법원에 처음 소가 제기된 때이다.','대판(이송과 시효중단)',1,false),
(102,1,'제40조','제1편 총칙','O','이송결정이 확정된 때에는 그 결정의 정본을 소송기록에 붙여 이송받을 법원에 보내야 한다(원본이 아니다).','민소 §40②',1,false),
(103,1,'제40조','제1편 총칙','O','소 제기에 의한 시효중단의 효력은 소송의 이송에 의하여 소멸되지 않는다.','대판(이송과 시효중단)',1,false),
(104,1,'제41조','제1편 총칙','O','기피신청사건의 재판에 관여한 것은 본안사건의 ''전심''에 관여한 것이 아니므로, 그 법관이 본안사건에 관여하더라도 제척사유인 전심관여에 해당하지 않는다.','판례',1,false),
(105,1,'제41조','제1편 총칙','O','재심대상 재판에 관여한 법관이 당해 재심사건의 재판에 관여하는 경우, 이는 제척사유인 전심관여에 해당하지 아니한다.','판례',1,false),
(106,1,'제41조','제1편 총칙','O','법관이 당사자인 단체(종중)의 구성원이라는 사정만으로는 당사자와 공동권리자·공동의무자 관계에 있다고 할 수 없어 제척사유가 되지 않는다.','판례',1,false),
(107,1,'제41조','제1편 총칙','O','법관의 제척원인인 전심관여란 최종변론과 판결의 합의에 관여하거나 종국판결과 더불어 상급심의 판단을 받는 중간적 재판에 관여함을 말하고, 최종변론 전의 변론·증거조사·기일지정 등 소송지휘상의 재판에 관여한 경우는 포함되지 않는다.','판례',1,false),
(108,1,'제41조','제1편 총칙','O','최종변론 전의 변론이나 증거조사에만 관여한 경우는 ''이전심급의 재판에 관여한 때''라고 할 수 없다.','대판(이전심급 관여)',1,false),
(109,1,'제41조','제1편 총칙','O','청구이의의 소는 집행권원에 관한 별개의 소이므로, 그 대상인 본안 확정판결은 이전심급의 재판에 해당하지 않아 그 본안판결에 관여한 법관이 청구이의의 소를 재판하여도 제척사유가 아니다.','대판(청구이의 제척)',1,false),
(110,1,'제41조','제1편 총칙','O','종중소송에서 재판부 구성법관이 종중의 구성원이면 당사자와 공동권리자·공동의무자의 관계에 있어 제척이유가 된다.','대판(종중 구성원 법관)',1,false),
(111,1,'제41조','제1편 총칙','O','재심대상 재판에 관여한 법관은 (그 재심사건이 이전심급의 재판에 해당하지 않으므로) 당해 재심사건의 직무를 집행할 수 있다.','대판(재심 제척)',1,false),
(112,1,'제41조','제1편 총칙','O','법관이 불복사건의 이전심급의 재판 중 판결선고에만 관여한 경우에는 불복사건의 직무를 집행할 수 있다.','대판(선고만 관여)',1,false),
(113,1,'제41조','제1편 총칙','O','법관이 다른 법원의 촉탁에 따라 그 직무를 수행한 경우는 §41 4호 단서에 의해 제척사유에서 제외되므로, 불복사건의 직무집행에서 제척되지 않는다.','민소 §41 4호 단서',1,false),
(114,1,'제43조','제1편 총칙','O','당사자가 법관을 기피할 이유가 있음을 알면서도 본안에 관하여 변론하거나 변론준비기일에서 진술을 한 경우에는 기피신청을 하지 못한다.','민소 §43②',2,false),
(115,1,'제43조','제1편 총칙','O','평균적 일반인인 당사자의 관점에서 법관이 불공정한 재판을 할 수 있다는 의심을 할 만한 객관적 사정이 있는 때에는, 실제 편파성이 없더라도 기피가 인정될 수 있다.','판례',1,false),
(116,1,'제43조','제1편 총칙','O','기피이유인 ''법관에게 공정한 재판을 기대하기 어려운 사정''이란, 통상인의 판단으로서 법관과 사건의 관계상 편파적이고 불공정한 재판을 하지 않을까 하는 염려를 일으킬 객관적 사정을 가리킨다.','대판(기피사유)',1,false),
(117,1,'제43조','제1편 총칙','O','소송당사자 일방이 재판장의 변경에 따라 소송대리인을 교체한 경우는, 재판의 공정을 기대하기 어려운 객관적 사정이 있는 때에 해당하지 않는다.','대판(기피 부정례)',1,false),
(118,1,'제44조','제1편 총칙','O','기피하는 이유와 소명방법은 신청한 날부터 3일 이내에 서면으로 제출하여야 하나, 기피 원인이 법원에 현저한 사실인 경우에는 달리 소명할 필요가 없다.','민소 §44②',2,false),
(119,1,'제44조','제1편 총칙','O','기피신청은 서면 또는 기일에서 말로 할 수 있으므로, 법정에서 구두로 한 기피신청도 적법하다.','민소규칙',1,false),
(120,1,'제45조','제1편 총칙','O','기피신청이 법이 정한 신청방식을 준수하지 않거나 소송지연을 목적으로 한 것이 분명한 때에는, 기피신청을 받은 법원이나 법관이 결정으로 그 신청을 각하한다.','민소 §45①',1,false),
(121,1,'제46조','제1편 총칙','O','기피신청의 당부 재판은 신청을 받은 법관의 소속 법원 합의부에서 결정으로 하고, 합의부를 구성하지 못하는 경우에는 소속 법원의 다른 법관이 재판한다.','민소 §46',1,false),
(122,1,'제46조','제1편 총칙','O','제척 또는 기피신청을 받은 법관 또는 법원사무관등은 그 재판에 관하여 의견을 진술할 수 있다.','민소 §46③·§50',1,false),
(123,1,'제46조','제1편 총칙','O','법관에 대한 제척·기피 재판은 그 소속 법원 합의부가 하지만, 법원사무관등에 대한 제척·기피 재판은 그가 속한 법원이 결정으로 한다(§50②).','민소 §46·§50',1,false),
(124,1,'제46조','제1편 총칙','O','법관에 대한 기피신청은 해당 법관의 소속 법원 합의부에서 결정하나, 해당 법원의 법관이 부족하여 기피신청을 받은 법관을 제외하고는 합의부를 구성하지 못하는 경우에는 바로 위의 상급법원이 결정하여야 한다.','민소 §46',1,false),
(125,1,'제46조','제1편 총칙','O','기피신청이 부적법하거나 소송지연 목적이 분명한 때에는 기피당한 법관이 속한 법원 또는 그 법관이 결정으로 이를 각하할 수 있다(간이각하).','민소 §45①',1,false),
(126,1,'제46조','제1편 총칙','O','지방법원 단독판사에 대한 제척·기피 재판은 그 법관이 속한 지방법원 합의부가 결정으로 한다.','민소 §46①',1,false),
(127,1,'제47조','제1편 총칙','O','지방법원 항소부 소속 법관에 대한 제척·기피신청에 각하결정 또는 소속 법원 합의부의 기각결정이 있은 경우, 이는 항소법원의 결정과 같으므로 대법원에 재항고하는 방법으로 다투어야 한다.','대결(항소부 법관 기피)',3,false),
(128,1,'제48조','제1편 총칙','O','법원은 제척·기피신청이 있는 경우 그 재판이 확정될 때까지 소송절차를 정지하여야 하나, 신청이 각하된 경우 또는 종국판결 선고·긴급을 요하는 행위를 하는 경우에는 그러하지 아니하다.','민소 §48',1,false),
(129,1,'제48조','제1편 총칙','O','법원은 제척 또는 기피신청을 각하한 경우에는 소송절차를 정지할 필요가 없다.','민소 §48',1,false),
(130,1,'제48조','제1편 총칙','O','종국판결의 선고는 기피신청이 있는 때에도 할 수 있으므로, 변론종결 후 기피신청을 당한 법관이 소송절차를 정지하지 아니하고 판결을 선고한 것이 위법하다고 할 수 없다.','대판(변론종결 후 기피)',2,false),
(131,1,'제48조','제1편 총칙','O','기피신청이 있는 때에는 원칙적으로 본안의 소송절차를 정지하여야 하나, 법원이 절차를 정지하지 아니하고 변론을 종결하여 선고기일을 지정하였더라도 그 당부는 종국판결에 대한 불복절차로 다툴 수 있을 뿐이다.','대판(절차정지 위반)',1,false),
(132,1,'제48조','제1편 총칙','O','제척신청이 (간이)각하된 때에는 그 결정이 확정되기 이전이라도 직무를 행할 수 있다.','민소 §48',1,false),
(133,1,'제48조','제1편 총칙','O','변론종결 후 법관에 대한 기피신청이 있는 경우에는 소송절차를 정지하지 아니하고 종국판결을 선고할 수 있다.','민소 §48',1,false),
(134,1,'제50조','제1편 총칙','O','법원사무관등(참여관·실무관)에 대해서도 제척·기피신청을 할 수 있다(§50).','민소 §50',1,false),
(135,1,'제50조','제1편 총칙','O','법원사무관등에 대하여도 법관의 제척·기피·회피에 관한 규정이 준용된다(§50).','민소 §50',1,false),
(136,1,'제51조','제1편 총칙','O','당사자능력은 소송요건으로서 사실심 변론종결시를 기준으로 판단한다.','판례',2,false),
(137,1,'제51조','제1편 총칙','O','불법말소된 근저당권설정등기의 회복등기청구는 그 말소 당시의 소유자를 상대로 하여야 한다.','대판 68다1617',1,false),
(138,1,'제51조','제1편 총칙','O','불법점유를 이유로 한 건물명도청구는 현실적으로 점유하는 사람을 상대로 하여야 하고, 타에 임대하여 현실적으로 점유하지 않는 사람을 상대로 할 것이 아니다.','대판 98다9045',1,false),
(139,1,'제51조','제1편 총칙','O','건물의 부지는 건물 소유자가 점유하므로 토지인도(건물철거)청구의 상대방은 건물 소유자이고, 건물 점유자에 대하여는 건물로부터의 퇴거를 구할 수 있을 뿐이다.','대판 2010다43801',1,false),
(140,1,'제51조','제1편 총칙','O','관리단으로부터 집합건물 관리업무를 위임받은 위탁관리회사는 특별한 사정이 없는 한 자기 이름으로 구분소유자 등을 상대로 관리비청구의 소를 제기할 당사자적격이 있다.','대판 2014다87885',1,false),
(141,1,'제51조','제1편 총칙','O','실종자를 당사자로 한 판결 확정 후 실종선고가 확정되어 사망간주 시점이 소제기 전으로 소급하더라도, 그 판결 자체가 소급하여 당사자능력 없는 사망자 상대 판결로서 무효가 된다고 볼 수 없다.','대판(실종선고 소급)',1,false),
(142,1,'제51조','제1편 총칙','O','소제기 당시 이미 사망한 자와 상속인이 공동원고로 표시된 손해배상청구의 소에서, 사망자 명의 소 부분은 부적법 각하될 뿐이고, 그 소제기로 상속인이 사망자의 손해배상청구권에 대한 자신의 상속분까지 권리행사한 것으로 볼 수는 없다.','대판(공동원고 사망)',1,false),
(143,1,'제51조','제1편 총칙','O','학교는 교육시설의 명칭에 불과하여 비송사건에서도 당사자능력이 인정되지 않는다.','대결(학교 당사자능력)',1,false),
(144,1,'제51조','제1편 총칙','O','대학교 학장은 학교법인의 기관의 하나에 지나지 아니하여 민사소송의 당사자적격이 인정되지 않는다.','대판(학장 당사자적격)',1,false),
(145,1,'제51조','제1편 총칙','O','자연물인 도롱뇽 또는 그를 포함한 자연 그 자체로서는 공사금지가처분 사건을 수행할 당사자능력이 인정되지 않는다.','대결 2006마(도롱뇽)',1,false),
(146,1,'제51조','제1편 총칙','O','소제기 단계에서 소송대리인의 대리권 존부는 소송요건으로서 직권조사사항이고, 그 존부가 불명한 경우에는 증명책임의 원칙이 적용되며 직권조사사항인 소송요건에 대한 증명책임은 원고에게 있다.','대판(직권조사 증명책임)',1,false),
(147,1,'제51조','제1편 총칙','O','이행의 소에서는 자기의 급부청구권을 주장하는 자가 정당한 원고이고, 급부의무자로 주장된 자가 정당한 피고이다.','통설·판례',1,false),
(148,1,'제51조','제1편 총칙','O','채권에 대한 압류 및 추심명령이 있으면 제3채무자에 대한 이행의 소는 추심채권자만이 제기할 수 있고 채무자는 당사자적격을 상실한다.','대판(추심명령)',2,false),
(149,1,'제51조','제1편 총칙','O','채권자가 채권자취소권을 행사하려면 수익자나 전득자를 상대로 취소소송을 제기하여야 하고, 채무자를 상대로 그 소송을 제기할 수는 없다.','대판(사해행위 피고)',1,false),
(150,1,'제51조','제1편 총칙','O','근저당권이 양도되어 이전 부기등기가 마쳐진 경우, 근저당권설정등기의 말소등기청구는 현재의 등기명의자인 양수인을 상대로 하여야 하고 양도인은 피고적격이 없다.','대판(근저당 이전 말소)',2,false),
(151,1,'제51조','제1편 총칙','O','비법인사단 대표자의 적법한 대표권 유무는 직권조사사항이므로, 이미 제출된 자료에 대표권의 적법성에 의심이 갈 만한 사정이 엿보이면 법원은 그에 관하여 심리·조사할 의무가 있다.','대판(대표권 직권조사)',1,false),
(152,1,'제51조','제1편 총칙','O','민법상 조합에서 조합규약·조합결의로 자기 이름으로 조합재산을 관리·집행할 권한을 수여받은 업무집행조합원은, 조합재산에 관한 소송에서 조합원으로부터 임의적 소송신탁을 받아 자기 이름으로 소송을 수행하는 것이 허용된다.','대판(업무집행조합원)',1,false),
(153,1,'제51조','제1편 총칙','O','등기의무자가 아닌 자나 등기에 이해관계 있는 제3자가 아닌 자를 상대로 한 등기말소절차 이행청구의 소는 당사자적격이 없는 자를 상대로 한 부적법한 소이다.','대판(말소등기 피고적격)',1,false),
(154,1,'제51조','제1편 총칙','O','금전채권에 대한 가압류가 있더라도 가압류채무자는 제3채무자를 상대로 그 금전채권의 이행을 구하는 소를 제기할 수 있다.','대판(가압류와 이행의 소)',1,false),
(155,1,'제51조','제1편 총칙','O','이사회결의 부존재확인의 소는 법인을 피고로 하여야 하고, 그 결의로 선임된 이사는 피고적격이 없다.','대판(이사회결의 부존재확인 피고)',1,false),
(156,1,'제51조','제1편 총칙','O','제1심이 당사자를 제대로 확정하였음에도 항소심이 이를 잘못 보아 소송당사자 아닌 자를 당사자로 취급하여 판결한 경우, 진정한 소송당사자는 상고를 제기하여 이를 다툴 수 있다.','대판 94다61243',1,false),
(157,1,'제51조','제1편 총칙','O','민법상 법인에 해당하면 그 단체는 (당사자능력의 일반적 전제로서) 당사자능력을 갖는다.','민소 §51',1,false),
(158,1,'제51조','제1편 총칙','O','당사자능력은 소송요건으로서 사실심 변론종결시를 기준으로 판단하므로, 소제기 당시 비법인사단의 실체가 없었더라도 변론종결시까지 그 실체를 갖추면 그 소가 부적법하다고 할 수 없다.','대판(당사자능력 기준시)',1,false),
(159,1,'제51조','제1편 총칙','O','소제기 전에 이미 사망한 자를 피고로 한 판결은 2당사자 대립구조의 흠결로 당연무효이다(상소·재심 대상이 아니라 무효).','대판(소제기 전 사망)',1,false),
(160,1,'제51조','제1편 총칙','O','채권자가 채권압류 및 추심명령을 받으면 채무자는 피압류채권에 대한 이행소송을 제기할 당사자적격을 상실한다.','대판(추심명령)',1,false),
(161,1,'제51조','제1편 총칙','O','사해행위취소의 소의 원고적격자는 채권자이며, 피고적격자는 수익자 또는 전득자이다.','대판(사해행위 당사자)',1,false),
(162,1,'제51조','제1편 총칙','O','취득시효 완성을 원인으로 하는 소유권이전등기청구의 피고적격자는 시효완성 당시의 등기부상 소유자이다.','대판(취득시효 피고)',1,false),
(163,1,'제51조','제1편 총칙','O','당사자능력이 없어 소각하판결을 하여야 함에도 이를 간과하고 본안판결을 하였을 때는, 확정 전이면 상소에 의하여 취소할 수 있다.','대판(당사자능력 간과)',1,false),
(164,1,'제51조','제1편 총칙','O','국가의 입법기관인 국회는 (독립한 권리·의무의 주체가 아니어서) 당사자능력이 없다.','대판(국회 당사자능력)',1,false),
(165,1,'제51조','제1편 총칙','O','외국법인의 국내 지점은 독립한 법인격이 없어 당사자능력이 없고, 외국법인 자체가 당사자능력을 가진다.','대판(외국법인 지점)',1,false),
(166,1,'제51조','제1편 총칙','O','청산종결등기가 있어도 청산사무가 종료하지 않는 이상 그 한도에서 청산법인은 당사자능력이 있다.','대판(청산법인)',1,false),
(167,1,'제51조','제1편 총칙','O','학교는 교육시설의 명칭에 불과하여 당사자능력이 인정되지 않고, 그 설립주체(학교법인 등)가 당사자가 되어야 한다.','대판(학교 당사자능력)',1,false),
(168,1,'제51조','제1편 총칙','O','이행의 소에서는 자기의 급부청구권을 주장하는 자가 원고적격을 가지므로, 실제로 권리가 없으면 소각하가 아니라 청구기각 판결을 한다.','대판(이행의 소 당사자적격)',1,false),
(169,1,'제51조','제1편 총칙','O','파산재단에 관한 소송을 수행하는 파산관재인은 (법률의 규정에 의한) 법정 소송담당이다.','통설',1,false),
(170,1,'제51조','제1편 총칙','O','추심명령을 얻은 압류채권자는 (법률의 규정에 의한) 법정 소송담당이다.','통설',1,false),
(171,1,'제51조','제1편 총칙','O','소제기 전 이미 사망한 자를 피고로 한 판결은 확정되더라도 당연무효이므로 기판력을 가지지 않는다.','대판(사망자 판결)',1,false),
(172,1,'제51조','제1편 총칙','O','이행의 소에서 피고적격은 원고에 의하여 이행의무자라고 주장된 자에게 있고, 실제로 정당한 이행의무자로 인정된 자에게 있는 것이 아니다(이는 본안의 문제).','대판(이행의 소 당사자적격)',1,false),
(173,1,'제51조','제1편 총칙','O','형성의 소에서는 보통 이를 인정하는 법규 자체에 원고 또는 피고로 될 사람을 명문으로 정하고 있고, 그 자가 원고·피고로서 적격을 가진다.','통설',1,false),
(174,1,'제51조','제1편 총칙','O','파산관재인은 법률의 규정에 의한 법정 소송담당이고 임의적 소송담당이 아니다.','통설',1,false),
(175,1,'제51조','제1편 총칙','O','어음의 추심위임배서의 피배서인은 임의적 소송담당이다.','대판(추심위임배서)',1,false),
(176,1,'제51조','제1편 총칙','O','금융기관의 연체대출금 회수위임을 받은 한국자산관리공사는 (법률이 허용한) 임의적 소송담당이다.','대판(자산관리공사)',1,false),
(177,1,'제51조','제1편 총칙','O','임의적 소송담당이란 권리관계의 주체가 자신의 의사로 제3자에게 자신의 권리에 대한 소송수행권을 수여하는 경우를 말한다.','통설',1,false),
(178,1,'제51조','제1편 총칙','O','업무집행조합원은 조합재산에 관하여 조합원으로부터 임의적 소송신탁을 받아 자기 이름으로 소송을 수행할 수 있다는 것이 판례이다.','대판(업무집행조합원)',1,false),
(179,1,'제51조','제1편 총칙','O','명문의 규정이 없는 경우 임의적 소송담당은 원칙적으로 허용되지 않는다는 것이 통설·판례이다.','대판(임의적 소송담당)',1,false),
(180,1,'제51조','제1편 총칙','O','소송 계속·판결 확정 당시 당사자능력이 있었던 이상, 그 후 실종선고로 사망간주 시점이 소 제기 전으로 소급하더라도 판결이 무효로 되는 것은 아니다.','대판(실종선고 소급)',1,false),
(181,1,'제52조','제1편 총칙','O','총유재산에 관한 소송은 비법인사단이 사원총회 결의를 거쳐 그 명의로 하거나 구성원 전원이 당사자가 되어 필수적 공동소송으로 할 수 있을 뿐이고, 사원총회 결의 없이 제기한 소송은 특별수권을 결하여 부적법하다.','대판(전합) 2004다44971',1,false),
(182,1,'제52조','제1편 총칙','O','법인이 아닌 사단이나 재단은 대표자 또는 관리인이 있는 경우 그 사단·재단의 이름으로 당사자가 될 수 있다.','민소 §52',2,false),
(183,1,'제52조','제1편 총칙','O','비법인 사단이 총유재산에 관한 소송을 제기할 때에는 특별한 사정이 없는 한 사원총회 결의를 거쳐야 하므로, 그 결의 없이 그 명의로 제기한 소송은 소송요건이 흠결되어 부적법하다.','대판(총유재산 소송)',1,false),
(184,1,'제52조','제1편 총칙','O','법인이 아닌 사단이 당사자능력을 가지려면 반드시 대표자 또는 관리인이 있어야 한다.','민소 §52',1,false),
(185,1,'제52조','제1편 총칙','O','법인의 하부조직이라도 스스로 단체로서의 실체를 갖추고 독자적인 활동을 하고 있다면, 법인과 별도의 법인이 아닌 사단으로서 당사자능력을 가진다.','대판(하부조직 당사자능력)',1,false),
(186,1,'제52조','제1편 총칙','O','회칙과 임원을 두고 월례회·임시회로 의사결정을 하여 온 아파트 부녀회는 비법인사단으로서 당사자능력이 있다.','대판(부녀회)',1,false),
(187,1,'제52조','제1편 총칙','O','노동조합의 하부조직이라도 독자적인 규약(지부준칙)을 가지고 독립된 활동을 하는 독자적 조직체인 노동조합 지부는 당사자능력이 있다.','대판(노조 지부)',1,false),
(188,1,'제52조','제1편 총칙','O','부락 주민을 구성원으로 하여 고유목적·의사결정기관·대표자를 두고 독자적으로 활동하는 자연부락은 비법인사단으로서 당사자능력이 있다.','대판(자연부락)',1,false),
(189,1,'제52조','제1편 총칙','O','총유재산에 관한 소송은 사원총회 결의를 거쳐 사단 자체의 명의로 하거나 구성원 전원이 당사자가 되어 할 수 있다(사단 명의로만 가능한 것이 아니다).','대판(총유재산 소송)',1,false),
(190,1,'제52조','제1편 총칙','O','총유재산의 보존을 위한 소도 사원총회 결의를 거쳐 사단 명의로 하거나 구성원 전원이 당사자가 되어야 하고, 대표자 개인이 제기할 수 없다.','대판(전합) 2004다44971',1,false),
(191,1,'제52조','제1편 총칙','O','법인이 아닌 사단의 대표자는 소송상 법정대리인에 준하여 취급된다.','민소 §52·§64',1,false),
(192,1,'제52조','제1편 총칙','O','법인이 아닌 사단의 대표자 자격에 관하여 상대방 당사자가 자백하여도(직권조사사항이므로) 법원을 구속하지 않는다.','대판(대표자 자격 직권)',1,false),
(193,1,'제52조','제1편 총칙','O','법인 아닌 사단은 구성원이 없게 되었더라도 곧바로 소멸하여 당사자능력을 상실하는 것은 아니고, 청산사무가 완료되어야 비로소 당사자능력이 소멸한다.','대판(비법인사단 청산)',1,false),
(194,1,'제53조','제1편 총칙','O','임차인들이 甲을 임대차계약상의 임대인이라고 주장하면서 甲에게 각 보증금의 반환을 청구하는 경우, 그 쟁점이 甲이 계약당사자인지 여부에 있으므로 임차인들은 공동의 이해관계가 있어 선정당사자를 선정할 수 있다.','대판; 민소 §53',1,false),
(195,1,'제53조','제1편 총칙','O','선정당사자가 받은 판결은 선정자에 대해서도 효력이 미치고, 선정당사자가 이행판결을 받았으면 이에 의하여 선정자를 위하여 또는 선정자에 대하여 강제집행을 할 수 있으며, 그 집행을 위하여는 선정자와의 관계에서 승계집행문이 필요하다.','통설·판례',1,false),
(196,1,'제53조','제1편 총칙','O','공동의 이해관계를 가진 여러 사람이 당사자를 선정한 경우 선정당사자는 특별한 약정이 없는 한 소송 종결에 이르기까지 모두를 위하여 소송을 수행할 수 있으므로 상소의 제기도 할 수 있다.','판례',1,false),
(197,1,'제53조','제1편 총칙','O','선정당사자는 선정자로부터 소송수행의 포괄적 권한을 받으므로 소의 취하 등 일체의 소송행위를 선정자의 개별적 동의 없이 할 수 있다.','판례',1,false),
(198,1,'제53조','제1편 총칙','O','선정당사자는 공동의 이해관계가 있는 자 중에서 선정하여야 하고, 선정당사자가 선정되면 선정자는 소송에서 탈퇴한다.','민소 §53',1,false),
(199,1,'제53조','제1편 총칙','O','선정당사자는 소송수행에 필요한 일체의 소송행위(소취하·부제소합의 포함)를 할 수 있으므로, 선정자들의 개별 동의가 없어도 그 합의의 효력이 선정자들에게 미친다.','대판(선정당사자 권한)',1,false),
(200,1,'제53조','제1편 총칙','O','선정당사자가 별도의 수권 없이 변호사 보수에 관한 약정을 하면서 향후 보수에 관하여 다투지 않기로 한 부제소합의는, 선정자로부터 별도로 위임받은 바 없다면 선정자에 대하여 효력이 없다.','대판(보수 부제소합의)',1,false),
(201,1,'제53조','제1편 총칙','O','선정당사자의 선정행위 시 심급의 제한에 관한 약정 등이 없는 한, 선정의 효력은 소송이 종료에 이르기까지 계속된다.','대판(선정 효력)',3,false),
(202,1,'제53조','제1편 총칙','O','가처분신청 절차에서 이루어진 선정행위의 효력은 그에 기한 제소명령신청 사건에는 미치지만, 가처분결정 취소신청 사건에는 그 선정의 효력이 미치지 아니한다.','대판(선정 효력 범위)',1,false),
(203,1,'제53조','제1편 총칙','O','변호사 보수에 관한 약정은 소송수행에 필요한 행위의 범위를 넘으므로, 선정자들의 개별 동의나 별도 위임 없이 한 보수 약정은 선정자들에게 효력이 미치지 않는다.','대판(선정 보수약정)',1,false),
(204,1,'제53조','제1편 총칙','O','다수자의 권리·의무가 동종이며 그 발생원인이 동종인 관계에 있는 것만으로는 공동의 이해관계가 있다고 할 수 없어 선정당사자의 선정을 허용할 것이 아니다.','대판(공동 이해관계)',2,false),
(205,1,'제53조','제1편 총칙','O','선정당사자가 받은 판결은 선정자에 대해서도 그 효력이 미친다.','민소 §53·§218③',1,false),
(206,1,'제53조','제1편 총칙','O','선정당사자는 공동의 이해관계를 가진 여러 사람 중에서 선정되어야 하므로, 선정당사자 본인에 대한 부분의 소가 취하되거나 판결이 확정되는 등으로 공동의 이해관계가 소멸하는 경우에는 그 자격을 당연히 상실한다.','대판',5,false),
(207,1,'제53조','제1편 총칙','O','당사자선정(선정당사자의 자격)은 서면으로 증명하여야 한다(§58 준용).','민소 §58',1,false),
(208,1,'제53조','제1편 총칙','O','소송이 계속된 후에 선정을 하면 선정자는 당연히 소송에서 탈퇴한다.','민소 §53②',1,false),
(209,1,'제53조','제1편 총칙','O','선정당사자 본인에 대한 부분의 소가 취하되어 공동의 이해관계가 소멸하면 선정당사자의 자격이 당연히 상실된다.','대판(선정자격 상실)',2,false),
(210,1,'제53조','제1편 총칙','O','어떤 심급에 한정하여 선정당사자를 선정하였다고 볼 사정이 없다면 선정의 효력은 소송 종료에 이르기까지 계속된다.','대판(선정 효력)',1,false),
(211,1,'제53조','제1편 총칙','O','선정당사자는 당사자 본인들의 선정행위(수권)에 의한 임의적 소송담당이다.','통설',2,false),
(212,1,'제53조','제1편 총칙','O','선정의 시기는 소송계속 전이거나 계속 후이거나 불문한다.','민소 §53',1,false),
(213,1,'제53조','제1편 총칙','O','선정당사자는 선정자를 위하여 일체의 소송행위를 할 수 있으므로 청구의 포기·인낙·화해·소취하 등도 특별한 수권 없이 할 수 있다.','대판(선정당사자 권한)',1,false),
(214,1,'제53조','제1편 총칙','O','선정자는 언제든지 선정을 철회할 수 있다.','민소 §53②',1,false),
(215,1,'제53조','제1편 총칙','O','명문의 규정이 있는 경우로는 선정당사자, 추심위임배서의 피배서인, 금융기관의 연체대출금 회수위임을 받은 한국자산관리공사를 들 수 있다.','통설',1,false),
(216,1,'제54조','제1편 총칙','O','여러 선정당사자 가운데 죽거나 자격을 잃은 사람이 있는 경우에는 다른 선정당사자가 모두를 위하여 소송행위를 한다.','민소 §54',1,false),
(217,1,'제54조','제1편 총칙','O','여러 선정당사자 중 일부가 사망하거나 자격을 상실하여도 다른 선정당사자가 전원을 위하여 소송행위를 하므로 소송절차가 중단되지 않는다.','민소 §54',1,false),
(218,1,'제55조','제1편 총칙','O','미성년자라도 독립하여 법률행위를 할 수 있는 범위(예: 허락된 영업, 임금 청구 등)에서는 소송능력이 인정되어 스스로 소송행위를 할 수 있다.','민소 §55',1,false),
(219,1,'제55조','제1편 총칙','O','피한정후견인은 한정후견인의 동의가 필요한 행위에 관하여는 대리권 있는 한정후견인에 의해서만 소송행위를 할 수 있다.','민소 §55①',1,false),
(220,1,'제55조','제1편 총칙','O','미성년자는 자신의 노무제공에 따른 임금의 청구를 독자적으로 할 수 있는 소송능력이 있다.','대판(미성년자 임금)',1,false),
(221,1,'제56조','제1편 총칙','O','미성년자의 후견인이 친족회 동의를 받아 소를 제기하였더라도, 그 소를 취하하기 위하여는 다시 친족회의 동의를 받아야 한다.','민소 §56②',1,false),
(222,1,'제56조','제1편 총칙','O','미성년자의 후견인이 상대방의 소제기·상소에 대하여 응소하는 소송행위를 하는 경우에는 친족회(후견감독인)의 동의를 받을 필요가 없다.','민소 §56①',1,false),
(223,1,'제57조','제1편 총칙','O','외국인은 그의 본국법에 따르면 소송능력이 없는 경우라도 대한민국의 법률에 따라 소송능력이 있는 경우에는 소송능력이 있는 것으로 본다.','민소 §57',1,false),
(224,1,'제58조','제1편 총칙','O','미성년자의 친권자가 미성년자를 대리하여 소송행위를 하는 경우에도 법정대리권이 있음을 서면으로 증명하여야 한다.','민소 §58①',1,false),
(225,1,'제58조','제1편 총칙','O','선정당사자의 자격은 서면증명을 필요로 하므로 선정서를 작성·제출하는 것이 보통이며, 이를 소송기록에 붙여야 한다.','민소 §58',1,false),
(226,1,'제59조','제1편 총칙','O','소송능력에 흠이 있는 경우 법원은 기간을 정하여 보정을 명하여야 하며, 보정 지연으로 손해가 생길 염려가 있는 경우에는 보정 전의 당사자로 하여금 일시적으로 소송행위를 하게 할 수 있다.','민소 §59',1,false),
(227,1,'제59조','제1편 총칙','O','제소과정에서 대리권의 존부는 소송요건이므로, 대리권에 흠이 있는 경우 변론종결시까지 보정되지 않으면 그 소는 종국판결로 부적법 각하된다.','대판(대리권 흠 각하)',1,false),
(228,1,'제60조','제1편 총칙','O','무권대리인이 행한 소송행위에 대하여 추인거절의 의사표시가 있는 이상, 무권대리행위는 확정적으로 무효가 되어 그 후에 다시 추인할 수 없다.','판례',1,false),
(229,1,'제60조','제1편 총칙','O','미성년자가 직접 변호인을 선임해 제1심을 수행하게 하였으나 제2심에서 법정대리인이 소송대리인을 선임하여 이의 없이 제1심 소송결과를 진술한 경우, 무권대리 소송행위를 묵시적으로 추인한 것으로 보아야 한다.','판례',1,false),
(230,1,'제60조','제1편 총칙','O','무권대표자의 소송행위에 대한 추인은 사실심(항소심)뿐만 아니라 상고심에서도 할 수 있다.','판례',1,false),
(231,1,'제60조','제1편 총칙','O','무권대리인의 소송행위 추인은 전체를 일괄하여 하여야 하나, 소를 제기·승소한 후 2심 계속 중 소를 취하한 일련의 소송행위 중 소취하 행위만을 제외하고 나머지를 추인하는 것은 유효하다.','판례',1,false),
(232,1,'제60조','제1편 총칙','O','적법한 대표자 자격이 없는 자가 비법인 사단을 대표하여 소를 제기하였다가 항소심에서 그가 특별대리인으로 선임되고, 상고심에서 그가 선임한 소송대리인이 기왕의 모든 소송행위를 추인한 경우, 그 소송행위는 행위시에 소급하여 효력을 갖는다.','대판(추인 소급)',1,false),
(233,1,'제60조','제1편 총칙','O','종중을 대표할 권한이 없는 자가 한 소송행위를 추인하면 그 행위시로 소급하여 유효하게 되며, 그 경우 제3자에 대하여도 추인의 효력이 미친다.','대판(무권대표 추인)',1,false),
(234,1,'제60조','제1편 총칙','O','한정치산자의 후견인이 친족회 동의 없이 소를 제기한 뒤 동의를 받지 못하면 후견인의 소송행위는 무효이나, 상고심에서 그 소송행위에 필요한 친족회의 동의(추인)를 받으면 행위시에 소급하여 효력이 생긴다.','대판(추인 소급)',1,false),
(235,1,'제60조','제1편 총칙','O','대리권의 존재는 소송행위의 유효요건이므로 무권대리에 의한 소송행위는 무효이나, 유동적 무효이므로 추인이 가능하다.','대판(무권대리 추인)',1,false),
(236,1,'제60조','제1편 총칙','O','추인의 시기는 제한이 없으며, 상고심에서 추인하여도 무방하다는 것이 판례이다.','대판(상고심 추인)',1,false),
(237,1,'제62조','제1편 총칙','O','법인이 당사자인 경우 대표자가 없거나 대표권이 없다는 사유로 특별대리인 선임을 신청하는 경우, 신청법원은 본안사건이 장래 계속될 또는 이미 계속된 수소법원이다.','민소 §62',1,false),
(238,1,'제62조','제1편 총칙','O','소송법상 특별대리인은 법인 대표자와 동일한 권한을 가져 소송수행에 관한 일체의 소송행위를 할 수 있으므로, 특별한 사정이 없는 한 상소의 제기·취하 권한이 있다.','판례',1,false),
(239,1,'제62조','제1편 총칙','O','법인 대표자의 대표권 흠이 보완되면, 특별대리인에 대한 해임결정이 있기 전이라도 그 대표자가 법인을 위하여 유효하게 소송행위를 할 수 있다.','실무제요 Ⅰ6389',2,true),
(240,1,'제62조','제1편 총칙','O','미성년자·피한정후견인·피성년후견인을 위한 특별대리인은 대리권 있는 후견인과 같은 권한이 있고, 그 대리권의 범위에서 법정대리인의 권한이 정지된다.','민소 §62',1,false),
(241,1,'제62조','제1편 총칙','O','의사능력이 없는 사람의 특정후견인·임의후견인도 그 사람의 소송수행을 위하여 특별대리인 선임을 신청할 수 있다.','민소 §62의2',1,false),
(242,1,'제62조','제1편 총칙','O','특별대리인 선임신청의 기각결정에 대해서는 항고할 수 있지만, 선임결정에 대해서는 항고할 수 없다.','민소',1,false),
(243,1,'제62조','제1편 총칙','O','조합에 이사·감사 등 법인을 대표할 다른 기관이 있는 경우에는 특별대리인 선임의 요건을 갖추지 못하여 특별대리인을 선임할 수 없다.','대결(특별대리인)',1,false),
(244,1,'제62조','제1편 총칙','O','법정대리인이 없는 미성년자가 소송을 당한 경우, 지방자치단체의 장 또는 검사는 해당 법원에 특별대리인 선임을 신청할 수 있다.','민소 §62①',1,false),
(245,1,'제62조','제1편 총칙','O','법원이 특별대리인을 선임하기로 하는 결정을 한 경우 그 결정에 대해서는 항고할 수 없다.','민소 §62',1,false),
(246,1,'제62조','제1편 총칙','O','사실상 의사능력을 상실하여 소송능력이 없는 사람에 대하여 소송을 제기하는 경우에도 특별대리인을 선임할 수 있다.','민소 §62',1,false),
(247,1,'제62조','제1편 총칙','O','비법인사단인 원고가 그 대표자인 피고 명의로 신탁한 부동산에 대하여 명의신탁해지를 원인으로 소유권 환원을 구하는 경우, 달리 그 피고를 대신하여 원고를 대표할 자가 없는 한 이해관계인은 특별대리인 선임을 신청할 수 있고 선임된 특별대리인이 원고를 대표하여 소송을 제기할 수 있다.','대판(특별대리인 선임)',1,false),
(248,1,'제62조','제1편 총칙','O','새로 선임된 대표이사가 적법한 대표자 자격이 없는 경우 당초의 대표이사가 적법한 대표이사가 취임할 때까지 대표이사의 권리의무를 지므로, 그 회사는 대표자가 없거나 대표권을 행사할 수 없는 경우에 해당하지 않아 특별대리인을 선임할 수 없다.','대판(퇴임이사 권리의무)',1,false),
(249,1,'제63조','제1편 총칙','O','당사자 선정은 언제든지 장래를 위하여 취소·변경할 수 있으며, 선정을 철회한 경우 상대방에게 철회 사실을 통지하지 아니하면 철회의 효력을 주장하지 못한다.','민소 §63',2,false),
(250,1,'제63조','제1편 총칙','O','법인 대표자의 대표권이 소멸된 경우, 그 소멸 사실의 통지가 없는 상태에서 구 대표자가 한 소취하는 상대방이 대표권 소멸 사실을 알고 있었더라도 유효하다.','대판(대표권 소멸 통지)',1,false),
(251,1,'제64조','제1편 총칙','O','소송당사자인 법인의 대표권에 흠이 있는 경우 법원은 기간을 정하여 보정을 명할 의무가 있고, 대표권의 보정은 항소심에서도 가능하다.','판례',1,false),
(252,1,'제64조','제1편 총칙','O','법인에 대표자가 없어 송달할 수 없는 경우에는 특별대리인(민소 제64조 등)의 선임 등에 의하여 송달할 수 있으므로, 공시송달만이 유일한 방법은 아니다.','판례',1,false),
(253,1,'제64조','제1편 총칙','O','법인 또는 법인 아닌 사단의 소송법상 특별대리인은 그 대표자와 동일한 권한을 가지므로, 특별한 사정이 없는 한 상소의 제기뿐만 아니라 취하할 권한도 가진다.','판례',1,false),
(254,1,'제64조','제1편 총칙','O','대표권 소멸은 상대방에게 통지하여야 중단되므로, 통지 전 구 대표자가 한 소취하는 상대방이 그 소멸 사실을 알았는지와 관계없이 유효하다.','대판(대표권 소멸 통지)',1,false),
(255,1,'제64조','제1편 총칙','O','무권대표자의 소송행위에 대한 추인은 상고심에서도 할 수 있다.','대판(추인 상고심)',1,false),
(256,1,'제64조','제1편 총칙','O','적법한 대표자 자격이 없는 비법인 사단 대표자의 소송행위는 후에 적법한 대표자가 추인하면 행위시에 소급하여 효력을 가지며, 이러한 추인은 상고심에서도 할 수 있다.','대판(추인 상고심)',1,false),
(257,1,'제64조','제1편 총칙','O','피고가 법인인 경우 법인 주소지로 송달불능되면 대표자의 주소지로도 송달해 보아야 하고, 이를 시도하지 않고 주소보정을 명하는 것은 위법하다.','대판(법인 송달)',1,false),
(258,1,'제65조','제1편 총칙','O','순차 마쳐진 소유권이전등기 각 말소청구 소송은 통상의 공동소송이므로, 그중 어느 한 등기명의자만을 상대로 말소를 구할 수 있고, 최종 등기명의자에게 말소를 구할 수 있는지와 관계없이 중간 등기명의자에게 말소를 구할 소의 이익이 있다.','대판(순차등기 말소)',1,false),
(259,1,'제66조','제1편 총칙','O','부진정연대채무자를 공동피고로 한 소송은 통상공동소송이므로(각 청구가 법률상 양립 가능), 상소하지 않은 공동소송인에 대하여는 상소로 인한 확정차단의 효력이 미치지 않는다.','판례',2,false),
(260,1,'제66조','제1편 총칙','O','통상공동소송에서 상소로 인한 확정차단의 효력은 상소인과 그 상대방에 대해서만 생기고, 다른 공동소송인에 대한 청구에는 미치지 아니한다.','판례',1,false),
(261,1,'제66조','제1편 총칙','O','통상공동소송인 가운데 한 사람에 대한 상대방의 소송행위는 다른 공동소송인에게 영향을 미치지 않는다.','민소 §66',2,false),
(262,1,'제66조','제1편 총칙','O','수인에 대한 공작물 철거청구는 각자에 대한 청구가 독립적이어서 고유필수적 공동소송이 아니라 통상공동소송이다.','판례',1,false),
(263,1,'제66조','제1편 총칙','O','채권자가 주채무자 A와 보증인 B를 공동피고로 전부 승소한 경우, 주채무자 A만 항소하면 보증인 B에 대한 청구 부분은 분리하여 확정된다.','판례',1,false),
(264,1,'제66조','제1편 총칙','O','주채무자와 보증인을 공동피고로 한 소에서 전부승소한 채권자에 대하여 보증인만 항소하였다면, 보증인에 대한 청구만 항소심 심판대상이 되고 항소하지 않은 주채무자에 대한 제1심판결은 분리 확정된다.','대판(통상공동소송 분리확정)',1,false),
(265,1,'제66조','제1편 총칙','O','통상의 공동소송에서 공동소송인 1인의 항소는 다른 공동소송인에게 영향을 미치지 않는다(공동소송인 독립의 원칙).','민소 §66',1,false),
(266,1,'제66조','제1편 총칙','O','통상공동소송의 경우 심리는 병합하여 행하여지지만 공동소송인 한 사람의 소송행위는 다른 공동소송인에게 영향을 미치지 않는다.','민소 §66',1,false),
(267,1,'제67조','제1편 총칙','O','공동상속인이 다른 공동상속인을 상대로 어떤 재산이 상속재산임의 확인을 구하는 소는 고유필수적 공동소송이고, 고유필수적 공동소송에서는 원고들 일부의 소취하 또는 피고들 일부에 대한 소취하는 특별한 사정이 없는 한 효력이 생기지 않는다.','판례',3,false),
(268,1,'제67조','제1편 총칙','O','소송계속 중 제3자가 소송목적인 권리의 전부·일부를 승계하였다고 주장하며 민사소송법 제81조에 따라 참가한 경우, 원고가 승계를 다투지 않으면서 소송탈퇴·소취하 등을 하지 않거나 피고 부동의로 원고가 소송에 남아 있다면, 중첩된 원고와 승계참가인의 청구 사이에는 민사소송법 제67조가 적용된다.','대판(전합) 2019다204869',2,false),
(269,1,'제67조','제1편 총칙','O','고유필수적 공동소송에서는 공동소송인 전원에 대한 하나의 종국판결을 선고하여야 하고, 일부에 대해서만 판결하거나 추가판결을 하는 것은 허용되지 않는다.','민소 §67',2,false),
(270,1,'제67조','제1편 총칙','O','동업약정에 따라 동업자 공동으로 토지를 매수하였다면 그 토지는 동업체가 매수한 것이므로, 그 매매계약에 기한 소유권이전등기 이행청구의 소는 동업자들이 공동으로 제기하여야 한다.','판례',2,false),
(271,1,'제67조','제1편 총칙','O','필수적 공동소송인 가운데 한 사람에 대한 상대방의 소송행위는 공동소송인 모두에게 효력이 미친다.','민소 §67②',3,false),
(272,1,'제67조','제1편 총칙','O','(공동수급체 구성원의 단독 무효확인 소 제기 가부에 관한 부분 — 해설상 옳지 않은 지문).','판례',1,true),
(273,1,'제67조','제1편 총칙','O','공유물분할의 소는 고유필수적 공동소송으로 합일확정이 요구되므로, 일부 공유자에 대한 상소기간 만료만으로 그 부분이 분리·확정되지 않는다.','판례',1,false),
(274,1,'제67조','제1편 총칙','O','고유필수적 공동소송에서는 공동소송인 전원이 일치하여 청구의 포기·인낙을 하여야 하고, 그 중 한 사람의 청구의 포기·인낙은 무효이다.','판례',1,false),
(275,1,'제67조','제1편 총칙','O','고유필수적 공동소송에서 공동소송인 중 한 사람이 한 소취하는 (불리한 행위이므로) 전원이 함께 하지 않는 한 효력이 없다.','민소 §67',1,false),
(276,1,'제67조','제1편 총칙','O','공유물분할청구의 소는 분할을 청구하는 공유자가 원고가 되어 다른 공유자 전부를 공동피고로 하여야 하는 고유필수적 공동소송이다.','대판(공유물분할)',3,false),
(277,1,'제67조','제1편 총칙','O','필수적 공동소송에서 공동소송인 중 한 사람의 소송행위는 모두의 이익을 위하여서만(유리한 경우에만) 효력이 있다.','민소 §67①',2,false),
(278,1,'제67조','제1편 총칙','O','공유물분할청구는 다른 나머지 공유자 전원을 공동피고로 하여야 하고, 공유자가 경계확정의 소를 제기할 때에는 공유자가 모두 공동원고가 되어야 한다.','대판(공유물분할·경계확정)',1,false),
(279,1,'제67조','제1편 총칙','O','조합재산에 속하는 채권에 관한 소송은 합유물에 관한 소송으로서 특별한 사정이 없는 한 조합원 전원이 공동으로 제기하여야 한다.','대판(조합채권 소송)',1,false),
(280,1,'제67조','제1편 총칙','O','총유재산에 관한 소송은 사원총회 결의를 거쳐 사단 명의로 하거나 구성원 전원이 당사자가 되어야 하고, 총유물의 보존행위라도 구성원 개인이 단독으로 소를 제기할 수 없다.','대판(전합) 2004다44971',1,false),
(281,1,'제67조','제1편 총칙','O','고유필수적 공동소송에서는 공동소송인 중 한 사람에게 소송요건의 흠이 있으면 전 소송을 부적법 각하한다.','대판(고유필수 흠)',1,false),
(282,1,'제67조','제1편 총칙','O','필수적 공동소송에서는 변론의 분리나 일부 판결을 할 수 없다.','민소 §67',1,false),
(283,1,'제67조','제1편 총칙','O','자백처럼 불리한 것은 공동소송인 전원이 함께 하지 않으면 안 되며, 한 사람이 하여도 그 한 사람이나 전원에 대하여 효력이 없다.','민소 §67①',1,false),
(284,1,'제67조','제1편 총칙','O','제3자가 공유자들을 상대로 하는 지분 이전등기청구는 각 지분별로 가분이어서 통상의 공동소송이고 고유필수적 공동소송이 아니다.','대판(공유자 통상공동)',1,false),
(285,1,'제67조','제1편 총칙','O','공동소송인 중 1인에 대한 상대방의 소송행위는 유리·불리를 묻지 않고 공동소송인 모두에게 효력이 있다.','민소 §67②',1,false),
(286,1,'제67조','제1편 총칙','O','공동소송인 중 일부가 제기한 상소는 다른 공동소송인에게도 효력이 미치므로, 공동소송인 전원에 대하여 판결의 확정이 차단되고 그 소송은 전체로서 상소심에 이심된다.','민소 §67①',1,false),
(287,1,'제67조','제1편 총칙','O','여럿의 파산관재인이 공동으로 원고가 되어 제기하는 소송은 필수적 공동소송이다.','대판(파산관재인)',1,false),
(288,1,'제67조','제1편 총칙','O','합유물의 보존행위는 합유자 각자가 할 수 있으므로(민법 §272 단서), 합유물 보존을 위한 소는 고유필수적 공동소송이 아니다.','대판(합유물 보존)',1,false),
(289,1,'제67조','제1편 총칙','O','여럿의 공유자를 상대로 제기하는 공유물분할청구는 고유필수적 공동소송이다.','대판(공유물분할)',1,false),
(290,1,'제67조','제1편 총칙','O','공동광업권자를 상대로 공동광업권의 인도를 구하는 소송은 고유필수적 공동소송이다.','대판(공동광업권)',1,false),
(291,1,'제67조','제1편 총칙','O','고유필수적 공동소송에서는 여러 명이 공동으로 원고가 되거나 피고가 되지 않으면 당사자적격 흠결로 부적법하게 된다.','대판(고유필수)',1,false),
(292,1,'제67조','제1편 총칙','O','유사필수적 공동소송에서는 공동소송인 중 1인에게 소송요건의 흠이 있으면 그 1인에 대한 소만 각하하고 소송 전부를 각하하는 것이 아니다.','대판(유사필수)',1,false),
(293,1,'제67조','제1편 총칙','O','소송목적이 공동소송인 모두에게 합일적으로 확정되어야 할 공동소송에서 공동소송인 가운데 한 사람의 소송행위는 모두의 이익을 위하여서만 효력을 가진다.','민소 §67①',1,false),
(294,1,'제67조','제1편 총칙','O','필수적 공동소송에서 공동소송인 가운데 한 사람에게 소송절차를 중단·중지하여야 할 이유가 있는 경우 그 중단·중지는 모두에게 효력이 미친다.','민소 §67③',1,false),
(295,1,'제68조','제1편 총칙','O','공동 특허무효심판은 유사필수적 공동소송이어서 특허권자는 일부 공동심판청구인만 상대로 심결취소소송을 제기할 수 있고, 제소기간이 지난 후 제소되지 않은 나머지 공동심판청구인을 당사자로 추가할 수는 없다.','판례',1,false),
(296,1,'제68조','제1편 총칙','O','고유필수적 공동소송인 가운데 일부가 누락된 경우에는 제1심 변론종결시까지 원고의 신청에 따라 결정으로 원고 또는 피고를 추가하도록 허가할 수 있다.','민소 §68',3,false),
(297,1,'제68조','제1편 총칙','O','필수적 공동소송인 중 일부가 누락되어 추가결정이 있는 경우, 시효중단의 효과는 처음 제소시로 소급한다.','민소 §68③',1,false),
(298,1,'제68조','제1편 총칙','O','원고가 A를 피고로 소송하다가 B를 공동소송인으로 추가하는 것은 원칙적으로 허용되지 않으나, B가 필수적 공동소송 또는 예비적·선택적 공동소송의 피고가 된다면 공동소송인으로 추가하는 것이 허용될 수 있다.','민소 §68·§70',1,false),
(299,1,'제68조','제1편 총칙','O','필수적 공동소송인의 추가는 제1심 변론종결시까지만 할 수 있다.','민소 §68①',3,false),
(300,1,'제68조','제1편 총칙','O','민법상 조합의 조합재산으로 매수한 부동산에 관한 소유권이전등기청구의 소(고유필수적 공동소송) 계속 중, 누락된 조합원을 당사자로 추가하는 것은 (제1심에서) 허용된다.','민소 §68①',1,false),
(301,1,'제70조','제1편 총칙','O','선택적·예비적 병합청구, 독립당사자참가소송, 주관적·예비적 공동소송의 경우 일부판결을 하지 못한다.','판례',1,false),
(302,1,'제70조','제1편 총칙','O','부진정연대채무 관계에 있는 채무자들을 공동피고로 하는 이행의 소는 민소 §70① 소정의 예비적·선택적 공동소송이라고 할 수 없다.','대판(부진정연대 통상공동)',1,false),
(303,1,'제70조','제1편 총칙','O','예비적·선택적 공동소송인의 추가는 청구가 실체법상 양립할 수 없는 경우뿐 아니라 소송법상 양립할 수 없는 경우에도 허용되므로, 이러한 피고 추가도 허용된다.','대판(예비적 추가)',1,false),
(304,1,'제70조','제1편 총칙','O','예비적·선택적 공동소송에서는 모든 공동소송인에 관한 청구에 대하여 판단하여야 하므로, 주위적 공동소송인에 대한 청구를 받아들이는 경우에도 예비적 공동소송인에 대한 청구를 판단하여야 한다.','민소 §70②',3,false),
(305,1,'제70조','제1편 총칙','O','처음에는 주위적 피고에 대한 청구만 하였다가, 그 청구가 받아들여지지 않을 경우 법률상 양립할 수 없는 관계의 예비적 피고에 대한 청구를 받아들여 달라는 취지로 예비적 피고를 추가하는 것도 가능하다.','대판(예비적 피고 추가)',1,false),
(306,1,'제70조','제1편 총칙','O','예비적 공동소송인의 추가는 제1심의 변론을 종결할 때까지 가능하다.','민소 §68·§70',1,false),
(307,1,'제70조','제1편 총칙','O','예비적 원고의 추가에는 원고로 추가될 사람의 동의가 필요하다.','민소 §68①단서',1,false),
(308,1,'제70조','제1편 총칙','O','예비적·선택적 공동소송에서는 모든 공동소송인에 관한 청구에 대하여 하나의 판결을 하여야 하므로, 일부 누락이 있으면 추가판결을 할 것이 아니라 상소로써 다투어야 한다.','대판(예비적 공동소송 판결)',1,false),
(309,1,'제70조','제1편 총칙','O','주관적·예비적 공동소송에서 공동소송인 중 1인이 상소를 제기하면 다른 공동소송인에 관한 청구 부분도 확정이 차단·이심되어 심판대상이 되며, 그 심판범위는 합일확정의 필요성을 고려하여 판단한다.','판례',3,false),
(310,1,'제70조','제1편 총칙','O','甲의 대리인 乙과 계약하였음을 이유로 甲에 대하여 청구하는 소송 중, 乙에게 대리권이 없을 경우를 대비하여 乙을 상대로 한 무권대리인 손해배상청구를 추가(예비적 공동소송)하는 것은 허용된다.','민소 §70',1,false),
(311,1,'제71조','제1편 총칙','O','대립하는 당사자구조를 갖지 못한 결정절차에서는 보조참가를 할 수 없다.','민소 §71',2,false),
(312,1,'제71조','제1편 총칙','O','보조참가의 이해관계는 사실상·경제상·감정상의 이해관계가 아니라 법률상의 이해관계를 가리킨다.','대판(보조참가 이익)',2,false),
(313,1,'제71조','제1편 총칙','O','보조참가인은 당사자가 아니므로, 소송계속 중 보조참가인이 사망하더라도 본소의 소송절차는 중단되지 아니한다.','대판(보조참가 사망)',2,false),
(314,1,'제71조','제1편 총칙','O','보조참가는 타인 간 소송에 참가하여 한쪽을 보조하는 것이고 독립한 소(소송중의 소)가 아니다.','통설',1,false),
(315,1,'제73조','제1편 총칙','O','보조참가신청에 대하여는 피참가인의 상대방은 물론 피참가인 자신도 이의신청을 할 수 있으나, 이의신청 없이 변론준비기일에서 진술한 때에는 이의신청권을 상실한다.','민소 §73·§74',1,false),
(316,1,'제73조','제1편 총칙','O','당사자는 참가에 대하여 이의를 신청할 수 있으며, 참가인은 그 참가에 대한 이의신청이 있는 경우라도 참가를 허가하지 아니하는 결정이 확정될 때까지 소송행위를 할 수 있다.','민소 §73·§75',1,false),
(317,1,'제73조','제1편 총칙','O','당사자가 보조참가에 대하여 이의를 신청한 때에는 참가인은 참가의 이유를 소명하여야 하며, 법원은 참가를 허가할 것인지 여부를 결정하여야 한다.','민소 §73',1,false),
(318,1,'제76조','제1편 총칙','O','피참가인은 보조참가인이 제기한 상소를 포기 또는 취하할 수 있다.','민소 §76②',1,false),
(319,1,'제76조','제1편 총칙','O','보조참가인은 공격·방어·이의·상소 등 모든 소송행위를 할 수 있지만, 참가할 때의 소송 진행 정도에 따라 할 수 없는 소송행위는 그러하지 아니하다.','민소 §76',2,false),
(320,1,'제76조','제1편 총칙','O','보조참가인이 제기한 항소라도 피참가인(원고)은 이를 임의로 포기하거나 취하할 수 있다(피참가인의 행위가 우선한다).','대판(보조참가 상소취하)',1,false),
(321,1,'제76조','제1편 총칙','O','보조참가인에게 기일통지서를 송달하지 아니하여 변론의 기회를 부여하지 아니한 채 행하여진 기일의 진행은 적법하다고 볼 수 없으나, 기일통지서를 송달받지 못한 보조참가인이 변론기일에 직접 출석하여 변론할 기회를 가졌고 그에 관하여 이의를 하지 아니하였다면 그 절차상 흠이 치유된다.','대판(보조참가 기일통지)',1,false),
(322,1,'제76조','제1편 총칙','O','보조참가인이 신청하여 적법하게 조사된 증거는, 자유심증주의에 따라 피참가인에게 불이익한 사실 인정의 자료로도 삼을 수 있다.','대판(보조참가 증거)',2,false),
(323,1,'제76조','제1편 총칙','O','보조참가인의 소송행위가 피참가인의 소송행위에 어긋나는 경우에는 보조참가인의 소송행위는 효력을 가지지 않는다.','민소 §76②',1,false),
(324,1,'제76조','제1편 총칙','O','보조참가인은 참가 당시의 소송 정도에 따라 피참가인이 할 수 없는 소송행위를 할 수 없으므로, 보조참가인으로서 상고를 제기하는 때에도 피참가인의 상고 제기기간 중에만 할 수 있다.','대판(보조참가 상고기간)',1,false),
(325,1,'제76조','제1편 총칙','O','보조참가인의 상소는 피참가인의 상소기간 내에만 할 수 있고, 보조참가인의 상소기간이 피참가인의 그것과 별도로 진행하는 것은 아니다.','대판(보조참가 상소기간)',1,false),
(326,1,'제76조','제1편 총칙','O','제1심의 보조참가인은 (피참가인의 상소기간 내에서, 피참가인의 의사에 어긋나지 않는 한) 독립하여 항소를 할 수 있다.','대판(보조참가 항소)',1,false),
(327,1,'제76조','제1편 총칙','O','청구의 포기·인낙은 피참가인(당사자)만 할 수 있고 보조참가인은 할 수 없다.','민소 §76',1,false),
(328,1,'제76조','제1편 총칙','O','소의 취하는 당사자(피참가인)만 할 수 있고 보조참가인은 할 수 없다.','민소 §76',2,false),
(329,1,'제76조','제1편 총칙','O','보조참가인은 상소의 제기를 할 수 있다(참가 당시 소송 진행정도에 따라 할 수 없는 행위는 제외).','민소 §76①',1,false),
(330,1,'제76조','제1편 총칙','O','보조참가인이 참가한 후에는 보조참가인에게도 기일통지·소송서류의 송달을 하여야 한다.','민소 §76',1,false),
(331,1,'제76조','제1편 총칙','O','보조참가인은 소취하, 청구의 포기, 재판상 화해를 할 수 없다.','민소 §76',1,false),
(332,1,'제76조','제1편 총칙','O','보조참가인은 참가신청을 자유롭게 취하할 수 있고, 변론한 뒤라도 피참가인이나 상대방의 동의가 필요하지 않다.','통설(참가신청 취하)',1,false),
(333,1,'제76조','제1편 총칙','O','보조참가인은 제3자로서 증인이나 감정인의 능력을 갖는다.','통설',1,false),
(334,1,'제77조','제1편 총칙','O','피참가인이 참가인이 할 수 없는 소송행위를 고의 또는 과실로 하지 아니한 때에는, 그 구별 없이 재판의 효력(참가적 효력)이 참가인에게 미치지 않는다.','민소 §77',1,false),
(335,1,'제77조','제1편 총칙','O','A와 B 사이의 소송에 C가 보조참가한 후 그 소송이 화해권고결정에 의하여 종료된 경우에는, 법원의 사실상·법률상 판단이 없으므로 참가적 효력이 인정되지 아니한다.','대판(화해권고 참가적효력)',4,false),
(336,1,'제77조','제1편 총칙','O','참가적 효력은 피참가인과 참가인 사이에만 미치고, 피참가인의 상대방과 참가인 사이에는 미치지 않는다.','대판(참가적 효력 범위)',2,false),
(337,1,'제77조','제1편 총칙','O','보조참가인에 대한 전소 확정판결의 참가적 효력은 전소 결론의 기초가 된 사실상·법률상 판단으로서 보조참가인이 피참가인과 공동이익으로 주장하거나 다툴 수 있었던 사항에 한하여 미친다.','대판(참가적 효력 객체)',1,false),
(338,1,'제77조','제1편 총칙','O','참가적효력은 피참가인이 패소한 경우 참가인이 뒤에 피참가인에 대한 관계에서 판결 내용이 부당하다고 주장할 수 없게 하는 금반언적 구속력으로, 기판력과는 다른 보조참가의 특수한 효력이다.','대판(참가적효력)',1,false),
(339,1,'제77조','제1편 총칙','O','기판력은 직권조사사항이지만, 참가적효력은 주장을 기다려 고려하여야 할 항변사항이다.','대판(참가적효력 항변사항)',1,false),
(340,1,'제77조','제1편 총칙','O','참가적효력은 판결주문뿐만 아니라 판결이유 중 패소이유가 된 사실상·법률상의 판단에도 미친다.','대판(참가적효력 범위)',1,false),
(341,1,'제78조','제1편 총칙','O','공동소송적 보조참가인이 있는 경우 피참가인의 재심의 소 취하는 참가인에게 불리하므로, 공동소송적 보조참가인의 동의가 없으면 효력이 없다.','대판(공동소송적 보조참가)',1,false),
(342,1,'제79조','제1편 총칙','O','독립당사자참가가 적법하다고 인정되어 세 당사자를 명의인으로 하는 하나의 종국판결이 선고되고 일방이 항소한 경우, 항소심 심리 결과 항소·부대항소를 제기하지 않은 당사자에게 결과적으로 제1심판결보다 유리하게 판결이 변경되는 것도 배제할 수 없다.','판례',2,false),
(343,1,'제79조','제1편 총칙','O','제1심에서 독립당사자참가신청을 각하하고 본소청구를 기각한 데 대하여 참가인이 항소하지 않고 원고만 항소한 경우, 참가신청 각하 부분은 분리확정되어 항소심으로 이심되지 않는다.','판례',1,true),
(344,1,'제79조','제1편 총칙','O','독립당사자참가소송에서 본소가 적법하게 취하되어 3면소송관계가 소멸하면, 당사자참가인의 원·피고에 대한 소가 독립의 소로서 소송요건을 갖춘 이상 그 소송계속은 적법하고, 참가신청 당시의 당사자참가요건 구비 여부는 더 이상 가려볼 필요가 없다.','판례',1,false),
(345,1,'제79조','제1편 총칙','O','상속인은 무효인 가처분결정에 의하여 생긴 외관을 제거하기 위하여 그 가처분결정에 대한 이의신청으로 취소를 구할 수 있다.','판례',1,false),
(346,1,'제79조','제1편 총칙','O','본소 청구와 양립할 수 있는 권리를 주장하는 참가는 권리주장참가(§79)의 요건(본소청구와 양립 불가)을 갖추지 못하여 부적법하다.','대판(권리주장참가)',1,false),
(347,1,'제79조','제1편 총칙','O','甲이 증축부분의 소유권에 터잡아 점유자 乙에게 명도를 구하는 소송에서, 丙이 그 증축부분이 자신의 소유임을 이유로 한 독립당사자참가신청은 적법하다.','대판(권리주장참가 적법)',1,false),
(348,1,'제79조','제1편 총칙','O','독립당사자참가에 의한 소송에서 원·피고 사이에서만 재판상 화해를 하는 것은 (3면소송의 합일확정에 반하여) 허용되지 않는다.','대판(독참 화해)',2,false),
(349,1,'제79조','제1편 총칙','O','원고의 피고에 대한 청구의 원인행위가 사해행위라는 이유로 원고에 대하여 사해행위취소를 청구하면서 한 독립당사자참가신청은 부적법하다.','대판(사해행위 독참)',1,false),
(350,1,'제79조','제1편 총칙','O','권리주장참가는 본소청구와 참가인 청구가 주장 자체에서 양립할 수 없는 관계인 경우에 허용되고, 사해방지참가는 본소의 원·피고가 소송으로 참가인의 권리를 침해할 의사가 객관적으로 인정되고 소송 결과 참가인의 권리·지위가 침해될 우려가 있는 경우에 허용된다.','대판(독참 요건)',1,false),
(351,1,'제79조','제1편 총칙','O','독립당사자참가소송에서 패소하였으나 상소·부대상소를 하지 아니한 당사자에게도 합일확정의 필요를 위하여 유리하게 원심판결이 변경될 수 있다.','대판(독참 합일확정)',1,false),
(352,1,'제79조','제1편 총칙','O','참가하려는 소송에 수개의 청구가 병합된 경우, 그 중 어느 하나의 청구라도 독립당사자참가인의 주장과 양립하지 않는 관계에 있으면 그 본소청구에 대한 참가가 허용된다.','대판(병합청구 독참)',1,false),
(353,1,'제79조','제1편 총칙','O','독립당사자참가인이 화해권고결정에 이의하면 3면소송의 합일확정 필요상 그 이의의 효력은 원·피고 사이에도 미친다.','대판(독참 화해권고 이의)',1,false),
(354,1,'제79조','제1편 총칙','O','독립당사자참가는 실질에 있어 소제기의 성질을 가지므로 상고심에서는 독립당사자참가를 할 수 없다.','대판(상고심 독참)',2,false),
(355,1,'제79조','제1편 총칙','O','독립당사자참가는 사실심 변론종결시까지 가능하고 법률심인 상고심에서는 할 수 없다.','대판(상고심 독참)',1,false),
(356,1,'제79조','제1편 총칙','O','권리주장참가(§79①전단)를 함에 있어서는 본소 원고의 청구와 양립되지 않는 권리 또는 원고에 우선할 수 있는 권리를 주장하여야 한다.','대판(권리주장참가)',1,false),
(357,1,'제79조','제1편 총칙','O','사해방지참가(§79①후단)를 함에 있어서는 본소 원고의 청구와 양립할 수 있는 권리를 주장하여도 상관없다.','대판(사해방지참가)',1,false),
(358,1,'제79조','제1편 총칙','O','법원은 반드시 갑·을·병 전원에 대하여 하나의 종국판결을 하여야 하고, 그 중 일부에 관해서만 판결할 수는 없다.','민소 §79②·§67',1,false),
(359,1,'제79조','제1편 총칙','O','소송목적의 전부나 일부가 자기의 권리라고 주장하거나 소송결과에 따라 권리가 침해된다고 주장하는 제3자는 당사자의 양쪽 또는 한쪽을 상대방으로 하여 당사자로서 소송에 참가할 수 있다.','민소 §79①',1,false),
(360,1,'제79조','제1편 총칙','O','독립당사자참가의 신청은 참가의 취지와 이유를 밝혀 참가하고자 하는 소송이 계속된 법원에 제기하여야 한다.','민소 §79②·§72',1,false),
(361,1,'제79조','제1편 총칙','O','본소가 취하·각하되더라도 독립당사자참가인의 원·피고에 대한 소가 소송요건을 갖추었다면 그 소송계속은 적법하게 유지된다.','대판(본소 취하·참가)',2,false),
(362,1,'제79조','제1편 총칙','O','독립당사자참가는 (소의 제기에 해당하는) 소송중의 소이다.','통설',1,false),
(363,1,'제79조','제1편 총칙','O','상고심에서는 독립당사자참가를 할 수 없다.','대판(상고심 참가)',1,false),
(364,1,'제79조','제1편 총칙','O','독립당사자참가소송은 세 당사자 사이에 합일확정이 요구되므로 변론을 분리하여 진행할 수 없다.','대판(독립참가 변론분리)',1,false),
(365,1,'제80조','제1편 총칙','O','A는 B가 동의하지 않으면 소송에서 탈퇴할 수 없다.','민소 §80',1,false),
(366,1,'제80조','제1편 총칙','O','A가 소송에서 탈퇴하여도 A는 판결의 효력을 받는다.','민소 §80',1,false),
(367,1,'제80조','제1편 총칙','O','소송탈퇴자에게도 확정판결의 효력(기판력)이 미친다.','민소 §80',1,false),
(368,1,'제80조','제1편 총칙','O','자기의 권리를 주장하기 위하여 참가한 사람이 있는 경우 참가 전의 원고나 피고는 상대방의 승낙을 받아 소송에서 탈퇴할 수 있으나, 판결은 탈퇴한 당사자에 대하여도 효력이 미친다.','민소 §80',1,false),
(369,1,'제80조','제1편 총칙','O','독립당사자참가 후에 원고가 본소를 취하함에는 참가인의 동의를 필요로 한다.','대판(참가 후 본소취하)',1,false),
(370,1,'제81조','제1편 총칙','O','승계참가는 소송의 목적이 된 권리를 승계한 경우뿐만 아니라 채무를 승계한 경우에도 할 수 있다.','판례',1,false),
(371,1,'제81조','제1편 총칙','O','C에 대하여도 A가 소를 제기한 때에 소급하여 대여금채권의 시효가 중단된다.','판례',1,false),
(372,1,'제81조','제1편 총칙','O','제1심 원고 승소 후 항소심에서 승계참가인이 참가신청을 하고 원고가 적법하게 탈퇴한 경우, 항소심은 제1심판결을 변경하여 승계참가인의 청구에 대한 판단을 하여야 하고 단순히 피고의 항소를 기각하는 것은 위법하다.','대판(승계참가)',1,false),
(373,1,'제81조','제1편 총칙','O','청구이의의 소가 제기되기 전에 청구권을 양수한 사람은 소송계속 중의 승계인이 아니므로, 그가 한 승계참가신청은 허용되지 않는다.','대판(승계참가 시기)',1,false),
(374,1,'제81조','제1편 총칙','O','승계참가인이 소송당사자로부터 계쟁 부동산 지분 일부를 양도받은 권리승계인이라 하여도, 상고심에 이르러 한 승계참가신청은 허용되지 않는다.','대판(상고심 승계참가)',1,false),
(375,1,'제81조','제1편 총칙','O','원고 A 상대 소송 계속 중 C가 A의 승계인이라며 참가신청을 한 경우, A가 승계를 다투지 않는다면 C는 상대방 B에 대해서만 청구하면 된다.','대판(승계참가)',1,false),
(376,1,'제81조','제1편 총칙','O','C가 A의 승계인이라며 참가하고 A가 탈퇴를 신청하였으나 B가 동의하지 않은 경우, A의 청구와 C의 청구는 통상의 공동소송으로서 모두 존속하므로 법원은 양 청구 모두에 대하여 판단하여야 한다.','대판(탈퇴 부동의)',1,false),
(377,1,'제81조','제1편 총칙','O','소송계속 중 실체법상 분쟁주체의 지위가 이전된 경우에는 승계참가·인수승계 제도로 처리되므로, 임의적 당사자변경을 인정할 실익이 생기는 것은 아니다.','대판(승계참가·인수)',1,false),
(378,1,'제81조','제1편 총칙','O','소유권이전등기청구권은 채권적 청구권이므로, 그 목적부동산을 양수한 제3자는 소송목적인 권리·의무를 승계한 자가 아니어서 소송승계인(특정승계인)에 포함되지 않는다.','대판(채권적 청구 승계)',1,false),
(379,1,'제81조','제1편 총칙','O','참가승계를 하면 당초의 소 제기 시에 소급하여 시효중단·기간준수의 효력이 생긴다.','대판(참가승계 시효중단)',1,false),
(380,1,'제81조','제1편 총칙','O','상고심에서는 참가승계·인수승계를 할 수 없다.','대판(상고심 승계)',1,false),
(381,1,'제82조','제1편 총칙','O','인수참가 후 본안 심리 결과 승계사실이 인정되지 않으면, 인수참가신청을 각하할 것이 아니라 인수참가인에 대한 청구를 기각(또는 소각하)하는 판결을 하여야 한다.','판례',1,false),
(382,1,'제82조','제1편 총칙','O','소송목적 권리를 양도한 원고가 소송인수 결정 후 피고 승낙으로 탈퇴하였는데 인수참가인의 양수 효력이 부정되어 청구기각·소각하가 확정된 경우, 그 날부터 6개월 내에 탈퇴 원고가 다시 같은 청구를 하면 탈퇴 전 청구로 인한 시효중단 효력이 그대로 유지된다.','대판(전합) 2017다',2,false),
(383,1,'제82조','제1편 총칙','O','A가 ''C가 B의 승계인''이라며 인수신청을 하였는데 법원이 C에 대한 심문을 하지 않고 인수를 명하는 결정을 하였다면 이는 위법하다.','민소 §82②',1,false),
(384,1,'제82조','제1편 총칙','O','소송인수 후 피인수자(B)가 탈퇴하더라도 §82③·§80에 따라 그 판결의 효력은 탈퇴한 B에게도 미친다.','민소 §82③·§80',1,false),
(385,1,'제83조','제1편 총칙','O','학교법인의 이사회결의무효확인의 소에 제3자는 공동소송참가를 할 수 없다.','판례',1,false),
(386,1,'제83조','제1편 총칙','O','채권자대위소송 계속 중 다른 채권자가 동일 채무자를 대위하여 권리를 행사하며 공동소송참가신청을 하는 경우, 양 청구의 소송물이 동일하다면 그 참가신청은 적법하다.','대판(전합) 2012다100746',2,false),
(387,1,'제83조','제1편 총칙','O','채권자대위소송 계속 중 다른 채권자가 동일 채권을 대위행사하며 한 공동소송참가신청은, 두 청구가 합일적으로 확정되어야 하므로 적법하다.','대판(전합) 2015다',1,false),
(388,1,'제84조','제1편 총칙','O','소송고지는 고지자의 자유이며 권한이나, 예외적으로 소송고지가 고지자의 의무인 경우가 있다.','판례',1,false),
(389,1,'제84조','제1편 총칙','O','당사자뿐만 아니라 보조참가인, 이들로부터 고지받은 피고지자도 소송고지를 할 수 있다.','민소 §84',1,false),
(390,1,'제84조','제1편 총칙','O','소송고지는 소송이 계속 중이면 상고심에서도 할 수 있다(제2심까지만 허용되는 것이 아니다).','대판(소송고지 시기)',1,false),
(391,1,'제84조','제1편 총칙','O','소송고지를 받은 사람도 다시 소송고지를 할 수 있다.','민소 §84②',1,false),
(392,1,'제85조','제1편 총칙','O','소송고지서는 피고지자만이 아니고 상대방 당사자에 대하여도 송달하여야 한다.','민소 §85②',2,false),
(393,1,'제85조','제1편 총칙','O','소송고지를 위하여는 그 이유와 소송의 진행정도를 적은 서면을 법원에 제출하여야 한다.','민소 §85①',1,false),
(394,1,'제86조','제1편 총칙','O','피고지자가 후일의 소송에서 주장할 수 없는 것은 전소 확정판결 결론의 기초가 된 사실상·법률상 판단에 반하는 것으로서, 피고지자가 보조참가를 하여 고지자와 공동이익으로 주장하거나 다툴 수 있었던 사항에 한한다.','민소 §86; 판례',1,false),
(395,1,'제86조','제1편 총칙','O','소송고지의 피고지자는 후일 고지자와의 소송에서 전소 확정판결 결론의 기초가 된 사실상·법률상의 판단에 반하는 것을 주장할 수 없다(참가적 효력).','대판(소송고지 참가적효력)',1,false),
(396,1,'제86조','제1편 총칙','O','소송고지를 받은 자가 참가하는지는 자유이지만, 고지자가 패소한 경우에는 피고지자가 참가할 수 있었을 때에 참가한 것과 마찬가지로 참가적 효력이 발생한다.','민소 §86',1,false),
(397,1,'제86조','제1편 총칙','O','소송고지를 받은 사람이 참가하지 아니한 경우라도 보조참가인이 참가하였을 경우 받을 참가적 효력이 미친다.','민소 §86',1,false),
(398,1,'제86조','제1편 총칙','O','소송고지를 받은 사람이 참가하지 아니한 경우 판결에 피고지자의 이름을 표시하여서는 아니 된다.','실무',1,false),
(399,1,'제87조','제1편 총칙','O','지방자치단체를 당사자로 하는 소송에는 ''국가를 당사자로 하는 소송에 관한 법률''에 의한 국가소송수행자의 지위가 인정되지 아니한다.','대판(지자체 소송수행자)',1,false),
(400,1,'제88조','제1편 총칙','O','소송목적의 값이 소제기 당시 1억 원 이하의 단독판사가 심리·재판하는 사건에서 법원의 허가를 받은 당사자의 배우자는 소송대리인이 될 수 있다.','민소 §88·규칙',1,false);
insert into atoms(id,subject_id,article_no,pyeon,ans,statement,ref,freq,verified) values
(401,1,'제88조','제1편 총칙','O','단독판사 사건에서 소송대리 허가신청에 의한 소송대리권은 법원의 허가를 얻은 때부터 발생하므로, 소송대리인이 허가일 이전에 변론기일 소환장을 수령하였다면 그 송달은 소송대리권 없는 자에 대한 송달로서 부적법하다.','판례',1,false),
(402,1,'제88조','제1편 총칙','O','변호사 외에도 당사자의 가족 등이 (단독사건 등에서 법원의 허가를 받아) 소송대리를 할 수 있는 경우가 있다.','민소 §88',1,false),
(403,1,'제88조','제1편 총칙','O','당사자의 배우자·직계혈족 또는 형제자매는 법원의 허가 없이 소송대리인이 될 수 있다.','소액사건심판법 §8',2,false),
(404,1,'제88조','제1편 총칙','O','단독사건에서 변호사 아닌 사람의 소송대리 허가는 규칙이 정한 소가 기준액 이하의 사건에 한하며, 그 기준액이 1억 원인 것은 아니다.','민소 규칙 §15',1,false),
(405,1,'제88조','제1편 총칙','O','대리인이 당사자의 배우자 또는 4촌 안의 친족으로서 당사자와의 생활관계에 비추어 상당하다고 인정되는 경우이어야 한다.','민소 규칙 §15①',1,false),
(406,1,'제88조','제1편 총칙','O','법원의 허가를 받아야 소송대리인이 될 수 있다.','민소 §88①',1,false),
(407,1,'제88조','제1편 총칙','O','허가신청은 서면으로 하여야 한다.','민소 규칙 §15②',1,false),
(408,1,'제89조','제1편 총칙','O','소송대리인의 권한은 서면으로 증명하여야 한다.','민소 §89①',2,false),
(409,1,'제89조','제1편 총칙','O','소송대리권은 서면으로 증명하여야 하나, 소송대리위임장을 법원에 제출한 이상 소송대리권이 있는 것이고, 법원의 잘못으로 위임장이 편철되지 않았다 하여 소송대리행위가 무효가 되는 것은 아니다.','판례',1,false),
(410,1,'제90조','제1편 총칙','O','소송상 화해나 청구의 포기에 관한 특별수권이 되어 있다면 특별한 사정이 없는 한 그 소송행위의 전제가 되는 소송물인 권리의 처분·포기에 대한 권한도 수여되어 있다고 봄이 상당하다.','판례',1,false),
(411,1,'제90조','제1편 총칙','O','소송대리인에게 소취하를 할 수 있는 대리권을 부여한 경우 상대방의 소취하에 대한 동의권도 포함되어 있으므로, 소송대리인이 한 소취하 동의는 본인에게 효력이 미친다.','판례',1,false),
(412,1,'제90조','제1편 총칙','O','소송위임(수권행위)은 소송대리권 발생을 목적으로 하는 단독 소송행위로서 그 기초인 위임계약과 성격을 달리하고, 의뢰인과 변호사 사이의 권리의무는 위임계약에 의하여 발생한다.','판례',1,false),
(413,1,'제90조','제1편 총칙','O','가압류사건을 수임한 변호사의 소송대리권은 제소명령 신청 권한뿐만 아니라 그 제소명령결정을 송달받을 권한에까지 미친다.','판례',1,false),
(414,1,'제90조','제1편 총칙','O','재심 전의 소송의 소송대리인에게 당연히 재심소송의 소송대리권이 있는 것은 아니다.','대판(재심 대리권)',1,false),
(415,1,'제90조','제1편 총칙','O','변제의 영수는 소송대리권의 범위에 포함되므로, 소송대리인은 특별수권 없이도 위임받은 사건에 관하여 상대방으로부터 변제를 받을 수 있다.','민소 §90①',1,false),
(416,1,'제90조','제1편 총칙','O','소송대리인의 소송대리권은 특별한 사정이 없는 한 당해 심급의 판결을 송달받은 때까지만 유지된다(심급대리).','대판(심급대리)',1,false),
(417,1,'제90조','제1편 총칙','O','항소제기에 관하여 특별수권을 받지 않은 1심 소송대리인이 제기한 항소는 위법하나, 그 당사자의 적법한 소송대리인이 항소심에서 본안에 대하여 변론하였다면 그 항소는 당사자가 적법하게 제기한 것으로 된다.','대판(항소 특별수권 추인)',1,false),
(418,1,'제90조','제1편 총칙','O','본안소송을 위임받은 소송대리인은 그 소송 수행에 필요한 강제집행, 가압류·가처분을 할 수 있다.','민소 §90①',1,false),
(419,1,'제90조','제1편 총칙','O','소송대리인이 상소 제기에 관한 특별한 권한을 따로 받았다면, 상소장에 인지를 붙이지 아니한 흠이 있는 경우 특별한 사정이 없는 한 그 흠을 보정할 수 있고 원심재판장도 소송대리인에게 인지 보정을 명할 수 있다.','대판(상소 특별수권 보정)',1,false),
(420,1,'제90조','제1편 총칙','O','사건이 상고심에서 환송되어 다시 항소심에 계속하게 된 경우, 환송받은 항소심에서 환송 전 항소심의 소송대리인에게 한 송달은 적법하다.','대판(환송 후 송달)',1,false),
(421,1,'제90조','제1편 총칙','O','소취하에 대한 동의는 민소 §90②의 특별수권사항이 아니므로, 소송대리인은 특별한 권한을 따로 받지 않고도 소취하에 동의할 수 있다.','대판(소취하 동의 수권)',1,false),
(422,1,'제90조','제1편 총칙','O','소송대리인은 위임받은 사건에 대하여 강제집행, 가압류·가처분에 관한 절차 등 일체의 소송행위와 변제의 영수를 할 수 있다.','민소 §90①',2,false),
(423,1,'제90조','제1편 총칙','O','반소에 응소하는 것은 통상의 대리권 범위에 속하나, 반소의 제기는 특별한 권한을 따로 받아야 하는 특별수권사항이다.','민소 §90②',1,false),
(424,1,'제90조','제1편 총칙','O','소송대리인은 당해 사건에 관한 공격방어방법의 전제로서 본인이 가진 상계권·취소권·해제권 등 사법상 형성권을 행사할 수 있다.','대판(대리인 형성권)',1,false),
(425,1,'제90조','제1편 총칙','O','소송위임에 의한 소송대리인은 위임받은 사건에 대하여 가압류·가처분이나 강제집행 등을 할 수 있다.','민소 §90①',1,false),
(426,1,'제90조','제1편 총칙','O','사건이 상고심에서 파기환송되어 다시 항소심에 계속하게 된 경우에는 상고 전 항소심에서의 소송대리인의 대리권이 부활한다.','대판(대리권 부활)',2,false),
(427,1,'제90조','제1편 총칙','O','소송대리권은 특별한 의사표시가 없는 한 당해 심급에 한하므로, 당해 심급의 심판절차가 종료되면 소멸함이 원칙이다.','대판(심급대리)',1,false),
(428,1,'제90조','제1편 총칙','O','특별수권이 없는 이상, 재심 전 소송의 소송대리인이 당연히 재심소송의 소송대리인이 되는 것은 아니다.','대판(재심 대리권)',1,false),
(429,1,'제90조','제1편 총칙','O','소송대리권은 심급마다 별개로 수여되어야 하지만, 사건이 상급심에서 파기환송되었을 때에는 환송 전 원심의 소송대리인의 대리권이 부활한다.','대판(대리권 부활)',1,false),
(430,1,'제90조','제1편 총칙','O','반소의 제기, 소의 취하, 화해, 청구의 포기·인낙, 상소의 제기 또는 취하 등은 모두 특별한 권한을 따로 받아야 할 수 있다.','민소 §90②',2,false),
(431,1,'제91조','제1편 총칙','O','변호사인 소송대리인의 대리권은 제한하지 못하지만, 변호사 아닌 소송대리인의 대리권은 제한할 수 있다.','민소 §91',1,false),
(432,1,'제91조','제1편 총칙','O','소송대리권은 제한하지 못하나, 다만 변호사가 아닌 소송대리인에 대하여는 그러하지 아니하다(제한 가능).','민소 §91',1,false),
(433,1,'제93조','제1편 총칙','O','같은 당사자에 대하여 여러 소송대리인이 있는 때에는 원칙적으로 소송대리인 각자가 당사자를 대리한다.','민소 §93①',1,false),
(434,1,'제93조','제1편 총칙','O','여러 소송대리인이 있는 때에는 각자가 당사자를 대리하고, 당사자가 이에 어긋나는 약정을 하더라도 그 약정은 효력이 없다.','민소 §93',2,false),
(435,1,'제94조','제1편 총칙','O','소송대리인의 사실상 진술은 당사자가 이를 곧 취소하거나 경정한 때에는 그 효력을 잃는다.','민소 §94',2,false),
(436,1,'제95조','제1편 총칙','O','소송위임을 한 뒤 소제기 전에 당사자가 사망하였더라도 소송대리권은 소멸하지 않으므로, 소송대리인이 제기한 소는 적법하고 그 효력은 상속인에게 미친다.','판례',1,false),
(437,1,'제95조','제1편 총칙','O','당사자의 사망이나 소송능력의 상실로는 소송대리권이 소멸되지 않는다(민사소송법 제95조).','민소 §95',2,false),
(438,1,'제95조','제1편 총칙','O','소송위임에 의한 소송대리권은 당사자의 사망으로 소멸하지 아니하며, 소송절차도 중단되지 않는다.','민소 §95·§238',1,false),
(439,1,'제95조','제1편 총칙','O','금전지급청구소송의 계속 중 수권자인 원고가 사망하더라도 원고의 소송대리인의 소송대리권은 소멸하지 않음이 원칙이다.','민소 §95',1,false),
(440,1,'제98조','제1편 총칙','O','소송비용은 원칙적으로 패소한 당사자가 부담한다.','민소 §98',1,false),
(441,1,'제99조','제1편 총칙','O','소송비용은 패소한 당사자가 부담함이 원칙이나, 예외적으로 승소한 당사자도 부담할 수 있다.','민소 §99',1,false),
(442,1,'제101조','제1편 총칙','O','일부 패소의 경우 각 당사자가 부담할 소송비용은 법원이 재량으로 정하는 것이고, 반드시 청구액과 인용액의 비율에 따라야 하는 것은 아니다.','민소 §101',1,false),
(443,1,'제102조','제1편 총칙','O','공동소송인은 소송비용을 균등하게 부담하나, 법원은 사정에 따라 연대 부담하게 하거나 다른 방법으로 부담하게 할 수 있다.','민소 §102',2,false),
(444,1,'제102조','제1편 총칙','O','재판주문에서 공동소송인별 부담비율을 정하거나 연대부담을 명하지 않고 단순히 ''소송비용은 공동소송인들의 부담으로 한다''라고 정하였다면, 공동소송인들은 상대방에 대하여 균등하게 소송비용을 부담한다.','대판(공동부담 균등)',1,false),
(445,1,'제104조','제1편 총칙','O','소송이 재판에 의하지 않고 완결된 경우 소송비용부담재판의 관할법원은 ''소송이 완결될 당시 소송이 계속된 법원''이며, 항소심에서 항소가 취하되면 그 당시 계속 법원은 항소심이 아니라 제1심 법원이다.','민소 §114·§104; 실무제요 Ⅰ7578',1,true),
(446,1,'제105조','제1편 총칙','O','상급법원이 본안의 재판을 바꾸는 경우 또는 환송·이송받은 법원이 사건을 완결하는 재판을 하는 경우에는 소송의 총비용에 대하여 재판하여야 한다.','민소 §105',1,false),
(447,1,'제106조','제1편 총칙','O','화해비용과 소송비용을 부담할 자와 부담의 방법을 정하지 아니한 경우에는 그 비용은 당사자들이 각자 부담한다(균등 분담이 아니다).','민소 §106',1,false),
(448,1,'제108조','제1편 총칙','O','소송대리인에게 대리권이 없다는 이유로 소가 각하되어 민소 §108에 따라 소송대리인이 소송비용 부담 재판을 받은 경우, 소송대리인은 자신에게 비용부담을 명한 재판에 대하여 재판 형식에 관계없이 즉시항고나 재항고로 불복할 수 있다.','대판(§108 비용)',1,false),
(449,1,'제108조','제1편 총칙','O','법정대리인·소송대리인으로서 소송행위를 한 사람이 대리권 등을 증명하지 못하거나 추인을 받지 못하여 소가 각하된 경우에는, 소송비용은 그 소송행위를 한 대리인이 부담한다.','민소 §108',1,false),
(450,1,'제108조','제1편 총칙','O','무권대리인이 제기한 소를 각하한 때에는 소송비용은 당사자 본인이 아니라 그 소송행위를 한 대리인의 부담으로 하여야 한다.','민소 §108',1,false),
(451,1,'제109조','제1편 총칙','O','소송을 대리한 변호사 보수는 대법원규칙이 정하는 금액의 범위에서 소송비용으로 인정하고, 그 계산 시 여러 변호사가 대리하였더라도 한 변호사가 대리한 것으로 본다.','민소 §109',1,false),
(452,1,'제109조','제1편 총칙','O','변호사에게 지급하거나 지급할 보수는 소송비용에 해당하나, 변호사가 변론이나 증거조사절차에 전혀 관여한 바 없으면 소송비용에 포함되지 않는다.','대판(변호사보수 비용)',1,false),
(453,1,'제110조','제1편 총칙','O','소송비용액확정신청의 피신청인이 부담할 소송비용액이 없는 경우, 송달료 등 확정절차 비용은 신청인이 부담할 성질이지 피신청인에게 부담시킬 수 없다.','판례',1,false),
(454,1,'제110조','제1편 총칙','O','소송비용의 청구는 소송비용액 확정절차에 의하도록 규정되어 있으므로, 그 절차에 의하지 아니하고 별개의 소로써 청구할 수는 없다.','판례',1,false),
(455,1,'제110조','제1편 총칙','O','소송비용액확정 결정절차에서는 상환할 소송비용의 액수를 정할 수 있을 뿐이고, 소송비용부담재판에서 확정한 상환의무 자체의 범위를 심리·판단하거나 변경할 수 없다.','대판(비용액확정)',1,false),
(456,1,'제110조','제1편 총칙','O','소송비용부담재판 후 의무자가 사망한 경우, 그 상속인들을 상대로 소송비용액 확정신청을 하려면 승계집행문을 부여받아야 한다.','대판(비용 승계집행문)',1,false),
(457,1,'제110조','제1편 총칙','O','소송비용액 확정결정 신청은 본안재판이 완결될 당시의 법원이 아니라 제1심 법원에 하여야 한다.','민소 §110①',1,false),
(458,1,'제110조','제1편 총칙','O','지방법원 합의부가 재판한 사건의 소송비용액 확정신청에 대한 사법보좌관 처분을 합의부가 아닌 단독판사가 인가한 것은 전속관할 위반이다.','대판(사법보좌관 인가)',1,false),
(459,1,'제110조','제1편 총칙','O','소송비용액 확정신청은 소송비용부담재판이 확정된 경우뿐만 아니라 그 재판이 집행력을 갖게 된 후에도 할 수 있다.','민소 §110①',2,false),
(460,1,'제110조','제1편 총칙','O','소송비용액의 확정은 소송비용액확정결정 신청에 의하여야 하고, 이에 갈음하여 별도의 소를 제기할 수 없다.','대판(비용액확정)',1,false),
(461,1,'제114조','제1편 총칙','O','소의 일부 취하·청구 감축 시 소송비용에 관하여는 민사소송법 제114조가 적용되므로, 그 부분 소송비용 상환을 위하여는 그 부분이 종결될 당시 소송계속법원에 별개 절차로서 소송비용부담재판을 신청하여야 한다.','판례',1,false),
(462,1,'제114조','제1편 총칙','O','소송이 재판에 의하지 아니하고 완결된 경우 당사자가 소송비용을 상환받기 위하여는 당해 소송이 완결될 당시의 소송계속법원에 소송비용부담재판의 신청을 하여야 한다.','민소 §114',1,false),
(463,1,'제114조','제1편 총칙','O','항소심에서 소취하가 된 경우에는 제1심을 포함한 총 소송비용에 관하여 항소심 법원에 소송비용 부담의 재판과 소송비용액확정을 신청하여야 한다.','대판(소취하 비용재판)',1,false),
(464,1,'제115조','제1편 총칙','O','소송비용액 확정신청이 있는 때에는 법원은 법원사무관등에게 소송비용액을 계산하게 하여야 한다.','민소 §115',1,false),
(465,1,'제117조','제1편 총칙','O','원고가 항소심에서 승소한 뒤 피고의 상고로 피상고인이 된 경우에는 그 상고심에서 원고에게도 소송비용 담보제공 신청권이 인정된다.','판례',1,false),
(466,1,'제117조','제1편 총칙','O','소송기록에 의하여 청구가 이유 없음이 명백한 때 등 담보제공이 필요한 경우 법원은 직권으로 원고에게 담보제공을 명할 수 있고, 피고의 신청이 있는 경우에는 원고에게 담보제공을 명하여야 한다.','민소 §117',1,false),
(467,1,'제118조','제1편 총칙','O','피고가 적법한 담보제공신청을 한 경우에는 그 후 응소를 거부하지 않고 본안에 관하여 변론 등을 하였더라도 이미 이루어진 담보제공신청의 효력이 상실되거나 부적법하게 되는 것은 아니다.','판례',1,false),
(468,1,'제118조','제1편 총칙','O','상소심에서의 소송비용 담보제공 신청은 담보제공 원인이 이미 1심·항소심에서 발생했음에도 신청인이 과실 없이 신청할 수 없었거나 상소심에서 새로이 원인이 발생한 경우에 한하여 가능하다.','판례',1,false),
(469,1,'제118조','제1편 총칙','O','담보를 제공할 사유가 있다는 것을 알고도 피고가 본안에 관하여 변론하거나 변론준비기일에서 진술한 경우에는 담보제공을 신청하지 못한다.','민소 §118',1,false),
(470,1,'제121조','제1편 총칙','O','법원이 직권으로 한 담보제공명령에 대하여도 민사소송법 제121조를 유추하여 즉시항고할 수 있다.','대결(직권 담보제공 즉시항고)',1,false),
(471,1,'제122조','제1편 총칙','O','소송비용 담보의 제공은 금전 또는 법원이 인정하는 유가증권을 공탁하거나 지급보증위탁계약 문서를 제출하는 방법으로 한다.','민소',1,false),
(472,1,'제124조','제1편 총칙','O','담보를 제공하여야 할 기간 이내에 원고가 이를 제공하지 아니하는 때에는 법원은 변론 없이 판결로 소를 각하할 수 있으나, 판결하기 전에 담보를 제공한 때에는 변론 없이 소를 각하할 수 없다.','민소 §124',1,false),
(473,1,'제128조','제1편 총칙','O','신청인의 자금능력과 관련하여 신청인이 얻고 있는 수입은 물론 보유하고 있는 자산도 그 자금능력을 판단하는 유력한 자료가 된다.','판례',1,false),
(474,1,'제128조','제1편 총칙','O','무자력 요건과 관련하여, 법인 그 밖의 단체의 경우는 소송비용을 지출함에 따라 그 목적사업의 수행이 저해되는 경우를 의미한다.','판례',1,false),
(475,1,'제128조','제1편 총칙','O','''패소할 것이 분명하지 않다''는 요건에 대하여, 신청인이 승소가능성을 적극적으로 진술·소명하여야 하는 것은 아니고, 법원이 자료를 기초로 패소가 분명하다고 판단할 수 있는 경우가 아니라면 그 요건은 구비된 것으로 보아야 한다.','판례',1,false),
(476,1,'제128조','제1편 총칙','O','무자력 요건은 자연인의 경우 국민기초생활보장법상 수급권자로 한정되지 않으며, 그보다 넓게 인정된다.','판례',1,false),
(477,1,'제128조','제1편 총칙','O','패소할 것이 분명한 사건에 대하여는 소송구조 신청에 필요한 소송비용과 그 불복신청에 필요한 소송비용에 대하여도 소송구조를 하지 아니한다.','판례',1,false),
(478,1,'제128조','제1편 총칙','O','소송구조의 요건으로는 자금능력 부족 외에도 패소할 것이 분명하지 않을 것이 요구된다.','민소 §128①',1,false),
(479,1,'제128조','제1편 총칙','O','소송구조의 대상인 변호사 보수는 변호사가 소송구조결정에 따라 구조를 받을 사람을 위하여 소송을 수행한 대가를 의미하고, 구조를 받을 사람의 상대방을 위한 변호사 보수는 포함되지 않는다.','대판(소송구조 변호사보수)',1,false),
(480,1,'제128조','제1편 총칙','O','소송구조신청은 서면으로 하여야 하고, 그 신청서에는 신청인과 그와 같이 사는 가족의 자금능력을 적은 서면을 붙여야 한다.','민소 규칙 §24',1,false),
(481,1,'제128조','제1편 총칙','O','법원은 소송비용을 지출할 자금능력이 부족한 사람의 신청에 따라 또는 직권으로 소송구조를 할 수 있으나, 패소할 것이 분명한 경우에는 그러하지 아니하다.','민소 §128①',3,false),
(482,1,'제128조','제1편 총칙','O','비송사건은 소송구조의 대상이 되지 아니하므로, 비송사건을 대상으로 하는 소송구조 신청은 부적법하다.','대판(비송 소송구조)',1,false),
(483,1,'제128조','제1편 총칙','O','''패소할 것이 분명하지 않을 것''은 소송구조의 소극적 요건이므로, 신청인이 승소가능성을 적극적으로 진술·소명할 필요는 없고 제출된 자료로 패소가 분명하다고 판단되지 않으면 그 요건이 구비된 것으로 본다.','대판(소송구조 패소요건)',2,false),
(484,1,'제128조','제1편 총칙','O','소송구조에 대한 재판은 소송기록을 보관하고 있는 법원이 한다.','민소 §128③',3,false),
(485,1,'제128조','제1편 총칙','O','소송구조는 당사자의 신청에 따라 또는 직권으로 할 수 있다.','민소 §128①',1,false),
(486,1,'제128조','제1편 총칙','O','패소할 것이 분명한 경우에는 직권에 의한 경우에도 소송구조를 할 수 없다.','민소 §128①단서',1,false),
(487,1,'제128조','제1편 총칙','O','소송구조를 신청하는 사람은 그 구조의 사유를 소명하여야 한다.','민소 §128②',1,false),
(488,1,'제129조','제1편 총칙','O','법원은 상당한 이유가 있는 때에는 재판비용의 납입유예, 변호사 보수의 지급유예 등 가운데 일부에 대하여만 소송구조를 할 수 있다.','민소 §129',1,false),
(489,1,'제129조','제1편 총칙','O','소송구조의 범위에는 재판비용의 납입유예, 변호사 및 집행관의 보수와 체당금의 지급유예, 소송비용의 담보면제, 대법원규칙이 정하는 그 밖의 비용의 유예나 면제가 해당된다.','민소 §129①',1,false),
(490,1,'제130조','제1편 총칙','O','소송구조의 효력은 원칙적으로 받는 사람에게만 미치지만, 법원은 소송승계인에게 미루어 둔 비용의 납입을 명할 수 있다.','민소 §130',2,false),
(491,1,'제130조','제1편 총칙','O','소송구조는 이를 받은 사람에게만 효력이 미치고, 그 승계인에게는 미치지 않는다.','민소 §130',2,false),
(492,1,'제131조','제1편 총칙','O','소송구조를 받은 당사자를 일반승계한 소송승계인에 대하여는 소송구조의 효력이 미치지 않는다.','민소 §131',1,false),
(493,1,'제131조','제1편 총칙','O','소송구조를 받은 사람이 소송비용을 납입할 자금능력이 있다는 것이 판명된 경우 법원은 직권으로 소송구조를 취소할 수 있고, 소송구조결정의 상대방도 법원에 소송구조의 취소를 신청할 수 있다.','민소 §131',2,false),
(494,1,'제133조','제1편 총칙','O','소송구조결정에 대한 상대방의 즉시항고는 ''소송비용 담보면제''의 구조결정에 대하여만 허용되고, 변호사보수 지급유예 등 다른 구조결정에 대하여는 허용되지 않는다.','실무제요 Ⅰ8386; 민소 §133',1,true),
(495,1,'제133조','제1편 총칙','O','소송구조결정의 상대방은 소송비용의 담보를 면제하는 소송구조결정에 대해서만 즉시항고를 할 수 있다.','대판(소송구조 즉시항고)',1,false),
(496,1,'제133조','제1편 총칙','O','소송구조에 대한 재판에 대하여는 즉시항고를 할 수 있고, 소송구조의 상대방도 담보면제 구조결정 등에 대하여는 즉시항고로 불복할 수 있다.','대판(소송구조 즉시항고)',1,false),
(497,1,'제134조','제1편 총칙','O','당사자가 서증을 제출하며 입증취지를 진술함으로써 서증에 기재된 사실을 주장하거나, 변론 전체로 보아 간접적으로 주장한 것으로 볼 수 있는 경우에도 주요사실의 주장이 있는 것으로 보아야 한다.','판례',1,false),
(498,1,'제134조','제1편 총칙','O','유권대리에 관한 주장 속에 무권대리에 속하는 표현대리의 주장이 포함되어 있다고 볼 수 없다.','대판(전합) 83다카1489',1,false),
(499,1,'제134조','제1편 총칙','O','대표권의 존부는 직권조사사항으로서 자백의 대상이 될 수 없다.','판례',1,false),
(500,1,'제134조','제1편 총칙','O','부제소합의 등은 그 존재가 인정되면 법원이 직권으로 고려하여야 하는 직권조사사항에 해당한다.','판례',1,false),
(501,1,'제134조','제1편 총칙','O','직권조사사항에 관하여, 법원은 그 판단의 기초자료인 사실과 증거를 직권으로 탐지할 의무까지는 없더라도, 이미 제출된 자료에 의하여 그 존부에 의심이 갈 만한 사정이 엿보인다면 그에 관하여 심리·조사할 의무가 있다.','대판(직권조사 심리의무)',2,false),
(502,1,'제134조','제1편 총칙','O','피보전채권의 존부는 직권조사사항이지만, 법원이 그 판단의 기초자료인 사실과 증거를 직권으로 탐지할 의무까지 있는 것은 아니다.','대판(직권조사 탐지)',1,false),
(503,1,'제134조','제1편 총칙','O','제척기간이 경과하였는지 여부는 이에 대한 당사자의 주장이 없더라도 법원이 당연히 직권으로 조사하여 재판에 고려하여야 한다.','대판(제척기간 직권)',1,false),
(504,1,'제134조','제1편 총칙','O','결정으로 완결할 사건은 변론을 거치지 아니할 수 있고, 심문 여부도 법원의 재량이다(반드시 심문을 열어야 하는 것은 아니다).','민소 §134①',1,false),
(505,1,'제134조','제1편 총칙','O','제출자료상 직권조사사항의 존부에 의심이 있는 경우에는 당사자의 이의 유무에 관계없이 이를 조사하여야 한다.','대판(직권조사 의무)',1,false),
(506,1,'제134조','제1편 총칙','O','직권조사사항에 속하는 것으로는 항변사항을 제외한 소송요건, 절차적 강행법규의 준수 여부, 실체법의 해석적용 등이 있다.','통설',1,false),
(507,1,'제134조','제1편 총칙','O','쌍방심리주의는 현행 민사소송법이 채택하고 있는 변론에 관한 원칙이다.','통설',2,false),
(508,1,'제134조','제1편 총칙','O','당사자가 서면을 제출하였더라도 변론에서 진술(또는 진술간주)되지 아니하면 판단자료로 삼을 수 없다.','민소 §134',1,false),
(509,1,'제136조','제1편 총칙','O','법원의 석명권 행사는 당사자의 주장에 모순·불완전·불명료한 점이 있을 때 이를 지적하여 정정·보충 기회를 주고 증거제출을 촉구하는 것을 내용으로 한다.','민소 §136',1,false),
(510,1,'제136조','제1편 총칙','O','소의 변경이 교환적·추가적·선택적인지 여부는 당사자의 의사해석에 의하므로, 구 청구 취하의 명백한 표시 없이 변경형태가 불분명한 경우 사실심 법원은 그 취지를 석명할 의무가 있다.','판례',1,false),
(511,1,'제136조','제1편 총칙','O','법원이 당사자가 주장하지 않은 요건사실이나 독립된 공격방어방법을 시사하여 제출을 권유하는 것은 변론주의에 위배되는 적극적 석명으로서 허용되지 않는다.','판례',1,false),
(512,1,'제136조','제1편 총칙','O','손해배상책임이 인정되는 경우 법원은 손해액에 관한 당사자의 주장·증명이 미흡하더라도 적극적으로 석명권을 행사하여 증명을 촉구하여야 하고, 경우에 따라서는 직권으로 손해액을 심리·판단하여야 한다.','판례',1,false),
(513,1,'제136조','제1편 총칙','O','당사자들이 부제소 합의의 효력·범위를 다투지 아니하는데도 법원이 직권으로 부제소 합의 위배를 이유로 소가 부적법하다고 판단하려면, 그 법률적 관점에 대하여 당사자에게 의견을 진술할 기회를 주어야 한다.','대판(부제소합의 직권)',2,false),
(514,1,'제136조','제1편 총칙','O','당사자가 부주의·오해로 요건사실 일부를 누락한 경우 법원이 이를 지적하여 의견진술 기회를 주는 것은 석명의무(§136④)의 이행으로서 변론주의에 위배되지 않는다.','대판(지적의무)',1,false),
(515,1,'제136조','제1편 총칙','O','청구취지가 특정되지 않았는데도 당사자가 부주의·오해로 이를 간과한 채 본안에 관하여 공방하고 있는 경우, 보정의 기회를 부여하지 아니한 채 청구취지 불특정을 이유로 소를 각하하는 것은 석명의무를 다하지 아니한 것으로서 위법하다.','대판(청구취지 불특정 석명)',1,false),
(516,1,'제136조','제1편 총칙','O','임대인이 임차인을 상대로 한 지상물철거·토지인도청구소송에서 임차인이 지상물매수청구권을 행사한 경우, 법원은 임대인에게 대금지급과 상환으로 지상물 인도청구로 소변경의 의사가 있는지에 대한 석명의무가 있다.','대판(지상물매수 석명)',1,false),
(517,1,'제136조','제1편 총칙','O','금원을 변제공탁하였다는 공탁서를 증거로 제출하면서 변제 주장을 명시적으로 하지 않았더라도, 공탁서 제출은 그 금액만큼 변제되었음을 주장하는 취지가 명백하므로 법원은 그러한 주장이 있는 것으로 보아 판단하거나 그 취지인지 석명하여야 한다.','대판(공탁서 제출 석명)',1,false),
(518,1,'제136조','제1편 총칙','O','손해배상청구의 법률적 근거가 계약책임인지 불법행위책임인지 명시하지 아니하였는데 법원이 불법행위책임으로 단정하여 재판한 경우, 법원은 어느 책임을 묻는지 석명할 의무가 있다.','대판(손배 근거 석명)',1,false),
(519,1,'제136조','제1편 총칙','O','청구변경의 형태가 교환적인지 추가적인지 불분명한 경우 법원이 이를 교환적 변경으로 단정하여 재판하는 것은 위법하고, 법원은 그 변경 취지를 석명할 의무가 있다.','대판(청구변경 석명)',1,false),
(520,1,'제136조','제1편 총칙','O','원고의 매매대금청구에 대하여 피고가 주장하지 아니하는 변제의 항변에 관하여는 법원이 석명할 의무가 없다(주장하지 않은 항변에 대한 석명의무 부정).','대판(변제 항변 석명 부정)',1,false),
(521,1,'제136조','제1편 총칙','O','당사자의 신청·주장에 있는 불분명·불완전·모순을 제거하는 방향의 소극적 석명은 허용된다.','대판(소극적 석명)',1,false),
(522,1,'제136조','제1편 총칙','O','적극적 석명도 일정한 범위에서는 허용되며(법률상 사항 지적의무 등), 일체 허용되지 않는 것은 아니다.','대판(적극적 석명)',1,false),
(523,1,'제136조','제1편 총칙','O','토지임대차 종료 시 임대인의 건물철거·토지인도청구에는 건물매수대금 지급과 상환으로 건물명도를 구하는 청구가 포함되어 있다고 볼 수 없다.','대판(전합 건물매수)',1,false),
(524,1,'제136조','제1편 총칙','O','채무불이행으로 인한 손해배상책임이 인정되는 경우 그 배상액(손해액)은 적극적 석명사항이다.','대판(손해액 석명)',1,false),
(525,1,'제141조','제1편 총칙','O','법원은 변론의 제한·분리·병합을 명하거나 그 명령을 취소할 수 있고, 종결된 변론을 다시 열도록 명할 수 있다.','민소 §141·§142',1,false),
(526,1,'제141조','제1편 총칙','O','변론의 제한·분리·병합은 법원의 직권사항이므로 당사자에게 이를 신청할 권리는 없고 직권발동을 촉구하는 의미만 있다.','민소 §141',1,false),
(527,1,'제141조','제1편 총칙','O','청구가 여러 개인 경우에 법원이 그 중 어느 청구를 분리하여 별개의 소송절차로 심리하기로 하는 것을 변론의 분리라고 한다.','통설',1,false),
(528,1,'제141조','제1편 총칙','O','같은 법원에 계속되어 있는 여러 개의 소송을 결합시켜 하나의 소송절차로 심리하기로 하는 결정을 변론의 병합이라고 한다.','통설',1,false),
(529,1,'제144조','제1편 총칙','O','법원은 소송관계를 분명하게 하기 위하여 필요한 진술을 할 수 없는 당사자나 대리인의 진술을 금지하고 변호사를 선임하도록 명할 수 있다(진술금지재판).','민소 §144',1,false),
(530,1,'제144조','제1편 총칙','O','당사자가 출석하였으나 진술금지의 재판을 받은 경우에는 불출석으로 된다.','대판(진술금지 불출석)',1,false),
(531,1,'제145조','제1편 총칙','O','민사소송 신모델은 화해·조정에 의한 분쟁해결을 지향(활성화)하며, 이를 지양하는 것이 아니다.','신모델',1,false),
(532,1,'제146조','제1편 총칙','O','민사소송법은 공격방어방법을 소송의 정도에 따라 적절한 시기에 제출하도록 하는 ''적시제출주의''를 채택하고 있고, 제출순서를 엄격히 정하는 법정순서주의를 취하지 않는다.','민소 §146',1,false),
(533,1,'제146조','제1편 총칙','O','현행 민사소송법은 수시제출주의가 아니라 적시제출주의를 채택하고 있다.','민소 §146',1,false),
(534,1,'제146조','제1편 총칙','O','주장·입증의 적시제출과 당사자 본인의 절차 참여 확대는 민사소송 신모델의 내용이다.','신모델',1,false),
(535,1,'제146조','제1편 총칙','O','공격방어방법은 소송의 정도에 따라 적절한 시기에 제출하여야 한다(적시제출주의).','민소 §146',1,false),
(536,1,'제147조','제1편 총칙','O','재판장은 당사자의 의견을 들어 한쪽 또는 양쪽 당사자에 대하여 특정한 사항에 관하여 주장 제출·증거 신청 기간을 정할 수 있다.','민소 §147',2,false),
(537,1,'제147조','제1편 총칙','O','재판장은 공격방어방법의 제출에 관하여 당사자에게 특정 사항의 주장·증거신청 기간을 정할 수 있으나, 이를 위해서는 당사자의 의견을 들어야 한다.','민소 §147',1,false),
(538,1,'제147조','제1편 총칙','O','재정기간을 넘겼더라도 당사자가 정당한 사유로 그 기간 내에 제출하지 못하였음을 소명하면 주장 제출·증거신청을 할 수 있다.','민소 §147②',1,false),
(539,1,'제148조','제1편 총칙','O','당사자 일방이 변론기일에 출석하지 않은 경우에도 그가 제출한 소장·답변서·준비서면에 적힌 사항을 진술한 것으로 보고 출석한 상대방에게 변론을 명할 수 있으나, 그 소장 등에 첨부된 서증이 제출된 것으로 간주할 수는 없다.','대판(진술간주 서증)',1,false),
(540,1,'제148조','제1편 총칙','O','한쪽 당사자가 불출석한 경우 진술간주제도를 적용하여 변론을 진행하느냐 기일을 연기하느냐는 법원의 재량에 속하는 사항이다.','대판(진술간주 재량)',1,false),
(541,1,'제148조','제1편 총칙','O','불출석 당사자가 준비서면에 서증 사본을 첨부하고 그 준비서면이 진술간주되더라도, 그 사본만으로는 서증이 제출된 것으로 간주되지 아니한다.','통설·판례',2,false),
(542,1,'제148조','제1편 총칙','O','원고가 불출석한 경우 그가 제출한 소장 등이 진술간주될 뿐이고, 그것만으로 법원이 원고의 청구를 기각하여야 하는 것은 아니다.','민소 §148',1,false),
(543,1,'제148조','제1편 총칙','O','출석한 당사자만으로 변론을 진행할 때에는, 불출석한 당사자가 그때까지 제출한 소장·답변서, 그 밖의 준비서면에 적힌 사항을 진술한 것으로 보아야 한다.','민소 §148①',1,false),
(544,1,'제148조','제1편 총칙','O','진술간주되는 서면에 청구의 포기·인낙 의사가 적혀 있고 ''공증사무소의 인증''을 받은 경우에 한하여 그 취지에 따라 청구의 포기·인낙이 성립된 것으로 본다.','민소 §148②',2,false),
(545,1,'제148조','제1편 총칙','O','불출석 당사자가 제출하여 진술한 것으로 보는 답변서·준비서면에 화해의 의사표시가 적혀 있고 공증사무소의 인증을 받은 경우, 상대방이 변론기일에 출석하여 그 화해의 의사표시를 받아들이면 화해가 성립된 것으로 본다.','민소 §148③',1,false),
(546,1,'제148조','제1편 총칙','O','준비서면에 적힌 사항은 진술간주되지만, 첨부된 서증까지 제출된 것으로 간주되지는 않으므로 서증은 변론기일에 현실적으로 제출하여야 한다.','대판(진술간주·서증)',1,false),
(547,1,'제148조','제1편 총칙','O','원고 또는 피고가 변론기일에 출석하지 아니하거나 출석하고서도 본안에 관하여 변론하지 아니한 때에는, 그가 제출한 소장·답변서·준비서면에 적힌 사항을 진술한 것으로 보고 출석한 상대방에게 변론을 명할 수 있다.','민소 §148①',1,false),
(548,1,'제149조','제1편 총칙','O','실기한 공격방어방법은 법원이 상대방의 신청에 의해서뿐만 아니라 직권으로도 각하할 수 있다.','민소 §149①',1,false),
(549,1,'제149조','제1편 총칙','O','실기한 공격·방어방법인지 판단할 때 항소심에서 새로운 공격방어방법이 제출된 경우에는 특별한 사정이 없는 한 항소심뿐만 아니라 제1심까지 통틀어 시기에 늦었는지를 판단한다.','판례',2,false),
(550,1,'제149조','제1편 총칙','O','공격·방어방법의 취지가 분명하지 아니한 경우 당사자가 필요한 설명을 하지 않거나 설명할 기일에 출석하지 않으면 법원은 상대방의 신청에 따라 결정으로 각하할 수 있다.','민소 §149②',1,false),
(551,1,'제149조','제1편 총칙','O','실기한 공격방어방법을 각하하려면 당사자에게 고의 또는 중과실이 있어야 하지만, 반드시 상대방의 신청이 필요한 것은 아니다(직권 각하 가능).','민소 §149①',1,false),
(552,1,'제149조','제1편 총칙','O','당사자가 제출한 공격방어방법의 취지가 분명하지 아니하여 법원이 석명권을 행사하였음에도 당사자가 필요한 설명을 하지 않으면, 법원은 그 공격방어방법을 각하할 수 있다.','민소 §149②',1,false),
(553,1,'제149조','제1편 총칙','O','적시제출주의에 위반한 경우 각하의 대상은 공격·방어방법(주장·부인·항변·증거신청)이고, 반소·소의 변경 등은 해당되지 않는다.','대판(실기 각하 대상)',1,false),
(554,1,'제149조','제1편 총칙','O','항소심에서 새로운 공격방어방법이 제출된 때에는 제1심의 경과까지 전체를 살펴 시기에 늦었는지를 판단하여야 한다.','대판(실기 판단)',1,false),
(555,1,'제150조','제1편 총칙','O','제1심에서 자백간주가 있었더라도 당해 심급은 물론 항소심에서 변론종결시까지 이를 다투었다면 자백간주는 성립하지 않는다.','판례',2,false),
(556,1,'제150조','제1편 총칙','O','공시송달로 기일이 통지된 경우에는 출석하지 않은 당사자에게 책임을 물을 수 없으므로 자백간주의 효과가 발생하지 않는다.','민소 §150③',1,false),
(557,1,'제150조','제1편 총칙','O','자백간주의 효과가 발생한 후 이후의 기일통지서가 송달불능으로 공시송달로 진행되었더라도 그 자백간주의 효과는 유지되므로, 자백간주된 사실과 배치되는 사실인정을 하는 것은 위법하다.','판례',1,false),
(558,1,'제150조','제1편 총칙','O','이행불능 여부는 법률적 판단에 관한 주장(법률상 주장)이므로 자백(자백간주)의 대상이 되지 않고 법원을 구속하지 않는다.','판례',1,false),
(559,1,'제150조','제1편 총칙','O','원고의 주장사실을 인정하는 취지의 답변서가 진술간주된 경우 그 인정은 자백(재판상 자백에 준함)에 해당하는 것이지 다투지 않음을 전제로 하는 자백간주가 성립하는 것은 아니다.','판례',1,false),
(560,1,'제150조','제1편 총칙','O','자백간주의 요건이 구비되어 일단 자백간주의 효과가 발생한 때에는, 그 이후 기일에 대한 소환장이 송달불능으로 공시송달되었더라도 이미 발생한 자백간주의 효과가 상실되는 것은 아니다.','대판(자백간주 공시송달)',1,false),
(561,1,'제150조','제1편 총칙','O','소송대리권의 존부에 대하여는 자백간주에 관한 규정이 적용될 여지가 없다.','대판(대리권 자백간주)',1,false),
(562,1,'제150조','제1편 총칙','O','자백간주는 재판상 자백과 달리 당사자에 대한 구속력이 없으므로, 사실심 변론종결시까지 이에 반하는 주장을 하여 번복할 수 있다.','대판(자백간주 구속력)',2,false),
(563,1,'제150조','제1편 총칙','O','자백간주는 당사자에 대한 구속력이 없으므로, 제1심에서 자백간주가 있었더라도 항소심에서 다투면 그 효력이 유지되지 않는다.','대판(자백간주 구속력)',1,false),
(564,1,'제150조','제1편 총칙','O','자백간주가 성립되면 재판상의 자백과 마찬가지로 법원은 그 사실을 판결의 기초로 삼아야 한다.','민소 §150③',1,false),
(565,1,'제150조','제1편 총칙','O','당사자가 변론기일에 출석하여 상대방 주장사실을 명백히 다투지 않더라도 변론 전체의 취지로 보아 다투었다고 인정되면 자백간주가 성립하지 않는다.','민소 §150①',1,false),
(566,1,'제150조','제1편 총칙','O','자백간주는 변론주의에 근거한 것이며, 직권조사사항·재심사유·법률상의 주장에 대해서는 자백간주가 있을 수 없다.','대판(자백간주 한계)',1,false),
(567,1,'제150조','제1편 총칙','O','공시송달에 의한 기일통지를 받고 불출석한 경우에는 자백간주의 효과가 발생하지 않는다.','민소 §150③단서',1,false),
(568,1,'제150조','제1편 총칙','O','아무런 답변을 하지 않는 것은 자백간주(의제자백)에 해당할 뿐 항변이 아니다.','민소 §150',1,false),
(569,1,'제150조','제1편 총칙','O','자백간주가 성립하면 법원은 이에 구속되나, 당사자에 대한 구속력은 없으므로 당사자는 사실심 변론종결시까지 상대방의 주장사실을 다투어 번복할 수 있다.','대판(자백간주)',1,false),
(570,1,'제150조','제1편 총칙','O','자백간주된 사실은 증명을 필요로 하지 않는다.','민소 §150',1,false),
(571,1,'제151조','제1편 총칙','O','당사자본인으로 신문하여야 함에도 증인으로 신문하였더라도, 상대방이 지체 없이 이의하지 아니하면 책문권(이의권)의 포기·상실로 그 하자가 치유된다.','민소 §151; 판례',3,false),
(572,1,'제151조','제1편 총칙','O','항소기간 등 불변기간의 기산점이 되는 판결정본 송달의 하자는 이의권(책문권)의 포기·상실로 치유되지 않는다.','대판(판결정본 송달 하자)',1,false),
(573,1,'제151조','제1편 총칙','O','직권조사사항은 공익적 사항이므로 당사자의 소송절차에 관한 이의권(책문권)의 포기·상실 대상이 되지 않는다.','대판(직권조사 이의권)',1,false),
(574,1,'제152조','제1편 총칙','O','변론의 내용이 조서에 기재되어 있을 때에는 다른 특별한 사정이 없는 한 그 내용이 진실하다는 점에 관하여 강한 증명력을 갖는다.','판례',1,false),
(575,1,'제152조','제1편 총칙','O','변론을 녹음하거나 속기하게 하는 경우 등에는 법원사무관등을 참여시키지 아니하고 변론기일을 열 수 있다(그 경우가 위법한 것은 아니다).','민소 §152①',1,false),
(576,1,'제153조','제1편 총칙','O','조서의 기재는 정한 경우 생략할 수 있으나, 변론방식에 관한 규정의 준수에 대하여는 생략할 수 없다.','민소 규칙',1,false),
(577,1,'제153조','제1편 총칙','O','조서에는 법원이 적당하다고 인정한 것을 인용하고 소송기록에 붙여 이를 조서의 일부로 삼을 수 있다.','민소 §153',1,false),
(578,1,'제158조','제1편 총칙','O','변론방식에 관한 규정이 지켜졌다는 것은 조서로만 증명할 수 있으나, 조서가 없어진 때에는 그러하지 아니하다.','민소 §158',1,false),
(579,1,'제158조','제1편 총칙','O','변론의 방식에 관한 규정이 지켜졌다는 것은 조서로만 증명할 수 있다(법원사무관등의 증언으로 증명할 수 없다).','민소 §158',1,false),
(580,1,'제159조','제1편 총칙','O','법원은 필요하다고 인정하면 변론의 전부·일부를 녹음하거나 속기하게 할 수 있고, 당사자가 신청하면 특별한 사유가 없는 한 이를 명하여야 하며, 녹음테이프·속기록은 조서의 일부로 삼는다.','민소 §159',1,false),
(581,1,'제159조','제1편 총칙','O','조서는 관계인이 신청하면 읽어주거나 보여주어야 한다.','민소 §159',1,false),
(582,1,'제164조의2','제1편 총칙','O','전문심리위원은 재판의 합의에 참여할 수 없고, 전문적 지식에 기한 설명·의견을 제출하여 소송절차에 참여할 뿐이다.','민소 §164의2',1,false),
(583,1,'제164조의2','제1편 총칙','O','전문심리위원의 설명·의견은 증거자료가 되는 것은 아니지만, 법원은 그에 관하여 당사자에게 의견을 진술할 기회를 주어야 한다.','민소 §164의2④',1,false),
(584,1,'제164조의2','제1편 총칙','O','전문심리위원은 당사자의 동의가 있더라도 재판의 합의에 참여할 수 없다.','민소 §164의2',1,false),
(585,1,'제164조의2','제1편 총칙','O','전문심리위원은 기일에 재판장의 허가를 받아 당사자, 증인 또는 감정인 등 소송관계인에게 직접 질문할 수 있다.','민소 §164의2②',1,false),
(586,1,'제164조의3','제1편 총칙','O','법원은 상당하다고 인정되는 경우 직권이나 당사자의 신청에 따라 전문심리위원 지정 결정을 취소할 수 있으며, 당사자들이 합의로 그 취소를 신청하는 경우에는 그 결정을 취소하여야 한다.','민소 §164의3',1,false),
(587,1,'제164조의5','제1편 총칙','O','전문심리위원에 대해서도 민사소송법에 따라 제척·기피신청을 할 수 있다.','민소 §164의5',1,false),
(588,1,'제165조','제1편 총칙','O','기일은 직권으로 또는 당사자의 신청에 따라 재판장이 지정하나, 수명법관·수탁판사가 신문·심문하는 기일은 그 수명법관·수탁판사가 지정한다.','민소 §165',1,false),
(589,1,'제165조','제1편 총칙','O','첫 변론기일(첫 변론준비기일)을 바꾸는 것은 당사자들의 합의가 있으면 현저한 사유가 없더라도 허가할 수 있다.','민소 §165②',1,false),
(590,1,'제167조','제1편 총칙','O','기일통지서 또는 출석요구서의 송달은 원본에 의한다.','민소 규칙',1,false),
(591,1,'제167조','제1편 총칙','O','기일통지서는 원본을 송달한다.','민소 규칙',1,false),
(592,1,'제167조','제1편 총칙','O','기일은 기일통지서 또는 출석요구서를 송달하여 통지하나, 그 사건으로 출석한 사람에게는 기일을 직접 고지하면 된다.','민소 §167',1,false),
(593,1,'제168조','제1편 총칙','O','소송관계인이 일정한 기일에 출석하겠다고 적은 서면을 제출한 때에는 기일통지서·출석요구서를 송달한 것과 같은 효력을 가진다.','민소 §168',1,false),
(594,1,'제170조','제1편 총칙','O','지급명령신청이 각하된 경우라도 6개월 이내에 다시 소를 제기하면 시효는 당초 지급명령신청이 있었던 때에 중단되었다고 보아야 한다.','대판(지급명령 각하 후 재소)',1,false),
(595,1,'제172조','제1편 총칙','O','위 결정들에 대한 이의신청기간이나 소취하간주 시의 기일지정신청기간이 모두 불변기간인 것은 아니다(불변기간은 법률이 불변기간으로 정한 경우에 한한다).','민소 §172',1,false),
(596,1,'제172조','제1편 총칙','O','제소전화해에서 소제기신청기간, 제권판결에 대한 불복기간, 중재판정취소의 소의 출소기간은 불변기간에 해당한다.','판례',1,false),
(597,1,'제173조','제1편 총칙','O','소장부본·판결정본이 공시송달로 송달되었다면 피고는 과실 없이 송달을 알지 못한 것이고, 책임질 수 없는 사유로 불변기간을 준수하지 못한 때에 해당하여 그 사유가 없어진 후 2주 내에 추완항소를 할 수 있다.','판례',1,false),
(598,1,'제173조','제1편 총칙','O','원고가 허위주소로 송달하여 사위판결을 얻은 경우 피고는 언제든지 상소를 제기할 수 있고, 상소의 추후보완도 허용된다.','판례',1,false),
(599,1,'제173조','제1편 총칙','O','지병·정신과 치료 등의 사유로 상고기간을 도과한 것은 원칙적으로 당사자가 책임질 수 없는 사유에 해당하지 않는다.','판례',1,false),
(600,1,'제173조','제1편 총칙','O','조정 불성립으로 종결된 후 피신청인이 주소변경신고를 하지 않은 상태에서 조정이 소송으로 이행되어 발송송달·공시송달된 경우에는, 처음부터 소장 부본이 적법하게 송달된 경우와 달라 피신청인에게 소송진행상황 조사의무가 있으므로, 이를 조사하지 않았다면 당사자가 책임질 수 없는 사유에 해당하지 아니한다.','판례',1,false),
(601,1,'제173조','제1편 총칙','O','통상의 배달기간을 넘는 이례적인 우편배달 지연으로 항소기간을 준수하지 못한 경우에는 당사자가 책임질 수 없는 사유에 해당할 수 있다.','판례',1,false),
(602,1,'제173조','제1편 총칙','O','당사자 본인뿐만 아니라 그 소송대리인 및 대리인의 보조인도 책임질 수 없는 사유로 불변기간을 지킬 수 없었던 경우에는 추후보완을 할 수 있다.','대판(추완 보조인)',1,false),
(603,1,'제173조','제1편 총칙','O','조정이 소송으로 이행되어 처음부터 공시송달 등으로 진행된 것과 같은 경우에는 당사자에게 소송 진행상황 조사의무가 없으므로, 상소기간을 지키지 못한 것은 당사자가 책임질 수 없는 사유에 해당하여 추후보완이 허용된다.','대판(조정→소송이행 추완)',1,false),
(604,1,'제173조','제1편 총칙','O','소송 도중 통상의 방법으로 송달할 수 없게 되어 공시송달한 경우에는 처음 소장부본부터 공시송달로 진행된 경우와 달라 당사자에게 소송 진행상황 조사의무가 있으므로, 이를 조사하지 않아 불변기간을 지키지 못하였다면 당사자가 책임질 수 없는 사유라 할 수 없다.','대판(소송 도중 공시송달)',1,false),
(605,1,'제173조','제1편 총칙','O','판결의 선고 및 송달 사실을 알지 못하여 상소기간을 지키지 못한 데 과실이 없다는 사정은 상소를 추후보완하려는 당사자 측에서 주장·입증하여야 한다.','대판(추완 입증책임)',1,false),
(606,1,'제173조','제1편 총칙','O','허위주소로 판결정본이 송달처리된 경우 그 송달은 무효이므로 항소기간이 진행되지 않고, 피고는 추후보완이 아니라 통상의 항소를 제기할 수 있다.','대판(전합) 78다1242',1,false),
(607,1,'제173조','제1편 총칙','O','서울에서 수원으로 배달증명우편으로 발송한 항소장이 4일 만에 배달되어 항소기간을 준수할 수 없었다는 것은 당사자가 책임질 수 없는 사유가 아니다.','대판(우편 지연)',1,false),
(608,1,'제173조','제1편 총칙','O','불변기간 준수에서 ''당사자가 책임질 수 없는 사유''란 일반적으로 하여야 할 주의를 다하였음에도 기간을 준수할 수 없었던 사유를 가리키고, 그 당사자에는 본인뿐만 아니라 소송대리인 및 대리인의 보조인도 포함된다.','대판(책임질 수 없는 사유)',1,false),
(609,1,'제173조','제1편 총칙','O','소송대리인이 판결정본을 송달받고도 당사자에게 알려주지 아니하여 당사자가 상고제기기간 경과 후 비로소 알게 되었더라도, 이는 당사자가 책임질 수 없는 사유에 해당하지 아니한다.','판례',2,false),
(610,1,'제173조','제1편 총칙','O','원고가 피고의 주소를 허위로 기재하여 소를 제기하고 그 허위주소로 송달되어 피고 아닌 자가 자백간주 형식 승소판결의 정본을 수령한 경우, 피고는 그 제1심판결에 대하여 항소를 제기하여 다툴 수 있다.','대판(허위주소 판결)',1,false),
(611,1,'제173조','제1편 총칙','O','상고이유서 제출기간은 불변기간이 아니므로 추후보완이 허용되지 않는다.','대판(불변기간)',1,false),
(612,1,'제173조','제1편 총칙','O','쌍방 당사자의 2회 불출석 후 기일지정신청기간(1월)은 불변기간이 아니므로 추후보완이 허용되지 않는다.','대판(불변기간)',1,false),
(613,1,'제173조','제1편 총칙','O','화해권고결정에 대한 이의신청기간은 불변기간이므로 책임 없는 사유로 도과한 경우 추후보완이 허용된다.','대판(불변기간)',1,false),
(614,1,'제173조','제1편 총칙','O','항소기간은 불변기간이므로 당사자가 책임질 수 없는 사유로 도과한 경우 추후보완이 허용된다.','민소 §396②',1,false),
(615,1,'제173조','제1편 총칙','O','당사자가 책임질 수 없는 사유로 불변기간을 지킬 수 없었던 경우에는 그 사유가 없어진 날부터 2주 이내에 게을리 한 소송행위를 보완할 수 있다.','민소 §173①',1,false),
(616,1,'제173조','제1편 총칙','O','허위주소 송달로 판결이 확정되지 않았으므로 추후보완항소가 아니라 통상의 항소로 다툴 수 있다.','대판 78다1242',1,false),
(617,1,'제174조','제1편 총칙','O','송달은 특별한 규정이 없으면 법원이 직권으로 한다.','민소 §174',1,false),
(618,1,'제174조','제1편 총칙','O','송달은 원칙적으로 법원이 직권으로 하지만, 공휴일 또는 해뜨기 전이나 해진 뒤에 하는 송달은 당사자의 신청에 따라 행한다.','민소 §174·§190',1,false),
(619,1,'제175조','제1편 총칙','O','송달에 관한 사무는 법원사무관 등이 처리한다.','민소 §175①',1,false),
(620,1,'제176조','제1편 총칙','O','송달사무를 담당하여 처리하는 기관은 법원사무관등이고, 원칙적인 송달실시기관은 집행관과 우편집배원이다.','민소 §176',1,false),
(621,1,'제177조','제1편 총칙','O','해당 사건에 출석한 사람에게는 법원사무관등이 직접 송달할 수 있다.','민소 §177',1,false),
(622,1,'제177조','제1편 총칙','O','법원사무관등이 당해 사건 때문에 출석한 사람으로부터 영수증을 받고 송달서류를 직접 교부하였다(출석자에 대한 교부송달로서 유효하다).','민소 §177',1,false),
(623,1,'제178조','제1편 총칙','O','송달은 특별한 규정이 없으면 송달받을 사람에게 서류의 등본 또는 부본을 교부하여야 한다.','민소 §178①',2,false),
(624,1,'제178조','제1편 총칙','O','서류의 제출에 갈음하여 조서, 그 밖의 서면을 작성한 때에는 그 등본 또는 초본을 교부하여 송달한다.','민소 §178②',1,false),
(625,1,'제178조','제1편 총칙','O','사망한 자에 대하여 실시된 송달은 원칙적으로 무효이나, 그 사망자의 상속인이 현실적으로 그 송달서류를 수령한 경우에는 하자가 치유되어 그 때에 상속인에 대한 송달로서 효력을 발생한다.','대판(사망자 송달 치유)',1,false),
(626,1,'제178조','제1편 총칙','O','소송대리인이 있음에도 기일통지서를 소송대리인이 아닌 당사자 본인에게 송달한 경우에도 그 송달은 (무효가 아니라) 유효하다.','대판(본인 송달 유효)',1,false),
(627,1,'제178조','제1편 총칙','O','송달은 원칙적으로 송달받을 사람에게 서류의 등본 또는 부본을 교부하는 방법에 의한다.','민소 §178①',1,false),
(628,1,'제179조','제1편 총칙','O','소송무능력자에게 할 송달은 그의 법정대리인에게 한다.','민소 §179',3,false),
(629,1,'제179조','제1편 총칙','O','법인 그 밖의 단체에 대한 송달은 그 대표자의 주소·거소·영업소 또는 사무소에 하여야 한다.','민소 §64·§183',1,false),
(630,1,'제179조','제1편 총칙','O','국가를 당사자로 하는 소송에서 국가에 대한 송달은 수소법원에 대응하는 검찰청의 장에게 한다.','국가소송법',2,false),
(631,1,'제180조','제1편 총칙','O','여러 사람이 공동으로 대리권을 행사하는 경우의 송달은 그 가운데 한 사람에게 하면 된다.','민소 §180',5,false),
(632,1,'제182조','제1편 총칙','O','교도소·구치소·유치장에 수감된 사람에게 할 송달을 그 장(長)에게 하지 아니하고 종전 주·거소에 하였다면 부적법하여 무효이고, 법원이 수감 사실을 몰랐더라도 마찬가지로 송달의 효력이 발생하지 않는다.','판례',1,false),
(633,1,'제182조','제1편 총칙','O','국가경찰관서의 유치장에 체포 또는 유치된 사람에게 할 송달은 국가경찰관서의 장에게 한다.','민소 §182',2,false),
(634,1,'제182조','제1편 총칙','O','재감자에 대한 송달은 교도소장에게 하여야 하므로, 수감 사실을 알지 못해 종전 주·거소에 한 송달은 부적법(무효)하다.','대판(재감자 송달)',1,false),
(635,1,'제182조','제1편 총칙','O','재감자에 대한 송달은 교도소 등의 소장에게 하여야 효력이 있으므로, 종전 주소에 한 송달은 무효이다.','대판(재감자 송달)',1,false),
(636,1,'제183조','제1편 총칙','O','법인에 대한 송달에서 ''영업소 또는 사무소''는 당해 법인 자신의 것을 의미하고, 그 대표자가 경영하는 별도 법인격을 가진 다른 법인의 영업소·사무소는 포함되지 않는다.','대판(영업소 송달)',1,false),
(637,1,'제183조','제1편 총칙','O','소장·지급명령신청서 등에 기재된 주소 등의 장소에 대한 송달을 시도하지 않은 채 곧바로 근무장소로 한 송달은 위법하다.','대판(근무장소 송달)',3,false),
(638,1,'제183조','제1편 총칙','O','송달받을 사람의 주소·거소·영업소·사무소나 근무장소가 국내에 없거나 알 수 없는 때에는 그를 만나는 장소에서 송달할 수 있다(조우송달).','민소 §183④',1,false),
(639,1,'제183조','제1편 총칙','O','송달받을 사람의 주소 등을 알지 못하거나 그 장소에서 송달할 수 없는 때에는, 고용·위임관계 등으로 취업하고 있는 근무장소에서 송달할 수 있다.','민소 §183②',1,false),
(640,1,'제184조','제1편 총칙','O','송달영수인의 지정 신고가 있는 경우 그 송달영수인의 사무원에게 한 송달은 적법하다.','대판(송달영수인)',1,false),
(641,1,'제185조','제1편 총칙','O','당사자가 송달장소로 신고한 장소에 송달된 바가 없는 경우, 그곳을 민사소송법 제185조 제2항의 ''종전에 송달받던 장소''라고 볼 수 없다.','판례',1,false),
(642,1,'제185조','제1편 총칙','O','화해권고결정 정본은 발송송달(등기우편)의 방법으로 송달할 수 없으므로, 그러한 발송송달은 부적법하다.','대판(화해권고 발송송달)',1,false),
(643,1,'제185조','제1편 총칙','O','송달장소가 송달불능된 경우 기록상 드러난 다른 송달가능 장소(본인 주소지 등)에 송달을 시도하지 않은 채 곧바로 한 발송송달은 부적법(무효)하다.','대판(발송송달 보충성)',1,false),
(644,1,'제185조','제1편 총칙','O','송달장소를 신고한 곳에 송달불능이 되었다 하여 곧바로 발송송달을 할 수 있는 것은 아니고, 다른 송달방법을 시도하여야 한다.','대판(발송송달)',1,false),
(645,1,'제186조','제1편 총칙','O','보충송달은 적법한 송달장소에서 하는 경우에만 허용되고, 송달장소가 아닌 곳에서 사무원·고용인·동거자를 만난 경우에는 그가 수령을 거부하지 않더라도 그 곳에서 교부하는 것은 부적법하다.','판례',2,false),
(646,1,'제186조','제1편 총칙','O','송달받을 사람 등이 정당한 사유 없이 송달받기를 거부하는 때에는 송달할 장소에 서류를 놓아두어(유치송달) 송달의 효력을 발생시킬 수 있다.','민소 §186③',2,false),
(647,1,'제186조','제1편 총칙','O','보충송달의 수령대행인은 동거인·사무원·피용자 등이어야 하므로, 단지 같은 집에 거주하는 임대인에게 한 보충송달은 부적법하다.','대판(보충송달 동거인)',1,false),
(648,1,'제186조','제1편 총칙','O','근무장소 외의 송달할 장소에서 송달받을 사람의 사무원·피용자 또는 동거인이 정당한 사유 없이 송달받기를 거부하는 때에는 유치송달을 할 수 있다.','민소 §186③',1,false),
(649,1,'제186조','제1편 총칙','O','유치송달은 근무장소 외의 장소에서 가능하고, 근무장소에서의 보충송달은 수령대행인이 수령을 거부하지 아니하는 경우에만 할 수 있다(거부 시 유치송달 불가).','민소 §186②③',2,false),
(650,1,'제186조','제1편 총칙','O','근무장소에서 송달받을 사람을 만나지 못한 경우, 그 피용자로서 사리를 분별할 지능이 있는 사람이 서류 수령을 거부하지 않으면 그에게 송달할 수 있다.','민소 §186②',1,false),
(651,1,'제186조','제1편 총칙','O','근무장소 외의 송달할 장소에서 송달받을 사람을 만나지 못한 때에는 그 사무원·피용자·동거인으로서 사리를 분별할 지능이 있는 사람에게 서류를 교부할 수 있다(보충송달).','민소 §186①',1,false),
(652,1,'제186조','제1편 총칙','O','이혼한 처라도 사정에 의하여 사실상 동일 세대에 소속되어 생활을 같이 하고 있다면 보충송달을 받을 수 있는 동거인이 될 수 있다.','대판(동거인)',1,false),
(653,1,'제186조','제1편 총칙','O','송달받을 사람의 직장(근무장소)에서 본인이 아닌 과장이 수령을 거부한 경우 유치송달을 한 것은 무효이다.','대판(근무장소 유치송달)',1,false),
(654,1,'제187조','제1편 총칙','O','보충송달·유치송달을 할 수 없을 때에만 등기우편에 의한 발송송달을 할 수 있다.','민소 §187',1,false),
(655,1,'제187조','제1편 총칙','O','발송송달을 한 적이 있더라도 그 후의 송달은 다시 교부송달 등 원칙적 송달을 시도하여야 하고, 우선적으로 발송송달을 하여야 하는 것은 아니다.','대판(발송송달)',1,false),
(656,1,'제194조','제1편 총칙','O','원고가 소권을 남용하여 청구가 이유 없음이 명백한 소를 반복 제기한 것에 대하여 법원이 변론 없이 판결로 소를 각하하는 경우 재판장은 직권으로 피고에 대하여 공시송달을 명할 수 있다.','민소',1,false),
(657,1,'제194조','제1편 총칙','O','당사자의 주소등 또는 근무장소를 알 수 없는 경우 법원사무관등은 직권 또는 신청에 따라 공시송달을 할 수 있고, 공시송달은 서류를 보관하고 그 사유를 법원게시판 게시 등의 방법으로 한다.','민소',1,false),
(658,1,'제194조','제1편 총칙','O','재판장의 명령에 의한 공시송달은 그 요건이 불비되었더라도 유효하므로, 상소기간이 도과하면 판결은 확정되고 기판력도 발생한다(다만 추후보완상소가 가능할 뿐이다).','대판(공시송달 효력)',1,false),
(659,1,'제194조','제1편 총칙','O','재판장은 직권으로 또는 당사자의 신청에 따라 공시송달을 명할 수 있다.','민소 §194',1,false),
(660,1,'제194조','제1편 총칙','O','재판장의 공시송달 명령에 의하여 공시송달을 한 이상, 공시송달의 요건을 구비하지 아니한 흠이 있더라도 송달의 효력에는 영향이 없다.','대판(공시송달 효력)',1,false),
(661,1,'제194조','제1편 총칙','O','공시송달이 법정요건에 해당하지 아니하더라도 재판장이 공시송달을 명하여 일단 공시송달이 행하여진 이상 그 공시송달은 유효하다.','대판(공시송달 효력)',1,false),
(662,1,'제195조','제1편 총칙','O','공시송달은 법원사무관등이 송달할 서류를 보관하고 그 사유를 법원게시판에 게시하거나 그 밖에 대법원규칙이 정하는 방법에 따라 하여야 한다.','민소 §195',1,false),
(663,1,'제196조','제1편 총칙','O','첫 공시송달은 실시한 날부터 2주가 지나야 효력이 생기고, 다만 같은 당사자에게 하는 그 뒤의 공시송달은 실시한 다음 날부터 효력이 생긴다.','민소 §196',2,false),
(664,1,'제198조','제1편 총칙','O','판결·결정은 법원의 재판이고, 명령은 재판장·수명법관 등 법관의 재판이다.','통설',1,false),
(665,1,'제198조','제1편 총칙','O','압류명령·전부명령의 성질은 결정이고, 소장각하명령의 성질은 명령이다.','통설',1,false),
(666,1,'제201조','제1편 총칙','O','중간판결에서는 원칙적으로 소송비용의 재판을 하지 아니하며, 중간판결에 대해서는 독립한 상소가 허용되지 않는다.','민소',1,false),
(667,1,'제202조','제1편 총칙','O','공해로 인한 손해배상청구에서 가해기업이 배출한 유해 원인물질이 피해물건에 도달하여 손해가 발생하고 그 유해의 정도가 참을 한도를 넘으면, 가해자가 무해함을 증명하지 못하는 한 인과관계를 인정할 수 있다.','판례',1,false),
(668,1,'제202조','제1편 총칙','O','의료과오소송에서 피해자측이 일반인의 상식에 바탕을 둔 의료상 과실행위를 증명하고 그 결과와 사이에 다른 원인이 개재될 수 없다는 점을 증명하면, 의사가 다른 원인임을 증명하지 못하는 한 과실과 결과 사이의 인과관계를 추정할 수 있다.','판례',1,false),
(669,1,'제202조','제1편 총칙','O','증명방해가 있더라도 증명책임이 전환되는 것은 아니고, 법원이 자유심증으로 방해자에게 불리한 평가를 할 수 있을 뿐이다.','대판 98다9915',1,false),
(670,1,'제202조','제1편 총칙','O','비밀 녹음 녹음테이프라도 증거능력이 부정되는 것은 아니고, 그 채증 여부는 사실심 법원의 재량에 속한다.','대판 2009다37138',1,false),
(671,1,'제202조','제1편 총칙','O','당사자가 부지로 다툰 서증에 관하여 거증자가 그 성립을 증명하지 아니한 경우라도 법원은 다른 증거에 의하지 않고 변론 전체의 취지를 참작하여 자유심증으로 그 성립을 인정할 수 있다.','판례',1,false),
(672,1,'제202조','제1편 총칙','O','당사자는 주장·증명을 통하여 감정결과의 당부를 다툴 수 있다.','대판 2001다27777',1,false),
(673,1,'제202조','제1편 총칙','O','처분문서는 그 진정성립이 인정된 이상 그 문서에 표시된 의사표시와 내용에 관하여 특별한 사유가 없는 한 실질적 증거력이 있으므로, 그 내용이 되는 법률행위의 존재를 인정하여야 한다.','대판(처분문서 증거력)',1,false),
(674,1,'제202조','제1편 총칙','O','처분문서는 그 진정성립이 인정되는 이상 법원은 반증이 없는 한 그 기재 내용대로 법률행위의 존재 및 내용을 인정하여야 한다.','대판(처분문서 증거력)',1,false),
(675,1,'제202조','제1편 총칙','O','위자료의 액수는 직권조사사항이 아니라 사실심 법원이 변론 전체의 취지와 증거조사 결과로 재량에 따라 정하는 사항이다.','대판(위자료 재량)',1,false),
(676,1,'제203조','제1편 총칙','O','건물철거·부지인도 청구와 건물매수대금 지급과 상환의 건물명도 청구는 별개이므로, 청구취지의 변경 없이 곧바로 상환이행(명도)판결을 할 수 없다.','판례',1,false),
(677,1,'제203조','제1편 총칙','O','매수인이 소유권이전등기청구만 하고 매도인이 동시이행 항변을 한 경우, 대금수령과 상환으로 이전등기를 명하는 것은 그 청구 중 대금지급과 상환으로 받겠다는 취지가 포함된 경우에 한하므로, 반대급부 의무가 없다는 취지가 분명하면 청구를 기각하여야 한다.','판례',1,false),
(678,1,'제203조','제1편 총칙','O','불법행위를 원인으로 한 손해배상청구에 대하여 채무불이행을 인정하여 손해배상을 명한 것은 위법하다.','판례',1,false),
(679,1,'제203조','제1편 총칙','O','피담보채무의 부존재(불발생)를 전제로 한 무조건 말소청구에는 피담보채무 변제를 조건으로 하는 장래이행청구가 포함되어 있다고 볼 수 없다.','판례',1,false),
(680,1,'제203조','제1편 총칙','O','부동산을 단독상속하기로 분할협의 하였다는 이유로 부동산 전부가 자기 소유임의 확인을 구하는 청구에는, 그 사실이 인정되지 않는 경우 자신의 상속지분에 대한 소유권확인을 구하는 취지가 포함되어 있다고 보아야 한다.','판례',1,false),
(681,1,'제203조','제1편 총칙','O','당사자가 주장하지 않더라도 자동차손해배상보장법의 규정을 민법상 손해배상 규정에 우선하여 적용하여도 처분권주의 위반이 아니다.','판례',1,false),
(682,1,'제203조','제1편 총칙','O','과실상계는 손해 전액에서 과실비율에 따라 감액하고, 그 잔액이 청구액을 넘지 않으면 잔액을, 넘으면 청구 전액을 인용한다(외측설).','대판 75다819',1,false),
(683,1,'제203조','제1편 총칙','O','피고가 본안전 항변으로 채권양도사실을 내세워 당사자적격이 없다고 주장하는 경우, 그 주장 속에는 원고가 채권을 양도하여 채권자가 아니므로 청구가 이유 없다는 본안 항변이 포함되어 있다.','대판(본안전항변 속 본안항변)',2,false),
(684,1,'제203조','제1편 총칙','O','증여를 원인으로 한 소유권이전등기청구에 피고가 시효취득을 주장하였다고 하여도, 그 주장 속에 원고의 이전등기청구권이 시효소멸하였다는 주장까지 포함된 것으로 볼 수 없다.','대판(시효취득 주장)',2,false),
(685,1,'제203조','제1편 총칙','O','응소행위로 인한 시효중단의 효과는 변론주의 원칙상 당사자가 응소행위로 시효가 중단되었다고 주장하여야 발생한다.','대판(응소행위 시효중단)',1,false),
(686,1,'제203조','제1편 총칙','O','중도금을 직접 지급하였느냐 수령권한 수임자를 통하여 지급하였느냐는 변제사실에 대한 간접사실에 지나지 않아 반드시 당사자의 구체적인 주장을 요하지 않는다.','대판(간접사실)',1,false),
(687,1,'제203조','제1편 총칙','O','대지임대차 종료 시 임대인의 건물철거 및 대지인도 청구에는, 임차인이 적법하게 건물매수청구권을 행사하였더라도 건물매수대금 지급과 동시에 건물명도를 구하는 청구가 포함되어 있다고 볼 수 없다.','대판(전합 건물매수)',1,false),
(688,1,'제203조','제1편 총칙','O','상속채권자가 상속인을 상대로 상속채무 이행을 청구하였는데 상속인의 한정승인 항변이 이유 있으면, 상속재산의 한도에서 상속채무를 이행할 것을 명해야 한다.','대판(한정승인 유한책임)',1,false),
(689,1,'제203조','제1편 총칙','O','매매계약 체결과 대금완납을 청구원인으로 소유권이전등기를 구하는 청구취지에는, 대금 중 미지급금이 있을 때에는 그 수령과 상환으로 이전등기를 구하는 취지도 포함되어 있다.','대판(상환이전등기)',1,false),
(690,1,'제203조','제1편 총칙','O','채무 전액 변제를 주장한 근저당말소청구라도 잔존채무가 있는 것으로 밝혀진 경우, 그 청구 중에는 확정된 잔존채무를 변제한 후에 말소를 구한다는 취지도 포함되어 있다.','대판(근저당 말소 잔존채무)',1,false),
(691,1,'제203조','제1편 총칙','O','변론주의 원칙은 권리의 발생·변경·소멸이라는 법률효과 판단의 요건이 되는 주요사실에 적용되므로, 소멸시효 항변은 변론주의 원칙상 당사자의 주장이 있어야만 법원의 판단대상이 된다.','대판(소멸시효 항변)',1,false),
(692,1,'제203조','제1편 총칙','O','소멸시효기간은 법률 적용의 문제이므로, 당사자가 민법상 기간을 주장하였더라도 법원은 직권으로 상법상 소멸시효기간을 적용할 수 있다.','대판(소멸시효기간 직권)',1,false),
(693,1,'제203조','제1편 총칙','O','본래의 소멸시효 기산일과 당사자가 주장하는 기산일이 서로 다른 경우에는, 변론주의 원칙상 법원은 당사자가 주장하는 기산일을 기준으로 소멸시효를 계산하여야 한다.','대판(시효 기산일)',1,false),
(694,1,'제203조','제1편 총칙','O','소유권에 기하여 미등기 무허가건물의 반환을 구하는 청구취지 속에 점유권에 기한 반환청구권을 행사한다는 취지가 당연히 포함되어 있다고 볼 수는 없다.','대판(소유권·점유권 청구)',1,false),
(695,1,'제203조','제1편 총칙','O','취득시효의 기산점은 간접사실에 불과하므로, 법원은 이에 관한 당사자의 주장에 구속되지 아니하고 소송상 나타난 자료에 의하여 점유의 시기를 인정할 수 있다.','대판(취득시효 기산점)',1,false),
(696,1,'제203조','제1편 총칙','O','원고가 향후치료비 상당 손해를 일시금 지급으로 청구한 데 대하여 법원이 정기금 지급으로 판단하더라도 (처분권주의에) 위법하지 않다.','대판(향후치료비 정기금)',1,false),
(697,1,'제203조','제1편 총칙','O','채무불이행으로 인한 손해배상 예정액 청구와 손해배상액 청구는 청구원인을 달리하는 별개의 청구이므로, 예정액 청구 가운데 손해배상액 청구가 포함되어 있다고 볼 수 없다.','대판(손해배상 예정액)',1,false),
(698,1,'제203조','제1편 총칙','O','1개의 손해배상청구권 중 일부가 청구된 경우 과실상계는 손해 전액에서 과실비율 감액 후 그 잔액이 청구액을 넘지 않으면 잔액을, 넘으면 청구 전액을 인용하는 것으로 해석함이 일부청구 당사자의 통상적 의사이므로, 이에 따른 인용은 처분권주의에 위배되지 않는다.','대판 75다819',1,false),
(699,1,'제203조','제1편 총칙','O','의사표시가 강박에 의한 것이어서 당연무효라는 주장 속에 강박을 이유로 취소한다는 주장이 당연히 포함되어 있다고 볼 수는 없다.','대판(무효·취소 주장)',1,false),
(700,1,'제203조','제1편 총칙','O','상한을 표시하지 않고 일정액 초과 채무의 부존재확인을 구하는 사건에서 그 초과 채무의 존재가 일부 인정되면, 법원은 청구 전부를 기각할 것이 아니라 존재가 인정되는 부분에 한하여 청구를 기각(나머지는 부존재 확인 인용)하여야 한다.','대판(채무부존재확인 일부인용)',2,false),
(701,1,'제203조','제1편 총칙','O','변론주의는 주요사실에 대하여서만 인정되고, 주요사실의 존부를 추인케 하는 간접사실에 대하여는 적용이 없다.','대판(간접사실 변론주의)',1,false),
(702,1,'제203조','제1편 총칙','O','당사자가 주장하지 않은 사실을 기초로 법원이 판단할 수는 없지만, 청구의 객관적 실체가 동일하다고 보이는 한 청구원인으로 주장된 실체적 권리관계에 대한 정당한 법률해석에 의하여 판결할 수 있다.','대판(법률해석)',1,false),
(703,1,'제203조','제1편 총칙','O','사실인 관습은 일상생활의 경험칙에 속하므로, 그 유무를 판단함에는 당사자의 주장·입증에 구애됨이 없이 법관 스스로 직권으로 판단할 수 있다.','대판(사실인 관습)',1,false),
(704,1,'제203조','제1편 총칙','O','법원의 심판 한계는 소송물에 한하므로, 그 소송물과 다른 소송물이나 소송물의 범위를 벗어난 사항에 대하여는 심판할 수 없다.','대판(처분권주의)',1,false),
(705,1,'제203조','제1편 총칙','O','형식적 형성의 소(공유물분할·경계확정 등)에는 처분권주의가 적용되지 않는다.','대판(형식적 형성의 소)',1,false),
(706,1,'제203조','제1편 총칙','O','손해배상소송에서 적극적 손해·소극적 손해·위자료 각 항목의 청구액을 초과하여 인용하는 것은 허용되지 않으며, 일부 항목 청구액을 초과 인용하였으나 청구총액을 벗어나지 않는 경우에도 처분권주의를 위배한 것이다.','대판(손해 3분설)',1,false),
(707,1,'제203조','제1편 총칙','O','이자청구소송의 소송물은 원금·이율·기간으로 정해지므로, 원고가 주장하는 원금·이율·기간 중 어느 하나라도 그 기준을 초과하여 인용하면 인용 이자액이 원고가 구하는 범위 내라도 처분권주의에 위반된다.','대판(이자청구)',1,true),
(708,1,'제203조','제1편 총칙','O','채권자취소소송에서 사해행위를 전부 취소하고 원상회복을 구하는 채권자의 주장 속에는 사해행위를 일부 취소하고 가액배상을 구하는 취지도 포함되어 있으므로, 채권자가 원상회복만을 구하는 경우에도 법원은 가액의 배상을 명할 수 있다.','대판(가액배상)',1,true),
(709,1,'제203조','제1편 총칙','O','주요사실은 법률효과를 발생시키는 법규의 직접 요건에 해당하는 사실로서, 당사자가 자기에게 유리한 주요사실을 변론에서 진술하지 않으면 그 사실이 존재하지 않는 것으로 취급되는 불이익을 받는다.','대판(변론주의)',1,false),
(710,1,'제203조','제1편 총칙','O','법원은 취득시효에서 점유개시의 시기(간접사실)에 관하여 당사자의 주장과 다르게 인정할 수 있다.','대판(취득시효 기산점)',1,false),
(711,1,'제203조','제1편 총칙','O','대리행위는 주요사실이므로 법원은 변론에서 당사자가 주장하지 않은 이상 이를 인정할 수 없다.','대판(대리 주요사실)',1,false),
(712,1,'제203조','제1편 총칙','O','소멸시효의 기산일은 변론주의의 적용 대상이므로, 당사자가 자백한 기산일과 다른 날짜를 기준으로 소멸시효를 계산할 수 없다.','대판(소멸시효 기산일 변론주의)',1,false),
(713,1,'제203조','제1편 총칙','O','적극손해 100·소극손해 50·위자료 30을 청구하였는데 법원이 적극손해 80·소극손해 60·위자료 20을 인용하는 것은(소극손해가 청구액 50을 초과하므로) 허용되지 않는다.','대판(손해 3분설)',1,false),
(714,1,'제203조','제1편 총칙','O','원고가 단순이행청구를 하고 있는데 피고의 동시이행항변이 이유 있는 경우, 법원이 상환이행판결을 하는 것은 허용된다.','대판(상환이행)',1,false),
(715,1,'제203조','제1편 총칙','O','공유물분할의 소는 형식적 형성의 소이므로 원고가 현물분할을 청구하더라도 법원은 경매에 의한 가격분할을 명할 수 있다.','대판(공유물분할 형식적 형성)',1,false),
(716,1,'제203조','제1편 총칙','O','100만 원의 대여금청구에서 40만 원의 대여사실만 인정되는 경우, 원고가 청구취지를 변경하지 않더라도 40만 원의 지급을 명하는 판결을 할 수 있다(일부 인용).','대판(일부 인용)',1,false),
(717,1,'제203조','제1편 총칙','O','기본사실의 경위·내력 등에 관한 사실은 간접사실로서 변론주의가 적용되는 주요사실이 아니다.','대판(간접사실)',2,false),
(718,1,'제203조','제1편 총칙','O','소멸시효의 기산일은 변론주의가 적용되는 주요사실에 해당한다.','대판(소멸시효 기산일)',1,false),
(719,1,'제203조','제1편 총칙','O','취득시효의 기산점은 간접사실이므로 변론주의가 적용되지 않고 법원이 당사자 주장과 다르게 인정할 수 있다.','대판(취득시효 기산점)',1,false),
(720,1,'제203조','제1편 총칙','O','주요사실(요건사실)은 법률효과가 생기는 요건으로 각 실체법규에 규정되어 있는 것에 해당하는 구체적 사실을 말한다.','통설',1,false),
(721,1,'제203조','제1편 총칙','O','간접사실은 변론에서 당사자의 주장이 없어도 증거로써 이를 인정할 수 있다.','대판(간접사실)',1,false),
(722,1,'제203조','제1편 총칙','O','주요사실이 증명의 목표이고, 간접사실은 주요사실을 추인하게 하는 수단으로서 증거와 같은 작용을 한다.','통설',1,false),
(723,1,'제203조','제1편 총칙','O','변론주의는 주요사실에만 적용되고 간접사실·보조사실에는 적용되지 않는다.','대판(변론주의)',1,false),
(724,1,'제204조','제1편 총칙','O','당사자가 법관 면전에서 말로 변론하여야 한다는 것은 구술주의이고, 직접주의는 변론·증거조사를 판결하는 법관이 직접 행하여야 한다는 원칙이다.','민소 §204·§134',1,false),
(725,1,'제204조','제1편 총칙','O','환송 후 항소심에서 법관 구성이 바뀐 경우에는 변론의 갱신절차를 거쳐야 한다.','대판(환송 후 변론갱신)',1,false),
(726,1,'제204조','제1편 총칙','O','직접심리주의는 현행 민사소송법이 채택하고 있는 변론에 관한 원칙이다.','통설',1,false),
(727,1,'제204조','제1편 총칙','O','법관이 바뀐 경우에 당사자는 종전의 변론결과를 진술하여야 하나(변론갱신), 소액사건의 경우에는 그러하지 아니하다.','소액사건심판법',1,false),
(728,1,'제207조','제1편 총칙','O','판결은 선고로 효력이 생기고, 당사자가 출석하지 않거나 소송절차가 중단되어 있더라도 선고할 수 있다.','민소 §207②',1,false),
(729,1,'제207조','제1편 총칙','O','변론종결 시 판결선고기일을 고지한 경우 재정하지 않은 당사자에게도 그 효력이 미치고, 별도로 선고기일 소환장을 송달하지 않아도 위법하지 않다(판결은 당사자 불출석 중에도 선고할 수 있다).','판례',1,false),
(730,1,'제208조','제1편 총칙','O','소액사건의 판결서에는 이유를 기재하지 아니하거나 이유의 요지만을 적을 수 있다(소액사건심판법 §11의2).','소액사건심판법 §11의2',1,false),
(731,1,'제208조','제1편 총칙','O','원고의 청구가 인용될 때에는 판결이유에 피고가 증여받았다는 주장을 배척하는 판단을 따로 할 필요는 없다.','대판(부인 판단)',1,false),
(732,1,'제208조','제1편 총칙','O','원고의 청구를 인용할 때 피고의 부인에 대하여는 별도로 배척하는 판단을 명시할 필요가 없다.','대판(부인 판단)',1,false),
(733,1,'제208조','제1편 총칙','O','판결서에는 법관의 서명날인을 요하지만, 결정·명령의 경우에는 서명날인을 기명날인으로 갈음할 수 있다.','민소 §208④',1,false),
(734,1,'제210조','제1편 총칙','O','판결·화해권고결정·조정에 갈음하는 결정 등은 그 정본을 송달한다(등본이 아니다).','민소 §210①',1,false),
(735,1,'제210조','제1편 총칙','O','판결은 그 정본을 송달한다(원본이 아니다).','민소 §210',1,false),
(736,1,'제211조','제1편 총칙','O','판결경정은 그 판결을 한 법원이 하는 것이고, 기록이 우연히 상소심에 있다 하여 상소심이 심판대상이 아닌 부분의 판결을 경정할 권한을 가지는 것은 아니다.','민소 §211',2,false),
(737,1,'제211조','제1편 총칙','O','판결경정결정을 함에 있어서는 소송 전 과정에 나타난 자료는 물론 경정대상 판결 이후에 제출된 자료도, 다른 당사자에게 불이익이 없거나 이를 다툴 기회가 있었던 경우에는 소송경제상 참작할 수 있다.','판례',2,false),
(738,1,'제211조','제1편 총칙','O','판결의 경정은 법원이 직권으로 또는 당사자의 신청에 따라 결정으로 할 수 있다.','민소 §211①',1,false),
(739,1,'제211조','제1편 총칙','O','판결경정은 위산·오기 등 표현상 명백한 오류이면 그 잘못의 원인이 당사자에게 있는 경우에도 할 수 있다.','판례',1,false),
(740,1,'제211조','제1편 총칙','O','경정결정에 대하여는 즉시항고를 할 수 있으나, 판결에 대하여 적법한 항소가 있는 때에는 즉시항고를 할 수 없다.','민소 §211③',1,false),
(741,1,'제211조','제1편 총칙','O','채권가압류결정의 경정이 그 동일성에 실질적 변경을 가하는 경우에는 소급효가 인정되지 않는다(경정결정의 효력은 소급하지 않는다).','판례',1,false),
(742,1,'제211조','제1편 총칙','O','판결이 경정되면 당초의 원판결과 일체가 되어 처음부터 경정된 내용의 판결이 있었던 것과 같은 효력이 있으므로, 불이익변경금지의 원칙은 경정된 판결을 기준으로 적용된다.','판례',1,false),
(743,1,'제211조','제1편 총칙','O','청구취지에서 누락된 원금 부분을 판결경정으로 추가하는 것은 경정의 한계를 벗어나는 것으로서 허용되지 않는다.','판례',1,false),
(744,1,'제211조','제1편 총칙','O','화해조서에 잘못된 계산이나 기재, 그 밖에 이와 비슷한 잘못이 있음이 분명한 때에는, 법원은 직권으로 또는 당사자의 신청에 따라 경정결정을 할 수 있다.','민소 §211',1,false),
(745,1,'제211조','제1편 총칙','O','판결경정 사유인 잘못이 분명한지 여부는 판결서의 기재뿐만 아니라 소송기록 전체와 대비하여 판단할 수 있다.','대판(경정 명백성)',2,false),
(746,1,'제211조','제1편 총칙','O','소유권이전등기이행을 명하는 판결에서 피고의 등기부상 주소를 기재하지 않은 것은 판결경정 사유가 아니라는 것이 판례이다.','대판(등기부상 주소)',1,false),
(747,1,'제211조','제1편 총칙','O','판결경정은 판결 주문에 대하여도 허용된다(주문·이유를 불문한다).','대판(경정 대상)',1,false),
(748,1,'제211조','제1편 총칙','O','판결경정신청을 기각한 결정에 대하여는 통상항고를 할 수 없고, 특별항고에 의할 수 있을 뿐이다.','판례',3,false),
(749,1,'제211조','제1편 총칙','O','판결경정이 가능한 오류에는 법원의 과실로 생긴 경우는 물론, 당사자의 청구에 잘못이 있어 생긴 경우도 포함된다.','대판(경정 원인불문)',1,false),
(750,1,'제211조','제1편 총칙','O','경정신청 기각결정에 대하여는 즉시항고를 할 수 없고 특별항고만 허용된다.','대판(경정 기각 특별항고)',1,false),
(751,1,'제211조','제1편 총칙','O','경정결정은 판결의 원본과 정본에 덧붙여 적어야 하나, 정본에 덧붙여 적을 수 없을 때에는 결정의 정본을 작성하여 당사자에게 송달하여야 한다.','민소 §211②',1,false),
(752,1,'제211조','제1편 총칙','O','상소로 기록이 상급법원에 송부된 경우에는 상급법원도 제1심 판결을 경정할 수 있다.','대판(경정 관할)',1,false),
(753,1,'제211조','제1편 총칙','O','판결경정 결정은 원판결과 일체가 되어 그 효력이 판결 선고시로 소급한다.','대판(경정 효력)',1,false),
(754,1,'제211조','제1편 총칙','O','경정 대상인 판결 이후에 제출된 자료나 집행과정에서 밝혀진 사실에 기초하여서도 판결경정을 할 수 있다.','대판(경정 자료)',1,false),
(755,1,'제211조','제1편 총칙','O','판결경정은 판결 주문의 기재부분에 대하여도 할 수 있다.','대판(경정 대상)',1,false),
(756,1,'제212조','제1편 총칙','O','예비적 청구에 대한 판단누락은 재판의 누락이 아니라 위법한 전부판결이므로, 상소가 제기되면 예비적 청구 부분도 상소심으로 이심되고 추가판결의 대상이 아니다.','대판(전합) 98다22253',1,false),
(757,1,'제212조','제1편 총칙','O','1심이 청구의 일부에 대한 판단을 누락한 경우 그 부분은 재판의 누락으로서 여전히 제1심에 계속되므로 추가판결의 대상이 되고, 항소로 항소심의 심판대상이 되는 것은 아니다.','판례',1,false),
(758,1,'제212조','제1편 총칙','O','재판의 누락 여부는 판결 주문의 기재를 기준으로 판단하므로, 판결이유에 판단이 있더라도 주문에 기재가 없으면 재판의 누락에 해당한다.','대판(재판누락 기준)',1,false),
(759,1,'제212조','제1편 총칙','O','원고가 2개의 청구를 단순병합하여 청구하였는데 항소심이 그 중 하나의 청구에 대하여 재판을 누락한 경우, 그 누락된 부분에 대한 상고는 부적법하다.','대판(재판누락 상고)',1,false),
(760,1,'제212조','제1편 총칙','O','재판의 누락이 있어 추가판결이 이루어진 경우, 추가판결과 전의 판결은 각각 별개의 판결로서 상소기간도 개별적으로 진행한다.','대판(추가판결)',1,false),
(761,1,'제212조','제1편 총칙','O','소송비용의 재판을 누락한 경우 법원은 직권·신청으로 그에 대한 재판을 하여야 하나, 종국판결에 대하여 적법한 항소가 있는 때에는 그 결정은 효력을 잃고 항소심이 소송 총비용에 대하여 재판한다.','민소 §212·§104',1,false),
(762,1,'제213조','제1편 총칙','O','당사자가 이혼이 성립하기 전에 이혼소송과 병합하여 재산분할청구를 하고 법원이 이혼과 동시에 재산분할을 명하는 판결을 하는 경우, 이혼판결이 확정되지 않은 상태이므로 그 시점에서 재산분할에 가집행을 허용할 수 없다.','판례',1,false),
(763,1,'제213조','제1편 총칙','O','재산권의 청구에 관한 판결이라도 의사의 진술을 명한 판결은 확정되어야만 집행력이 생기므로 가집행선고를 할 수 없다.','민소 §213①단서',1,false),
(764,1,'제213조','제1편 총칙','O','가집행선고 있는 판결은 선고에 의하여 즉시 집행력이 발생하므로, 이행판결이면 바로 집행권원이 된다.','민소 §213',1,false),
(765,1,'제213조','제1편 총칙','O','가집행선고 있는 판결로 재산명시신청은 할 수 있으나, 채무불이행자명부 등재신청은 금전지급 집행권원이 ''확정''된 후에 할 수 있으므로 가집행선고만으로는 할 수 없다.','민집 §61·§70',1,false),
(766,1,'제213조','제1편 총칙','O','가집행의 면제선고는 직권이 아니라 당사자(피고)의 신청에 의하여 할 수 있다.','민소 §213③',1,false),
(767,1,'제213조','제1편 총칙','O','법원이 이혼과 동시에 재산분할을 명하는 판결을 하는 경우 가집행선고를 허용할 수 없다는 것이 판례의 태도이다.','대판(재산분할 가집행)',1,false),
(768,1,'제213조','제1편 총칙','O','가집행선고는 재산권의 청구에 관한 이행판결에 붙일 수 있고, 확인판결·형성판결에는 원칙적으로 붙일 수 없다.','대판(가집행선고 대상)',1,false),
(769,1,'제213조','제1편 총칙','O','법원은 직권으로 가집행선고를 하여야 하며, 다만 상소법원은 불복신청이 없는 부분에 대하여는 당사자의 신청에 따라 결정으로 가집행선고를 할 수 있다.','민소 §213①·④',1,false),
(770,1,'제213조','제1편 총칙','O','가집행선고는 담보를 제공하거나 제공하지 아니할 것을 조건으로 할 수 있으나, 어음금·수표금 청구에 관한 판결에는 담보를 제공하게 하지 않아야 한다.','민소 §213①단서',1,false),
(771,1,'제215조','제1편 총칙','O','가지급물 반환신청의 법적 성질은 예비적 반소에 해당한다.','대판 96다5001',1,false),
(772,1,'제215조','제1편 총칙','O','가집행에 의한 금원의 추심은 확정적 변제가 아니므로 기본채권에 대한 변제의 효과가 발생하지 않는다(상소심에서 본안판결이 바뀌면 실효된다).','판례',1,false),
(773,1,'제215조','제1편 총칙','O','가집행의 선고는 그 선고 또는 본안판결을 바꾸는 판결의 선고로 바뀌는 한도에서 그 효력을 잃는다.','민소 §215①',1,false),
(774,1,'제215조','제1편 총칙','O','제1심에서 가집행선고부 패소판결을 받고 항소한 당사자가 항소심에서 가지급물반환신청을 하지 않고 제1심 본안판결을 바꾸는 판결을 선고받아 상대방이 상고한 경우, 상고심에서는 그 가지급물반환신청을 하지 못한다.','판례',1,false),
(775,1,'제215조','제1편 총칙','O','가지급물반환 신청은 소송 중의 소의 일종으로 그 성질이 예비적 반소이므로, 가집행선고부 제1심판결에 대하여 피고가 항소하였다가 항소가 기각된 경우 항소심이 별도로 가지급물반환 신청에 대한 판단을 하지 아니한 것은 적법하다.','대판(가지급물반환)',1,false),
(776,1,'제215조','제1편 총칙','O','가집행선고의 실효로 인한 원상회복 및 손해배상책임은 무과실책임이다.','대판(가집행 실효 원상회복)',1,false),
(777,1,'제215조','제1편 총칙','O','본안판결의 취소·변경으로 가집행선고가 실효된 경우, 가집행채권자는 고의·과실 유무에 불구하고 가집행으로 인한 손해를 배상할 책임이 있다(무과실책임).','대판(가집행 실효 배상)',1,false),
(778,1,'제215조','제1편 총칙','O','가집행선고로 인한 지급물의 반환신청은 사실관계에 다툼이 없어 사실심리를 요하지 아니하는 경우를 제외하고는 상고심에서는 원칙적으로 허용되지 않는다.','대판(가지급물 반환신청)',1,false),
(779,1,'제216조','제1편 총칙','O','확정판결은 주문에 포함된 것에 한하여 기판력을 가지고 판결이유 중의 판단에는 원칙적으로 기판력이 미치지 않으나, 상계를 주장한 청구의 성립 여부 판단은 예외적으로 상계로 대항한 액수에 한하여 기판력을 가진다.','민소 §216①',2,false),
(780,1,'제216조','제1편 총칙','O','소유권확인청구 판결이 확정된 후 동일 피고를 상대로 소유권에 기한 물권적 청구권을 청구원인으로 하는 소송을 제기한 경우, 전소 확정판결의 소유권 존부 판단에 구속되어 당사자·법원 모두 이와 다른 주장·판단을 할 수 없다.','판례',2,false),
(781,1,'제216조','제1편 총칙','O','확정판결의 기판력은 전소의 변론종결 전에 당사자가 주장하였거나 주장할 수 있었던 모든 공격방어방법에 미친다.','판례(차단효)',1,false),
(782,1,'제216조','제1편 총칙','O','나머지 부분 유보를 명시하지 않은 일부 청구에서 전부 승소한 채권자는, 나머지 부분에 기판력이 미쳐 청구확장을 위한 항소의 이익이 없다.','판례',1,false),
(783,1,'제216조','제1편 총칙','O','(시효중단을 위한 후소에서 전소 판결의 기판력·다투는 방법에 관한 부분으로 정답(틀린 지문)일 가능성이 높음 — 판례 재확인 필요).','대판(전합) 2015다232316 관련',1,true),
(784,1,'제216조','제1편 총칙','O','승소한 당사자는 판결이유 중의 판단에 불만이 있어도 상소의 이익이 없으나, 예비적 상계항변이 이유 있다 하여 승소한 피고는 상소의 이익이 있다.','판례',1,false),
(785,1,'제216조','제1편 총칙','O','대여금 일부를 변제받고도 전액으로 승소 확정판결을 받아 강제집행으로 수령한 채권자에 대하여, 그 확정판결이 재심 등으로 취소되지 않는 한 강제집행으로 교부받은 금원을 부당이득이라 할 수 없다.','대판 94다41430',1,false),
(786,1,'제216조','제1편 총칙','O','전소와 후소는 변제 조건 등 청구원인을 달리하여 소송물이 동일하지 않으므로, 후소가 전소 확정판결의 기판력에 저촉된다고 볼 수 없다.','판례',1,false),
(787,1,'제216조','제1편 총칙','O','가등기에 기한 소유권이전등기절차 이행을 명한 전소 확정판결이 있은 후 그 가등기만의 말소를 청구하는 것은 전소 확정판결의 기판력에 저촉된다고 볼 수 없다.','판례',1,false),
(788,1,'제216조','제1편 총칙','O','확정판결의 존부는 직권조사사항이므로, 당사자가 사실심에서 주장하지 않았더라도 상고심에서 새로이 주장·증명할 수 있다.','판례',2,false),
(789,1,'제216조','제1편 총칙','O','소송상 상계항변에 대하여 다시 소송상 상계의 재항변을 하는 것은 다른 특별한 사정이 없는 한 허용되지 않는다.','대판(상계 재항변)',1,false),
(790,1,'제216조','제1편 총칙','O','상계항변이 반대채권 부존재로 배척된 경우에도 민소 §216②에 의하여 그 반대채권의 부존재에 대하여 대항한 액수에 한하여 기판력이 생긴다.','민소 §216②',1,false),
(791,1,'제216조','제1편 총칙','O','대여금청구에 피고가 상계항변을 하여 제1심이 이를 받아들여 원고 청구를 전부기각한 경우, 피고는 반대채권이 상계로 소멸하므로 항소의 이익이 있다.','대판(상계 인용 청구기각 항소이익)',1,false),
(792,1,'제216조','제1편 총칙','O','조정 성립으로 수동채권의 존재에 관한 법원의 실질적 판단이 이루어지지 않은 경우에는, 그 소송절차에서 한 소송상 상계항변의 사법상 효과도 발생하지 않는다.','대판 2013다95964',1,false),
(793,1,'제216조','제1편 총칙','O','원고가 10억 원의 대여금 중 1억 원만 청구한다는 취지를 명시하여 승소한 뒤 다시 9억 원을 청구하는 소를 제기하는 것도 가능하다(명시적 일부청구).','대판(명시적 일부청구)',1,false),
(794,1,'제216조','제1편 총칙','O','말소등기청구와 진정명의회복을 위한 이전등기청구는 실질적으로 동일한 소송물이므로, 말소청구 패소 확정판결의 기판력은 진정명의회복 이전등기청구에도 미친다.','대판(전합) 2001다63516',2,false),
(795,1,'제216조','제1편 총칙','O','적극적 손해(치료비)와 정신적 손해(위자료)는 소송물이 별개이므로, 치료비청구 패소 후 위자료청구는 기판력에 반하지 않는다.','대판(손해 3분설)',1,false),
(796,1,'제216조','제1편 총칙','O','매매계약 무효를 원인으로 한 말소등기청구와 매매계약 해제를 원인으로 하는 말소등기청구는 소송물이 동일하다.','대판(말소등기 소송물)',1,false),
(797,1,'제216조','제1편 총칙','O','말소등기청구 기각 확정판결의 기판력은 소송물을 달리하는 소유권확인청구에는 미치지 않으므로, 그 소유권확인의 소가 부적법한 것은 아니다.','대판(말소 기각 후 소유권확인)',1,false),
(798,1,'제216조','제1편 총칙','O','소유권이전등기말소청구소송에서 패소확정판결을 받았다면 그 기판력은 그 후 제기된 진정명의회복을 원인으로 한 소유권이전등기청구소송에도 미친다.','대판(전합) 2001다63516',1,false),
(799,1,'제216조','제1편 총칙','O','확정 승소판결에는 기판력이 있어 동일 청구의 후소는 권리보호이익이 없어 부적법하나, 예외적으로 확정판결에 의한 채권의 소멸시효기간 10년의 경과가 임박한 경우에는 그 시효중단을 위한 소는 소의 이익이 있다.','대판(시효중단 재소)',1,false),
(800,1,'제216조','제1편 총칙','O','소구채권 자체를 부정하여 청구를 기각한 판결과 소구채권의 존재를 인정하면서 상계항변을 받아들여 청구를 기각한 판결은 기판력의 범위를 달리하므로, 후자의 판결에 대하여 피고는 상소의 이익이 있다.','판례',3,false);
insert into atoms(id,subject_id,article_no,pyeon,ans,statement,ref,freq,verified) values
(801,1,'제216조','제1편 총칙','O','패소 확정판결을 받은 당사자가 동일 청구의 후소를 제기한 경우, 후소 법원은 전소 확정판결과 모순되는 판단을 할 수 없으므로 소를 각하할 것이 아니라 청구기각 판결을 하여야 한다.','대판 99다25785',1,false),
(802,1,'제216조','제1편 총칙','O','소송요건의 흠결을 이유로 소를 각하하는 판결은 그 판결에서 확정한 소송요건의 흠결에 관하여 기판력이 발생한다.','대판(소각하 기판력)',1,false),
(803,1,'제216조','제1편 총칙','O','확정판결의 효력은 표준시인 사실심 변론종결시를 기준으로 발생하므로, 그 이후에 새로운 사유가 발생한 경우까지 전소 확정판결의 기판력이 미치는 것은 아니다.','대판(표준시)',1,false),
(804,1,'제216조','제1편 총칙','O','일시금으로 손해배상을 명한 확정판결 후 피해자가 기대여명보다 일찍 사망하였더라도, 전소 피고가 지급된 배상금 일부의 부당이득 반환을 구하는 것은 전소 확정판결의 기판력에 저촉되어 허용되지 않는다.','대판(기대여명 조기사망)',1,false),
(805,1,'제216조','제1편 총칙','O','전소판결과 저촉되는 후소판결이 확정된 경우, 후소판결이 재심으로 취소되지 않는 한 후소판결이 효력을 가지는 것이고, 전소의 기판력이 차단되는 것은 아니다.','대판(모순된 확정판결)',1,false),
(806,1,'제216조','제1편 총칙','O','인낙조서의 기판력은 그 소송물(대금반환청구권)에만 미치고 선결관계인 매매계약의 효력에는 미치지 않으므로, 매매 유효를 전제로 한 이전등기청구가 인낙조서의 기판력에 저촉되는 것은 아니다.','대판(인낙조서 기판력)',1,false),
(807,1,'제216조','제1편 총칙','O','상계 주장의 대상이 된 수동채권이 동시이행항변으로 행사된 채권일 경우에는, 그 상계 주장에 대한 판단에는 기판력이 발생하지 않는다.','대판(동시이행 상계 기판력)',1,false),
(808,1,'제216조','제1편 총칙','O','시효중단 등 특별한 사정으로 예외적으로 확정 승소판결과 동일 소송물의 신소가 허용되는 경우라도 신소 판결이 전소 승소확정판결 내용에 저촉되어서는 안 되므로, 후소 법원은 확정된 권리를 주장할 수 있는 요건이 구비되었는지를 다시 심리할 수 없다.','대판(시효중단 재소 저촉)',2,false),
(809,1,'제216조','제1편 총칙','O','별소로 계속 중인 채권을 자동채권으로 하는 소송상 상계의 주장도 (중복제소금지에 반하지 않아) 허용된다.','대판(별소 채권 상계)',2,false),
(810,1,'제216조','제1편 총칙','O','소송판결의 기판력은 그 판결에서 확정한 소송요건의 흠결에 관하여 미치지만, 당사자가 그 소송요건의 흠결을 보완하여 다시 소를 제기한 경우에는 그 기판력의 제한을 받지 않는다.','대판(소송판결 기판력)',1,false),
(811,1,'제216조','제1편 총칙','O','부당이득반환청구권과 불법행위로 인한 손해배상청구권은 소송물을 달리하므로, 어느 하나의 청구권에 관한 소를 제기하여 승소 확정판결을 받았더라도 아직 채권의 만족을 얻지 못한 경우에는 다른 청구권에 관한 이행의 소를 제기할 수 있다.','대판(청구권경합 소송물)',1,false),
(812,1,'제216조','제1편 총칙','O','불법행위로 인한 적극적 손해의 배상을 명한 전소의 변론종결 후에 새로운 적극적 손해가 발생한 경우, 전소 변론종결 당시 그 손해 발생을 예견할 수 없었고 그 부분 청구를 포기하였다고 볼 수 없는 등 특별한 사정이 있다면 그 부분 손해배상청구는 전소와 별개의 소송물이다.','대판(후발손해)',1,false),
(813,1,'제216조','제1편 총칙','O','1필지 토지 전부에 대한 이전등기청구에서 토지 일부 매수사실은 인정되나 특정할 수 없다는 이유로 전부패소 확정된 후 매수 부분을 특정하여 이전등기를 구하는 경우, 그 특정 부분 매수 여부에 관하여는 전소의 기판력이 미치지 아니한다.','대판(특정불능 패소)',1,false),
(814,1,'제216조','제1편 총칙','O','기판력의 차단효(실권효)는 당사자가 변론종결시까지 제출할 수 있었던 공격방어방법 전부에 미치므로, 그것을 알지 못한 데 과실이 없었더라도 차단되어 후소에서 주장할 수 없다.','대판(기판력 실권효)',1,false),
(815,1,'제216조','제1편 총칙','O','임료 상당 부당이득 승소 확정 후 임료가 상당하지 않게 되는 등 특별한 사정이 발생한 경우, 차액 상당 부당이득금 반환을 구하는 후소에는 전소판결의 기판력이 미치지 않는다.','대판(부당이득 사정변경)',1,false),
(816,1,'제216조','제1편 총칙','O','명시적 일부청구로 4,000만 원에 대하여 승소한 후 나머지 6,000만 원을 청구하는 잔부청구에는 전소판결의 기판력이 미치지 않는다.','대판(명시적 일부청구)',1,false),
(817,1,'제216조','제1편 총칙','O','말소등기청구 패소(소유권 부정) 확정 후 소유권확인 후소는 소송물이 달라 전소판결의 기판력이 미치지 않는다.','대판(말소→소유권확인)',1,false),
(818,1,'제216조','제1편 총칙','O','소유권이전등기말소소송에서 소유권이 없다는 이유로 패소판결을 받은 후, 동일 피고를 상대로 진정명의회복을 위한 소유권이전등기의 후소를 제기한 경우에는 전소판결의 기판력이 미친다.','대판(전합) 2001다63516',1,false),
(819,1,'제216조','제1편 총칙','O','취소권을 소송 중에 행사하지 않아 취소권자에게 불리하게 판결이 확정된 경우, 그 확정 후 취소권을 행사하여 판결확정의 효력을 부인할 수 없다.','대판(실권효)',1,false),
(820,1,'제216조','제1편 총칙','O','백지어음 소지인이 어음금 청구소송의 사실심 변론종결일까지 백지 부분을 보충하지 않아 패소확정된 경우, 그 후 백지보충권을 행사하여 완성한 어음으로 동일 어음금을 다시 청구할 수 없다.','대판(백지어음 실권)',1,false),
(821,1,'제216조','제1편 총칙','O','건물매수청구권은 형성권으로서 전소에서 행사하지 않아 패소확정되었더라도 실권되지 않으므로, 그 후 별소로 건물매수청구권을 행사하여 건물매매대금의 지급을 구할 수 있다.','대판(전합) 94다34265',1,false),
(822,1,'제216조','제1편 총칙','O','확정판결의 변론종결 전에 상계적상에 있는 채권을 가지고 있었으나 상계의 의사표시는 변론종결 후에 한 경우, 이는 적법한 청구이의 사유가 된다.','대판(상계 청구이의)',2,false),
(823,1,'제216조','제1편 총칙','O','소송요건의 흠결을 이유로 소각하판결이 선고되어 확정되더라도, 그 흠결을 보완하여 다시 소를 제기하면 기판력의 저촉 문제는 생기지 않는다.','대판(소각하 기판력)',1,false),
(824,1,'제216조','제1편 총칙','O','100만 원을 청구함에 대하여 200만 원의 반대채권으로 상계항변한 경우, 상계항변이 인용되든 배척되든 자동채권에 관한 판단의 기판력은 100만 원(대항한 액수)에 한정된다.','민소 §216②',1,false),
(825,1,'제216조','제1편 총칙','O','상속인을 상대로 한 금전지급청구 승소판결 확정 후, 상속인이 변론종결 전의 상속포기를 주장하는 것은 기판력에 저촉되나, 변론종결 전의 한정승인을 주장하는 것은 (책임범위에 관한 것이어서) 기판력에 저촉되지 않는다.','대판(한정승인·상속포기)',1,false),
(826,1,'제216조','제1편 총칙','O','어음채권에 기한 청구와 원인채권에 기한 청구는 별개의 소송물이다.','대판(어음·원인채권)',1,false),
(827,1,'제216조','제1편 총칙','O','소유권이전등기 말소등기청구의 청구원인은 등기원인의 무효에 국한되고, 개개의 무효원인은 공격방법의 차이에 지나지 않는다.','대판(말소등기 소송물)',1,false),
(828,1,'제216조','제1편 총칙','O','취소권·해제권 등은 변론종결 전 행사하지 않으면 실권효를 받지만, 상계권은 변론종결 후 행사하더라도 기판력의 실권효를 받지 않아 청구이의 사유가 된다.','대판(상계권 실권 예외)',1,false),
(829,1,'제216조','제1편 총칙','O','전 소송에서 일부청구임을 명시한 경우에는 후소의 잔부청구가 기판력에 저촉되지 않는다.','대판(명시적 일부청구)',1,false),
(830,1,'제216조','제1편 총칙','O','민사판결의 이유에서 확정한 사실관계는 후소에서 동일한 사실관계가 문제될 경우 유력한 증거가 되므로, 합리적 이유의 설시 없이 이를 배척할 수 없다.','대판(판결이유 증명력)',1,false),
(831,1,'제216조','제1편 총칙','O','전소에서 정지조건 미성취를 이유로 청구가 기각되었더라도 변론종결 후에 그 조건이 성취되었다면, 동일한 청구에 대하여 다시 소를 제기할 수 있다.','대판(조건 성취 새 사유)',1,false),
(832,1,'제216조','제1편 총칙','O','매매를 원인으로 하는 이전등기청구와 취득시효 완성을 원인으로 하는 이전등기청구는 등기청구권의 발생원인이 달라 별개의 소송물이다.','대판(이전등기 소송물)',1,false),
(833,1,'제216조','제1편 총칙','O','기망으로 인한 매매계약 취소를 원인으로 하는 소유권이전등기말소청구와 매매계약 부존재를 원인으로 하는 소유권이전등기말소청구는 소송물이 동일하다(말소등기청구의 소송물은 등기원인 무효이고 개개의 무효원인은 공격방법에 불과).','대판(말소등기 소송물)',1,false),
(834,1,'제216조','제1편 총칙','O','채무불이행책임에 기한 손해배상청구와 불법행위책임에 기한 손해배상청구는 청구권경합으로서 별개의 소송물이다.','대판(청구권경합)',1,false),
(835,1,'제216조','제1편 총칙','O','예비적 상계의 항변이 이유 있다 하여 승소한 피고는 (반대채권 소멸에 기판력이 생기므로) 상소의 이익이 있다.','대판(상계 승소 피고)',1,false),
(836,1,'제216조','제1편 총칙','O','상계를 주장한 청구가 성립되는지 아닌지의 판단은 상계하자고 대항한 액수에 한하여 기판력을 가진다.','민소 §216②',2,false),
(837,1,'제216조','제1편 총칙','O','소유권이전등기말소청구소송의 소송물과 진정명의회복을 원인으로 한 소유권이전등기청구소송의 소송물은 실질상 동일하다.','대판(전합) 2001다4101',1,false),
(838,1,'제216조','제1편 총칙','O','소유권이전등기청구에서 등기원인(매매·취득시효 등)이 다르면 각각 별개의 소송물이고 단순한 공격방어방법이 아니다.','대판(이전등기 소송물)',1,false),
(839,1,'제216조','제1편 총칙','O','말소등기청구의 소송물은 등기의 말소청구권이고, 무효원인을 달리하는 것은 공격방어방법의 차이일 뿐 별개의 소송물이 아니다.','대판(말소등기 소송물)',1,false),
(840,1,'제216조','제1편 총칙','O','사실심 변론종결 후에 새로 발생한 사실을 주장하는 것은 기판력의 시적 범위 밖이므로 기판력에 저촉되지 않는다.','대판(변론종결 후 사유)',1,false),
(841,1,'제217조','제1편 총칙','O','상호보증은 조약 체결을 요하지 않고, 당해 외국이 우리 동종 판결을 승인할 것으로 기대할 수 있으면 충분하다.','대판(상호보증)',1,false),
(842,1,'제217조','제1편 총칙','O','외국재판의 승인이 사회질서에 어긋나는지는 그 승인 여부를 판단하는 시점을 기준으로 판단한다.','대판(승인 기준시점)',1,false),
(843,1,'제217조','제1편 총칙','O','판결국에서 피고에게 방어할 기회를 부여하기 위하여 규정한 송달의 방식·절차를 따르지 아니한 경우에는 민소 §217①2호에서 말하는 적법한 방식에 따른 송달이 이루어졌다고 할 수 없다.','대판(송달요건)',1,false),
(844,1,'제217조','제1편 총칙','O','외국재판 승인 결과가 선량한 풍속·사회질서에 어긋나는지는 승인 여부를 판단하는 시점에서, 그 승인이 국내 법질서가 보호하려는 기본 도덕·사회질서에 미치는 영향을 사안과 우리나라의 관련성 정도에 비추어 판단하여야 한다.','대판(승인 판단)',1,false),
(845,1,'제217조','제1편 총칙','O','외국재판 승인 결과가 사회질서에 어긋나는지를 심리한다는 명목으로 실질적으로 그 옳고 그름을 전면적으로 재심사하는 것은 허용되지 아니한다.','대판(실질재심사 금지)',1,false),
(846,1,'제217조','제1편 총칙','O','법원은 외국재판의 승인 요건이 충족되었는지에 관하여 직권으로 조사하여야 한다.','대판(승인요건 직권조사)',1,false),
(847,1,'제217조의2','제1편 총칙','O','민소 §217의2①은 징벌적 손해배상 등 전보 범위를 초과하는 배상을 명한 외국재판의 승인을 제한하기 위한 것이므로, 실손해를 전보하는 손해배상을 명한 경우에는 그 규정을 근거로 승인을 제한할 수 없다.','대판 2015다1284',2,false),
(848,1,'제218조','제1편 총칙','O','기판력의 주관적 범위는 신분·회사관계소송 등 제3자에게 효력이 미치도록 규정된 경우를 제외하고는 원칙적으로 당사자, 변론종결 뒤의 승계인, 청구목적물 소지자, 소송담당의 경우 권리귀속주체에 국한되고, 그 외의 제3자나 변론종결 전의 승계인에게는 미치지 않는다.','민소 §218①',2,false),
(849,1,'제218조','제1편 총칙','O','변론종결 후에 새로 발생한 사유는 전소 판결의 기판력에 의하여 차단되지 아니하므로, 그 새로운 사유를 들어 다툴 수 있다.','판례(기판력 표준시)',1,false),
(850,1,'제218조','제1편 총칙','O','자격 없는 수계인에 대하여 본안 실체판결이 확정되었더라도 그 판결의 기판력은 진정한 수계인(상속인)에게는 미치지 아니한다.','대판 1981.3.10. 80다1895',1,false),
(851,1,'제218조','제1편 총칙','O','건물 소유권에 기한 물권적 청구권에 의한 건물명도소송의 사실심 변론종결 뒤 패소자로부터 건물을 매수해 이전등기를 마친 제3자는 민사소송법 제218조 제1항의 변론종결 뒤의 승계인에 해당한다.','판례',1,false),
(852,1,'제218조','제1편 총칙','O','채권자가 채권자대위권 행사로 제3채무자를 상대로 소송을 제기하여 판결을 받은 경우, 어떠한 사유로든 채무자가 대위소송이 제기된 사실을 알았을 경우에 한하여 그 판결의 효력이 채무자에게 미친다.','대판(대위소송 기판력)',2,false),
(853,1,'제218조','제1편 총칙','O','대지 소유권에 기한 방해배제로 지상건물 철거 승소확정판결을 얻은 경우, 그 건물에 관하여 확정판결 변론종결 전에 마쳐진 소유권이전청구권가등기에 기하여 변론종결 후 소유권이전등기를 마친 자에게도 그 확정판결의 기판력이 미친다.','대판(가등기 변론종결 후 등기)',1,false),
(854,1,'제218조','제1편 총칙','O','채권자가 제3채무자를 상대로 채권자대위소송을 제기하였다가 피보전채권이 인정되지 않는다는 이유로 소각하 판결을 받아 확정된 경우, 채무자가 대위소송 제기 사실을 알았는지 여부에 관계없이 그 판결의 기판력은 채권자가 채무자를 상대로 피보전채권의 이행을 구하는 소송에 미치지 않는다.','대판(대위 소각하 기판력)',1,false),
(855,1,'제218조','제1편 총칙','O','법인 아닌 사단이 당사자가 된 판결의 기판력도 그 대표자나 구성원 개인에게는 미치지 않는다.','대판(비법인사단 기판력)',1,false),
(856,1,'제218조','제1편 총칙','O','차임 상당 부당이득반환 확정판결의 기판력은 채권적 청구권에 관한 것이므로, 그 변론종결 후 토지 소유권을 취득한 사람은 변론종결 뒤의 승계인에 해당하지 않는다.','대판(부당이득 승계인)',1,false),
(857,1,'제218조','제1편 총칙','O','소송물이 동일하거나 선결문제·모순관계로 기판력이 미치는 객관적 범위에 해당하지 아니하는 경우에는, 전소 변론종결 후에 계쟁물 등을 승계한 자가 후소를 제기하더라도 그 후소에 전소판결의 기판력이 미치지 아니한다.','대판(승계인 객관적 범위)',1,false),
(858,1,'제218조','제1편 총칙','O','사해행위취소판결의 기판력은 취소권을 행사한 채권자와 그 상대방인 수익자·전득자 사이의 상대적 관계에서만 미치고, 그 소송에 참가하지 아니한 채무자 또는 채무자와 수익자 사이의 법률관계에는 미치지 아니한다.','대판(사해행위 상대효)',1,false),
(859,1,'제218조','제1편 총칙','O','채권자대위소송에서 피보전채권 부정으로 소각하 확정된 경우, 그 판결의 기판력은 소송요건(당사자적격)에 관한 것이어서 채권자가 채무자를 상대로 피보전채권 이행을 구하는 소송에는 미치지 않는다.','대판(대위 소각하 기판력)',1,false),
(860,1,'제218조','제1편 총칙','O','물건 인도 확정판결의 기판력·집행력은 변론종결 후 그 물건의 점유를 승계한 자에게도 미친다(점유보조자가 아닌 독립 점유 승계인의 경우).','대판(인도판결 승계인)',1,false),
(861,1,'제218조','제1편 총칙','O','채무자(을)가 채권자대위소송 계속 중 그 소송이 제기되었음을 알았다면, 그 대위소송의 기판력은 채무자에게 미친다.','대판(대위소송 기판력)',1,false),
(862,1,'제218조','제1편 총칙','O','매매에 기한 소유권이전등기청구 승소확정판결 후 등기를 마치기 전에, 피고로부터 변론종결 후 소유권이전등기를 넘겨받은 제3자는 (이전등기청구권이 채권이어서) 승계인이 아니므로 기판력이 미치지 않는다.','대판(채권적 청구 승계인)',1,false),
(863,1,'제218조','제1편 총칙','O','채권자대위소송이 제기된 사실을 안 채무자에게는 그 대위소송 확정판결의 기판력이 미친다.','대판(대위소송 기판력)',1,false),
(864,1,'제218조','제1편 총칙','O','변론을 종결한 뒤의 승계인에게는 확정판결의 기판력이 미친다.','민소 §218①',1,false),
(865,1,'제218조','제1편 총칙','O','청구의 목적물을 소지한 임차인이나 전세권자는 자기 고유의 점유권원으로 점유하는 자이므로, 당사자를 위하여 청구목적물을 소지한 자에 해당하지 않아 확정판결의 기판력이 미치지 않는다.','대판(목적물 소지자)',1,false),
(866,1,'제218조','제1편 총칙','O','재판권의 부존재를 간과하고 한 본안판결은 (확정되더라도) 무효이므로 기판력이 발생하지 않는다.','대판(재판권 흠 무효)',1,false),
(867,1,'제218조','제1편 총칙','O','제3자의 소송담당에 의한 확정판결은 권리귀속주체인 다른 사람에게 효력이 미치며, ''소송계속을 안 경우에 한하여''는 채권자대위소송 등 일부에 적용될 뿐 일반화할 수 없다.','민소 §218③',1,false),
(868,1,'제218조','제1편 총칙','O','확정판결은 변론을 종결한 뒤의 승계인에 대하여 효력이 미친다(변론종결 전 승계인이 아니다).','민소 §218①',1,false),
(869,1,'제219조','제1편 총칙','O','원고가 소권을 남용하여 청구가 이유 없음이 명백한 소를 반복적으로 제기한 경우에는 법원은 결정으로 500만 원 이하의 과태료에 처한다.','민소 §219의2',1,false),
(870,1,'제219조','제1편 총칙','O','부적법한 소로서 그 흠을 보정할 수 없는 경우에는 변론 없이 판결로 소를 각하할 수 있다.','민소 §219',1,false),
(871,1,'제220조','제1편 총칙','O','재판상 화해의 당사자는 소송당사자 아닌 제3자도 될 수 있고, 필요한 경우 소송물 아닌 권리·법률관계를 첨가할 수도 있다.','판례',1,false),
(872,1,'제220조','제1편 총칙','O','재심의 소에서 ''재심대상판결을 취소한다''는 화해가 성립되었더라도 이러한 화해조항은 당연무효이다.','판례',1,false),
(873,1,'제220조','제1편 총칙','O','재판상 화해에 실효조건(해제조건)을 붙이는 약정도 허용되며, 그 실효조건이 성취되면 화해의 효력이 실효된다.','실무제요 Ⅲ5585; 민소 §220',1,true),
(874,1,'제220조','제1편 총칙','O','화해의 내용이 강행법규에 위반된다 하더라도 화해가 무효라는 주장을 할 수 없다.','판례',1,false),
(875,1,'제220조','제1편 총칙','O','예비적 병합의 경우 예비적 청구에 관하여만 인낙을 할 수는 없고, 인낙 취지가 조서에 기재되었더라도 그 인낙의 효력이 발생하지 아니한다.','판례',1,false),
(876,1,'제220조','제1편 총칙','O','주주총회결의의 하자를 다투는 소에서는 청구의 인낙을 할 수 없다.','판례',1,false),
(877,1,'제220조','제1편 총칙','O','청구인낙의 취지가 변론조서에 기재되었다면 따로 인낙조서를 작성하지 않았더라도 청구인낙으로서의 효력이 발생한다.','판례',1,false),
(878,1,'제220조','제1편 총칙','O','확정된 이행권고결정에는 기판력이 없으므로, 기판력의 배제를 주목적으로 하는 준재심의 대상이 될 수 없다.','대판(이행권고결정 기판력)',1,false),
(879,1,'제220조','제1편 총칙','O','소송행위에 조건을 붙이는 것은 원칙적으로 허용되지 않으나, 재판상 화해에 제3자의 이의 등을 실효조건으로 붙이는 약정은 허용된다.','대판(실효조건부 화해)',1,false),
(880,1,'제220조','제1편 총칙','O','화해조항 자체에 그 화해의 효력을 상실시킬 수 있는 조건이 있는 때에는, 그 조건의 성취로 화해는 당연히 실효된다.','대판(실효조건부 화해)',1,false),
(881,1,'제220조','제1편 총칙','O','화해조서에 확정판결의 당연무효 사유와 같은 사유가 없으면, 그 내용이 강행법규에 위반된다 하더라도 준재심으로 취소되지 않는 한 화해조서를 무효라고 주장할 수 없다.','대판(화해조서 효력)',1,false),
(882,1,'제220조','제1편 총칙','O','재심사건에서 재심대상 확정판결을 취소한다는 내용의 화해는 당사자가 처분할 수 없는 사항(판결의 취소)을 대상으로 하므로 당연무효이다.','대판(재심대상판결 취소 화해)',1,false),
(883,1,'제220조','제1편 총칙','O','이의신청을 한 피고는 제1심판결이 선고되기 전까지 이의신청을 취하할 수 있다.','소액사건심판법 §5의4',1,false),
(884,1,'제220조','제1편 총칙','O','법원사무관등은 이행권고결정이 확정판결과 같은 효력을 가지게 된 때에는 이행권고결정서 정본을 원고에게 송달하여야 한다.','소액사건심판법 §5의7',1,false),
(885,1,'제220조','제1편 총칙','O','확정된 이행권고결정에 기한 강제집행에서는 원칙적으로 집행문을 부여받을 필요 없이 이행권고결정서 정본에 의하여 집행할 수 있다.','소액사건심판법 §5의8',1,false),
(886,1,'제220조','제1편 총칙','O','주주총회결의 부존재·무효 확인의 소에서 청구의 인낙이나 그 부존재·무효를 확인하는 화해·조정은 할 수 없고, 가사 그러한 인낙·화해·조정이 이루어졌더라도 그 조서는 효력이 없다.','대판(주총결의 인낙)',1,false),
(887,1,'제220조','제1편 총칙','O','당사자 일방이 화해조서의 당연무효 사유를 주장하며 기일지정신청을 한 때에는 법원은 기일을 지정하여 심리한 다음 무효사유가 인정되지 아니하면 판결로써 소송종료를 선언하여야 한다.','대판(화해 무효 기일지정)',1,false),
(888,1,'제220조','제1편 총칙','O','제소전화해조서는 확정판결과 동일한 효력이 있어 당사자 사이에 기판력이 생긴다.','대판(제소전화해 기판력)',1,false),
(889,1,'제220조','제1편 총칙','O','소송상화해는 소송계속 중에 이루어진다는 점에서 제소전화해와 다르고, 상호 양보하여 합의한다는 점에서 청구의 포기·인낙과 다르다.','통설',1,false),
(890,1,'제220조','제1편 총칙','O','소송상화해가 실효조건의 성취로 실효된 경우에는 화해가 없었던 상태로 돌아가므로, 당사자는 화해 성립 전의 법률관계를 다시 주장할 수 있다.','대판(실효조건 화해)',1,false),
(891,1,'제220조','제1편 총칙','O','소송상화해는 소송계속 중이면 어느 때나 할 수 있으므로 상고심에서도 할 수 있다.','대판(상고심 화해)',1,false),
(892,1,'제220조','제1편 총칙','O','소송상화해(화해조서)에 당연무효 사유가 아닌 실체법상의 하자가 있는 경우에는 기일지정신청으로 다툴 수 없고 준재심의 소로만 다툴 수 있다.','대판(화해 무효 다투기)',1,false),
(893,1,'제220조','제1편 총칙','O','소송상 화해의 효력에 관하여 다투면서 기일지정신청을 하는 경우 (화해가 유효하면) 소송종료선언을 하여야 한다.','대판(화해 기일지정)',1,false),
(894,1,'제220조','제1편 총칙','O','청구의 포기에 의하여 소송이 종료되었음에도 이를 간과하고 심리를 계속 진행한 사실이 발견된 경우 소송종료선언을 하여야 한다.','대판(종료 간과)',1,false),
(895,1,'제220조','제1편 총칙','O','소송상 화해는 준재심의 소에 의하여만 다툴 수 있으므로, 제3자의 사기를 이유로 민법상 제3자 사기 규정에 따라 화해를 취소할 수 있는 것이 아니다.','대판(소송상화해 준재심)',1,false),
(896,1,'제220조','제1편 총칙','O','재판상 화해에서 제3자의 이의가 있을 때에 화해의 효력을 실효시키기로 하는 약정이 가능하고, 그 실효조건의 성취로 화해의 효력은 당연히 소멸된다.','대판(실효조건부 화해)',1,false),
(897,1,'제220조','제1편 총칙','O','청구의 포기·인낙은 상고심에서도 할 수 있다.','대판(포기·인낙 시기)',1,false),
(898,1,'제220조','제1편 총칙','O','청구의 포기 또는 인낙은 무조건이어야 하고, 조건 또는 기한부 청구의 포기·인낙은 허용되지 않는다.','통설',1,false),
(899,1,'제220조','제1편 총칙','O','청구의 포기·인낙, 화해·조정의 무효를 다투며 기일지정신청을 하는 경우, 당연무효 사유가 없으면 소송종료선언을 한다.','대판(기일지정)',1,false),
(900,1,'제220조','제1편 총칙','O','소송상화해에는 당사자 외에 이해관계 있는 제3자가 참가하여 함께 화해할 수 있다.','대판(화해 참가)',1,false),
(901,1,'제220조','제1편 총칙','O','청구의 인낙조서 등은 그 정본을 송달한다(원본이 아니다).','실무',1,false),
(902,1,'제221조','제1편 총칙','O','결정·명령은 고지에 의하여 효력이 발생하므로, 고지되어 효력이 발생하기 전에는 항고할 수 없다.','판례',1,false),
(903,1,'제225조','제1편 총칙','O','법원은 소송 계속 중인 사건에 대하여 직권으로 당사자의 이익 등 모든 사정을 참작하여 청구취지에 어긋나지 않는 범위에서 사건의 공평한 해결을 위한 화해권고결정을 할 수 있다.','민소 §225',2,false),
(904,1,'제225조','제1편 총칙','O','화해권고결정서의 송달은 우편송달(발송송달)·공시송달의 방법으로는 할 수 없다.','대판(화해권고결정 송달)',1,false),
(905,1,'제225조','제1편 총칙','O','화해권고결정은 그 정본을 송달한다(원본이 아니다).','민소 §210',1,false),
(906,1,'제226조','제1편 총칙','O','화해권고결정 정본이 송달되기 전에도 이의신청을 할 수 있다(송달 전 이의신청이 부적법한 것은 아니다).','판례',1,false),
(907,1,'제226조','제1편 총칙','O','이의신청서에 기재하도록 요구되는 화해권고결정의 표시와 이의신청의 취지는, 제출된 서면을 전체적으로 보아 어떤 화해권고결정에 대하여 이의한다는 취지가 나타나면 족하고, 서면 표제가 준비서면 등 다른 명칭이라도 달리 볼 것은 아니다.','대판(이의신청 방식)',1,false),
(908,1,'제227조','제1편 총칙','O','어느 당사자가 화해권고결정에 대해 이의를 신청한 때에는 이의신청의 상대방에게 이의신청서의 부본을 송달하여야 한다.','민소 §227',1,false),
(909,1,'제228조','제1편 총칙','O','화해권고결정에 대하여 이의신청을 한 당사자는 그 심급의 판결이 선고될 때까지 상대방의 동의를 얻어 이의신청을 취하할 수 있다.','민소 §228',2,false),
(910,1,'제229조','제1편 총칙','O','화해권고결정에 대한 이의신청권은 그 신청 전까지 포기할 수 있고, 이의신청권의 포기는 서면으로 하여야 한다.','민소 §229',1,false),
(911,1,'제230조','제1편 총칙','O','화해권고결정에 대한 이의신청권의 포기는 서면으로 하여야 한다.','민소 규칙',2,false),
(912,1,'제231조','제1편 총칙','O','위 준비서면과 항소장 제출은 화해권고결정에 대한 이의신청으로 볼 수 있으므로, 화해권고결정이 확정되었다고 볼 수 없다.','대판(이의신청 해당성)',1,false),
(913,1,'제231조','제1편 총칙','O','화해권고결정은 이의신청 기간 내에 이의신청이 없는 때, 이의신청 각하결정이 확정된 때, 이의신청을 취하하거나 이의신청권을 포기한 때에 재판상 화해와 같은 효력을 가지므로, 확정된 화해권고결정은 당사자 사이에 기판력을 가진다.','민소 §231·§220',1,false),
(914,1,'제231조','제1편 총칙','O','화해권고결정에 대한 이의로 판결이 선고된 이후에는 이의신청을 취하하더라도 화해권고결정이 다시 확정되지 않는다(이미 판결로 실효).','대판(이의 후 판결)',1,false),
(915,1,'제231조','제1편 총칙','O','화해권고결정의 기판력은 그 확정시를 기준으로 하여 발생한다.','대판(화해권고 표준시)',1,false),
(916,1,'제231조','제1편 총칙','O','동일 당사자 사이의 전소에서 확정된 화해권고결정이 있는 경우, 당사자는 이에 반하는 주장을 할 수 없고 법원도 이에 저촉되는 판단을 할 수 없다.','대판(화해권고 기판력)',1,false),
(917,1,'제231조','제1편 총칙','O','당사자가 화해권고결정을 송달받고 2주 이내에 이의신청을 하지 아니하면 화해권고결정은 재판상 화해와 같은 효력을 가진다.','민소 §231',1,false),
(918,1,'제232조','제1편 총칙','O','소송종료선언은 종국판결이므로 그에 대하여 상소할 수 있다.','대판(소송종료선언)',1,false),
(919,1,'제232조','제1편 총칙','O','조정조서가 작성된 뒤 당사자가 조정에 응한 적도 없는데 조정조서가 작성되었다고 다투며 기일지정신청을 한 경우, 조정이 적법하게 성립하였다고 인정되면 법원은 소송종료선언을 한다.','대판(기일지정신청)',1,false),
(920,1,'제232조','제1편 총칙','O','이미 확정된 판결을 다투면서 기일지정신청을 하는 것은 (재심 등 별도 불복방법에 의할 것이어서) 소송종료선언을 하여야 할 경우에 해당하지 않는다.','대판(확정판결 기일지정)',1,false),
(921,1,'제232조','제1편 총칙','O','소송종료선언은 종국판결의 형식으로 하며, 이에 대하여는 상소할 수 있다(결정·항고가 아니다).','대판(소송종료선언 형식)',1,false),
(922,1,'제232조','제1편 총칙','O','화해권고결정에 대한 이의신청이 적법하면 소송은 그 이전 상태로 돌아가 계속되지만, 이의신청 전에 행한 소송행위는 그대로 효력을 유지한다.','민소 §232',1,false),
(923,1,'제233조','제1편 총칙','O','당사자 사망으로 인한 중단사유를 간과하고 절차가 진행되어 종국판결이 선고되었더라도 그 판결은 당연무효가 아니고, 대리권 흠결의 경우와 같이 상소 또는 재심으로 취소를 구할 수 있다.','판례',2,false),
(924,1,'제233조','제1편 총칙','O','사망자를 피고로 하는 소제기는 부적법하여 제1심판결이 선고되었더라도 당연무효이며, 사망자인 피고의 상속인들에 의한 항소나 수계신청은 부적법하다.','판례',1,false),
(925,1,'제233조','제1편 총칙','O','이사가 주주총회결의 취소의 소를 제기하였다가 소송 계속 중 또는 사실심 변론종결 후 사망하였다면, 그 소송은 이사의 사망으로 중단되지 않고 그대로 종료된다.','판례',1,false),
(926,1,'제233조','제1편 총칙','O','상속인들로부터 항소심 소송을 위임받은 소송대리인이 수계절차를 취하지 않은 채 사망한 당사자 명의로 항소장·항소이유서를 제출하였더라도, 상속인들이 항소심에서 수계신청을 하고 그 소송행위를 추인하면 그 하자는 치유된다.','판례',1,false),
(927,1,'제233조','제1편 총칙','O','소송위임 후 소제기 전에 당사자가 사망했는데 소송대리인이 이를 모르고 그를 원고로 표시하여 소를 제기하였다면 소제기는 적법하고, 그 효력은 상속인에게 귀속되며 상속인이 소송절차를 수계하여야 한다.','대판 2014다210449',1,false),
(928,1,'제233조','제1편 총칙','O','이혼소송 계속 중 배우자 일방이 사망하면 상속인이 수계할 수 없어 이혼소송은 종료되고, 이혼 성립을 전제로 한 재산분할청구도 함께 종료된다.','대판(이혼소송 사망)',1,false),
(929,1,'제233조','제1편 총칙','O','소송중단을 간과한 판결도 당연무효는 아니므로, 사망한 당사자가 표시된 그 판결에 기하여 승계인을 위한 또는 그에 대한 승계집행문을 부여할 수 있다.','대판(중단 간과 판결)',1,false),
(930,1,'제233조','제1편 총칙','O','소송계속 중 당사자 사망으로 인한 중단을 간과하고 판결이 선고된 경우, 적법한 상속인들이 수계신청을 하여 판결을 송달받아 상고하거나 사실상 송달받아 상고장을 제출하고 상고심에서 수계절차를 밟은 경우 그 수계와 상고는 적법하다.','대판(중단 간과 수계 상고)',1,false),
(931,1,'제233조','제1편 총칙','O','소송계속 중 당사자 사망에 의한 소송절차 중단을 간과하고 변론이 종결되어 판결이 선고된 경우, 그 판결은 절차상 위법은 있으나 당연무효는 아니고, 대리권 흠결을 이유로 상소 또는 재심으로 취소를 구할 수 있을 뿐이다.','대판(중단 간과 판결)',2,false),
(932,1,'제233조','제1편 총칙','O','소송중단사유를 간과하고 한 본안판결은 당연무효가 아니고, 대리권 흠결에 준하여 상소·재심으로 취소를 구할 수 있을 뿐이다.','대판(중단 간과 판결)',1,false),
(933,1,'제233조','제1편 총칙','O','일신전속적인 법률관계에서 당사자가 사망한 경우 소송이 종료되었는지에 다툼이 있더라도 소송종료선언을 할 수 있다.','대판(일신전속 사망)',1,false),
(934,1,'제233조','제1편 총칙','O','중단을 간과한 판결은 당연무효가 아니므로, 상속인이 수계하여 상고하거나 사실상 송달받아 상고하고 상고심에서 수계한 경우 그 수계·상고는 적법하다.','대판(중단 간과 판결)',1,false),
(935,1,'제234조','제1편 총칙','O','당사자인 법인이 합병에 의하여 소멸된 때에는 소송절차가 중단되지만, 소송대리인이 있는 경우에는 그러하지 아니하다.','민소',1,false),
(936,1,'제234조','제1편 총칙','O','법인이 합병 이외의 사유로 해산된 때에는 청산법인으로 존속하므로 소송절차가 중단되지 않지만, 청산절차를 밟지 않고 소멸된 경우에는 중단된다.','대판(법인 해산)',1,false),
(937,1,'제235조','제1편 총칙','O','법인 아닌 사단 대표자의 대표권이 소멸한 경우 중단사유에 해당하지만 소송대리인이 선임되어 있으면 곧바로 중단되지 아니하므로, 대표자 변경을 이유로 한 수계신청은 당사자표시정정신청으로 보면 된다.','대판(대표권 소멸 수계)',1,false),
(938,1,'제235조','제1편 총칙','O','소송계속 중 비법인 사단 대표자의 대표권이 소멸한 경우 중단사유에 해당하지만 소송대리인이 선임되어 있으면 곧바로 중단되지 아니하고, 심급대리 원칙상 그 심급의 판결정본이 소송대리인에게 송달됨으로써 소송절차가 중단된다.','대판(심급대리 중단)',1,false),
(939,1,'제235조','제1편 총칙','O','법인 대표자의 직무집행이 정지된 경우에도 소송대리인이 있으면 소송절차는 중단되지 아니하나, 종국판결이 소송대리인에게 송달됨으로써 그 소송절차는 중단된다.','대판(직무집행정지 중단)',1,false),
(940,1,'제235조','제1편 총칙','O','소송계속 중 당사자가 소송능력을 상실하면 소송절차가 중단될 뿐이고(법정대리인 등이 수계), 그 사유만으로 소가 부적법해져 각하되는 것은 아니다.','민소 §235',1,false),
(941,1,'제236조','제1편 총칙','O','신탁으로 인한 수탁자의 임무가 끝난 때 소송절차는 중단되고 새로운 수탁자가 수계하여야 하나, 소송대리인이 있는 경우에는 소송절차가 중단되지 않고 소송대리권도 소멸하지 않는다.','민소',1,false),
(942,1,'제237조','제1편 총칙','O','공동파산관재인 중 일부가 자격을 상실한 때에는 남은 파산관재인에게 관리처분권이 귀속되어 소송절차가 중단되지 않으므로, 남은 파산관재인은 따로 수계절차를 거칠 필요 없이 혼자서 소송행위를 할 수 있다.','판례',1,false),
(943,1,'제238조','제1편 총칙','O','당사자가 사망하더라도 소송대리인이 있는 경우에는 소송절차가 중단되지 않는다.','민소 §238',2,false),
(944,1,'제238조','제1편 총칙','O','당사자가 사망하였으나 소송대리인이 있는 경우 소송절차는 중단되지 않고 그 판결은 상속인 전원에 대하여 효력이 있으나, 심급대리의 원칙상 판결정본이 소송대리인에게 송달된 때에는 소송절차가 중단된다.','판례',1,false),
(945,1,'제238조','제1편 총칙','O','소송대리인이 있어 중단되지 않은 경우, 일부 상속인만 당사자로 표시되었더라도 그 판결의 효력은 수계하지 않은 나머지 공동상속인 전원에게 미친다.','대판(일부 수계)',1,false),
(946,1,'제238조','제1편 총칙','O','상소제기에 관한 특별수권을 받은 소송대리인이 상소를 제기하면 그 상소제기로 대리권이 소멸하므로, 상소심 절차는 중단된다.','대판(상소 특별수권)',1,false),
(947,1,'제238조','제1편 총칙','O','피고에게 소송대리인이 있으면 (당사자 사망의) 중단사유에도 불구하고 소송절차는 중단되지 않는다.','민소 §238',1,false),
(948,1,'제238조','제1편 총칙','O','피고에게 소송대리인이 있어 소송절차가 중단되지 않는 경우, 상속인으로 당사자 표시를 정정하지 않고 사망한 피고를 그대로 당사자로 표시하여 판결하였더라도 그 판결의 효력은 상속인들에게 미친다.','대판(소송대리인 있는 사망)',1,false),
(949,1,'제238조','제1편 총칙','O','당연승계가 있어도 피승계인에게 소송대리인이 있으면 소송절차는 중단되지 않는다.','민소 §238',1,false),
(950,1,'제238조','제1편 총칙','O','소송대리인은 수계절차를 밟지 않아도 신당사자의 소송대리인이 되며, 판결의 효력은 신당사자에게 미친다.','대판(소송대리인 수계)',1,false),
(951,1,'제239조','제1편 총칙','O','소송계속 중 당사자가 소송능력을 상실하여도 소송대리인이 있으면 중단되지 않으나, 그 당사자가 파산선고를 받은 때에는 소송대리인이 있더라도 파산재단에 관한 소송절차는 중단된다.','민소 §238·§239',1,false),
(952,1,'제241조','제1편 총칙','O','원고도 사망한 피고의 상속인들을 위하여 중단된 소송절차의 수계신청을 할 수 있다.','민소 §241',1,false),
(953,1,'제241조','제1편 총칙','O','갑과 을 간의 소송에서 을이 사망하였다면 갑도 을의 상속인들을 위하여 수계신청을 할 수 있다.','민소 §241',1,false),
(954,1,'제243조','제1편 총칙','O','소송수계신청의 적법 여부는 직권조사사항이므로, 수계가 이유 없으면 기각하나 이유가 있을 때에는 별도의 재판 없이 그대로 소송절차를 진행할 수 있다.','대판(수계신청)',1,false),
(955,1,'제243조','제1편 총칙','O','소송절차 수계신청이 있는 경우 법원은 그 신청 상대방에게 이를 통지하여야 한다.','민소 §242',1,false),
(956,1,'제243조','제1편 총칙','O','소송수계신청이 이유 없다고 인정한 때에는 결정으로 신청을 기각하여야 하나, 이유 있다고 인정한 때에는 별도의 재판을 할 필요 없이 그대로 소송절차를 진행하면 된다.','대판(수계신청 처리)',2,false),
(957,1,'제245조','제1편 총칙','O','천재지변 등으로 법원이 직무를 수행할 수 없는 때에 소송절차는 그 사고가 소멸될 때까지 중지된다.','민소 §245',1,false),
(958,1,'제247조','제1편 총칙','O','변론종결 뒤에 당사자가 사망한 경우에는 판결을 선고할 수 있다.','민소 §247①',1,false),
(959,1,'제247조','제1편 총칙','O','지급명령이 송달된 후 이의신청 기간 내에 회생절차개시결정 등 소송중단 사유가 생긴 경우에는 민사소송법 제247조 제2항이 준용되어 이의신청 기간의 진행이 정지된다.','판례',1,false),
(960,1,'제247조','제1편 총칙','O','소송절차의 중단 또는 중지가 해소되면 그 때부터 (구별 없이) 전체 기간이 새로이 진행된다.','민소 §247②',1,false),
(961,1,'제248조','제2편 제1심의 소송절차','O','채권이 가압류되더라도 채무자는 제3채무자를 상대로 이행의 소를 제기할 수 있다(현실 추심만 제한될 뿐이다).','판례',2,false),
(962,1,'제248조','제2편 제1심의 소송절차','O','토지거래허가구역 내 토지에 관하여 허가를 받기 전(유동적 무효) 단계에서는 장차 허가받을 것을 조건으로 하는 소유권이전등기청구도 허용되지 않는다.','판례',1,false),
(963,1,'제248조','제2편 제1심의 소송절차','O','확정판결로 인정된 채권의 소멸시효 중단을 위한 재소는 소의 이익이 인정된다.','판례',1,false),
(964,1,'제248조','제2편 제1심의 소송절차','O','법원은 소장에 붙이거나 납부한 인지액이 최소인지금액(소가 3,000만 원 이하 1,000원 등)에 미달하는 때에는 소장의 접수를 보류할 수 있다(의무가 아닌 재량).','민소 §248②; 인지법 §13②; 실무제요 Ⅰ2525',1,true),
(965,1,'제248조','제2편 제1심의 소송절차','O','강제집행 당사자 사이에 그 신청을 취하하기로 하는 약정은 사법상 유효하더라도, 이를 위배하였다 하여 직접 소송으로 그 취하를 청구하는 것은 허용되지 않는다.','판례',1,false),
(966,1,'제248조','제2편 제1심의 소송절차','O','소액사건의 소는 법관이 아니라 법원사무관등의 면전에서 구술로 진술하여 제기할 수 있다.','소액사건심판법 §4',1,false),
(967,1,'제248조','제2편 제1심의 소송절차','O','더 간편한 절차를 이용할 수 있었음에도 이용하지 않았다는 사정은 소송제기에 있어 소극적 권리보호요건인 직권조사사항이다.','대판 98다17145',1,false),
(968,1,'제248조','제2편 제1심의 소송절차','O','원인 없이 말소된 근저당권설정등기의 회복등기절차 이행 및 승낙의 의사표시를 구하는 소송 도중에 근저당목적물에 관하여 경매절차가 진행되어 매각허가결정이 확정되고 매수인이 매각대금을 완납한 경우, 회복등기절차 이행이나 승낙의 의사표시를 구할 법률상 이익이 없게 된다.','대판(경매 매각 회복등기)',1,false),
(969,1,'제248조','제2편 제1심의 소송절차','O','순차 마쳐진 이전등기 말소청구는 통상공동소송이므로, 최종 등기명의인에 대한 패소확정과 관계없이 중간 등기명의인에 대한 말소청구의 소의 이익이 인정된다.','대판(순차등기 말소)',1,false),
(970,1,'제248조','제2편 제1심의 소송절차','O','이행판결이 확정되었으나 그 내용이 특정되지 아니하여 집행을 할 수 없는 경우에는, 소송물이 동일하더라도 다시 소를 제기할 권리보호의 이익이 있다.','대판(집행불능 재소)',1,false),
(971,1,'제248조','제2편 제1심의 소송절차','O','사해행위의 취소 및 원상회복을 구하는 소송계속 중 사해행위가 해제·해지되어 목적부동산이 채무자에게 복귀한 경우에는, 특별한 사정이 없는 한 그 채권자취소소송은 권리보호의 이익이 없다.','대판(사해행위 복귀)',1,false),
(972,1,'제248조','제2편 제1심의 소송절차','O','소의 제기가 부제소 합의에 위배되었는지 여부는 소송요건에 관한 것으로서 법원의 직권조사사항이다.','대판(부제소합의 직권)',1,false),
(973,1,'제248조','제2편 제1심의 소송절차','O','직권조사사항인 소송요건에 대한 증명책임은 (그 소송요건의 존재로 이익을 받는) 원고에게 있다.','대판(소송요건 증명책임)',1,false),
(974,1,'제248조','제2편 제1심의 소송절차','O','형성의 소는 법률에 규정이 있는 경우에 한하여 제기할 수 있고, 법률의 규정에 따라 제기되었다면 소의 이익도 인정됨이 원칙이다.','대판(형성의 소)',1,false),
(975,1,'제248조','제2편 제1심의 소송절차','O','경계확정의 소는 형식적 형성의 소로서 법원이 실제 경계를 확정하여야 하므로, 당사자의 주장이 일치하더라도 권리보호의 이익이 없어지는 것은 아니다.','대판(경계확정의 소)',1,false),
(976,1,'제248조','제2편 제1심의 소송절차','O','채무자의 재산이 채무 전부를 변제하기에 부족한 경우, 채무자가 유일한 재산을 특정 채권자에게 대물변제로 제공하여 양도한 행위는 다른 특별한 사정이 없는 한 다른 채권자들에 대한 관계에서 사해행위가 된다.','대판(대물변제 사해행위)',1,false),
(977,1,'제248조','제2편 제1심의 소송절차','O','사해행위 당시 수익자가 선의였음을 인정하려면 객관적이고 납득할 만한 증거자료가 뒷받침되어야 하고, 채무자의 일방적 진술이나 제3자의 추측에 불과한 진술 등에만 터잡아 선의로 단정하여서는 아니 된다.','대판(수익자 선의)',1,false),
(978,1,'제248조','제2편 제1심의 소송절차','O','여러 채권자가 각각 사해행위취소·가액배상을 구하는 경우 각 채권자는 자신의 채권액 범위 내에서 가액배상 전부를 청구할 수 있고, 채권액에 비례하여 안분한 범위로 제한되는 것이 아니다.','대판(가액배상)',1,false),
(979,1,'제248조','제2편 제1심의 소송절차','O','소송물이 특정되었는지 여부는 소송요건으로서 법원의 직권조사사항에 속한다.','대판(소송물 특정)',1,false),
(980,1,'제248조','제2편 제1심의 소송절차','O','소의 이익은 소송요건이므로 그 흠이 있을 때에는 소가 부적법하다는 소각하판결을 하여야 한다.','통설',1,false),
(981,1,'제248조','제2편 제1심의 소송절차','O','채권자취소권의 행사기간은 제소기간이므로, 법원은 그 기간 준수 여부를 직권으로 조사하여 기간이 도과된 후 제기된 채권자취소의 소는 부적법한 것으로 각하하여야 한다.','대판(채권자취소 제소기간)',1,false),
(982,1,'제248조','제2편 제1심의 소송절차','O','소액사건에서는 구술에 의한 소의 제기(법원사무관등 면전 진술)가 허용되므로, 서면에 의하여만 소를 제기해야 하는 통상의 소송절차와 다르다.','소액사건심판법 §4',1,false),
(983,1,'제248조','제2편 제1심의 소송절차','O','소제기 후 소송목적물에 가치의 등락이 있더라도 인지를 추가로 납부하거나 반환하지 아니한다.','인지법(소가 기준시)',1,false),
(984,1,'제248조','제2편 제1심의 소송절차','O','물건에 대한 점유권의 가액은 소유권 가액과 같지 않고, 인지규칙상 그 일정 비율(예: 3분의 1)로 산정한다.','인지규칙',1,false),
(985,1,'제248조','제2편 제1심의 소송절차','O','소송계속의 여부는 직권조사사항이다.','대판(소송계속 직권)',1,false),
(986,1,'제248조','제2편 제1심의 소송절차','O','부제소특약(부제소합의)의 위배 여부는 소송요건으로서 직권조사사항이다.','대판(부제소합의 직권)',1,false),
(987,1,'제248조','제2편 제1심의 소송절차','O','공유물분할의 소는 형식적 형성의 소이다.','통설',2,false),
(988,1,'제248조','제2편 제1심의 소송절차','O','법정지상권이 성립한 경우 그 지료를 결정하는 소는 형식적 형성의 소이다.','대판(지료결정)',1,false),
(989,1,'제248조','제2편 제1심의 소송절차','O','주주총회결의 취소의 소는 법률관계의 변동을 목적으로 하는 본래의(실질적) 형성의 소이고 형식적 형성의 소가 아니다.','통설',1,false),
(990,1,'제249조','제2편 제1심의 소송절차','O','법정대리인의 표시는 소장·판결의 필요적 기재사항이다.','민소 §249·§208',1,false),
(991,1,'제249조','제2편 제1심의 소송절차','O','소장의 필수적 기재사항은 당사자 및 법정대리인, 청구취지와 청구원인이고, 사건의 표시·법원의 표시는 임의적 기재사항이다.','민소 §249①',1,false),
(992,1,'제249조','제2편 제1심의 소송절차','O','청구취지는 원고가 구하는 판결의 내용·종류를 표시하는 부분이고, 권리·법률관계의 성립원인 사실은 청구원인에 기재한다.','민소 §249①',1,false),
(993,1,'제249조','제2편 제1심의 소송절차','O','청구취지는 소가 산정의 기준이 된다.','민소 §249',1,false),
(994,1,'제249조','제2편 제1심의 소송절차','O','청구취지는 사물관할과 상소이익의 유무를 판단하는 기준이 된다.','대판(상소이익)',1,false),
(995,1,'제249조','제2편 제1심의 소송절차','O','청구취지는 원고가 어떠한 내용과 종류의 판결을 구하는가를 밝히는 소의 결론부분이다.','민소 §249①',1,false),
(996,1,'제250조','제2편 제1심의 소송절차','O','A→B→C로 순차로 마쳐진 소유권이전등기의 각 말소를 청구하는 소송에서 후순위 등기명의자인 피고 C에 대하여 이미 패소판결이 확정되었더라도 선순위 등기명의자인 피고 A, B 명의의 등기말소를 청구할 소의 이익이 있다.','판례',1,false),
(997,1,'제250조','제2편 제1심의 소송절차','O','말소회복등기와 양립할 수 없는 등기의 명의인은 등기상 이해관계 있는 제3자가 아니므로, 그를 상대로 승낙의 의사표시를 구할 것이 아니라 그 등기의 말소를 구하여야 한다.','판례',1,false),
(998,1,'제250조','제2편 제1심의 소송절차','O','과거의 법률관계에 대한 확인을 구하는 것이 허용되는 예외가 있다.','판례',1,false),
(999,1,'제250조','제2편 제1심의 소송절차','O','권리의 소멸시효 완성이 임박한 경우 시효중단을 위한 소제기가 있음에 대한 확인을 구할 수 있다.','대판(전합) 2015다232316',1,false),
(1000,1,'제250조','제2편 제1심의 소송절차','O','근저당권설정자가 근저당권설정등기의 말소를 구함과 함께 피담보채무 부존재 확인을 구하는 경우, 피담보채무 부존재 확인을 구하는 것은 확인의 이익이 있다고 할 수 없다.','판례',1,false),
(1001,1,'제250조','제2편 제1심의 소송절차','O','피고가 일단 권리관계를 다투어 확인의 소가 제기된 이상, 그 후 피고가 다투지 않게 되었더라도 곧바로 확인의 이익이 없어지는 것은 아니다.','판례',1,false),
(1002,1,'제250조','제2편 제1심의 소송절차','O','채무자가 강제집행승낙문구가 기재된 공정증서를 작성해 준 후 청구이의의 소가 아닌 채무부존재확인의 소를 제기한 경우, 그 목적이 오로지 집행력 배제에 있지 않은 이상 청구이의의 소를 제기할 수 있다는 사정만으로 확인의 이익이 없다고 할 것은 아니다.','판례',1,false),
(1003,1,'제250조','제2편 제1심의 소송절차','O','단체의 구성원이 단체 내부규정의 효력을 다투는 소는 구체적인 권리·법률관계의 존부확인을 구하는 것이 아니므로 부적법하다.','판례',1,false),
(1004,1,'제250조','제2편 제1심의 소송절차','O','처분금지가처분등기는 집행법원의 가처분결정 취소나 집행취소의 방법에 의해서만 말소될 수 있으므로, 그 처분금지가처분등기의 이행을 소구할 수 없다.','판례',1,false),
(1005,1,'제250조','제2편 제1심의 소송절차','O','(이행의 소가 가능한 경우 계약 해제 확인의 이익 인정 여부에 관한 부분 — 해설 정답키상 옳지 않은 지문).','판례',1,true),
(1006,1,'제250조','제2편 제1심의 소송절차','O','甲 소유 부동산에 乙 명의의 소유권이전등기청구권가등기가 마쳐진 후 가압류등기를 한 丙은 그 가등기가 담보목적 가등기인지 여부의 확인을 구할 확인의 이익이 없다.','판례',1,false),
(1007,1,'제250조','제2편 제1심의 소송절차','O','소유권보존등기가 되었던 종전건물의 소유자가 이를 헐어내고 건물을 신축한 경우, 종전건물 멸실등기 및 새 건물 보존등기를 위하여 종전건물 보존등기에 터잡아 마쳐진 원인무효의 소유권이전등기의 말소를 청구할 소의 이익이 있다.','판례',1,false),
(1008,1,'제250조','제2편 제1심의 소송절차','O','건축법상 각종 신고·신청 절차를 마치지 않은 채 소유권보존등기가 이루어진 경우, 정당한 원시취득자임을 주장하여 건축주 명의변경 절차의 이행을 구하는 소는 소의 이익을 부정할 수 없다.','판례',1,false),
(1009,1,'제250조','제2편 제1심의 소송절차','O','시효중단을 위한 후소로서 이행소송 외에, 전소 판결로 확정된 채권의 시효중단을 위한 ''재판상 청구가 있다는 점에 대하여만 확인을 구하는 형태의 확인소송''도 허용된다.','대판(전합) 2015다232316',1,false),
(1010,1,'제250조','제2편 제1심의 소송절차','O','확정된 전소가 이행소송이었더라도 채권자는 시효중단을 위하여 이행소송과 ''재판상 청구가 있다는 확인을 구하는 소'' 중 어느 것이든 임의로 선택하여 제기할 수 있다.','대판(전합) 2015다232316',1,false),
(1011,1,'제250조','제2편 제1심의 소송절차','O','근저당권설정등기 말소청구를 구하면서 그 피담보채무의 부존재확인청구를 함께 한 경우, 그 채무부존재확인청구는 확인의 이익이 없다.','대판(말소+부존재확인)',1,false),
(1012,1,'제250조','제2편 제1심의 소송절차','O','원고가 적법하게 손해배상채무 부존재확인의 소를 제기한 경우, 피고가 그 채무의 이행을 구하는 반소를 제기하였다고 하여 원고의 확인의 소가 부적법하게 되는 것은 아니다.','대판(부존재확인 본소+이행 반소)',1,false),
(1013,1,'제250조','제2편 제1심의 소송절차','O','증서의 진정 여부를 확인하는 소(§250)의 대상은 법률관계를 증명하는 서면(처분문서)에 한하고, 세금계산서·영수증과 같은 보고문서는 그 대상이 되지 않는다.','대판(증서진부확인)',1,false),
(1014,1,'제250조','제2편 제1심의 소송절차','O','확인의 소에서는 그 청구에 대하여 확인의 이익을 가지는 자가 원고적격을 가진다.','통설',1,false),
(1015,1,'제251조','제2편 제1심의 소송절차','O','근저당권 피담보채권액에 다툼이 있어 잔존 피담보채권 수령과 상환으로 근저당권설정등기 말소를 구하는 경우, 소송에서 밝혀진 잔존 채권액 지급을 조건으로 말소를 구하는 취지도 포함되었다고 보며, 이는 장래이행의 소로서 미리 청구할 이익이 있다.','판례',1,false),
(1016,1,'제251조','제2편 제1심의 소송절차','O','채무자의 태도나 채무의 내용·성질에 비추어 이행기가 도래하더라도 채무자의 이행을 기대할 수 없다고 판단되는 경우에는 장래의 이행을 청구하는 소를 미리 청구할 필요가 있다고 보아야 한다.','대판(미리 청구 필요)',1,false),
(1017,1,'제251조','제2편 제1심의 소송절차','O','장래에 이행기가 도래할 예정이라도, 채무불이행 사유가 언제까지 존속할지 불확실하여 변론종결 당시 채무자가 책임지는 기간을 확정적으로 예정할 수 없다면 장래의 이행을 명하는 판결을 할 수 없다.','대판(장래이행 기간 특정)',1,false),
(1018,1,'제251조','제2편 제1심의 소송절차','O','제권판결에 대한 취소판결의 확정을 조건으로 하는 수표금청구는 장래이행의 소의 요건(미리 청구할 필요)을 갖추지 못하여 허용되지 않는다.','대판(제권판결 취소 조건)',1,false),
(1019,1,'제251조','제2편 제1심의 소송절차','O','이행기가 장래 도래하는 청구권이라도 미리 청구할 필요가 있으면 장래이행의 소를 제기할 수 있고, 이행판결 주문에서 변론종결 이후 기간까지 이행을 명한 이상 확정판결의 기판력은 주문에 포함된 기간까지의 청구권 존부에 미치는 것이 원칙이다.','대판(장래이행 기판력)',1,false),
(1020,1,'제251조','제2편 제1심의 소송절차','O','장래의 이행을 청구하는 소에서, 이행기에 이르거나 조건이 성취될 때에 채무자의 무자력으로 집행이 곤란해지거나 이행불능에 빠질 사정이 있다는 것만으로는 미리 청구할 필요가 있다고 할 수 없다.','대판(미리 청구 필요)',1,false),
(1021,1,'제252조','제2편 제1심의 소송절차','O','민소 §252①의 정기금판결에 대한 변경의 소는 판결 확정 뒤에 발생한 사정변경을 요건으로 하므로, 단순히 종전 확정판결의 결론이 위법·부당하다는 사정을 이유로 정기금 액수를 바꾸어 달라고 하는 것은 허용될 수 없다.','대판(정기금 변경의 소)',1,false),
(1022,1,'제253조','제2편 제1심의 소송절차','O','예비적 병합에서 주위적 청구를 배척하면서 예비적 청구에 대하여 판단하지 아니한 판결에 상소가 제기되면, 판단이 누락된 예비적 청구 부분도 상소심으로 이심되고 그 부분이 재판의 누락에 해당하여 원심에 계속 중이라고 볼 것은 아니다.','대판(전합) 98다22253',2,false),
(1023,1,'제253조','제2편 제1심의 소송절차','O','예비적 병합에서 피고만 항소한 경우 주위적 청구도 이심되지만, 원고가 항소·부대항소를 하지 않는 한 항소심의 심판대상이 되지는 않는다.','판례(이심/심판대상)',1,false),
(1024,1,'제253조','제2편 제1심의 소송절차','O','수개의 청구가 제1심에서 선택적으로 병합되고 그중 어느 하나의 청구에 대한 인용판결이 선고되어 피고가 항소를 제기한 때에는 제1심이 판단하지 아니한 나머지 청구까지도 항소심으로 이심되어 항소심의 심판 범위가 된다.','판례',2,false),
(1025,1,'제253조','제2편 제1심의 소송절차','O','선택적으로 병합된 수개의 청구 중 어느 하나의 인용판결에 피고가 항소한 경우, 항소심이 원고의 청구를 인용할 때에는 병합된 청구 중 어느 하나를 임의로 선택하여 심판할 수 있다.','판례',1,false),
(1026,1,'제253조','제2편 제1심의 소송절차','O','논리적으로 관계가 없어 단순병합으로 구하여야 할 수개의 청구를 선택적으로 병합한 경우, 제1심이 그 중 하나만 인용하고 나머지 심리·판단을 생략한 판결에 피고만이 항소하였다면 나머지 심리·판단하지 않은 청구는 여전히 제1심에 남아 있게 된다.','판례',1,false),
(1027,1,'제253조','제2편 제1심의 소송절차','O','본래적 급부청구에 집행불능에 대비한 전보배상청구를 병합한 것은 현재의 급부청구와 장래의 급부청구의 단순병합에 해당한다.','판례',2,false),
(1028,1,'제253조','제2편 제1심의 소송절차','O','병합의 형태가 선택적 병합인지 예비적 병합인지는 당사자의 의사가 아닌 병합청구의 성질을 기준으로 판단한다.','판례',1,false),
(1029,1,'제253조','제2편 제1심의 소송절차','O','통상의 민사사건과 가처분 이의사건은 절차의 성격이 달라 병합할 수 없다.','판례',1,false),
(1030,1,'제253조','제2편 제1심의 소송절차','O','주위적 청구와 동일한 목적물에 관하여 동일한 청구원인을 내용으로 하면서 주위적 청구를 양적·질적으로 일부 감축하여 하는 청구는 주위적 청구에 흡수될 뿐 소송상의 예비적 청구라고 할 수 없다.','대판(예비적 청구)',1,false),
(1031,1,'제253조','제2편 제1심의 소송절차','O','주위적·예비적 병합 사건에서 주위적 청구를 인용하는 제1심판결에 대하여 항소하면, 제1심에서 심판받지 않은 예비적 청구도 모두 이심된다.','대판(예비적 이심)',2,false),
(1032,1,'제253조','제2편 제1심의 소송절차','O','단순병합 관계의 청구를 주위적·예비적으로 청구하였더라도 그 실질은 단순병합이므로, 1심이 모두 판단한 이상 피고가 인용 청구에만 항소하여도 나머지 청구 부분도 함께 이심된다.','대판(부진정 예비적병합)',1,false),
(1033,1,'제253조','제2편 제1심의 소송절차','O','실질적으로 선택적 병합 관계에 있는 두 청구를 당사자가 주위적·예비적으로 순위를 붙여 청구하였고, 1심이 주위적 기각·예비적 인용 판결을 하여 피고만이 항소한 경우에도, 항소심은 두 청구 모두를 심판대상으로 삼아 판단하여야 한다.','대판(부진정 선택적병합)',1,false),
(1034,1,'제253조','제2편 제1심의 소송절차','O','선택적 병합에서 1심이 하나만 판단·기각하고 나머지를 판단하지 않은 채 원고가 항소하면, 선택적 청구 전부가 이심되어 항소심 심판대상이 되고 재판의 탈루에 해당하지 않는다.','대판(선택적병합 탈루)',1,false),
(1035,1,'제253조','제2편 제1심의 소송절차','O','채권자가 본래적 급부청구에 그것이 판결확정 후 이행불능·집행불능이 된 경우에 대비한 대상청구를 병합하여 소구한 경우, 양자의 경합은 현재의 급부청구와 장래의 급부청구의 단순병합에 속한다.','대판(대상청구 단순병합)',1,false),
(1036,1,'제253조','제2편 제1심의 소송절차','O','논리적으로 전혀 관계가 없어 순수하게 단순병합으로 구하여야 할 수개의 청구를 선택적 또는 예비적 청구로 병합하여 청구하는 것은 부적법하여 허용되지 않는다.','대판(부진정 병합)',2,false),
(1037,1,'제253조','제2편 제1심의 소송절차','O','매매대금 지급청구(주위적)를 인용한 판결에 피고가 항소하면, 매매목적물 반환청구(예비적)도 항소심에 이심되고 심판대상이 된다.','대판(예비적 청구 이심)',1,false),
(1038,1,'제253조','제2편 제1심의 소송절차','O','법원은 매매대금 지급청구(주위적)를 먼저 심리하여 인용되면 매매목적물 반환청구(예비적)를 심판할 필요가 없다.','대판(예비적 병합 심판순서)',1,false),
(1039,1,'제253조','제2편 제1심의 소송절차','O','매매대금 지급청구를 기각하면서 매매목적물 반환청구를 인용한 항소심판결에 대하여 피고만이 상고하고 원고는 상고·부대상고를 하지 않은 경우, 매매대금 지급청구는 상고심 판결 선고시에 확정된다.','대판(예비적 병합 확정시기)',1,false),
(1040,1,'제253조','제2편 제1심의 소송절차','O','주위적·예비적 청구는 불가분이므로, 주위적 청구를 배척하면서 예비적 청구 판단을 누락하였더라도 그 예비적 청구는 재판누락이 아니라 상소로 이심되어 상소심 심판대상이 된다.','대판(예비적 청구 판단누락)',3,false),
(1041,1,'제253조','제2편 제1심의 소송절차','O','청구의 예비적 병합에서 주위적 청구를 배척하고 예비적 청구를 인용하는 경우에는, 판결 주문에 주위적 청구를 기각한다는 뜻과 예비적 청구를 인용한다는 뜻을 다같이 표시하여야 한다.','대판(예비적 병합 주문)',1,false),
(1042,1,'제253조','제2편 제1심의 소송절차','O','선택적 병합에서 그 중 하나의 청구를 인용한 판결에 대하여 피고가 항소한 경우, 제1심이 판단하지 않은 나머지 청구도 항소심으로 이심되어 심판대상이 된다.','대판(선택적 병합 이심)',1,false),
(1043,1,'제253조','제2편 제1심의 소송절차','O','예비적 병합은 불가분이므로 피고만 항소하여도 불복하지 아니한 주위적 청구까지 항소심으로 이심되어 심판대상이 된다.','대판(예비적 병합 이심)',1,false),
(1044,1,'제253조','제2편 제1심의 소송절차','O','예비적 청구는 주위적 청구와 서로 논리적으로 양립할 수 없는 모순관계에 있어야 한다.','대판(예비적 병합)',1,false),
(1045,1,'제253조','제2편 제1심의 소송절차','O','주위적으로 무조건적 이전등기 이행을, 예비적으로 금전 지급과 상환으로 이전등기 이행을 구하는 경우는 소송상의 예비적 청구라고 볼 수 없다.','대판(부진정 예비적)',1,false),
(1046,1,'제253조','제2편 제1심의 소송절차','O','통상의 민사사건과 비송사건은 서로 병합이 허용되지 않는다.','통설',1,false),
(1047,1,'제253조','제2편 제1심의 소송절차','O','선택적 병합에서 하나의 청구를 인용한 판결에 대하여 항소하면 판단하지 아니한 나머지 청구도 항소심으로 이심된다.','대판(선택적 병합 이심)',1,false),
(1048,1,'제254조','제2편 제1심의 소송절차','O','소장각하명령이 성립된 이상 명령정본이 당사자에게 고지되기 전에 부족한 인지를 보정하였더라도 각하명령이 위법하게 되거나 재도의 고안으로 취소할 수 있는 것은 아니다.','판례(대결 전합 2025.7.24. 2021마6542; 종전 2018마5882 변경)',2,true),
(1049,1,'제254조','제2편 제1심의 소송절차','O','보정기간 내에 흠을 보정하지 아니한 때에는 ''재판장''이 명령으로 소장을 각하한다.','민소 §254②',1,false),
(1050,1,'제254조','제2편 제1심의 소송절차','O','법인에 대하여 소장 부본을 단지 법인의 주소지로 송달하였다가 송달불능되었다는 이유만으로 주소보정을 명하고, 그 불응을 이유로 소장각하명령을 하는 것은 위법하다(대표자 주소·영업소 등으로도 송달을 시도해야 한다).','판례 대판 2003.12.12. 2003마1694; 실무제요 Ⅱ1847',1,true),
(1051,1,'제254조','제2편 제1심의 소송절차','O','인지 보정명령 이후 인지액 상당의 현금이 송달료로 납부된 사실이 확인되는 경우, 인지를 보정하는 취지로 납부한 것인지 석명을 구하고 다시 인지 보정 기회를 부여하여야 하며, 이를 하지 않은 채 소장각하명령을 하는 것은 위법하다.','판례',1,false),
(1052,1,'제254조','제2편 제1심의 소송절차','O','소장의 흠에 대한 보정명령서에 보정기한이 공란으로 되어 있어 보정기간이 언제까지인지 지정된 바 없다면, 이는 적법한 보정명령이라고 볼 수 없다.','판례(대판 1980.6.); 실무제요 Ⅰ3031',2,true),
(1053,1,'제254조','제2편 제1심의 소송절차','O','소송구조신청이 있으면 원칙적으로 기각결정 확정시까지 인지첩부의무 발생이 저지되고, 인지보정명령에 따른 보정기간 중 제기된 소송구조신청이 기각확정되면 종전 보정기간 전체가 아니라 이미 진행된 기간을 공제한 남은 보정기간 경과 시 각하명령을 할 수 있다.','판례',1,false),
(1054,1,'제254조','제2편 제1심의 소송절차','O','원칙적으로 소장의 심사는 소송요건 및 청구의 당부를 판단하는 것보다 선행되어야 한다.','판례',1,false),
(1055,1,'제254조','제2편 제1심의 소송절차','O','증거방법은 소장의 필요적 기재사항이 아니므로, 그 보정명령에 불응하였다는 이유로 소장각하명령을 할 수는 없다.','판례',1,false),
(1056,1,'제254조','제2편 제1심의 소송절차','O','소송구조신청 기각결정 확정 시 종전 보정기간 전체가 아니라 이미 진행된 기간을 공제한 ''남은 보정기간''이 경과한 때에 각하명령을 할 수 있다(사안의 날짜 계산상 2.20.에는 아직 각하할 수 없다).','대판(소송구조 보정기간)',1,false),
(1057,1,'제254조','제2편 제1심의 소송절차','O','결정·명령은 그 원본이 법원사무관등에게 교부되었을 때 성립하므로, 각하명령이 성립한 이상 그 명령정본이 당사자에게 고지되기 전에 부족한 인지를 보정하였다 하여도 각하명령이 위법한 것으로 되는 것은 아니다.','대판(전합) 2021마6542',1,false),
(1058,1,'제254조','제2편 제1심의 소송절차','O','원고가 소장 제출 시 인지를 첩부하지 아니하고 소송구조신청을 한 경우, 그 구조신청에 대한 기각결정이 확정되기 전에는 인지 미첩부를 이유로 소장을 각하하여서는 안 된다.','대판(소송구조 중 각하)',1,false),
(1059,1,'제254조','제2편 제1심의 소송절차','O','재판장의 소장각하명령에 대하여는 즉시항고를 할 수 있다.','민소 §254③',1,false),
(1060,1,'제254조','제2편 제1심의 소송절차','O','소장에 대표자의 표시가 되어 있는 이상 그 표시에 잘못이 있더라도 이를 정정하라는 보정명령을 하고 그 불응을 이유로 소장을 각하하는 것은 허용되지 않고, 이러한 경우에는 판결로써 소를 각하할 수 있을 뿐이다.','판례',3,false),
(1061,1,'제254조','제2편 제1심의 소송절차','O','원고가 소장에 인지를 붙이지 아니한 경우 재판장은 상당한 기간을 정하여 보정을 명하여야 하고, 인지보정명령에 대하여는 독립하여 이의신청이나 항고를 할 수 없다.','대판(인지보정명령 불복)',2,false),
(1062,1,'제254조','제2편 제1심의 소송절차','O','인지 상당액을 잘못하여 송달료로 납부한 경우, 재판장이 인지 보정 취지인지 석명을 구하고 보정 기회를 부여하지 아니한 채 소장·상소장을 각하하는 것은 위법하다.','대판(송달료 오납 석명)',1,false),
(1063,1,'제254조','제2편 제1심의 소송절차','O','인지보정명령에 대하여는 독립하여 이의신청이나 항고를 할 수 없고, 다만 인지를 보정하지 아니하여 소장·상소장이 각하되면 그 각하명령에 대하여 즉시항고로 다툴 수밖에 없다.','대판(인지보정명령 불복)',1,false),
(1064,1,'제254조','제2편 제1심의 소송절차','O','소장 심사 시 재판권 없음이 명백하면 재판장은 명령으로 소장을 각하할 수 있다.','대판(재판권 소장각하)',1,false),
(1065,1,'제255조','제2편 제1심의 소송절차','O','재판장은 원고에게 기간을 정하여 피고에 대한 송달 가능한 주소를 보정할 것을 명한다.','민소 §255',1,false),
(1066,1,'제255조','제2편 제1심의 소송절차','O','원고가 보정명령에서 정한 기간이 지나도록 보정을 하지 않으면 재판장은 소장각하명령을 한다.','민소 §255②',1,false),
(1067,1,'제255조','제2편 제1심의 소송절차','O','보정명령에 따라 원고가 주소를 보정하였으나 그 주소로의 송달불능으로 되면 다시 보정명령을 하여야 한다.','실무',1,false),
(1068,1,'제256조','제2편 제1심의 소송절차','O','피고가 공시송달의 방법으로 소장 부본을 송달받은 경우가 아니라면, 원고의 청구를 다투는 경우 소장 부본을 송달받은 날부터 30일 이내에 답변서를 제출하여야 한다.','민소 §256①',2,false),
(1069,1,'제257조','제2편 제1심의 소송절차','O','무변론판결이 선고되기 전까지 피고가 원고의 청구를 다투는 취지의 답변서를 제출한 경우에는 무변론판결을 할 수 없다.','민소 §257①',2,false),
(1070,1,'제257조','제2편 제1심의 소송절차','O','피고가 청구원인 사실을 모두 자백하는 취지의 답변서를 제출하고 항변하지 않은 때에는 무변론판결을 할 수 있다.','민소 §257①',2,false),
(1071,1,'제257조','제2편 제1심의 소송절차','O','직권으로 조사할 사항이 있는 경우에는 무변론판결을 할 수 없다.','민소 §257① 단서',3,false),
(1072,1,'제257조','제2편 제1심의 소송절차','O','피고가 답변서를 제출하였더라도 청구원인 사실을 모두 자백하고 따로 항변하지 않는 취지이면 변론 없이 판결할 수 있으므로, 무변론판결이 답변서 미제출의 경우에만 가능한 것은 아니다.','민소 §257',1,false),
(1073,1,'제257조','제2편 제1심의 소송절차','O','법원은 피고가 소장 부본을 송달받은 날부터 30일의 답변서 제출기간 내에 답변서를 제출하지 아니한 때에는 청구의 원인이 된 사실을 자백한 것으로 보고 변론 없이 판결할 수 있다.','민소 §257①',1,false),
(1074,1,'제257조','제2편 제1심의 소송절차','O','법원은 피고가 답변서를 제출하지 아니한 때에는 변론 없이 판결할 수 있다.','민소 §257①',1,false),
(1075,1,'제257조','제2편 제1심의 소송절차','O','무변론판결 선고 전까지 청구원인을 다투는 답변서를 제출하면 무변론판결을 할 수 없다.','민소 §257①',1,false),
(1076,1,'제257조','제2편 제1심의 소송절차','O','원고의 청구원인 사실에 대하여 모두 자백하는 취지의 답변서를 제출한 경우는 무변론판결의 대상이 된다.','민소 §257①',1,false),
(1077,1,'제259조','제2편 제1심의 소송절차','O','중복제소에서 전소와 후소의 판별기준은 소송계속의 발생시기, 즉 소장이 피고에게 송달된 때의 선후에 의한다.','판례',2,false),
(1078,1,'제259조','제2편 제1심의 소송절차','O','채권자대위소송이 제기된 후 채무자가 같은 내용의 별소를 제기하는 것은, 채무자가 대위소송 제기 사실을 알았는지 여부를 불문하고 중복소송으로서 금지된다.','판례',1,false),
(1079,1,'제259조','제2편 제1심의 소송절차','O','먼저 제기된 소송에서 상계 항변을 제출한 다음 그 소송계속 중에 자동채권과 동일한 채권에 기한 소송을 별도의 소나 반소로 제기하는 것도 가능하다.','판례',1,false),
(1080,1,'제259조','제2편 제1심의 소송절차','O','중복제소금지 원칙에 위배되어 제기된 소에 대한 판결이나 그 소송절차에서 이루어진 화해라도 확정된 경우에는 당연무효라고 할 수 없다.','판례',1,false),
(1081,1,'제259조','제2편 제1심의 소송절차','O','채무자가 제3채무자를 상대로 제기한 이행의 소가 계속 중인 경우, 압류채권자가 제3채무자를 상대로 제기한 추심의 소는 채무자의 이행의 소에 대한 관계에서 중복제소에 해당하지 않는다.','대판(전합) 2013다202120',2,false),
(1082,1,'제259조','제2편 제1심의 소송절차','O','(이행청구소송 계속 중 채무자측의 채무부존재확인 별소의 중복제소 해당 여부에 관한 부분 — 해설상 옳지 않은 지문).','판례',1,true),
(1083,1,'제259조','제2편 제1심의 소송절차','O','명시적으로 일부청구임을 유보한 경우, 전소 계속 중 나머지를 별소로 청구하여도 중복제소에 해당하지 않는다.','대판 84다552',1,false),
(1084,1,'제259조','제2편 제1심의 소송절차','O','채권자대위소송이 이미 계속 중일 때 같은 채무자의 다른 채권자가 동일한 소송물에 대하여 대위권에 기한 소를 제기하면, 시간적으로 나중에 계속된 소송은 중복제소금지에 위배되어 부적법하다.','대판 93다53092',2,false),
(1085,1,'제259조','제2편 제1심의 소송절차','O','소가 중복제소에 해당하지 아니한다는 당사자의 주장에 관하여 판단하지 않더라도 판단유탈에 해당하지 않는다.','대판 88다카25274',1,false),
(1086,1,'제259조','제2편 제1심의 소송절차','O','여러 명의 채권자가 동시에 또는 시기를 달리하여 사해행위취소 및 원상회복청구의 소를 제기한 경우 이들 소는 중복제소에 해당하지 않는다.','대판 2004다67806',1,false),
(1087,1,'제259조','제2편 제1심의 소송절차','O','전소의 소송요건에 흠이 있어 부적법하더라도, 후소의 변론종결시까지 전소가 취하·각하 등으로 그 계속이 소멸되지 않는 한 후소는 중복제소로서 부적법하다.','판례',2,false),
(1088,1,'제259조','제2편 제1심의 소송절차','O','당사자와 소송물이 동일한 소송이 시간을 달리하여 제기된 경우, 전소가 후소 변론종결 시까지 취하·각하 등으로 소송계속이 소멸되지 않으면 후소는 중복제소금지에 위반되어 부적법하다.','대판(중복제소 기준)',1,false),
(1089,1,'제259조','제2편 제1심의 소송절차','O','전소가 소송요건을 흠결하여 부적법하더라도 취하·각하로 그 소송계속이 소멸되지 않는 한 후소는 중복제소금지에 위배된다.','대판 97다45532',1,false),
(1090,1,'제259조','제2편 제1심의 소송절차','O','채권자들이 동시 또는 이시에 채권자취소 및 원상회복소송을 제기한 경우 이들 소송은 중복제소에 해당하지 아니한다.','대판(사해행위 중복)',1,false),
(1091,1,'제259조','제2편 제1심의 소송절차','O','채권자대위소송 계속 중 다른 채권자가 동일한 채권에 관하여 다시 대위소송을 제기하면, 나중에 계속된 후소는 중복제소에 해당하여 부적법하다.','대판(대위 중복제소)',1,false),
(1092,1,'제259조','제2편 제1심의 소송절차','O','채권자대위소송 계속 중에 다른 채권자가 동일한 소송물에 대하여 대위권에 기한 소를 제기하면 중복소송에 해당한다.','대판(대위 중복)',1,false),
(1093,1,'제259조','제2편 제1심의 소송절차','O','채권자대위소송 계속 중 다른 채권자가 같은 채무자를 대위하여 같은 제3채무자를 상대로 소를 제기한 경우, 두 소송의 소송물이 같다면 나중에 계속된 소는 중복제소금지에 위배되어 부적법하다.','대판(대위 중복)',1,false),
(1094,1,'제259조','제2편 제1심의 소송절차','O','채권자취소소송 계속 중 다른 채권자가 동일한 사해행위에 대하여 채권자취소소송을 제기한 경우 중복제소에 해당하지 아니한다.','대판(사해행위 중복)',1,false),
(1095,1,'제259조','제2편 제1심의 소송절차','O','명시적으로 일부청구임을 유보한 때에는 그 일부청구 소송 계속 중 유보한 나머지 청구를 별도 소송으로 제기하더라도 중복제소에 해당하지 아니한다.','대판(명시적 일부청구)',1,false),
(1096,1,'제259조','제2편 제1심의 소송절차','O','채권자취소권의 요건을 갖춘 각 채권자는 고유의 권리로 사해행위를 취소하고 원상회복을 구할 수 있으므로, 여러 채권자가 동시·이시에 사해행위취소 및 원상회복청구의 소를 제기하여도 중복제소에 해당하지 아니한다.','대판(사해행위 중복)',1,false),
(1097,1,'제259조','제2편 제1심의 소송절차','O','채권자대위소송 제기 후 채무자가 제3채무자를 상대로 같은 금전채권의 지급을 구하는 소를 제기하였다면 이는 중복소송에 해당한다.','대판(대위 후 채무자 소)',1,false),
(1098,1,'제259조','제2편 제1심의 소송절차','O','채권자대위소송 계속 중 다른 채권자가 동일 채권에 대해 제기한 대위소송은 중복제소에 해당한다.','대판(대위 중복)',1,false),
(1099,1,'제259조','제2편 제1심의 소송절차','O','중복 소제기에 해당하면 법원은 이를 직권으로 조사하여 후소를 각하하는 것이 원칙이다.','대판(중복제소 처리)',1,false),
(1100,1,'제259조','제2편 제1심의 소송절차','O','중복제소는 소송요건의 흠이므로 법원은 직권으로 후소를 (기각이 아니라) 각하한다.','민소 §259',1,false),
(1101,1,'제259조','제2편 제1심의 소송절차','O','중복제소를 간과한 본안판결이 확정된 경우 그 판결은 당연무효가 아니다.','대판(중복제소 간과)',1,false),
(1102,1,'제259조','제2편 제1심의 소송절차','O','중복제소는 같은 법원에 제기될 필요가 없고 다른 법원에 제기되어도 성립한다(당사자·소송물 동일이면 족함).','대판(중복제소)',1,false),
(1103,1,'제259조','제2편 제1심의 소송절차','O','전소가 소송요건을 구비하지 못한 경우에도 후소의 변론종결일까지 전소의 소송계속이 소멸되지 않으면 후소는 중복소송에 해당한다.','대판 97다45532',1,false),
(1104,1,'제259조','제2편 제1심의 소송절차','O','중복제소의 전후는 소송계속의 발생시점(소장 부본이 송달된 때)을 기준으로 하고 보전절차의 경료와는 관계가 없다.','대판(중복제소 기준)',1,false),
(1105,1,'제259조','제2편 제1심의 소송절차','O','채권자대위소송의 계속 중 다른 채권자가 같은 피대위채권에 관하여 대위소송을 제기하면 중복제소에 해당한다.','대판(대위소송 중복)',1,false),
(1106,1,'제259조','제2편 제1심의 소송절차','O','채권자취소소송의 계속 중에 다시 다른 채권자가 채권자취소소송을 제기하는 경우 이는 그 채권자 고유의 권리행사이므로 중복제소가 아니다.','대판(취소소송 중복)',1,false),
(1107,1,'제259조','제2편 제1심의 소송절차','O','명시적 일부청구의 경우 유보한 나머지 부분을 별도소송으로 제기하여도 소송물이 달라 중복제소에 해당하지 않는다.','대판(명시적 일부청구)',1,false),
(1108,1,'제260조','제2편 제1심의 소송절차','O','피고경정신청을 기각하는 결정에 대하여 불복이 있는 원고는 그 결정에 대하여 특별항고를 제기할 수 있다.','판례',1,false),
(1109,1,'제260조','제2편 제1심의 소송절차','O','종전의 피고에게 소장부본이 송달되었다면 피고경정신청서는 종전 피고에게 이를 송달하여야 한다.','민소 §260③',1,false),
(1110,1,'제260조','제2편 제1심의 소송절차','O','죽은 사람의 이름으로 항고를 제기하였더라도 실제로 항고를 제기한 행위자가 그 상속인이었다면, 항고장에 항고인의 표시를 잘못한 것으로 보아 이를 정정하게 하여야 한다.','판례',1,false),
(1111,1,'제260조','제2편 제1심의 소송절차','O','사망자를 피고로 제소한 뒤 상속인으로 당사자표시정정을 하면서 일부 상속인을 누락한 경우, 그 누락된 상속인을 피고로 추가하는 것은 제1심 변론종결 시까지만 가능하고 항소심에서는 추가할 수 없다.','민소 §68; 판례',1,true),
(1112,1,'제260조','제2편 제1심의 소송절차','O','실질적 피고가 상속인인 이상, 사망자를 피고로 기재하여 소를 제기하였더라도 당사자표시정정으로 상속인을 피고로 정정할 수 있다.','판례',1,false),
(1113,1,'제260조','제2편 제1심의 소송절차','O','피고 경정은 제1심 변론종결시까지 허용되지만, 당사자표시정정은 제1심은 물론 상급심에서도 허용된다.','대판(경정·표시정정)',1,false),
(1114,1,'제260조','제2편 제1심의 소송절차','O','피고 경정은 경정신청서 제출시에 시효중단·기간준수의 효과가 생기지만, 표시정정은 당초 소 제기시의 효과가 유지된다.','대판(경정 시효중단)',1,false),
(1115,1,'제260조','제2편 제1심의 소송절차','O','피고경정은 청구취지·청구원인의 기재 자체로 보아 피고 지정이 잘못된 것이 명백한 경우에 한하여 허용되고, 증거조사 결과 판명된 사실관계에 비추어 피고 지정이 잘못된 경우에는 허용되지 않는다.','대판(피고경정 요건)',1,false),
(1116,1,'제260조','제2편 제1심의 소송절차','O','개인이 설립·경영하는 학교시설을 피고로 표시하였다가 그 개인 명의로 피고 표시를 정정하는 것은 피고 경정이 아니라 당사자표시정정에 해당한다.','대판(학교 표시정정)',1,false),
(1117,1,'제260조','제2편 제1심의 소송절차','O','항소심에서 당사자표시정정이 있었다 하여도 당사자의 심급의 이익을 박탈하는 것이 아니므로 상대방의 동의가 필요하지 아니하다.','대판(항소심 표시정정)',1,false),
(1118,1,'제260조','제2편 제1심의 소송절차','O','민사소송법은 당사자 표시정정에 관한 명문 규정을 두고 있지 않고, 당사자 경정에 관하여는 피고의 경정에 대하여만 명문 규정을 두고 있다.','민소 §260',1,false),
(1119,1,'제260조','제2편 제1심의 소송절차','O','A 회사의 대표이사 B가 A 회사 명의로 제기하였어야 할 소송을 본인의 이름으로 제기한 경우, B가 원고를 A 회사로 당사자표시정정 신청을 하더라도 이는 (당사자의 동일성이 없어) 허용될 수 없다.','대판(표시정정 한계)',1,false),
(1120,1,'제260조','제2편 제1심의 소송절차','O','피고표시정정의 대상이 되는 것을 표시정정절차에 의하지 않고 피고경정의 방법을 취하였더라도, 그 실질이 표시정정이면 피고표시정정으로서의 법적 성질 및 효과를 잃지 아니한다.','대판(표시정정 실질)',1,false),
(1121,1,'제260조','제2편 제1심의 소송절차','O','피고의 경정은 제1심 변론종결시까지만 허용되고 항소심·상고심에서는 허용되지 않는다.','민소 §260',1,false),
(1122,1,'제260조','제2편 제1심의 소송절차','O','원고가 사망 사실을 모르고 사망자를 피고로 표시하여 소를 제기한 경우, 사망자의 상속인으로의 당사자표시정정이 허용된다.','대판(사망자 표시정정)',1,false),
(1123,1,'제260조','제2편 제1심의 소송절차','O','당사자표시정정은 당사자의 동일성이 유지되는 범위 내에서 항소심에서도 허용된다.','대판(표시정정 심급)',1,false),
(1124,1,'제260조','제2편 제1심의 소송절차','O','갑을 공동선조로 하는 종중을 갑의 후손인 을을 공동선조로 하는 종중으로 변경하는 것은 (당사자 동일성이 없어) 허용되지 않는다.','대판(종중 변경)',1,false),
(1125,1,'제260조','제2편 제1심의 소송절차','O','원고 갑을 그 아버지인 원고 을로 변경하는 것은 (당사자 동일성이 없어) 허용되지 않는다.','대판(당사자 변경)',1,false),
(1126,1,'제260조','제2편 제1심의 소송절차','O','누가 수급인인지는 본안의 실체판단 문제이므로, 명의인을 수급인으로 잘못 안 것은 ''피고를 잘못 지정한 것이 명백한 때''에 해당하지 않아 피고경정이 허용되지 않는다.','대판(피고경정)',1,true),
(1127,1,'제260조','제2편 제1심의 소송절차','O','주식회사를 피고로 하여야 하는데 잘못하여 그 대표이사 개인을 피고로 제소하였다가 소송 계속 중 피고를 주식회사로 (당사자표시정정으로) 바꾸는 것은 허용된다.','대판(당사자표시정정 한계)',1,true),
(1128,1,'제260조','제2편 제1심의 소송절차','O','피고경정신청은 본소 제기 후 제1심 변론종결시까지 할 것을 요한다.','민소 §260①',1,false),
(1129,1,'제260조','제2편 제1심의 소송절차','O','종전 피고가 경정신청서를 송달받은 날부터 2주 이내에 이의를 제기하지 아니하면 동의한 것으로 본다.','민소 §260④',1,false),
(1130,1,'제260조','제2편 제1심의 소송절차','O','피고의 교체 전후를 통하여 소송물이 동일하여야 한다.','대판(피고경정)',1,false),
(1131,1,'제260조','제2편 제1심의 소송절차','O','피고경정신청을 허가하는 결정에 대하여는 동의가 없었다는 사유로만 즉시항고를 할 수 있다.','민소 §261③',1,false),
(1132,1,'제260조','제2편 제1심의 소송절차','O','사망자를 피고로 잘못 표시하여 제소한 경우에도 실질적 피고는 상속인이므로 당사자표시정정으로 피고를 상속인으로 바로잡는 것이 허용된다.','대판(사망자 피고 표시정정)',1,false),
(1133,1,'제261조','제2편 제1심의 소송절차','O','경정을 허가하는 결정에 대하여 종전 피고는 경정에 부동의하였음을 사유로 즉시항고를 할 수 있다.','민소 §261',1,false),
(1134,1,'제261조','제2편 제1심의 소송절차','O','새로운 피고에게는 경정을 허가하는 결정이 있은 후 그 결정정본 등을 송달하는 것이고, 경정신청서 접수 단계에서 새 피고에게 신청서를 송달하여야 하는 것은 아니다.','민소 §261',1,false),
(1135,1,'제261조','제2편 제1심의 소송절차','O','부작위채무를 명하는 판결절차에서 그 의무 위반에 대비하여 간접강제(배상)를 함께 명할 수 있다.','대판(부작위 간접강제)',1,false),
(1136,1,'제262조','제2편 제1심의 소송절차','O','서면에 의하지 아니한 청구취지의 변경은 잘못이지만, 이에 대하여 상대방이 지체 없이 이의를 하지 않았다면 이의권이 상실된다.','판례',3,false),
(1137,1,'제262조','제2편 제1심의 소송절차','O','2회에 걸쳐 상고심으로부터 환송된 후 항소심 변론종결 당시에 청구를 변경하려는 것은 소송절차를 현저히 지연시키는 경우에 해당하여 청구변경을 허용하지 않았더라도 위법이라 할 수 없다.','판례',1,false),
(1138,1,'제262조','제2편 제1심의 소송절차','O','청구취지의 변경은 서면으로 신청하여야 하나, 청구원인의 변경은 반드시 서면에 의할 필요가 없고 말로 변경해도 된다.','민소 §262②',3,false),
(1139,1,'제262조','제2편 제1심의 소송절차','O','본등기청구의 피담보채권에 관한 주장을 달리하는 것은 공격방법의 변경에 불과하고 청구의 변경이 아니다.','대판(피담보채권 주장변경)',1,false),
(1140,1,'제262조','제2편 제1심의 소송절차','O','교환적 변경으로 구청구는 취하되고 신청구가 심판대상이 되었음에도 구청구에 대하여 심리·판단한 제1심판결에 항소한 경우, 항소심은 제1심판결을 취소하고 구청구에 대하여 소송종료선언을 하여야 한다.','대판(교환적 변경 소송종료선언)',1,false),
(1141,1,'제262조','제2편 제1심의 소송절차','O','항소심에서 청구가 교환적으로 변경된 경우 항소심은 신청구에 대하여 재판하며, 제1심이 (구)청구를 기각하였고 항소심이 신청구를 기각할 때에는 ''항소기각''이 아니라 신청구에 대한 ''청구기각'' 주문을 하여야 한다.','실무제요 Ⅱ3025; 민소 §262',2,true),
(1142,1,'제262조','제2편 제1심의 소송절차','O','청구변경으로 청구의 기초가 바뀌었더라도, 상대방이 지체 없이 이의하지 않고 변경된 청구의 본안 변론을 한 때에는 더 이상 청구변경의 적법 여부를 다투지 못한다.','대판(청구변경 이의권)',1,false),
(1143,1,'제262조','제2편 제1심의 소송절차','O','채권자대위권에 기한 청구를 양수금청구로 교환적으로 변경하여 구청구가 취하된 것으로 보더라도, 당초의 채권자대위소송으로 인한 시효중단의 효력은 소멸하지 않는다.','대판(대위→양수금 변경)',2,false),
(1144,1,'제262조','제2편 제1심의 소송절차','O','피고만이 항소한 항소심에서 소의 교환적 변경이 적법하게 이루어진 후 피고가 항소를 취하한 경우, 제1심판결은 교환적 변경에 의한 소취하로 실효되고 항소심은 교환된 새 소송을 사실상 제1심으로 재판하므로, 그 항소취하는 대상이 없어 아무런 효력을 발생할 수 없다.','대판(교환적 변경 후 항소취하)',2,false),
(1145,1,'제262조','제2편 제1심의 소송절차','O','원고 패소의 제1심판결에 대하여 원고가 항소한 후 항소심에서 예비적 청구를 추가하였는데 항소심이 종래의 주위적 청구에 대한 항소가 이유 없다고 판단한 경우에는, 예비적 청구에 대하여 제1심으로 판단하여야 한다.','대판(항소심 예비적 추가)',1,false),
(1146,1,'제262조','제2편 제1심의 소송절차','O','상고심에서는 청구의 변경이 허용되지 않는다.','대판(상고심 청구변경)',2,false),
(1147,1,'제262조','제2편 제1심의 소송절차','O','당사자가 구청구를 취하한다는 명백한 의사표시 없이 청구를 변경하는 등 그 변경형태가 불분명한 경우, 사실심법원은 청구변경의 취지가 교환적인가 추가적인가 또는 선택적인가를 석명할 의무가 있다.','대판(청구변경 석명)',1,false),
(1148,1,'제262조','제2편 제1심의 소송절차','O','사해행위취소의 소에서 피보전채권을 추가하거나 교환하는 것은 공격방법의 변경에 불과하고 청구(소송물)의 변경에 해당하지 않는다.','대판(사해행위 피보전채권)',1,false),
(1149,1,'제262조','제2편 제1심의 소송절차','O','동일 부동산에 대하여 이전등기를 구하면서 그 등기청구권의 발생원인을 처음에는 매매로 하였다가 후에 취득시효의 완성을 선택적으로 추가하는 것은 별개의 청구를 추가시킨 것이다.','대판(이전등기 소송물)',1,false),
(1150,1,'제262조','제2편 제1심의 소송절차','O','채권자가 사해행위의 취소를 청구하면서 그 보전하고자 하는 채권을 추가하거나 교환하는 것은 소(청구)의 변경이라 할 수 없다.','대판(사해행위 피보전채권)',1,false),
(1151,1,'제262조','제2편 제1심의 소송절차','O','상환이행청구에서 단순이행청구로 바꾸는 것과 같은 질적 확장도 청구의 변경에 해당한다.','대판(질적 변경)',1,false),
(1152,1,'제262조','제2편 제1심의 소송절차','O','청구의 교환적 변경에서는 원고의 청구변경 의사표시로 구청구 취하와 신청구 추가가 이루어지므로, 피고가 본안에 응소한 경우에도 구청구 취하에 피고의 별도 동의를 요하는 것은 아니다(2013 문16 공식정답 ②).','대판(교환적 변경)',1,true),
(1153,1,'제262조','제2편 제1심의 소송절차','O','청구기초의 동일성을 요구하는 이유는 피고의 방어이익을 보호하려는 것이므로, 피고의 이의가 없으면 청구기초가 동일하지 않은 변경도 허용된다.','대판(청구기초 동일성)',1,false),
(1154,1,'제262조','제2편 제1심의 소송절차','O','피고의 항소로 인한 항소심에서 소의 교환적 변경이 적법하게 이루어지면 제1심판결은 소취하로 실효되므로, 그 후 피고의 항소취하는 대상이 없어 효력이 없고 제1심판결이 그대로 확정되는 것이 아니다.','대판(교환적 변경 후 항소취하)',1,false),
(1155,1,'제262조','제2편 제1심의 소송절차','O','매매를 원인으로 한 소유권이전등기청구소송에서 청구원인에 취득시효 완성을 추가하는 것은 소의 추가적 변경에 해당한다.','대판(청구원인 추가)',1,false),
(1156,1,'제262조','제2편 제1심의 소송절차','O','항소심에서도 청구의 교환적 변경은 허용된다.','대판(항소심 교환적 변경)',1,false),
(1157,1,'제262조','제2편 제1심의 소송절차','O','청구의 변경은 반드시 서면에 의하여야 하는 것은 아니다.','민소 §262②',1,true),
(1158,1,'제262조','제2편 제1심의 소송절차','O','청구취지를 확장하는 경우 추가로 붙일 인지액은 확장 후 소가에 대한 인지액에서 확장 전 소가에 대한 인지액을 뺀 차액이다(단순히 소가의 차액을 기준으로 계산하는 것이 아니다).','인지법',1,true),
(1159,1,'제262조','제2편 제1심의 소송절차','O','청구를 감축하는 경우에는 인지를 붙이지 않는다.','인지법',1,false),
(1160,1,'제262조','제2편 제1심의 소송절차','O','청구의 변경은 사실심 변론종결 전까지 가능하다.','민소 §262①',1,false),
(1161,1,'제262조','제2편 제1심의 소송절차','O','가압류·가처분(보전)사건에서 본안소송으로의 청구변경은 절차가 다르므로 허용되지 않는다.','대판(보전·본안)',1,false),
(1162,1,'제262조','제2편 제1심의 소송절차','O','청구의 변경은 청구의 기초가 바뀌지 아니할 것을 그 요건으로 한다.','민소 §262①',1,false),
(1163,1,'제262조','제2편 제1심의 소송절차','O','결의취소사유를 부존재·무효사유로 주장하여 그 확인의 소를 취소 제소기간 내에 제기한 후 취소소송으로 변경한 경우에는 당초의 소 제기 시에 제소기간을 준수한 것으로 본다.','대판 2003다35215',1,false),
(1164,1,'제262조','제2편 제1심의 소송절차','O','제1심에서 전부 승소한 원고라도 상대방이 제기한 항소로 항소심이 계속되는 중에는 그 청구취지를 확장·변경할 수 있다.','대판(전부승소 원고 변경)',1,false),
(1165,1,'제262조','제2편 제1심의 소송절차','O','항소심에서 청구가 교환적으로 변경된 경우에는 구청구는 취하되고 신청구가 심판의 대상이 된다.','대판(교환적 변경)',1,false),
(1166,1,'제263조','제2편 제1심의 소송절차','O','청구변경 불허가결정은 종국판결 전의 중간적 재판이므로 독립하여 항고할 수 없다.','판례',1,false),
(1167,1,'제263조','제2편 제1심의 소송절차','O','청구변경이 부적법하면 법원은 변경을 불허하는 재판을 할 뿐이고 소각하판결을 하는 것이 아니다.','민소 §263',1,false),
(1168,1,'제263조','제2편 제1심의 소송절차','O','의사의 진술을 명하는 판결은 확정과 동시에 의사를 진술한 것으로 간주되므로, 그 의사진술이 어떤 법적 효과를 가지는 경우에는 소로써 구할 이익이 있지만, 아무런 법적 효과가 발생하지 아니할 경우에는 소로써 청구할 법률상 이익이 없다.','대판(의사진술 판결)',1,false),
(1169,1,'제263조','제2편 제1심의 소송절차','O','법원이 청구의 취지 또는 원인의 변경이 옳지 아니하다고 인정한 때에는 직권으로 또는 상대방의 신청에 따라 변경을 허가하지 아니하는 결정을 하여야 한다.','민소 §263',1,false),
(1170,1,'제264조','제2편 제1심의 소송절차','O','중간확인의 소를 제기할 때에는 서면으로 하여야 하고, 그 서면은 상대방에게 송달하여야 한다.','민소 §264',1,false),
(1171,1,'제264조','제2편 제1심의 소송절차','O','재심 소송절차에서 중간확인의 소는 재심청구 인용을 전제로 재심대상소송 본안청구에 선결관계에 있는 법률관계 확인을 구하는 것이므로, 재심사유가 인정되지 않아 재심청구를 기각하는 경우에는 중간확인의 소의 선결적 법률관계 존부를 심리할 필요가 없다.','판례',1,false),
(1172,1,'제264조','제2편 제1심의 소송절차','O','중간확인의 소는 항소심에서도 제기할 수 있다.','민소 §264',1,false),
(1173,1,'제264조','제2편 제1심의 소송절차','O','중간확인의 소는 독립한 소이므로 그에 대한 판단은 종국판결의 주문에 표시하여야 한다.','판례',1,false),
(1174,1,'제264조','제2편 제1심의 소송절차','O','중간확인의 소는 소송중의 소이다.','통설',1,false),
(1175,1,'제265조','제2편 제1심의 소송절차','O','채권자대위소송 중 피대위채권을 양수하여 양수금청구로 변경하더라도 당초 대위소송 제기로 인한 시효중단의 효력은 소멸하지 않는다.','대판 2010.6.24. 2010다17284',1,false),
(1176,1,'제265조','제2편 제1심의 소송절차','O','시효중단이나 법률상 기간 준수의 효력은 소변경신청서를 제출한 때에 발생한다.','민소 §265',1,false),
(1177,1,'제265조','제2편 제1심의 소송절차','O','채권 일부만 청구해도 전부에 관하여 판결을 구하는 취지로 해석되면 동일성 범위 내 전부에 시효중단 효력이 생기고, 이는 불법행위 손해배상채권의 지연손해금청구에도 적용된다.','대판 99다72521',1,false),
(1178,1,'제265조','제2편 제1심의 소송절차','O','소송고지에 의한 최고의 시효중단 효력은 소송고지서가 송달된 때가 아니라 고지자가 소송고지서를 법원에 제출한 때에 발생한다.','대판(소송고지 최고)',1,false),
(1179,1,'제265조','제2편 제1심의 소송절차','O','부동산 공유자의 1인은 제3자 명의로 원인무효의 소유권이전등기가 경료되어 있는 경우, 공유물의 보존행위로서 제3자에 대하여 그 등기 전부의 말소를 구할 수 있다.','대판(공유 보존행위)',1,false),
(1180,1,'제265조','제2편 제1심의 소송절차','O','공유자의 1인은 단독 명의로 등기한 다른 공유자에 대하여 자신의 공유지분 범위 내에서만 (경정)등기를 구할 수 있고, 공유지분 전부의 말소를 보존행위로 구할 수는 없다.','대판(공유자 경정등기)',1,false),
(1181,1,'제265조','제2편 제1심의 소송절차','O','대여금 채권의 지급을 확보하기 위하여 약속어음을 교부받은 채권자가 약속어음금의 지급을 구하는 소를 제기한 때에는, 그 대여금 채권의 소멸시효도 중단된다.','대판(어음금 소 시효중단)',1,false),
(1182,1,'제265조','제2편 제1심의 소송절차','O','해고무효확인의 소의 제기는 그 고용관계에서 파생하는 보수채권에 대하여도 재판상 청구에 준하는 시효중단의 효력이 있다.','대판 2011다19737',1,false),
(1183,1,'제265조','제2편 제1심의 소송절차','O','물상보증인이 제기한 저당권설정등기 말소청구소송에서 채권자가 청구기각을 구하며 피담보채권의 존재를 적극 주장하더라도, 그 피담보채권에 관하여 (채무자에 대한) 소멸시효 중단의 효력이 생기지 않는다.','대판(물상보증인 응소)',1,false),
(1184,1,'제265조','제2편 제1심의 소송절차','O','소송고지에 의한 최고의 경우 6월 기간의 기산점은 소송고지서가 송달된 때가 아니라 그 고지된 소송이 종료된 때이다.','대판 2009다26831',1,false),
(1185,1,'제265조','제2편 제1심의 소송절차','O','권리자가 피고로서 응소하여 적극적으로 권리를 주장하고 그것이 받아들여진 경우, 시효중단사유인 재판상의 청구에 해당한다.','대판(응소 시효중단)',1,false),
(1186,1,'제265조','제2편 제1심의 소송절차','O','채권자가 동일한 목적을 달성하기 위하여 복수의 채권을 갖고 있는 경우, 특별한 사정이 없는 한 그 중 어느 하나의 채권을 행사하는 것이 다른 채권에 대한 소멸시효 중단의 효력이 있다고 할 수 없다.','대판(복수채권 시효)',1,false),
(1187,1,'제265조','제2편 제1심의 소송절차','O','근저당권설정등기청구의 소 제기는 그 피담보채권이 될 채권에 대한 소멸시효 중단사유가 될 수 있다.','대판(근저당설정청구 시효중단)',1,false),
(1188,1,'제265조','제2편 제1심의 소송절차','O','재판상 청구로 인한 시효중단의 효력은 소를 제기한 때(소장을 법원에 제출한 때)에 발생한다.','민소 §265',1,false),
(1189,1,'제265조','제2편 제1심의 소송절차','O','청구의 변경에 의한 시효중단·기간준수의 효과는 소변경서를 법원에 제출한 때에 발생한다.','민소 §262②·§265',1,true),
(1190,1,'제265조','제2편 제1심의 소송절차','O','소제기에 의한 시효중단의 효력은 소를 제기한 때에 발생한다.','민소 §265',2,false),
(1191,1,'제265조','제2편 제1심의 소송절차','O','토지의 공유자는 단독으로 그 토지의 불법점유자에 대하여 명도(인도)를 구할 수 있다(보존행위).','대판(공유 보존행위)',1,false),
(1192,1,'제265조','제2편 제1심의 소송절차','O','소의 변경에 의한 시효중단의 효과는 소 변경의 서면을 법원에 제출한 때에 발생한다.','대판(소변경 시효중단)',2,false),
(1193,1,'제265조','제2편 제1심의 소송절차','O','신체감정 결과에 따라 청구금액을 확장할 것을 전제로 우선 일부 손해배상을 청구한 경우, 소 제기로 인한 시효중단의 효력은 손해배상채권의 동일성 범위 내에서 채권 전부에 미친다.','대판(확장 전제 일부청구)',1,false),
(1194,1,'제265조','제2편 제1심의 소송절차','O','소의 추가적 변경이 있는 경우 시효중단의 효력은 소변경신청서 부본을 상대방에게 송달한 때가 아니라 소변경신청서를 법원에 제출한 때 발생한다.','대판(소변경 시효중단)',1,false),
(1195,1,'제266조','제2편 제1심의 소송절차','O','소의 취하는 상대방이 본안에 관하여 준비서면을 제출하거나 변론준비기일에서 진술하거나 변론을 한 뒤에는 상대방의 동의를 받아야 효력을 가지나, 항소의 취하는 상대방의 동의 없이 일방적으로 할 수 있다.','민소 §266②',4,false),
(1196,1,'제266조','제2편 제1심의 소송절차','O','소의 취하는 소의 일부에 대하여도 할 수 있으나, 항소의 취하는 항소의 전부에 대하여 하여야 하고 항소의 일부 취하는 효력이 없다.','판례',1,false),
(1197,1,'제266조','제2편 제1심의 소송절차','O','청구의 감축(소의 일부취하)에 대한 상대방의 동의는 묵시적으로도 할 수 있고 반드시 명시적으로 표시되어야 하는 것은 아니다.','판례',1,false),
(1198,1,'제266조','제2편 제1심의 소송절차','O','환송판결 전에 소취하 합의가 있었으나, 환송 후 원심 변론기일에서 이를 주장하지 않은 채 본안에 관하여 변론하는 등 계속 응소한 피고가 상고심에 이르러서야 소취하 합의 사실을 주장하는 경우, 그 소취하 합의는 묵시적으로 해제되었다고 봄이 상당하다.','판례',1,false),
(1199,1,'제266조','제2편 제1심의 소송절차','O','소의 취하는 판결이 확정되기 전까지 할 수 있으므로 상고심에서도 소를 취하할 수 있다.','민소 §266①',5,false),
(1200,1,'제266조','제2편 제1심의 소송절차','O','재판상 화해조서에 다른 소송을 취하하기로 하는 내용이 포함되어 있더라도, 그것만으로 곧바로 그 다른 소송의 소취하 효력이 발생하는 것은 아니다(별도의 소취하가 필요).','대판(화해조서 소취하 약정)',1,false);
insert into atoms(id,subject_id,article_no,pyeon,ans,statement,ref,freq,verified) values
(1201,1,'제266조','제2편 제1심의 소송절차','O','원고의 소취하에 대하여 피고가 일단 확정적으로 동의를 거절하면 원고의 소취하는 효력이 발생하지 않고, 이후 피고가 동의하더라도 소취하의 효력이 다시 생기지 않는다.','대판(동의 거절)',1,false),
(1202,1,'제266조','제2편 제1심의 소송절차','O','소취하의 서면이 송달된 날부터 2주 이내에 상대방이 이의를 제기하지 아니한 경우에는 소취하에 동의한 것으로 본다.','민소 §266⑥',1,false),
(1203,1,'제266조','제2편 제1심의 소송절차','O','원고 소송대리인으로부터 사임신고서 제출을 지시받은 사무원은 원고 소송대리인의 표시기관에 해당하므로 그의 착오는 소송대리인의 착오로 보아야 하고, 그 사무원의 착오로 소송대리인의 의사에 반하여 소를 취하하였더라도 이를 무효라고 볼 수 없다.','대판(표시기관 착오)',1,false),
(1204,1,'제266조','제2편 제1심의 소송절차','O','소의 취하는 그 서면이 법원에 제출된 때에 효력이 발생하므로, 상대방에게 송달되기 전이라도 원고가 이를 임의로 철회할 수 없다.','대판(소취하 철회)',2,false),
(1205,1,'제266조','제2편 제1심의 소송절차','O','당사자가 소취하서를 작성하여 제출할 경우 반드시 취하권자나 그 포괄승계인만이 제출하여야 하는 것은 아니고 제3자에 의한 제출도 허용되며, 상대방에게 소취하서를 교부하여 제출하게 하는 것도 무방하다.','대판(소취하서 제출자)',1,false),
(1206,1,'제266조','제2편 제1심의 소송절차','O','소의 취하가 부존재 또는 무효라는 것을 주장하는 당사자는 기일지정신청을 할 수 있고, 법원이 변론을 열어 심리한 결과 신청이 이유 없다고 인정하는 경우에는 판결로 소송종료를 선언하여야 한다.','규칙 §67',1,false),
(1207,1,'제266조','제2편 제1심의 소송절차','O','재판상 화해에서 계속 중인 다른 소송을 취하하기로 하는 화해조서가 작성된 경우, 그 다른 소송 계속 법원에 취하서를 제출하지 않는 이상 소송이 취하로 종결되지는 않지만, 그 화해가 취소·변경되는 등의 특별한 사정이 없는 한 그 원고에게는 권리보호의 이익이 없어 소가 각하되어야 한다.','대판(화해조서 취하약정)',1,false),
(1208,1,'제266조','제2편 제1심의 소송절차','O','제3자에 의한 소취하서의 제출도 허용되고, 상대방에게 소취하서를 교부하여 그로 하여금 제출하게 하는 것도 무방하다.','대판(소취하서 제출자)',1,false),
(1209,1,'제266조','제2편 제1심의 소송절차','O','소의 취하는 서면으로 하여야 하나, 다만 변론 또는 변론준비기일에서는 말로 할 수 있다.','민소 §266③',1,false),
(1210,1,'제266조','제2편 제1심의 소송절차','O','소 취하의 효력을 다투면서 기일지정신청을 한 경우 (취하가 유효하면) 소송종료선언을 하여야 한다.','규칙 §67',1,false),
(1211,1,'제266조','제2편 제1심의 소송절차','O','소의 취하는 원고의 소제기 후 판결이 확정되기까지 어느 때라도 할 수 있다.','민소 §266①',2,false),
(1212,1,'제266조','제2편 제1심의 소송절차','O','피고가 본안에 관하여 준비서면을 제출한 경우 원고가 소를 취하하려면 피고의 동의를 요한다.','민소 §266②',1,false),
(1213,1,'제266조','제2편 제1심의 소송절차','O','소의 취하는 사실심 변론종결시까지가 아니라 판결이 확정될 때까지 그 전부나 일부를 취하할 수 있다.','민소 §266①',1,false),
(1214,1,'제266조','제2편 제1심의 소송절차','O','상대방이 본안에 관하여 준비서면을 제출한 뒤에는 상대방의 동의를 받아야 소취하의 효력이 생긴다.','민소 §266②',1,false),
(1215,1,'제266조','제2편 제1심의 소송절차','O','변론준비기일에서 말로 소를 취하할 수 있다.','민소 §266③',1,false),
(1216,1,'제266조','제2편 제1심의 소송절차','O','피고가 본안에 관한 준비서면을 제출한 후에는 변론을 하기 전이라도 소취하에 관하여 피고의 동의가 필요하다.','대판(소취하 동의)',1,false),
(1217,1,'제266조','제2편 제1심의 소송절차','O','피고가 일단 소취하에 부동의(거절)의 의사를 표시한 경우에는 그 후 이를 철회하여 동의하더라도 소취하의 효력이 생기지 않는다.','대판(소취하 부동의)',1,false),
(1218,1,'제266조','제2편 제1심의 소송절차','O','소취하서에 약칭만 기재되었더라도 사건번호·대표자 이름·피고 표시 등으로 원고의 소취하임을 인정할 수 있으면 유효하다.','대판(소취하서 해석)',1,false),
(1219,1,'제266조','제2편 제1심의 소송절차','O','취하권자에 의하여 작성된 소취하서이면 상대방이 제출하였더라도 소취하는 유효하다.','대판(소취하서 제출)',1,false),
(1220,1,'제267조','제2편 제1심의 소송절차','O','본안에 대한 종국판결이 있은 뒤에 소를 취하한 사람은 같은 소를 다시 제기하지 못한다.','민소 §267②',4,false),
(1221,1,'제267조','제2편 제1심의 소송절차','O','소가 취하된 부분에 대하여는 소송이 처음부터 계속되지 아니한 것으로 본다.','민소 §267①',1,false),
(1222,1,'제267조','제2편 제1심의 소송절차','O','본안 종국판결이 있은 뒤에 ''원고는 소를 취하하고 피고는 동의한다''는 내용의 화해권고결정이 확정되어 소송이 종결된 경우, 소취하한 경우와 마찬가지로 재소금지의 효력이 있다.','판례',1,false),
(1223,1,'제267조','제2편 제1심의 소송절차','O','후소가 전소의 소송물을 선결적 법률관계 내지 전제로 하는 것일 때에는 소송물은 다르더라도 재소금지의 취지·목적에 비추어 후소를 전소와 ''같은 소''로 보아 판결을 구할 수 없다.','판례',1,false),
(1224,1,'제267조','제2편 제1심의 소송절차','O','재소금지는 제재적 취지의 규정이므로, 본안 종국판결 후 소를 취하한 자라도 그 취지에 반하지 않고 소제기를 필요로 하는 정당한 사정이 있다면 다시 소를 제기할 수 있다.','판례',1,false),
(1225,1,'제267조','제2편 제1심의 소송절차','O','본안 종국판결 후 교환적 변경으로 취하되었던 구청구를 다시 본래의 청구로 교환적 변경하는 것은 재소금지에 저촉되어 부적법하다.','판례',1,false),
(1226,1,'제267조','제2편 제1심의 소송절차','O','항소심에서 교환적 변경으로 취하된 구청구(손해배상)를 다시 청구하는 것은 재소금지(§267②)에 저촉되어 허용되지 않는다.','대판(재소금지)',1,false),
(1227,1,'제267조','제2편 제1심의 소송절차','O','본안에 대한 종국판결이 있은 후 구청구를 신청구로 교환적 변경을 한 다음 다시 본래의 구청구로 교환적 변경을 하는 것은, 종국판결 후 소를 취하하였다가 동일한 소를 다시 제기한 경우에 해당하여 부적법하다.','대판(재소금지)',1,false),
(1228,1,'제267조','제2편 제1심의 소송절차','O','피고가 원고의 소취하의 전제조건으로 한 약정사항을 이행하지 않아 약정이 해제·실효되는 사정변경이 있으면 (재소금지에도 불구하고) 재소 제기가 가능하다.','대판(재소금지 예외)',1,false),
(1229,1,'제267조','제2편 제1심의 소송절차','O','본안판결 후 대위소송을 취하한 경우, 채무자가 대위소송이 제기된 사실을 안 경우에 한하여 재소금지의 효과가 채무자에게 미친다.','대판(대위 재소금지)',1,false),
(1230,1,'제267조','제2편 제1심의 소송절차','O','소의 취하가 있었음에도 이를 간과하고 심리를 계속 진행한 경우, 법원은 직권으로 소송종료선언을 하여야 한다.','대판(소송종료선언)',1,false),
(1231,1,'제267조','제2편 제1심의 소송절차','O','본안 종국판결 후 구청구를 신청구로 교환적 변경하면 구청구는 종국판결 후 취하된 것이 되어 재소금지에 걸리므로 다시 본래의 구청구로 교환적 변경을 할 수 없다.','대판(재소금지)',1,false),
(1232,1,'제268조','제2편 제1심의 소송절차','O','변론기일에 출석하였다가 변론하지 아니하고 임의로 퇴정하거나 소란행위 등으로 퇴정명령을 받아 퇴정당한 경우에도 기일의 해태(불출석)에 해당한다.','판례',1,false),
(1233,1,'제268조','제2편 제1심의 소송절차','O','요건을 갖추지 못한 위법한 공시송달로 당사자가 출석하지 못한 경우에는 적법한 기일통지가 없는 것이어서 쌍방 불출석의 효과가 발생하지 않는다.','판례',1,false),
(1234,1,'제268조','제2편 제1심의 소송절차','O','법인 당사자가 주소 변경을 신고하지 않아 2차에 걸친 변론기일소환장이 송달불능되어 공시송달로 진행한 결과 쌍방불출석으로 취하간주된 경우, 이는 당사자의 책임으로 돌릴 수 없는 사유로 기일을 해태한 경우라고 볼 수 없다.','대판(공시송달 쌍불)',1,false),
(1235,1,'제268조','제2편 제1심의 소송절차','O','배당이의소송에서는 첫 변론준비기일에 출석한 원고라도 첫 변론기일에 출석하지 않으면 곧바로 배당이의의 소를 취하한 것으로 본다.','대판(배당이의 첫 변론기일)',1,false),
(1236,1,'제268조','제2편 제1심의 소송절차','O','변론준비기일에서의 양쪽 불출석 효과는 변론기일에 승계되지 않으므로, 변론준비기일 1회와 변론기일 1회의 불출석만으로는 취하간주의 효과가 발생하지 않는다.','대판 2006다69141',2,false),
(1237,1,'제268조','제2편 제1심의 소송절차','O','기일지정신청은 쌍방 불출석 변론기일로부터 1월 내에 하여야 하는 것이고, 신청인이 그 사실을 안 때로부터 기산하는 것이 아니다.','대판(기일지정신청 기산)',1,false),
(1238,1,'제268조','제2편 제1심의 소송절차','O','양쪽 당사자가 변론기일에 2회 불출석한 후 1월 내에 기일지정신청을 하지 아니하거나, 그 기일지정신청에 의하여 정한 변론기일 또는 그 뒤의 변론기일에 다시 양쪽이 불출석하면 소를 취하한 것으로 본다.','민소 §268',2,false),
(1239,1,'제268조','제2편 제1심의 소송절차','O','당사자의 일방 또는 쌍방이 출석한 경우에 기일을 연기하는 것은 출석한 당사자에게 기일 해태의 효력이 생기지 않는다.','대판(기일 연기)',1,false),
(1240,1,'제268조','제2편 제1심의 소송절차','O','양쪽 당사자가 불출석한 변론기일에서는 기일 해태(쌍방 불출석)로 처리될 뿐이므로, 그 기일에 변론을 종결할 수 있는 것은 아니다.','대판(쌍불 변론종결)',1,false),
(1241,1,'제268조','제2편 제1심의 소송절차','O','변론준비기일에서 양쪽 당사자 불출석의 효과는 변론기일에 승계되지 않는다.','대판 2006다69141',1,false),
(1242,1,'제268조','제2편 제1심의 소송절차','O','항소심에서 양쪽 당사자가 변론기일에 2회 불출석하고 그로부터 1개월 이내에 기일지정신청이 없으면 항소가 취하된 것으로 본다.','민소 §268④',1,false),
(1243,1,'제268조','제2편 제1심의 소송절차','O','변론준비기일에는 기일해태의 효과가 발생할 수 있으나, 판결선고기일에는 당사자가 출석하지 않아도 선고할 수 있어 기일해태의 효과가 발생하지 않는다.','대판(기일해태 범위)',1,false),
(1244,1,'제268조','제2편 제1심의 소송절차','O','법정 외에서 한다는 특별한 사정이 없는 한 증거조사기일에도 기일해태의 효과가 발생한다.','대판(증거조사기일)',1,false),
(1245,1,'제268조','제2편 제1심의 소송절차','O','원고는 출석하지 아니하고 피고는 출석하였으나 변론을 하지 아니한 경우(쌍방 불출석), 재판장은 다시 변론기일을 정하여 양쪽 당사자에게 통지하여야 한다.','대판(쌍불 처리)',1,false),
(1246,1,'제268조','제2편 제1심의 소송절차','O','양쪽 당사자가 변론기일에 두 번 결석한 후 그로부터 1월 이내에 기일지정신청을 하지 아니하면 소를 취하한 것으로 본다.','민소 §268②',1,false),
(1247,1,'제268조','제2편 제1심의 소송절차','O','변론준비기일에서의 불출석은 변론기일에 승계되지 않으므로, 변론기일에 두 번 불출석하고 1월 내 기일지정신청이 없어야 소취하 간주된다(변론준비기일 1회 + 변론기일 2회로는 부족).','대판(변론준비기일 승계)',1,false),
(1248,1,'제268조','제2편 제1심의 소송절차','O','본소 계속 중 양쪽이 한 번 결석한 뒤 반소가 제기되고 다시 한 번 결석한 뒤 기일지정신청이 없을 때, 소취하 효과는 본소에만 미치고 반소에는 미치지 않는다.','대판(본소·반소 쌍불)',1,false),
(1249,1,'제269조','제2편 제1심의 소송절차','O','반소는 본소의 사실심 변론종결 전까지 제기할 수 있고(상고심에서는 제기할 수 없으며), 항소심에서의 반소 제기는 상대방의 심급의 이익을 해할 우려가 없거나 상대방의 동의를 받은 경우에 허용된다.','민소 §269·§412',1,false),
(1250,1,'제269조','제2편 제1심의 소송절차','O','본소 이혼이 기각되더라도 반소로 이혼이 명해져 이혼이 성립하는 경우에는 원고의 재산분할청구에 대하여도 판단하여야 한다.','대판 2001므718',1,false),
(1251,1,'제269조','제2편 제1심의 소송절차','O','단순반소가 적법하게 제기된 이상 그 후 본소가 취하되어도 반소의 소송계속에는 아무런 영향이 없다.','민소 §269',1,false),
(1252,1,'제269조','제2편 제1심의 소송절차','O','어떤 채권에 기한 이행의 소에 대하여 동일 채권에 관한 채무부존재확인의 반소를 제기하는 것은, 그 청구 내용이 실질적으로 본소청구의 기각을 구하는 데 그치므로 (확인의 이익이 없어) 부적법하다.','대판(부존재확인 반소)',1,false),
(1253,1,'제269조','제2편 제1심의 소송절차','O','채무부존재확인의 본소 제기 후 피고가 이행의 반소를 제기하였더라도, 그러한 사정만으로 본소의 확인의 이익이 소멸하여 본소가 부적법하게 되는 것은 아니다.','대판(부존재확인 본소+이행 반소)',1,false),
(1254,1,'제269조','제2편 제1심의 소송절차','O','피고가 제기하려는 반소가 필수적 공동소송이 될 때에는 필수적 공동소송인 추가의 요건을 갖춘다면 원고 이외의 제3자를 추가하는 반소도 허용될 수 있다.','대판(반소 제3자 추가)',2,false),
(1255,1,'제269조','제2편 제1심의 소송절차','O','제1심에서 원고의 본소청구에 대하여 피고가 본소청구 인용을 조건으로 한 예비적 반소를 제기한 경우, 제1심이 원고의 본소청구를 배척한다면 피고의 예비적 반소는 제1심의 심판대상이 될 수 없다.','대판(예비적 반소)',1,false),
(1256,1,'제269조','제2편 제1심의 소송절차','O','제1심에서 적법하게 반소를 제기한 당사자가 항소심에서 반소를 교환적으로 변경하는 경우, 변경된 청구와 종전 청구가 실질적 쟁점이 동일하여 청구의 기초에 변경이 없으면 그 변경이 허용된다.','대판(항소심 반소 변경)',1,false),
(1257,1,'제269조','제2편 제1심의 소송절차','O','본소가 단독사건인 경우 피고가 반소로 합의사건에 속하는 청구를 한 때에는 법원은 직권 또는 신청으로 본소와 반소를 합의부에 이송하여야 하나, 반소에 관하여 변론관할권을 가지는 경우에는 그러하지 아니하다.','민소 §269②',3,false),
(1258,1,'제269조','제2편 제1심의 소송절차','O','항소심이 원고의 본소청구를 인용하게 되면 예비적 반소의 심판조건이 성취되므로, 피고가 반소에 대해 항소하지 않았더라도 그 예비적 반소청구는 항소심의 심판대상이 되어 판단하여야 한다.','대판(예비적 반소 이심)',1,false),
(1259,1,'제269조','제2편 제1심의 소송절차','O','반소에 대하여는 별도의 사건번호와 사건명을 부여한다.','실무',1,false),
(1260,1,'제269조','제2편 제1심의 소송절차','O','상고심에서는 반소를 제기할 수 없다.','대판(상고심 반소)',1,false),
(1261,1,'제269조','제2편 제1심의 소송절차','O','본소와 반소의 목적이 동일한 소송물인 때에는 (이미 본소에서 인지를 납부하였으므로) 반소장에 별도의 인지를 붙일 필요가 없다.','인지법',1,false),
(1262,1,'제269조','제2편 제1심의 소송절차','O','피고는 사실심 변론종결 전까지만 반소를 제기할 수 있다.','민소 §269',1,false),
(1263,1,'제269조','제2편 제1심의 소송절차','O','반소가 소송절차를 현저히 지연시키는 경우에는 반소의 제기를 불허할 수 있다(§269① 단서).','민소 §269①단서',1,false),
(1264,1,'제269조','제2편 제1심의 소송절차','O','반소는 사실심 변론종결시까지 제기할 수 있으므로 항소심에서도(상대방 동의 등 요건 하에) 제기할 수 있다.','대판(항소심 반소)',1,false),
(1265,1,'제269조','제2편 제1심의 소송절차','O','본소가 이행의 소인 경우 그 채무의 부존재확인을 구하는 반소는 확인의 이익이 없어 허용되지 않는다.','대판(채무부존재 반소)',1,false),
(1266,1,'제269조','제2편 제1심의 소송절차','O','단독사건의 본소 계속 중 합의부 관할에 속하는 반소가 제기된 때에는 법원은 결정으로 본소와 반소를 합의부에 이송하며, 합산하여 판단하는 것이 아니다.','민소 §269②',1,false),
(1267,1,'제269조','제2편 제1심의 소송절차','O','반소청구는 본소의 청구나 방어방법과 서로 관련이 있어야 하나, 반소 제기 후 본소가 취하되더라도 (예비적 반소가 아닌 한) 반소의 소송계속에는 영향이 없다.','대판(본소취하·반소)',1,false),
(1268,1,'제269조','제2편 제1심의 소송절차','O','피고는 소송절차를 현저히 지연시키지 아니하는 경우에만 변론종결시까지 본소가 계속된 법원에 반소를 제기할 수 있고, 그 청구는 다른 법원의 전속관할에 속하지 아니하고 본소의 청구 또는 방어방법과 서로 관련이 있어야 한다.','민소 §269①',1,false),
(1269,1,'제269조','제2편 제1심의 소송절차','O','반소는 항변 등의 방어방법이 아니라 피고가 자기의 신청에 대하여 판결을 구하는 독립한 소이다.','통설',1,false),
(1270,1,'제269조','제2편 제1심의 소송절차','O','반소는 소송중의 소이다.','통설',1,false),
(1271,1,'제271조','제2편 제1심의 소송절차','O','본소가 부적법 각하된 경우에는 (본소취하의 경우와 달리) 원고의 동의가 있어야 반소취하의 효력이 발생한다.','대판 84다카298',3,false),
(1272,1,'제271조','제2편 제1심의 소송절차','O','본소가 취하된 때에는 피고는 원고의 동의 없이 반소를 취하할 수 있지만, 본소가 부적법 각하된 경우에는 원고의 동의가 있어야 반소취하의 효력이 생긴다.','대판 84다카298',4,false),
(1273,1,'제271조','제2편 제1심의 소송절차','O','단순반소가 적법하게 제기된 이상 본소가 취하되어도 반소의 소송계속에는 아무런 영향이 없다(본소 취하로 반소가 취하 간주되는 것이 아니다).','민소 §271',1,false),
(1274,1,'제271조','제2편 제1심의 소송절차','O','본소가 취하된 경우 피고는 원고의 동의 없이 반소를 취하할 수 있다.','민소 §271',3,false),
(1275,1,'제271조','제2편 제1심의 소송절차','O','본소의 취하 후에 반소를 취하함에는 원고의 동의가 필요 없다.','민소 §271',1,false),
(1276,1,'제272조','제2편 제1심의 소송절차','O','단독사건의 변론은 서면으로 준비하지 아니할 수 있으나, 상대방이 준비하지 아니하면 진술할 수 없는 사항은 서면으로 준비하여야 한다.','민소 §272②',1,false),
(1277,1,'제272조','제2편 제1심의 소송절차','O','단독사건에서는 준비서면에 미리 적지 아니한 사항도 변론에서 주장할 수 있으므로, 미리 적지 않은 재정증인에 대한 증거조사가 곧바로 위법한 것은 아니다.','판례',1,false),
(1278,1,'제272조','제2편 제1심의 소송절차','O','차별화된 사건관리, 서면절차와 구술절차의 명확한 구분은 민사소송 신모델의 내용이다.','신모델',1,false),
(1279,1,'제272조','제2편 제1심의 소송절차','O','서면공방의 선행과 재판기일의 최소화는 민사소송 신모델의 내용이다.','신모델',1,false),
(1280,1,'제273조','제2편 제1심의 소송절차','O','준비서면은 적힌 사항에 대하여 상대방이 준비하는 데 필요한 기간을 두고 제출하여야 하며, 법원은 상대방에게 그 부본을 송달하여야 한다.','민소 §273',1,false),
(1281,1,'제276조','제2편 제1심의 소송절차','O','준비서면에 취득시효완성 주장사실이 기재되어 있더라도 그 준비서면이 변론기일에서 진술된 흔적이 없다면, 취득시효완성 주장에 대한 판단누락의 위법이 있다고 할 수 없다.','판례',1,false),
(1282,1,'제276조','제2편 제1심의 소송절차','O','변론에 상대방이 출석하지 않았다면 준비서면에 기재하지 않은 사실을 주장할 수 없는 것이 원칙이다.','민소 §276',1,false),
(1283,1,'제276조','제2편 제1심의 소송절차','O','준비서면에 적지 않은 사실은 상대방이 출석하지 아니한 때에는 변론에서 주장하지 못한다.','민소 §276',1,false),
(1284,1,'제279조','제2편 제1심의 소송절차','O','재판장은 특별한 사정이 있는 때에는 변론기일을 연 뒤에도 사건을 변론준비절차에 부칠 수 있다.','민소 §279',1,false),
(1285,1,'제281조','제2편 제1심의 소송절차','O','재판장은 변론준비를 위하여 필요하다고 인정하면 증거결정을 할 수 있고, 변론이 효율적·집중적으로 실시되도록 하기 위한 목적 달성에 필요한 범위 안에서 증거조사를 할 수 있다.','민소 §281',1,false),
(1286,1,'제282조','제2편 제1심의 소송절차','O','당사자는 재판장의 허가를 얻어 변론준비기일에 제3자와 함께 출석할 수 있다.','민소 §282',1,false),
(1287,1,'제282조','제2편 제1심의 소송절차','O','변론준비기일에서는 쟁점정리가 완결되지 않은 사건에 대한 쟁점 및 증거정리를 할 수 있다.','민소 §282',1,false),
(1288,1,'제282조','제2편 제1심의 소송절차','O','변론준비기일에 소송대리인이 있더라도 재판장은 화해 등을 위하여 당사자 본인의 출석을 명할 수 있다.','민소 §282·§287',1,false),
(1289,1,'제282조','제2편 제1심의 소송절차','O','변론준비기일은 화해권고나 조정의 적기가 된다.','실무',1,false),
(1290,1,'제284조','제2편 제1심의 소송절차','O','변론준비기일에서 양쪽 당사자의 불출석이 밝혀진 경우 재판장 등은 새로운 변론준비기일을 지정함이 없이 당사자의 불출석을 이유로 변론준비절차를 종결할 수 있다.','민소 §284',1,false),
(1291,1,'제285조','제2편 제1심의 소송절차','O','변론준비기일은 원칙적으로 주장·증거신청의 마지막 기회이다(종결의 실권효).','민소 §285',1,false),
(1292,1,'제285조','제2편 제1심의 소송절차','O','변론준비절차가 열리기 전에 준비서면을 제출하였으면 변론준비절차에서 진술하지 아니하였더라도 그 사항에 관하여 변론에서 주장할 수 있다.','대판(준비서면 주장)',1,false),
(1293,1,'제286조','제2편 제1심의 소송절차','O','변론준비기일에서 양쪽 당사자 불출석의 효과는 변론기일에 승계되지 아니한다.','대판 2006.10.27. 2004다69581',2,false),
(1294,1,'제287조','제2편 제1심의 소송절차','O','변론준비기일에서 제출된 주장과 증거는 그 뒤의 변론기일에서 당사자의 진술에 의하여 변론에 상정됨으로써 심리·판단의 자료가 된다.','민소 §287②',1,false),
(1295,1,'제287조','제2편 제1심의 소송절차','O','법원은 변론준비절차를 마친 경우에는 첫 변론기일을 거친 뒤 바로 변론을 종결할 수 있도록 하여야 하며, 당사자는 이에 협력하여야 한다.','민소 §287③',1,false),
(1296,1,'제288조','제2편 제1심의 소송절차','O','서증의 진정성립에 관한 자백은 보조사실에 관한 것이지만 재판상 자백으로서 법원을 구속한다.','판례',1,false),
(1297,1,'제288조','제2편 제1심의 소송절차','O','점유취득시효에서 점유개시 시기에 대한 자백은 법원·당사자를 구속하지 않으나, 소멸시효 항변에서 본래의 기산일과 당사자가 주장하는 기산일이 다른 경우 법원은 당사자가 주장하는 기산일을 기준으로 소멸시효를 계산하여야 한다.','판례',1,false),
(1298,1,'제288조','제2편 제1심의 소송절차','O','어느 소멸시효기간이 적용되는지는 법률 적용의 문제이므로, 당사자가 민법상 시효기간을 주장하더라도 법원은 직권으로 상법상 시효기간을 적용할 수 있다.','판례',1,false),
(1299,1,'제288조','제2편 제1심의 소송절차','O','청구이의의 소에서는 이의사유(변제·면제 등 청구권의 소멸·저지 사유)에 대한 증명책임이 원고(채무자)에게 있고, 통상의 이행소송처럼 ''원고=청구원인사실, 피고=항변사실''로 단순 분배되지 않는다.','민집 §44; 통설·판례',1,true),
(1300,1,'제288조','제2편 제1심의 소송절차','O','당사자 일방의 진술에 잘못된 계산·기재 등 표현상의 잘못이 있고 그 잘못이 분명한 경우에는, 상대방이 이를 원용하였더라도 자백이 성립할 수 없다.','판례',1,false),
(1301,1,'제288조','제2편 제1심의 소송절차','O','강제경매든 임의경매든 경매개시결정에 대한 이의 재판절차에는 민사소송법상 재판상 자백 규정이 준용되지 않는다.','판례',1,false),
(1302,1,'제288조','제2편 제1심의 소송절차','O','자백이 진실과 부합되지 않는 사실이 증명된 경우라면, 변론 전체의 취지에 의하여 그 자백이 착오로 인한 것이라는 점을 인정할 수 있다.','판례',1,false),
(1303,1,'제288조','제2편 제1심의 소송절차','O','법정변제충당의 순서 자체에 관한 진술은 비록 그 진술자에게 불리하더라도 이를 자백이라고 볼 수 없다.','판례',1,false),
(1304,1,'제288조','제2편 제1심의 소송절차','O','인수참가인이 채무승계 사실에 관한 상대방의 주장을 모두 인정하여 자백하고 소송을 인수·수행하였다면, 그 자백이 진실에 반하고 착오로 인한 것이 아닌 한 인수참가인은 자백에 반하여 채무승계 사실을 다툴 수 없다.','판례',1,false),
(1305,1,'제288조','제2편 제1심의 소송절차','O','자백의 취소는 반드시 명시적일 필요가 없고, 종전 자백과 배치되는 사실을 주장하면 묵시적으로 자백을 취소한 것으로 볼 수 있다.','대판(자백취소 묵시)',1,false),
(1306,1,'제288조','제2편 제1심의 소송절차','O','자백이 진실에 반함이 증명되어도 그것만으로 착오에 의한 것으로 추정되지 않으며, 반진실과 착오를 모두 증명하여야 한다.','대판(자백취소 요건)',2,false),
(1307,1,'제288조','제2편 제1심의 소송절차','O','자백이 성립한 후 자백한 당사자가 이를 취소하고 이에 대하여 상대방이 이의 없이 동의하면 자백의 취소가 인정된다.','대판(자백취소 동의)',1,false),
(1308,1,'제288조','제2편 제1심의 소송절차','O','서증의 진정성립에 관한 자백도 보조사실에 관한 것이지만 주요사실의 자백과 마찬가지로 그 취소에 제한을 받는다(자백의 구속력 인정).','대판(서증 진정성립 자백)',1,false),
(1309,1,'제288조','제2편 제1심의 소송절차','O','소유권에 기한 이전등기말소청구소송에서 피고가 원고 주장의 소유권을 인정하는 진술은 그 소의 전제가 되는 소유권의 내용을 이루는 사실에 대한 진술로 볼 수 있으므로 재판상 자백이다.','대판(권리자백)',3,false),
(1310,1,'제288조','제2편 제1심의 소송절차','O','채권자대위소송에서 피보전채권의 존부는 소송요건으로서 직권조사사항이므로, 그 발생·소멸의 요건사실은 재판상 자백의 대상이 되지 않는다.','대판(피보전채권 직권조사)',1,false),
(1311,1,'제288조','제2편 제1심의 소송절차','O','당사자가 변론에서 상대방이 주장하기도 전에 스스로 자신에게 불이익한 사실을 진술한 경우, 상대방이 이를 명시적으로 원용하거나 그와 일치되는 진술을 하면 재판상 자백(선행자백)이 성립하여 법원도 이에 구속된다.','대판(선행자백)',1,false),
(1312,1,'제288조','제2편 제1심의 소송절차','O','재판상 자백의 취소는 반드시 명시적으로 하여야만 하는 것은 아니고, 종전의 자백과 배치되는 사실을 주장함으로써 묵시적으로도 할 수 있다.','대판(자백취소 묵시)',1,false),
(1313,1,'제288조','제2편 제1심의 소송절차','O','법률상 혼인외의 자가 아닌 것을 혼인외의 자라고 시인하였다 하더라도 (권리·법률효과에 관한 진술이어서) 자백이 성립하지 아니한다.','대판(권리자백 부정)',1,false),
(1314,1,'제288조','제2편 제1심의 소송절차','O','문서의 성립에 관한 자백은 보조사실에 관한 자백이기는 하나 자유롭게 이를 취소할 수 없다는 것이 판례이다.','대판(문서성립 자백)',1,false),
(1315,1,'제288조','제2편 제1심의 소송절차','O','재판상 자백이 성립한 사실에 대하여는 법원도 이에 기속되므로, 당사자 사이에 다툼이 없는 사실에 관하여 법원은 그와 배치되는 사실을 증거에 의하여 인정할 수 없다.','대판(자백 구속력)',1,false),
(1316,1,'제288조','제2편 제1심의 소송절차','O','상고심에 이르러서는 진실에 반하고 착오로 인한 것임이 증명된 경우라도 원심에서 한 자백을 취소할 수 없다.','대판(상고심 자백취소)',1,false),
(1317,1,'제288조','제2편 제1심의 소송절차','O','자백의 취소는 상대방의 동의가 있으면 반진실·착오 요건 없이 가능하나, 상대방이 단순히 이의를 제기하지 않은 것만으로 곧바로 동의가 있다고 보아 취소를 인정할 수는 없다.','대판(자백취소 동의)',1,false),
(1318,1,'제288조','제2편 제1심의 소송절차','O','원고는 소비대차계약을 체결하였다는 사실을 주장하여야 한다.','통설·판례',1,false),
(1319,1,'제288조','제2편 제1심의 소송절차','O','원고는 대여를, 피고는 증여를 주장하는데 어느 쪽이 진실인지 불명확한 경우에는, (증명책임상) 돈을 대여하였다는 사실은 없는 것으로 취급하여야 한다.','대판(증명책임)',1,false),
(1320,1,'제288조','제2편 제1심의 소송절차','O','피고의 증여 주장은 원고의 대여사실에 대한 부인에 불과하므로 피고가 증여 사실에 대하여 증명책임을 부담하지 않으며, 대여(소비대차) 사실의 증명책임은 원고에게 있다.','대판(부인·항변)',1,false),
(1321,1,'제288조','제2편 제1심의 소송절차','O','자백을 취소하는 당사자는 그 자백이 진실에 반한다는 것 외에 착오에 인한 것임을 아울러 증명하여야 하나, 자백이 진실에 반함이 증명된 경우에는 변론 전체의 취지로 착오로 인한 것임을 인정할 수 있다.','대판(자백취소 요건)',2,false),
(1322,1,'제288조','제2편 제1심의 소송절차','O','피고의 ''정지조건부 법률행위에 해당한다''는 사실의 주장은 항변에 해당한다.','통설',1,false),
(1323,1,'제288조','제2편 제1심의 소송절차','O','피고의 정지조건부 법률행위 주장에 대하여, 원고가 ''정지조건부 법률행위가 아니다''라고 하는 것은 부인이고, ''정지조건이 성취되었다''는 주장은 재항변에 해당한다.','통설',1,false),
(1324,1,'제288조','제2편 제1심의 소송절차','O','원고의 대여금반환청구에 대하여 피고가 ''대여가 아니라 증여를 받았다''고 주장하는 것은 부인에 해당한다.','통설',1,false),
(1325,1,'제288조','제2편 제1심의 소송절차','O','자백의 대상이 되는 사실은 원칙적으로 주요사실에 한하며, 간접사실과 보조사실에 대하여는 자백이 성립하지 않는다.','통설',1,false),
(1326,1,'제288조','제2편 제1심의 소송절차','O','이행불능에 관한 주장은 법률적 효과에 관한 진술에 불과하고 사실에 관한 진술이 아니므로, 자유로이 철회할 수 있고 법원도 이에 구속되지 않는다.','대판(권리자백)',1,false),
(1327,1,'제288조','제2편 제1심의 소송절차','O','다른 소송이나 소송 밖에서 한 불리한 진술은 재판상 자백으로서의 효력이 없다.','대판(재판상 자백 범위)',1,false),
(1328,1,'제288조','제2편 제1심의 소송절차','O','문서의 진정성립에 관한 자백은 보조사실에 관한 것이지만 (자백의 구속력이 인정되어) 자유롭게 철회할 수 없다.','대판(문서성립 자백)',1,false),
(1329,1,'제288조','제2편 제1심의 소송절차','O','소송요건은 재판상의 자백이나 자백간주의 대상이 될 수 없다.','대판(소송요건 자백)',1,false),
(1330,1,'제288조','제2편 제1심의 소송절차','O','대여금반환청구에서 ''매매대금으로 돈을 받은 것''이라는 주장은 (금전대여 사실 자체를 부정하는) 부인에 해당하고 항변이 아니다.','통설',1,false),
(1331,1,'제288조','제2편 제1심의 소송절차','O','대여금반환청구에 대하여 ''대여금을 이미 변제하였다''는 주장은 항변에 해당한다.','통설',1,false),
(1332,1,'제288조','제2편 제1심의 소송절차','O','대여금반환청구에 대하여 ''불공정한 법률행위였다''는 주장은 (무효를 주장하는) 항변에 해당한다.','통설',1,false),
(1333,1,'제288조','제2편 제1심의 소송절차','O','원고의 소비대차에 기한 대여금반환청구에 대하여 피고가 소멸시효의 완성을 주장하는 것은 항변에 해당한다.','통설',2,false),
(1334,1,'제288조','제2편 제1심의 소송절차','O','당사자본인신문 결과 중에 당사자의 진술로서 상대방의 주장사실과 일치되는 것이 나왔다고 하더라도 그것은 재판상 자백이 될 수 없다.','대판(본인신문 자백)',1,false),
(1335,1,'제288조','제2편 제1심의 소송절차','O','자백의 취소에 대하여 상대방이 아무런 이의를 제기하지 않고 있다는 점만으로는 그 취소에 동의하였다고 볼 수 없다.','대판(자백취소 동의)',1,false),
(1336,1,'제288조','제2편 제1심의 소송절차','O','직권조사사항의 존부 자체는 재판상의 자백이나 자백간주의 대상이 될 수 없다.','대판(직권조사 자백)',1,false),
(1337,1,'제288조','제2편 제1심의 소송절차','O','항변이란 원고가 주장하는 청구원인 주요사실의 존재 자체는 인정하면서 이와 양립 가능한 별개의 방어방법을 주장하는 것이다.','통설',1,false),
(1338,1,'제288조','제2편 제1심의 소송절차','O','피고가 항변한 경우 그 증명책임은 대개 피고에게 있다.','통설',1,false),
(1339,1,'제288조','제2편 제1심의 소송절차','O','피고가 부인한 경우 그 사실의 증명책임은 대개 원고에게 있다.','통설',1,false),
(1340,1,'제288조','제2편 제1심의 소송절차','O','간접사실에 대해서는 자백이 되어도 구속력이 없다.','대판(간접사실 자백)',1,false),
(1341,1,'제288조','제2편 제1심의 소송절차','O','상대방의 주장사실을 부정하는 단순부인이고 항변이 아니다.','통설',1,false),
(1342,1,'제288조','제2편 제1심의 소송절차','O','소비대차 사실을 부정하면서 그 이유를 붙인 이유부 부인이고 항변이 아니다.','통설',1,false),
(1343,1,'제288조','제2편 제1심의 소송절차','O','원고의 대여 주장에 대하여 ''돈을 받았지만 모두 갚았다(변제)''고 주장하는 것은 항변이다.','통설',1,false),
(1344,1,'제288조','제2편 제1심의 소송절차','O','문서의 진정성립에 관한 자백은 보조사실에 관한 자백이지만 주요사실의 자백과 같이 함부로 철회할 수 없다.','대판(진정성립 자백)',1,false),
(1345,1,'제288조','제2편 제1심의 소송절차','O','선행자백(자발적 자백)이 상대방에 의하여 원용되기 전이거나 이에 상응하는 일치된 진술이 없는 때에는 자유롭게 철회가 가능하다.','대판(선행자백)',1,false),
(1346,1,'제288조','제2편 제1심의 소송절차','O','자백은 변론이나 변론준비절차에서 소송행위로서 진술하여야 하므로, 소송 밖에서 한 자백이나 다른 소송에서 한 자백은 사실인정의 자료가 될 뿐 당연히 법원의 사실인정권을 배제하는 효과가 있는 것은 아니다.','대판(재판외 자백)',1,false),
(1347,1,'제288조','제2편 제1심의 소송절차','O','상대방 주장과 전부 일치해야 하는 것은 아니고 일치하는 부분에 한해 자백이 인정되므로, 자백의 가분성 원칙이 인정된다.','대판(자백 가분성)',1,false),
(1348,1,'제288조','제2편 제1심의 소송절차','O','취득시효의 일정기간 계속점유에 관하여 전후 양시의 점유로부터 전 기간 점유의 계속을 추정하는 것은 사실 추정이다.','민법 §198',1,false),
(1349,1,'제288조','제2편 제1심의 소송절차','O','귀속불명 재산을 부부공유로 추정하는 것은 권리(소유관계) 추정이고 사실 추정이 아니다.','민법 §830②',1,false),
(1350,1,'제288조','제2편 제1심의 소송절차','O','처가 혼인 중에 포태한 자를 부의 친생자로 추정하는 것은 (친자라는) 사실 추정이다.','민법 §844',1,false),
(1351,1,'제288조','제2편 제1심의 소송절차','O','일자의 기재가 없는 배서는 지급거절증서 작성기간 경과 전에 한 것으로 추정하는 것은 사실(시기) 추정이다.','어음법',1,false),
(1352,1,'제288조','제2편 제1심의 소송절차','O','재판상 자백이 성립하면 원칙적으로 그 진실 여부를 판단할 필요가 없고, 증거조사 결과 반대의 심증을 얻었더라도 자백에 반하는 사실을 인정할 수 없다.','대판(자백 구속력)',1,false),
(1353,1,'제288조','제2편 제1심의 소송절차','O','보조사실 중 문서의 진정성립에 관한 자백은 예외적으로 자백의 효력(구속력)이 생긴다.','대판(진정성립 자백)',1,false),
(1354,1,'제288조','제2편 제1심의 소송절차','O','상대방의 동의가 있거나, 자백이 진실에 반하고 착오로 인한 것임을 증명한 때에는 자백의 취소가 허용된다.','민소 §288단서',1,false),
(1355,1,'제288조','제2편 제1심의 소송절차','O','재판상 자백한 사실은 증명을 필요로 하지 않는다.','민소 §288',2,false),
(1356,1,'제288조','제2편 제1심의 소송절차','O','간접사실은 (다툼이 있으면) 증명할 필요가 있는 사실이다.','통설',1,false),
(1357,1,'제289조','제2편 제1심의 소송절차','O','증거의 신청과 조사는 변론기일 전에도 할 수 있다.','민소 §289②',1,false),
(1358,1,'제289조','제2편 제1심의 소송절차','O','증거의 신청은 서면 또는 말로 할 수 있고, 증거신청서에는 인지를 붙일 필요가 없다.','민소 §289',1,false),
(1359,1,'제289조','제2편 제1심의 소송절차','O','증거의 신청은 증거조사가 개시된 뒤에는 상대방의 동의가 있어야 철회할 수 있다.','대판(증거신청 철회)',1,false),
(1360,1,'제290조','제2편 제1심의 소송절차','O','법원은 유일한 증거가 아닌 한, 당사자가 신청한 증거를 필요하지 아니하다고 인정한 때에는 조사하지 아니할 수 있다.','민소 §290',1,false),
(1361,1,'제292조','제2편 제1심의 소송절차','O','법원은 당사자가 신청한 증거에 의하여 심증을 얻을 수 없거나 그 밖에 필요하다고 인정한 때에는 직권으로 증거조사를 할 수 있다.','민소 §292',1,false),
(1362,1,'제294조','제2편 제1심의 소송절차','O','사실조회(조사의 촉탁) 회보에 관하여는 원칙적으로 이를 따로 서증으로 제출시킬 필요는 없다.','대판(사실조회 회보)',1,false),
(1363,1,'제295조','제2편 제1심의 소송절차','O','당사자가 기일에 출석하지 아니한 때에도 증거조사를 할 수 있다.','민소 §295',2,false),
(1364,1,'제297조','제2편 제1심의 소송절차','O','다른 법원의 판사에게 증거조사의 실시를 촉탁할 수 있다(수탁판사).','민소 §297',1,false),
(1365,1,'제309조','제2편 제1심의 소송절차','O','증인에 대하여 전화·팩스 등 간이한 방법을 이용하여 출석요구를 한 경우에는 과태료 부과와 같은 법률상의 제재를 가할 수 없다.','민소 규칙',1,false),
(1366,1,'제310조','제2편 제1심의 소송절차','O','법원은 효율적인 증인신문을 위하여 필요하면 증인을 신청한 당사자에게 증인진술서를 제출하게 할 수 있고, 제출된 증인진술서는 서증으로 채택하되 그 증인이 불출석하는 경우에는 원칙적으로 서증으로도 채택하지 않아야 한다.','규칙 §79의2',1,false),
(1367,1,'제310조','제2편 제1심의 소송절차','O','법원은 상당하다고 인정하는 때에는 출석·증언에 갈음하여 증언할 사항을 적은 서면을 제출하게 할 수 있고, 제출된 서면증언은 변론기일에 현출됨으로써 증언으로서의 효력을 갖는다.','민소 §310',1,false),
(1368,1,'제310조','제2편 제1심의 소송절차','O','서면에 의한 증언(증언서면 제출) 방식으로 증인조사를 하는 경우에는 출석에 갈음하는 것이므로 그 증인에 대하여 출석요구를 하지 않는다.','민소 §310',1,false),
(1369,1,'제310조','제2편 제1심의 소송절차','O','상대방의 이의 유무에 관계없이 법원은 상당하다고 인정하는 경우에는 출석·증언에 갈음하여 증언할 사항을 적은 서면을 제출하게 할 수 있다.','민소 §310①',1,false),
(1370,1,'제310조','제2편 제1심의 소송절차','O','서면에 의한 증언방식에서 법원은 상대방의 이의가 있거나 필요하다고 인정하는 때에는 증인에게 출석·증언하게 할 수 있다.','민소 §310②',1,false),
(1371,1,'제311조','제2편 제1심의 소송절차','O','출석의무가 있는 증인이 불출석한 경우에는 소송비용 부담과 과태료 부과, 감치, 구인 등의 제재를 할 수 있다.','민소 §311·§312',1,false),
(1372,1,'제311조','제2편 제1심의 소송절차','O','증인이 불출석에 따른 과태료 재판을 받고도 정당한 사유 없이 다시 출석하지 아니한 때에는 법원은 결정으로 증인을 7일 이내의 감치에 처할 수 있다.','민소 §311②',1,false),
(1373,1,'제311조','제2편 제1심의 소송절차','O','증인이 정당한 사유 없이 출석하지 아니한 때에는 법원은 결정으로 증인에게 500만 원 이하의 과태료에 처할 수 있다.','민소 §311①',1,false),
(1374,1,'제312조','제2편 제1심의 소송절차','O','법원은 정당한 사유 없이 출석하지 아니한 증인을 구인하도록 명할 수 있고, 증인의 구인절차에는 형사소송법의 구인 규정이 준용된다.','민소 §312',1,false),
(1375,1,'제314조','제2편 제1심의 소송절차','O','증언거부권은 증인 자신이나 친족이 공소제기·유죄판결을 받을 염려가 있거나 치욕이 될 사항에 관하여 인정되고, 단지 친족과 현저한 이해관계가 있다는 것만으로는 증언을 거부할 수 없다.','민소 §314',2,false),
(1376,1,'제314조','제2편 제1심의 소송절차','O','현저한 이해관계가 있다는 것만으로는 증언거부사유에 해당하지 않는다(공소제기·유죄·치욕 사항이어야 함).','민소 §314',1,false),
(1377,1,'제314조','제2편 제1심의 소송절차','O','증언이 자기나 친족 등이 공소제기되거나 유죄판결을 받을 염려가 있는 사항 또는 치욕이 될 사항에 관한 것인 때는 증언거부사유이다.','민소 §314',2,false),
(1378,1,'제315조','제2편 제1심의 소송절차','O','증인은 기술 또는 직업의 비밀에 속하는 사항에 대하여 신문을 받을 때 증언을 거부할 수 있다.','민소 §315',3,false),
(1379,1,'제315조','제2편 제1심의 소송절차','O','변호사·변리사·공증인·공인회계사·세무사·의료인·약사 등 법령상 비밀유지의무가 있는 직책에 있(었)는 사람이 직무상 비밀에 속하는 사항에 대하여 신문을 받을 때는 증언거부사유이다.','민소 §315①',1,false),
(1380,1,'제318조','제2편 제1심의 소송절차','O','증언·선서 거부에 정당한 이유가 없다고 한 재판 확정 후에도 거부한 때에는 과태료에 처할 수 있을 뿐이고, 감치처분은 할 수 없다(감치는 증인 불출석의 경우).','민소 §318',1,false),
(1381,1,'제322조','제2편 제1심의 소송절차','O','선서무능력자는 16세 미만인 사람 등이므로, 만 17세의 증인에게는 선서를 시켜야 한다.','민소 §322',1,false),
(1382,1,'제322조','제2편 제1심의 소송절차','O','16세 미만인 사람이나 선서의 취지를 이해하지 못하는 사람을 증인으로 신문할 때에는 선서를 시키지 못한다.','민소 §322',2,false),
(1383,1,'제327조','제2편 제1심의 소송절차','O','주신문·반대신문·재주신문이 끝난 뒤 다시 신문하려면 재판장의 허가를 받아야 한다.','민소규칙',1,false),
(1384,1,'제327조','제2편 제1심의 소송절차','O','주신문은 증명할 사항과 이에 관련된 사항에 관하여 하며, 반대신문은 주신문에 나타난 사항과 이에 관련된 사항에 관하여 하여야 한다.','규칙',2,false),
(1385,1,'제327조의2','제2편 제1심의 소송절차','O','법원은 교통이 불편한 곳에 살고 있는 사람을 증인으로 신문하는 경우, 법정 아닌 곳에 출석하게 하고 비디오 등 중계장치에 의한 중계시설을 통하여 증인신문할 수 있다.','민소 §327의2',1,false),
(1386,1,'제336조','제2편 제1심의 소송절차','O','감정인이 성실하게 감정할 수 없는 사정이 있는 때에 당사자는 그를 기피할 수 있으나, 당사자가 감정사항에 관한 진술 전부터 기피 이유를 알고 있었던 때에는 그 진술 후에 기피하지 못한다.','민소 §336',1,false),
(1387,1,'제339조','제2편 제1심의 소송절차','O','선서하지 아니한 감정인에 의한 감정 결과는 (감정으로서는) 증거능력이 없으므로, 법원이 감정을 명하면서 착오로 감정인의 선서를 누락하였다면 그 감정 결과는 증거능력이 없다.','대판(감정 선서)',1,false),
(1388,1,'제339조','제2편 제1심의 소송절차','O','선서하지 않은 감정인의 감정서라도 당사자가 서증으로 제출하고 법원이 그 내용을 합리적이라고 인정하면 사실인정의 자료로 삼을 수 있다.','대판(사감정 서증)',1,false),
(1389,1,'제339조','제2편 제1심의 소송절차','O','감정인신문에도 민소 §327의2가 준용되므로, 감정인이 직접 출석하기 어려운 특별한 사정이 있으면 비디오 등 중계장치를 이용하여 감정인신문을 할 수 있다.','민소 §339·§327의2',1,false),
(1390,1,'제340조','제2편 제1심의 소송절차','O','특별한 학식·경험에 의하여 알게 된 과거의 사실을 보고하는 감정증인은 감정인이 아니라 증인이므로, 증인신문에 관한 규정이 적용된다.','민소 §340',1,false),
(1391,1,'제341조','제2편 제1심의 소송절차','O','법원이 필요하다고 인정하는 경우에는 공공기관·학교, 그 밖에 상당한 설비가 있는 단체 또는 외국 공공기관에 감정을 촉탁할 수 있고, 이 경우 선서에 관한 규정을 적용하지 아니한다.','민소 §341',1,false),
(1392,1,'제342조','제2편 제1심의 소송절차','O','감정인은 감정에 필요한 경우 법원의 허가를 받아 남의 토지·주거 등에 들어갈 수 있다.','민소 §342',1,false),
(1393,1,'제343조','제2편 제1심의 소송절차','O','문서를 가진 사람에게 제출을 명할 것을 신청하는 것은 서증을 신청하는 방식 중 하나이므로, 법원은 그 제출명령신청 대상 문서가 서증으로서 필요하지 아니하다고 인정할 때에는 그 신청을 받아들이지 아니할 수 있다.','대판(문서제출 필요성)',1,false),
(1394,1,'제343조','제2편 제1심의 소송절차','O','서증은 법원 밖에서 증거조사를 하는 경우 외에는 당사자가 변론기일·변론준비기일에 출석하여 현실적으로 제출하여야 하고, 서증이 첨부된 소장·준비서면 등이 진술되는 경우에도 마찬가지이다.','대판(서증 현실 제출)',1,false),
(1395,1,'제343조','제2편 제1심의 소송절차','O','당사자가 서증을 신청하고자 하는 때에는 문서를 제출하는 방식 또는 문서를 가진 사람에게 그것을 제출하도록 명할 것을 신청하는 방식으로 한다.','민소 §343',1,false),
(1396,1,'제343조','제2편 제1심의 소송절차','O','문서제출명령의 신청이 있고 그에 따른 제출명령이 있었다 하더라도, 그 문서가 법원에 제출되기 전에 그 신청을 철회함에는 상대방의 동의를 필요로 하지 않는다.','대판(문서제출 철회)',1,false),
(1397,1,'제343조','제2편 제1심의 소송절차','O','문서의 지질·형상 자체가 증명의 대상이 된 경우에는 서증이 아니라 검증의 방법에 의한다.','대판(서증·검증)',1,false),
(1398,1,'제343조','제2편 제1심의 소송절차','O','당해 사건에서의 증인신문조서는 이미 소송자료가 되어 있으므로 다시 서증의 대상이 되는 것이 아니다.','대판(증인신문조서)',1,false),
(1399,1,'제343조','제2편 제1심의 소송절차','O','소 제기 후 계쟁사실에 관하여 작성된 문서도 증거능력이 있다.','대판(소제기 후 문서)',1,false),
(1400,1,'제343조','제2편 제1심의 소송절차','O','소제기 후에 작성된 문서나 그 사본도 증거능력이 인정된다.','대판(소제기 후 문서)',1,false),
(1401,1,'제344조','제2편 제1심의 소송절차','O','법원은 문서제출명령의 대상 문서로 입증하고자 하는 사항이 해당 청구와 직접 관련이 없는 것이라면 그 신청을 받아들이지 아니할 수 있다.','대판(문서제출 관련성)',1,false),
(1402,1,'제344조','제2편 제1심의 소송절차','O','문서가 개인정보 보호법상 개인정보에 해당한다는 사정만으로는 문서제출을 거부할 수 없다.','대판(개인정보 문서제출)',1,false),
(1403,1,'제344조','제2편 제1심의 소송절차','O','당사자가 소송에서 인용한 문서를 가지고 있는 때에는, 그 문서를 가지고 있는 사람은 그 제출을 거부하지 못한다.','민소 §344①1호',1,false),
(1404,1,'제344조','제2편 제1심의 소송절차','O','법원은 신청 또는 직권으로 상업장부 또는 그 일부분의 제출을 명할 수 있다(상법 §32).','상법 §32',1,false),
(1405,1,'제345조','제2편 제1심의 소송절차','O','문서제출명령을 하려면 문서의 존재와 소지가 증명되어야 하고, 그 증명책임은 원칙적으로 신청인에게 있다.','판례',1,false),
(1406,1,'제346조','제2편 제1심의 소송절차','O','문서제출명령 신청인은 문서의 취지나 증명할 사실을 개괄적으로 표시하여 상대방이 가지고 있는 문서 목록을 제출하도록 명할 것을 신청할 수 있다.','민소 §346',1,false),
(1407,1,'제347조','제2편 제1심의 소송절차','O','문서제출명령은 당사자가 아닌 제3자에 대해서도 할 수 있으나, 이 경우 제3자나 그가 지정하는 자를 심문하여야 한다.','민소 §347③',1,false),
(1408,1,'제348조','제2편 제1심의 소송절차','O','제3자에 대한 문서제출명령에서 민소 §347③의 심문절차를 누락한 경우, 그에 대하여 즉시항고할 수 있는 자는 ''그 제3자''에 한하고 본안소송 당사자는 즉시항고할 수 없다.','실무제요 Ⅲ3773; 민소 §348',1,true),
(1409,1,'제348조','제2편 제1심의 소송절차','O','문서제출명령에 대해서는 독립하여 즉시항고를 할 수 있다.','민소 §348',1,false),
(1410,1,'제349조','제2편 제1심의 소송절차','O','당사자가 문서제출명령을 받고도 따르지 아니하는 때에는 법원은 그 문서의 기재에 대한 상대방의 주장을 진실한 것으로 인정할 수 있으나, 과태료 부과의 제재는 없다.','민소 §349',1,false),
(1411,1,'제349조','제2편 제1심의 소송절차','O','당사자가 문서제출명령에 불응한 때에는 법원은 문서 기재에 관한 상대방의 주장을 진실한 것으로 인정할 수 있을 뿐이고, 과태료(500만 원 이하) 제재는 제3자가 문서제출명령에 불응한 경우에 부과된다.','민소 §349·§351',1,false),
(1412,1,'제351조','제2편 제1심의 소송절차','O','당사자 아닌 제3자가 문서제출명령에 따르지 않은 때에는 과태료에 처할 수 있을 뿐이고, 신청인의 주장을 진실한 것으로 인정할 수 있는 것은 아니다(진실인정은 당사자 불응의 경우).','민소 §351',2,false),
(1413,1,'제352조','제2편 제1심의 소송절차','O','문서송부촉탁의 신청은 변론기일에서 할 수 있으나 기일 전에도 할 수 있다.','민소규칙',1,false),
(1414,1,'제352조','제2편 제1심의 소송절차','O','법령상 정본 또는 등본의 교부를 청구할 수 있는 문서에 대하여는 문서송부촉탁을 할 수 없다(보충성).','민소규칙(보충성)',2,false),
(1415,1,'제352조','제2편 제1심의 소송절차','O','문서송부촉탁신청이 채택되면 재판장은 소지자에게 송부를 촉탁하는데, 촉탁서 원본은 발송하고 사본은 기록에 편철한다.','실무',1,false),
(1416,1,'제352조','제2편 제1심의 소송절차','O','문서송부촉탁은 법원·검찰청이 보관하는 특정 사건의 기록 전부라도 상관없고, 기록의 불특정한 일부에 대하여도 할 수 있다.','판례',1,false),
(1417,1,'제352조','제2편 제1심의 소송절차','O','문서송부촉탁에 의하여 송부된 문서는 자동적으로 증거자료가 되는 것이 아니고, 신청인이 그 중 필요한 것을 서증으로 제출함으로써 비로소 증거자료가 된다.','대판(문서송부촉탁)',2,false),
(1418,1,'제352조','제2편 제1심의 소송절차','O','문서의 제출의무를 부담하지 않는 문서소지인을 상대로도 그 문서를 법원에 보내도록 촉탁할 것을 신청할 수 있다.','민소 §352',1,false),
(1419,1,'제352조','제2편 제1심의 소송절차','O','문서송부촉탁은 반드시 원본의 송부를 촉탁하여야 하는 것은 아니고 등본·초본의 송부를 촉탁할 수도 있다.','대판(문서송부촉탁)',1,false),
(1420,1,'제355조','제2편 제1심의 소송절차','O','문서제출명령에 기하여 제출하는 문서는 원본·정본 또는 인증등본이어야 한다.','민소 §355',1,false),
(1421,1,'제355조','제2편 제1심의 소송절차','O','법원에 문서를 제출하거나 보낼 때에는 원본, 정본, 또는 인증이 있는 등본으로 하여야 한다.','민소 §355①',1,false),
(1422,1,'제355조','제2편 제1심의 소송절차','O','문서 제출은 원본·정본·인증등본에 의함이 원칙이나, 원본의 존재·진정성립이 인정되는 등 일정한 경우에는 사본도 증거능력이 인정될 수 있다(전적으로 부정되는 것은 아니다).','대판(사본 증거능력)',1,false),
(1423,1,'제356조','제2편 제1심의 소송절차','O','공무원이 직무상 작성한 것으로 인정되는 문서는 진정한 공문서로 추정되며, 외국 공공기관이 작성한 것으로 인정되는 문서도 같다.','민소 §356①③',1,false),
(1424,1,'제356조','제2편 제1심의 소송절차','O','문서의 방식과 취지에 의하여 공문서로 인정되는 때에는 진정한 공문서로 추정한다.','민소 §356①',1,false),
(1425,1,'제356조','제2편 제1심의 소송절차','O','문서의 작성방식과 취지에 의하여 공무원이 직무상 작성한 것으로 인정한 때에는 이를 진정한 공문서로 추정한다.','민소 §356②',1,false),
(1426,1,'제357조','제2편 제1심의 소송절차','O','사문서의 진정성립은 그 문서를 증거로 제출하는 자(거증자)가 증명할 책임이 있다.','판례',1,false),
(1427,1,'제357조','제2편 제1심의 소송절차','O','사문서의 진정성립은 증명방법에 제한이 없으므로, 작성명의인이 아닌 제3자의 증언으로도 증명할 수 있다.','판례',1,false),
(1428,1,'제358조','제2편 제1심의 소송절차','O','작성명의인의 날인만 되어 있고 내용이 백지인 문서를 교부받아 후일 백지부분을 작성명의인이 아닌 자가 보충한 문서의 경우, 문서제출자는 그 기재내용이 작성명의인으로부터 위임받은 정당한 권원에 의한 것이라는 사실까지 증명할 책임이 있고, 이는 그 문서가 처분문서라도 달라지지 않는다.','판례',1,false),
(1429,1,'제358조','제2편 제1심의 소송절차','O','문서에 찍힌 인영의 진정함을 인정한 당사자는 나중에 이를 자유롭게 철회할 수 없다.','판례',2,false),
(1430,1,'제358조','제2편 제1심의 소송절차','O','사문서의 진정성립은 다른 증거 없이 변론 전체의 취지만으로도 인정할 수 있다.','판례(92다12070)',2,false),
(1431,1,'제358조','제2편 제1심의 소송절차','O','처분문서에 기재된 작성명의인의 서명이 자기의 자필임을 당사자 자신도 다투지 아니하는 경우에는 날인이 되어 있지 않더라도 진정성립이 추정되므로, 납득할 만한 설명 없이 함부로 그 증명력을 배척할 수 없다.','판례',1,false),
(1432,1,'제358조','제2편 제1심의 소송절차','O','인영의 진정성립이 인정되면 특별한 사정이 없는 한 문서 전체가 완성된 상태에서 작성명의인이 서명·날인·무인을 한 것으로 추정된다(2단의 추정).','대판 2009다37831',1,false),
(1433,1,'제358조','제2편 제1심의 소송절차','O','완성문서 추정이 번복된 경우, 그 백지·미완성 부분이 정당한 권한에 기하여 보충되었다는 점은 그 문서의 진정성립을 주장하는 자(문서제출자)가 입증하여야 한다.','대판 2001다11406',1,false),
(1434,1,'제358조','제2편 제1심의 소송절차','O','작성명의인의 인영이 그의 인장에 의하여 현출된 것으로 인정되면 특단의 사정이 없는 한 날인행위가 그 의사에 기한 것으로 추정되고 문서 전체의 진정성립까지 추정되므로, 위조를 주장하는 자가 그 인영이 명의인의 의사에 반하여 날인된 것임을 증명해야 한다.','대판(2단의 추정)',1,false),
(1435,1,'제358조','제2편 제1심의 소송절차','O','문서의 진정성립에 관하여 상대방이 성립인정이나 침묵으로 답변하면 주요사실처럼 재판상의 자백·자백간주의 법리가 적용된다.','대판(문서성립 자백)',1,false),
(1436,1,'제358조','제2편 제1심의 소송절차','O','내용증명우편은 우체국이 작성한 부분(공문서)에 한하여 진정성립이 추정되고, 그 내용 전체의 진정성립이 추정되는 것은 아니다.','대판(내용증명)',1,false),
(1437,1,'제358조','제2편 제1심의 소송절차','O','회계장부·일기는 작성자의 견문·판단을 기재한 보고문서이고 처분문서가 아니다.','대판(보고문서)',1,false),
(1438,1,'제358조','제2편 제1심의 소송절차','O','문서에 찍힌 인영의 진정함을 인정하는 것은 보조사실에 관한 자백으로서 함부로 철회할 수 없다.','대판(인영 자백)',1,false),
(1439,1,'제358조','제2편 제1심의 소송절차','O','제3자가 작성한 사문서에 관하여 상대방이 부지로 다투었는데 제출자가 성립의 진정을 증명하지 아니한 경우에도, 법원은 변론 전체의 취지를 참작하여 자유심증으로 그 성립의 진정을 인정할 수 있다.','대판(변론전취지 성립)',1,false),
(1440,1,'제358조','제2편 제1심의 소송절차','O','사문서에 날인된 작성명의인의 인영이 그의 인장에 의하여 현출된 것이면 인영의 진정성립이 추정되나, 이를 다투는 사람이 반증으로 법원에 의심을 품게 할 사정을 입증하면 그 추정은 깨어진다.','대판(인영 추정 번복)',1,false),
(1441,1,'제358조','제2편 제1심의 소송절차','O','진단서는 작성자의 판단·견문을 기재한 보고문서이므로 처분문서가 아니다.','통설',1,false),
(1442,1,'제358조','제2편 제1심의 소송절차','O','어음은 그 문서에 의하여 법률행위(어음행위)가 이루어진 처분문서이다.','통설',1,false),
(1443,1,'제358조','제2편 제1심의 소송절차','O','차용증서는 소비대차의 법률행위가 이루어진 처분문서이다.','통설',1,false),
(1444,1,'제358조','제2편 제1심의 소송절차','O','해약통지서는 해지·해제의 의사표시가 담긴 처분문서이다.','통설',1,false),
(1445,1,'제358조','제2편 제1심의 소송절차','O','사문서는 본인 또는 대리인의 서명이나 날인 또는 무인이 있는 때에는 진정한 것으로 추정한다.','민소 §358',1,false),
(1446,1,'제359조','제2편 제1심의 소송절차','O','문서의 진정성립은 필적·인영의 대조로 증명할 수 있고, 반드시 전문가 감정에 의하여야 하는 것은 아니며 육안에 의한 대조로도 판단할 수 있다.','판례',2,false),
(1447,1,'제359조','제2편 제1심의 소송절차','O','서류의 위조 여부 등은 반드시 전문가의 감정에 의하여서만 판별할 수 있는 것이 아니고 육안에 의한 대조로도 판단할 수 있다.','대판(육안 대조)',1,false),
(1448,1,'제359조','제2편 제1심의 소송절차','O','문서의 진정성립은 전문가의 감정뿐 아니라 육안에 의한 대조로도 판단할 수 있다.','대판(육안 대조)',1,false),
(1449,1,'제363조','제2편 제1심의 소송절차','O','당사자 또는 그 대리인이 고의나 중대한 과실로 진실에 어긋나게 문서의 진정을 다툰 때에는 법원은 결정으로 과태료에 처한다.','민소 §363',2,false),
(1450,1,'제367조','제2편 제1심의 소송절차','O','당사자본인신문은 증거조사일 뿐 변론이 아니므로, 그 진술이 상대방 주장과 일치하더라도 재판상 자백이 되지 않는다.','판례',1,false),
(1451,1,'제367조','제2편 제1심의 소송절차','O','법원은 직권으로 또는 당사자의 신청에 따라 당사자 본인을 신문할 수 있다.','민소 §367',2,false),
(1452,1,'제367조','제2편 제1심의 소송절차','O','당사자 본인으로 신문하여야 함에도 증인으로 신문하였더라도, 상대방이 지체 없이 이의하지 아니하면 책문권의 포기·상실로 그 하자가 치유된다.','대판(당사자 증인신문)',1,false),
(1453,1,'제367조','제2편 제1심의 소송절차','O','당사자본인신문을 위하여 출석을 요구하는 경우에는 공시송달을 할 수 없다.','대판(당사자신문 공시송달)',1,false),
(1454,1,'제367조','제2편 제1심의 소송절차','O','당사자신문은 보충적 증거방법이 아니라 독립된 증거방법이므로, 다른 증거방법으로 심증을 얻지 못한 경우에 한하여 허용되는 것이 아니다.','민소 §367',1,false),
(1455,1,'제367조','제2편 제1심의 소송절차','O','당사자신문은 당사자의 신청이 없더라도 법원이 직권으로 할 수 있다.','민소 §367',1,false),
(1456,1,'제367조','제2편 제1심의 소송절차','O','소송대리인은 그 소송의 제3자에 불과하므로 그 소송의 증인이 될 자격이 있다.','통설',1,false),
(1457,1,'제367조','제2편 제1심의 소송절차','O','제1심에서 공동소송인이었더라도 항소심에서 더 이상 당사자(공동소송인)가 아니게 되면 그 사람은 증인이 될 수 있다.','대판(증인능력)',1,false),
(1458,1,'제367조','제2편 제1심의 소송절차','O','당사자신문에서의 진술은 증거자료이지 변론이 아니므로 재판상의 자백은 성립하지 아니한다.','대판(당사자신문 자백)',1,false),
(1459,1,'제369조','제2편 제1심의 소송절차','O','당사자 본인은 증인과 달리 불출석하더라도 구인할 수 없다(신문사항에 관한 상대방 주장을 진실로 인정할 수 있을 뿐).','민소 §369·§370',1,false),
(1460,1,'제369조','제2편 제1심의 소송절차','O','당사자신문을 하는 경우 법원은 당사자에게 선서를 하게 하여야 한다.','민소 §369',1,false),
(1461,1,'제369조','제2편 제1심의 소송절차','O','당사자가 정당한 사유 없이 선서를 거부한 때에는 법원은 신문사항에 관한 상대방의 주장을 진실한 것으로 인정할 수 있다.','민소 §369·§349',2,false),
(1462,1,'제370조','제2편 제1심의 소송절차','O','선서한 당사자가 허위진술을 하였음을 이유로 상대방이 과태료 제재를 신청한 경우, 상대방에게는 직권발동을 촉구하는 의미 외에 과태료 재판을 신청할 권리는 없다.','판례',1,false),
(1463,1,'제372조','제2편 제1심의 소송절차','O','소송제한능력자(소송무능력자)도 당사자신문의 대상이 될 수 있다.','민소 §372',3,false),
(1464,1,'제372조','제2편 제1심의 소송절차','O','당사자인 법인의 대표자는 증인이 될 수 없고 당사자신문의 대상이 된다.','대판(법인 대표자 신문)',2,false),
(1465,1,'제372조','제2편 제1심의 소송절차','O','소송무능력자의 경우 법정대리인을 당사자신문의 대상으로 할 수 있으나, 소송무능력자 본인도 당사자신문의 대상이 될 수 있다.','민소 §372',1,false),
(1466,1,'제376조','제2편 제1심의 소송절차','O','증거보전의 신청은 상대방을 지정할 수 없는 경우에도 할 수 있다.','민소 §378',1,false),
(1467,1,'제376조','제2편 제1심의 소송절차','O','증거보전의 신청은 소를 제기한 뒤에는 그 증거를 사용할 심급의 법원에 하여야 한다.','민소 §376①',1,false),
(1468,1,'제380조','제2편 제1심의 소송절차','O','증거보전의 결정에 대하여는 불복할 수 없다.','민소 §380',1,false),
(1469,1,'제381조','제2편 제1심의 소송절차','O','증거보전에 관한 기록은 본안소송의 기록이 있는 법원에 보내야 한다.','민소 §381',1,false),
(1470,1,'제388조','제2편 제1심의 소송절차','O','제소전화해가 성립되지 아니한 경우 신청인뿐만 아니라 피신청인도 소제기신청을 할 수 있다.','민소 §388',1,false),
(1471,1,'제390조','제3편 상소','O','불상소(불항소)의 합의는 명시적이어야 하며, 단순히 변론 중 구술 진술만으로 인정되는 것은 아니다(서면 등 명확한 합의 필요).','민소 §390①',2,false),
(1472,1,'제390조','제3편 상소','O','원고의 청구에 대해 피고가 청구기각을 구하였으나 법원이 소 각하 판결을 한 경우, 피고가 청구기각을 구하면서 제기하는 항소는 상소이익이 인정되지 않는다.','판례',1,false),
(1473,1,'제390조','제3편 상소','O','불항소 합의의 유무는 항소의 적법요건에 관한 법원의 직권조사사항이다.','판례',1,false),
(1474,1,'제390조','제3편 상소','O','가분채권의 일부청구임을 명시하지 않고 청구하여 전부승소한 경우에도, 잔부에 기판력이 미쳐 다시 소구할 수 없게 되므로 그 원고에게는 잔부 청구를 위하여 항소할 이익이 인정된다.','대판 1997.10.24. 96다12276; 실무제요 Ⅱ3029',3,true),
(1475,1,'제390조','제3편 상소','O','항소심에서의 환송판결·이송판결도 종국판결로서 상고의 대상이 된다.','대판(환송판결 종국판결)',1,false),
(1476,1,'제390조','제3편 상소','O','가분채권 이행청구의 소에서 나머지 부분을 유보하고 일부만 청구한다는 취지를 명시하지 아니한 경우, 일부 청구에 관하여 전부승소한 채권자라도 나머지 부분 청구확장을 위한 항소가 허용된다.','대판 96다12276',1,false),
(1477,1,'제390조','제3편 상소','O','판결 선고 전에 적법한 불상소(불항소) 합의가 있으면 그 판결은 선고와 동시에 확정된다.','대판(불상소합의 확정시기)',2,false),
(1478,1,'제390조','제3편 상소','O','특정 법률관계에 관하여 당사자 쌍방이 제1심판결 선고 전에 미리 항소하지 아니하기로 합의하였다면, 그 판결 선고 후에는 합의에 의하더라도 불항소합의를 해제하고 소송계속을 부활시킬 수 없다.','대판(불항소합의 부활)',1,false),
(1479,1,'제390조','제3편 상소','O','구체적 사건의 소송계속 중 당사자 쌍방이 판결 선고 전에 미리 상소하지 아니하기로 합의하는 경우 반드시 서면에 의하여야 한다.','민소 §390②',1,false),
(1480,1,'제390조','제3편 상소','O','상계항변이 이유 있다 하여 전부 승소한 피고는 (반대채권 소멸에 기판력이 생기므로) 상소의 이익이 있다.','대판(상계 전부승소 상소이익)',1,false),
(1481,1,'제390조','제3편 상소','O','불항소 합의는 당사자 쌍방이 하여야 하고, 당사자 일방만이 항소하지 아니하기로 하는 약정은 공평에 어긋나 효력이 없다.','대판(편면적 불항소합의)',2,false),
(1482,1,'제390조','제3편 상소','O','가분채권의 일부청구임을 명시하지 않고 청구하여 전부승소한 채권자에게도 잔부에 기판력이 미치므로, 나머지 청구를 확장하기 위한 항소가 허용된다.','대판 96다12276',1,false),
(1483,1,'제390조','제3편 상소','O','전부 승소한 당사자라도 (가분채권의 명시되지 않은 일부청구에서 전부승소한 경우 등) 예외적으로 상소의 이익이 인정될 수 있으므로, 그 부정이 절대적인 것은 아니다.','대판(전부승소 상소이익)',1,false),
(1484,1,'제390조','제3편 상소','O','당사자는 제1심의 종국판결 뒤에 상고할 권리를 유보하고 항소를 하지 아니하기로 합의할 수 있다(비약상고 합의).','민소 §390①단서',2,false),
(1485,1,'제390조','제3편 상소','O','전부승소한 원고가 단지 청구취지 확장·소변경을 위하여 상소하는 것은 원칙적으로 상소의 이익이 없어 허용되지 않는다.','대판(전부승소 상소)',1,false),
(1486,1,'제390조','제3편 상소','O','전부승소한 피고는 상소의 이익이 없으므로, 반소를 제기하기 위하여 상소하는 것은 허용되지 않는다.','대판(전부승소 피고)',1,false),
(1487,1,'제390조','제3편 상소','O','가분채권의 일부청구임을 명시하지 않고 청구하여 전부승소한 자에게도 잔부 청구를 위한 항소의 이익이 인정된다.','대판 96다12276',1,false),
(1488,1,'제391조','제3편 상소','O','소송비용부담의 재판에 대해서는 독립하여 상소할 수 없고, 본안재판과 함께 불복하여야 한다.','대판(비용재판 독립상소)',1,false),
(1489,1,'제391조','제3편 상소','O','본안의 재판 중에 한 소송비용 및 가집행에 관한 재판에 대하여는 독립하여 상소하지 못한다.','민소 §391',2,false),
(1490,1,'제391조','제3편 상소','O','소송비용에 관한 재판에 대하여는 독립하여 항소를 하지 못한다.','민소 §391',1,false),
(1491,1,'제393조','제3편 상소','O','항소의 취하는 소의 취하와 달리 상대방의 동의를 필요로 하지 않는다.','민소 §393',4,false),
(1492,1,'제393조','제3편 상소','O','항소기간 경과 전에 항소를 취하하였더라도 그 판결은 확정되지 않고, 항소기간 내라면 다시 항소를 제기할 수 있다.','판례',1,false),
(1493,1,'제393조','제3편 상소','O','항소기간 경과 후 항소취하가 있으면 항소기간 만료 시로 소급하여 제1심판결이 확정되나, 항소기간 경과 전 항소취하가 있으면 판결은 확정되지 않고 항소기간 내라면 다시 항소할 수 있다.','판례',2,false),
(1494,1,'제393조','제3편 상소','O','항소의 취하는 항소심의 종국판결이 선고되기 전까지 할 수 있다.','민소 §393①',2,false),
(1495,1,'제393조','제3편 상소','O','항소의 일부취하는 효력이 없으므로, 일부 청구 부분에 대한 항소취하에도 불구하고 그 부분은 여전히 항소심에 계속되어 있다(다시 항소를 제기할 여지가 없다).','대판(항소 일부취하)',1,false),
(1496,1,'제393조','제3편 상소','O','항소기간 경과 후에 항소취하가 있는 경우에는 항소기간 만료 시로 소급하여 제1심판결이 확정된다.','대판(항소취하 소급)',1,false),
(1497,1,'제393조','제3편 상소','O','항소심의 종국판결이 선고된 뒤라도 그 판결이 상고심에서 파기환송된 경우에는, 부대항소 제기 여부와 관계없이 새로운 종국판결이 있기까지 항소인은 항소를 취하할 수 있다.','대판(파기환송 후 항소취하)',1,false),
(1498,1,'제393조','제3편 상소','O','항소의 취하는 항소법원에 하여야 하나, 소송기록이 원심법원에 있을 때에는 원심법원에 하여야 한다.','민소 §393',2,false),
(1499,1,'제393조','제3편 상소','O','피고의 항소로 인한 항소심에서 소의 교환적 변경이 적법하게 이루어진 뒤에 한 피고의 항소 취하는, 그 대상이 없어 아무런 효력이 발생할 수 없다.','대판(교환적 변경 후 항소취하)',1,false),
(1500,1,'제393조','제3편 상소','O','항소인은 종국판결이 있기 전까지는 피항소인이 부대항소를 제기한 경우에도 피항소인의 동의 없이 항소를 취하할 수 있다.','대판(부대항소와 항소취하)',1,false),
(1501,1,'제393조','제3편 상소','O','항소의 취하에는 상대방의 동의가 필요하지 않다(부대항소의 취하에도 동의가 필요하지 않다).','민소 §393',1,false),
(1502,1,'제393조','제3편 상소','O','항소심의 종국판결이 선고된 뒤에는 소의 취하는 가능하지만 항소의 취하는 불가능하다.','민소 §393①',1,false),
(1503,1,'제395조','제3편 상소','O','항소권의 포기는 항소를 하기 이전에는 제1심 법원에, 항소를 한 뒤에는 소송기록이 있는 법원에 서면으로 하여야 한다.','민소 §395',3,false),
(1504,1,'제395조','제3편 상소','O','항소포기의 의사를 표시하는 서면이 법원에 제출되기 전에 그 약정을 해제하기로 다시 합의하고 항소를 제기하였다면, 그 합의 해제의 효력에 따라 위 항소는 적법하다.','판례',1,false),
(1505,1,'제395조','제3편 상소','O','항소를 한 뒤 소송기록이 제1심법원에 있는 동안 제1심법원에 항소권포기서를 제출한 경우에는 제출한 즉시 항소권 포기의 효력이 발생한다.','민소 §395',2,false),
(1506,1,'제395조','제3편 상소','O','항소를 한 뒤의 항소권의 포기는 항소취하의 효력도 가진다.','민소 §395',2,false),
(1507,1,'제396조','제3편 상소','O','항소장이 제1심 법원이 아닌 항소심 법원에 접수되었다가 제1심 법원으로 송부된 경우에는 항소심 법원 접수시가 아니라 제1심 법원 도착시를 기준으로 항소기간 준수 여부를 판단하여야 한다.','판례',1,false),
(1508,1,'제396조','제3편 상소','O','상소장을 상소법원에 잘못 제출하여 상소법원이 원법원에 송부한 경우, 상소기간의 준수 여부는 원칙적으로 상소장이 원법원에 제출된 때를 기준으로 한다.','대판(상소장 오제출)',1,false),
(1509,1,'제396조','제3편 상소','O','항소는 판결서가 송달된 날부터 2주 이내에 하여야 하지만, 판결서 송달 전에도 할 수 있다.','민소 §396①',4,false),
(1510,1,'제396조','제3편 상소','O','항소는 판결서 송달 전에도 할 수 있다.','민소 §396①',1,false),
(1511,1,'제396조','제3편 상소','O','허위주소로 한 판결정본 송달은 무효이므로 항소기간이 진행하지 않아 항소를 각하할 수 없다.','대판 78다1242',1,false),
(1512,1,'제396조','제3편 상소','O','피고는 제1심 판결정본의 송달을 받지 않은 상태에 있으므로, 그 항소는 제1심판결정본 송달 전에 제기된 것으로서 적법하다.','대판 78다1242',1,false),
(1513,1,'제397조','제3편 상소','O','항소장에는 당사자와 법정대리인 및 제1심판결을 표시하고 그 판결에 대하여 항소하는 취지를 기재하면 족하며, 불복의 범위와 이유를 기재할 필요는 없다.','민소 §397②',1,false),
(1514,1,'제397조','제3편 상소','O','항소장에는 당사자 또는 대리인이 기명날인·서명하여야 하나, 누락되었더라도 기재에 의하여 항소인이 누구인지 알 수 있고 그것이 항소인의 의사로 제출된 것으로 인정되면 무효라고 할 수 없다.','대판(항소장 기명날인)',1,false),
(1515,1,'제397조','제3편 상소','O','항소의 제기는 항소장을 제1심법원에 제출함으로써 한다.','민소 §397①',1,false),
(1516,1,'제397조','제3편 상소','O','항소의 제기는 제1심 법원에 항소장을 제출할 것을 요한다.','민소 §397①',1,false),
(1517,1,'제399조','제3편 상소','O','항소권 포기로 제1심판결이 확정된 후 제기된 항소는 부적법함이 분명하므로, 원심재판장이 항소장 각하명령을 할 수 있다.','판례',1,false),
(1518,1,'제399조','제3편 상소','O','항소장·상고장의 인지 등 보정명령은 재판장뿐만 아니라 법원사무관등으로 하여금 하게 할 수도 있다.','민소 §399·§402',1,false),
(1519,1,'제400조','제3편 상소','O','원심법원의 법원사무관등은 항소장이 제출된 날부터 2주 이내에 항소기록을 항소법원으로 보내야 한다.','민소 §400',1,false),
(1520,1,'제402조','제3편 상소','O','독립당사자참가소송의 제1심 본안판결에 일방이 항소하고 피항소인 중 1명에게 항소장이 적법하게 송달되어 항소심과 당사자들 사이의 소송관계가 일부라도 성립한 것으로 볼 수 있다면, 항소심재판장은 더 이상 단독으로 항소장 각하명령을 할 수 없다.','판례',1,false),
(1521,1,'제402조','제3편 상소','O','항소장이 피항소인에게 송달되어 항소심의 변론이 개시된 후에는 재판장은 명령으로 항소장을 각하할 수 없다.','대판(항소장 각하 한계)',1,false),
(1522,1,'제403조','제3편 상소','O','원고 전부승소판결에 대하여 피고가 지연손해금 부분에 대하여만 항소하고 원고가 부대항소로 청구취지를 확장변경한 경우, 항소심이 제1심 인용금액을 초과하여 청구를 인용하여도 불이익변경금지 원칙에 위배되지 않는다.','판례',2,false),
(1523,1,'제403조','제3편 상소','O','부대항소는 항소심의 변론이 종결될 때까지 할 수 있다(판결 선고시까지가 아니다).','민소 §403',2,false),
(1524,1,'제403조','제3편 상소','O','피항소인이 항소기간이 지난 뒤에 단순한 항소기각 신청을 넘어 제1심판결보다 자신에게 유리한 판결을 구하는 적극적·공격적 신청이 명백히 기재된 서면을 제출하고 상대방에게 절차적 권리가 보장된 경우에는, ''부대항소장''이라는 표현이 없더라도 이를 부대항소로 볼 수 있다.','판례',1,false),
(1525,1,'제403조','제3편 상소','O','피항소인이 부대항소를 할 수 있는 범위는 항소인이 주된 항소로 불복을 제기한 범위에 의하여 제한을 받지 않는다.','판례',2,false),
(1526,1,'제403조','제3편 상소','O','통상공동소송에서는 항소하지 않은 공동소송인에 대한 청구는 이심되지 않고 분리확정되므로, 그를 상대로 한 부대항소는 허용되지 않는다.','대판(통상공동소송 부대항소)',1,false),
(1527,1,'제403조','제3편 상소','O','피항소인은 항소권의 포기나 항소기간의 도과로 자기의 항소권이 소멸한 후에도 부대항소를 제기할 수 있다.','민소 §403',3,false),
(1528,1,'제403조','제3편 상소','O','제1심에서 원고가 전부 승소하여 피고만이 항소한 경우에도 원고는 항소심에서 청구취지를 확장할 수 있고, 그에 의하여 피고에게 불리하게 되는 한도에서 부대항소를 한 것으로 본다.','판례',3,false),
(1529,1,'제403조','제3편 상소','O','항소인은 일부 청구에 대한 불복신청을 철회하였더라도 항소심 변론종결시까지 불복의 범위를 다시 확장할 수 있다.','대판(불복범위 확장)',1,false),
(1530,1,'제403조','제3편 상소','O','부대항소는 항소심 변론종결시까지 할 수 있으며, 부대상고는 상고이유서 제출기간 만료시까지 할 수 있다.','대판(부대상고 시기)',1,false),
(1531,1,'제403조','제3편 상소','O','부대항소인이 제1심 판결정본을 송달받은 날부터 2주일 이내에 제기한 부대항소는 (그 자체로 독립한 항소이므로) 주된 항소의 취하·각하에 영향을 받지 않는다.','대판(독립 부대항소)',1,false),
(1532,1,'제403조','제3편 상소','O','피고만 항소한 경우에도 원고가 부대항소를 하면 불이익변경금지가 배제되어, 항소심은 제1심판결의 인용 금액을 초과하여 원고의 청구를 인용할 수 있다.','대판(부대항소와 불이익변경)',1,false),
(1533,1,'제403조','제3편 상소','O','부대항소도 취하할 수 있으며, 부대항소를 취하함에는 상대방의 동의를 얻을 필요가 없다.','대판(부대항소 취하)',1,false),
(1534,1,'제403조','제3편 상소','O','부대항소는 항소심의 변론종결 전까지 가능하다.','민소 §403',1,false),
(1535,1,'제403조','제3편 상소','O','통상의 공동소송에서 공동당사자 일부만이 항소를 제기한 때에는, 피항소인은 항소인인 공동소송인 이외의 다른 공동소송인을 상대방으로 하여 부대항소를 제기할 수 없다.','대판(통상공동소송 부대항소)',1,false),
(1536,1,'제403조','제3편 상소','O','부대항소의 취하에는 상대방의 동의가 필요하지 않다.','대판(부대항소 취하)',1,false),
(1537,1,'제403조','제3편 상소','O','주된 항소가 적법하게 계속되어 있어야 부대항소를 할 수 있다.','민소 §403',1,false),
(1538,1,'제404조','제3편 상소','O','항소기간 이내에 한 부대항소는 독립된 항소로 본다.','민소 §404',1,false),
(1539,1,'제404조','제3편 상소','O','채권자가 대위권을 행사할 당시에 이미 채무자가 그 권리를 재판상 행사하였을 때에는, 채권자는 채무자를 대위하여 그 권리를 행사할 수 없다.','대판(중복 대위)',1,false),
(1540,1,'제404조','제3편 상소','O','비법인사단인 채무자 명의로 제3채무자를 상대로 한 소가 사원총회 결의 없이 총유재산에 관한 소가 제기되었다는 이유로 각하확정된 경우에는, 채무자가 스스로 제3채무자에 대한 권리를 행사한 것으로 볼 수 없다.','대판(총유 각하)',1,false),
(1541,1,'제404조','제3편 상소','O','채권자대위소송에서 채권자의 피보전채권이 인정되지 않으면 당사자적격이 없어 소를 각하하여야 한다.','대판(피보전채권 당사자적격)',1,false),
(1542,1,'제404조','제3편 상소','O','채권자대위권에 기해 청구하다가 피대위채권 자체를 양수하여 양수금청구로 소를 변경한 경우, 당초의 채권자대위소송으로 인한 시효중단의 효력은 소멸하지 않는다.','대판(대위→양수금)',1,false),
(1543,1,'제404조','제3편 상소','O','부대항소는 주된 항소가 취하·각하되면 효력을 잃는 것이 원칙이고, 다만 항소기간 내에 제기된 부대항소만 독립된 항소로 보아 처리한다.','민소 §404',1,false),
(1544,1,'제404조','제3편 상소','O','채권자대위소송은 제3자의 소송담당의 한 유형이다.','통설',1,false),
(1545,1,'제404조','제3편 상소','O','채권자대위소송에서 피보전채권이 존재하지 않음이 밝혀지면 원고는 당사자적격이 없으므로 청구기각이 아니라 소각하 판결을 하여야 한다.','대판(피보전채권 당사자적격)',1,false),
(1546,1,'제404조','제3편 상소','O','채권자대위권을 행사한 채권자는 법정 소송담당이다.','통설',1,false),
(1547,1,'제404조','제3편 상소','O','부대항소는 항소가 취하되면 그 효력을 잃는다.','민소 §404',1,false),
(1548,1,'제404조','제3편 상소','O','항소기간 이내에 한 부대항소는 독립된 항소로 보므로, 주된 항소가 취하·각하되더라도 그 효력을 잃지 않는다.','민소 §404단서',1,false),
(1549,1,'제407조','제3편 상소','O','당사자는 항소심에서 제1심 변론의 결과를 진술하여야 한다.','민소 §407②',1,false),
(1550,1,'제412조','제3편 상소','O','항소심에서의 반소제기는 상대방의 심급의 이익을 해할 우려가 없거나 상대방이 동의한 경우에 허용된다(심급이익을 해할 우려가 없으면 동의 없이도 가능).','민소 §412',1,false),
(1551,1,'제412조','제3편 상소','O','항소심에서 피고의 반소장 진술에 원고가 ''반소기각 답변''만 한 것으로는 민소 §412② ''이의 없이 반소 본안에 변론한 때''에 해당하지 않는다.','민소 §412②',1,false),
(1552,1,'제412조','제3편 상소','O','피고가 본소에 대한 추완항소를 하면서 항소심에서 비로소 반소를 제기한 경우, 그 항소가 부적법 각하되면 반소도 소멸한다.','대판(추완항소 반소)',1,false),
(1553,1,'제412조','제3편 상소','O','반소청구의 기초인 실질적 쟁점이 제1심에서 본소 청구원인·방어방법과 관련하여 충분히 심리되어, 항소심에서의 반소 제기를 동의 없이 허용하더라도 상대방에게 심급의 이익을 잃게 하거나 절차를 현저히 지연시킬 염려가 없는 경우에는, 동의 여부와 관계없이 항소심에서의 반소 제기를 허용하여야 한다.','대판(항소심 반소)',2,false),
(1554,1,'제413조','제3편 상소','O','부적법한 항소가 각하되는 경우 제1심판결의 확정 시점은 일률적으로 ''항소각하판결 확정 시''가 아니라 부적법 사유에 따라 정해진다(예: 항소기간 도과 시에는 그 기간 만료 시 이미 확정).','판례·통설',1,true),
(1555,1,'제415조','제3편 상소','O','원고의 청구를 기각하여야 할 것인데도 소가 부적법하다고 각하한 제1심판결에 대하여 원고만이 항소한 경우, 불이익변경금지의 원칙상 더 불리한 청구기각 판결을 할 수 없으므로 원고의 항소를 기각할 수밖에 없다.','판례',2,false),
(1556,1,'제415조','제3편 상소','O','수개의 청구에서 패소한 당사자가 그 중 일부에 대하여만 항소한 경우, 항소되지 않은 나머지 부분도 확정이 차단되고 이심은 되나, 항소취지를 확장하지 않는 한 항소심 심판대상이 되지 않고 항소심 판결선고와 동시에 확정되어 소송이 종료된다.','판례',2,false),
(1557,1,'제415조','제3편 상소','O','동시이행의 판결에서는 피고의 반대급부이행청구에 관하여 기판력이 생기지 아니하므로, 반대급부의 내용이 원고에게 불리하게 변경되더라도 불이익변경금지 원칙에 반한다고 할 수 없다.','판례',2,false),
(1558,1,'제415조','제3편 상소','O','원고 채권의 발생을 인정하고 피고 상계항변을 받아들여 청구기각한 제1심판결에 원고만 항소한 경우, 항소심이 원고 채권 자체가 부존재한다고 보더라도 상계항변의 기판력(§216②) 때문에 제1심보다 불리하게 변경할 수 없어 항소를 기각하여야 한다.','민소 §216②·§415; 실무제요 Ⅱ5723',1,true),
(1559,1,'제415조','제3편 상소','O','원고가 재산상 손해(소극적 손해)에 대하여는 형식상 전부 승소하였으나 위자료에 대하여 일부 패소하여 그 패소부분에 불복하여 항소한 경우, 항소심에서 위자료는 물론 재산상 손해에 관하여도 청구를 확장할 수 있다.','판례',1,false),
(1560,1,'제415조','제3편 상소','O','원본채권과 지연손해금채권은 별개의 소송물이므로, 불이익변경 여부는 원금과 지연손해금 부분을 각각 따로 비교하여 판단하여야 하고 합산한 전체 금액 기준으로 판단하여서는 안 된다.','판례',2,false),
(1561,1,'제415조','제3편 상소','O','재심은 상소와 유사한 성질을 가지므로 부대재심이 제기되지 않는 한 재심원고에 대하여 원래의 확정판결보다 불이익한 판결을 할 수 없다.','판례',1,false),
(1562,1,'제415조','제3편 상소','O','가집행선고가 붙지 않은 제1심판결에 피고만이 항소한 항소심에서 항소를 기각하면서 가집행선고를 붙였더라도 불이익변경금지 원칙에 위배되지 않는다.','판례',1,false),
(1563,1,'제415조','제3편 상소','O','원고가 1,000만 원을 청구하여 600만 원 일부 승소판결을 받은 경우, 원고가 패소한 400만 원에 불복하여 항소하면 불복하지 않은 600만 원 부분도 항소심에 이심된다.','판례',1,false),
(1564,1,'제415조','제3편 상소','O','''피고는 원고로부터 3,000만 원을 지급받음과 동시에 이전등기를 이행하라''는 제1심판결에 원고만이 항소하였는데 항소심이 ''4,000만 원을 지급받음과 동시에 이전등기를 하라''는 판결을 하는 것은 불이익변경금지 원칙에 위반된다.','대판(상환이행 불이익변경)',1,false),
(1565,1,'제415조','제3편 상소','O','소가 부적법하다고 하여 소각하한 제1심판결에 대하여 원고가 항소한 경우, 항소심이 소는 적법하나 청구가 이유 없다고 판단할 때에는 (불이익변경금지상) 항소를 기각하여야 한다.','대판(소각하→청구기각 불가)',1,false),
(1566,1,'제417조','제3편 상소','O','제1심법원이 피고의 답변서 제출을 간과한 채 무변론판결을 선고하여 제1심판결 절차가 법률에 어긋난 경우, 항소법원은 제1심판결을 취소하여야 한다.','민소 §417',1,false),
(1567,1,'제422조','제3편 상소','O','제1심판결에 대하여 불복하지 않은 당사자는 그에 대한 항소심판결이 제1심판결보다 불리하지 않다면 항소심판결에 대해 상고의 이익이 없다.','대판(상소이익)',1,false),
(1568,1,'제422조','제3편 상소','O','피고의 상계항변을 인용하여 청구를 기각한 경우 피고는 반대채권이 상계로 소멸하는 불이익(기판력)을 받으므로, 그 판결에 대하여 상고를 제기할 상소의 이익이 있다.','대판(상계 인용 상소이익)',1,false),
(1569,1,'제423조','제3편 상소','O','소액사건에서 ''대법원 판례에 상반되는 판단을 한 때''라는 상고이유 요건을 갖추지 못하였더라도, 법령해석의 통일이라는 대법원의 본질적 기능 수행에 필요한 특별한 사정이 있는 경우에는 상고심에서 실체법 해석·적용에 관하여 판단할 수 있다.','대판(소액 상고 특별사정)',1,false),
(1570,1,'제423조','제3편 상소','O','사실관계의 당부 판단에 대해서는 상고할 수 없는 것이 원칙이다.','민소 §423',1,false),
(1571,1,'제423조','제3편 상소','O','상고심은 법률심으로서 사후심제가 원칙이다.','통설',1,false),
(1572,1,'제424조','제3편 상소','O','전속관할을 어긴 경우는 절대적 상고이유와 재심사유에 해당한다.','민소',1,false),
(1573,1,'제424조','제3편 상소','O','변호사 아닌 지방자치단체 소속 공무원으로 하여금 소송수행자로서 지방자치단체의 소송대리를 하도록 한 것은 민사소송법 제424조 제1항의 절대적 상고이유에 해당한다.','대판(소송수행자)',1,false),
(1574,1,'제424조','제3편 상소','O','법원이 대리권 없음을 간과하고 본안판결을 하였더라도 그 판결은 당연무효가 아니고, 상소 또는 재심(§451①3호)으로 다툴 수 있을 뿐이다.','대판(대리권 흠 판결)',2,false),
(1575,1,'제424조','제3편 상소','O','법률에 따라 판결에 관여할 수 없는 판사가 판결에 관여한 때는 절대적 상고이유에 해당한다.','민소 §424①1호',1,false),
(1576,1,'제424조','제3편 상소','O','판결의 이유를 밝히지 아니하거나 이유에 모순이 있는 때는 절대적 상고이유에 해당한다.','민소 §424①6호',2,false),
(1577,1,'제424조','제3편 상소','O','재판에 관여한 법관이 그 사건에 관하여 직무에 관한 죄를 범한 때는 절대적 상고이유가 아니라 재심사유(§451①4호)에 해당한다.','민소 §451①4호',1,false),
(1578,1,'제424조','제3편 상소','O','법정대리권·소송대리권 또는 대리인의 소송행위에 대한 특별한 권한의 수여에 흠이 있는 때는 절대적 상고이유에 해당한다.','민소 §424①4호',1,false),
(1579,1,'제424조','제3편 상소','O','전속관할에 관한 규정에 어긋난 때는 절대적 상고이유에 해당한다.','민소 §424①3호',3,false),
(1580,1,'제424조','제3편 상소','O','판결에 심리미진의 위법이 있는 때는 절대적 상고이유(§424①)에 해당하지 않는다.','민소 §424①',1,false),
(1581,1,'제425조','제3편 상소','O','상고장이 대법원에 바로 제출되었다가 다시 원심법원에 송부된 경우에는, 상고장이 원심법원에 접수된 때를 기준으로 상고 제기기간 준수 여부를 따져야 한다.','대판(상고장 오제출)',1,false),
(1582,1,'제425조','제3편 상소','O','상고는 상고기간 내에 상고장을 원심법원에 제출함으로써 한다.','민소 §425·§397',1,false),
(1583,1,'제427조','제3편 상소','O','상고인은 소송기록 접수의 통지를 받은 날부터 20일 이내에 상고이유서를 제출하여야 한다.','민소 §427',3,false),
(1584,1,'제430조','제3편 상소','O','상고법원은 소송관계를 분명하게 하기 위하여 필요한 경우에는 특정한 사항에 관하여 변론을 열어 참고인의 진술을 들을 수 있다.','민소 §430②',1,false),
(1585,1,'제433조','제3편 상소','O','상고법원은 비약적 상고에 대하여는 원심판결의 사실확정이 법률에 어긋난다는 것을 이유로 그 판결을 파기하지 못한다.','민소 §433',1,false),
(1586,1,'제434조','제3편 상소','O','상고심은 법률심이나 직권조사사항에 대하여는 사실심의 전권사항이 아니므로, 상고심도 직권으로 사실을 조사·확정할 수 있다.','대판(직권조사 상고심)',1,false),
(1587,1,'제436조','제3편 상소','O','대법원의 환송판결이 일부만 파기환송하고 나머지 상고를 기각하였다면, 파기환송되지 않은 부분은 환송판결의 선고로써 확정된다.','판례',1,false),
(1588,1,'제436조','제3편 상소','O','사건을 환송받거나 이송받은 법원은 상고법원이 파기의 이유로 삼은 사실상 및 법률상의 판단에 기속된다.','민소 §436②',1,false),
(1589,1,'제439조','제3편 상소','O','이미 성립한 결정에 대하여는 결정이 고지되어 효력을 발생하기 전에도 결정에 불복하여 항고할 수 있다.','판례',1,false),
(1590,1,'제439조','제3편 상소','O','통상항고는 기간의 제한이 없고 불복의 실익이 있는 한 언제든지 제기할 수 있다.','민소 §439',1,false),
(1591,1,'제442조','제3편 상소','O','항고기각 결정에 대한 재항고는 그 재판을 받은 당사자(항고인)만 할 수 있고, 결정에 이해관계가 있다는 것만으로 제3자가 재항고를 할 수 있는 것은 아니다.','대결(재항고 주체)',1,false),
(1592,1,'제443조','제3편 상소','O','민사소송법은 항고이유서 제출기한에 관한 규정을 두고 있지 아니하므로, 가압류이의신청에 대한 재판의 항고인이 즉시항고이유서를 제출하지 않았거나 이유를 적어 내지 않았다는 이유로 그 즉시항고를 각하할 수는 없다.','판례',1,false),
(1593,1,'제444조','제3편 상소','O','즉시항고와 특별항고는 재판이 고지된 날부터 1주 이내에 하여야 하고, 그 기간은 불변기간이다.','민소 §444·§449②',2,false),
(1594,1,'제444조','제3편 상소','O','민사소송법상 즉시항고에는 형사소송법과 달리 항고이유서 제출 강제 규정이 없으므로, 이유서를 제출하지 않았다는 이유로 즉시항고를 각하할 수 없다.','대결(즉시항고 이유서)',1,false),
(1595,1,'제444조','제3편 상소','O','즉시항고는 이를 허용하는 규정이 있는 경우에 한하여 허용된다.','민소 §444',1,false),
(1596,1,'제446조','제3편 상소','O','원심법원은 항고에 정당한 이유가 있다고 인정하는 경우 그 재판을 경정하여야 하는데, 여기의 경정에는 원재판의 취소·변경도 포함된다.','민소 §446',1,false),
(1597,1,'제446조','제3편 상소','O','재도의 고안은 적법한 항고의 경우에 허용된다는 것이 통설이다.','통설',1,false),
(1598,1,'제446조','제3편 상소','O','재도의 고안은 통상항고·즉시항고 등에는 허용되지만, 대법원의 권한에 속하는 특별항고에는 허용되지 않는다.','대판(재도의 고안 범위)',1,false),
(1599,1,'제446조','제3편 상소','O','상소장의 인지 부족으로 각하명령이 내려진 후 부족한 인지를 보정하였다 하더라도 재도의 고안에 의해 그 명령을 취소할 수는 없다.','대판(각하명령 보정)',1,false),
(1600,1,'제447조','제3편 상소','O','통상항고를 제기하더라도 집행정지의 효력이 발생하지 않는다.','민소 §447',1,false);
insert into atoms(id,subject_id,article_no,pyeon,ans,statement,ref,freq,verified) values
(1601,1,'제449조','제3편 상소','O','강제집행정지를 위한 담보제공명령은 중간적 재판으로서 독립하여 불복할 수 없고, 특별항고의 대상이 되는 재판에도 해당하지 않는다.','판례',2,false),
(1602,1,'제449조','제3편 상소','O','특별항고의 제기기간은 재판이 고지된 날부터 1주일이다.','민소 §449③',1,false),
(1603,1,'제449조','제3편 상소','O','특별항고를 제기한 당사자가 특별항고장에 이유를 적지 아니한 때에는 소송기록 접수통지를 받은 날부터 20일 내에 특별항고이유서를 제출하여야 하고, 제출하지 않으면 특별항고가 기각된다.','민소',1,false),
(1604,1,'제449조','제3편 상소','O','특별항고만 허용되는 재판에 대하여 당사자가 특별항고라는 표시와 항고법원을 대법원으로 표시하지 않았더라도, 항고장을 접수한 법원은 이를 특별항고로 보아 소송기록을 대법원에 송부하여야 한다.','판례',3,false),
(1605,1,'제449조','제3편 상소','O','특별항고가 있는 경우 원심법원은 경정결정을 할 수 없고 기록을 그대로 대법원에 송부하여야 한다.','판례',1,false),
(1606,1,'제449조','제3편 상소','O','소송요건의 적법 여부를 다투는 특별항고 사건에서도 대법원은 재판에 영향을 미친 헌법위반 등 특별항고사유가 있는지에 한정하여 심사하여야 하고, 단순한 법률위반만으로 원심결정을 파기할 수 없다.','대판(특별항고 심사범위)',1,false),
(1607,1,'제449조','제3편 상소','O','특별항고는 대법원의 권한에 속하므로 원심법원이 재도의 고안으로 경정결정을 할 수 없다.','대판(특별항고 재도의 고안)',1,false),
(1608,1,'제449조','제3편 상소','O','서면의 제목이 ''특별항고장''이고 대법원에 보내달라는 취지가 기재되어 있으면 당사자의 의사를 존중하여 특별항고로 취급할 것이고 이송할 것이 아니다.','대판(특별항고 취급)',1,false),
(1609,1,'제451조','제4편 재심','O','원고가 피고의 주소를 알면서 허위주소로 공시송달명령을 받아 판결을 확정시킨 경우, 피고는 추완상소 기간이 지났더라도 재심기간 내에 재심청구를 할 수 있다.','대판 2011다73540',2,false),
(1610,1,'제451조','제4편 재심','O','공동의 이해관계가 없는 자가 선정당사자로 선정되어 청구를 인낙하였더라도, 선정자가 스스로 선정행위를 한 경우에는 그 선정당사자 자격의 흠이 민사소송법 제451조 제1항 제3호의 재심사유에 해당하지 아니한다.','대판 2007.7.12. 2005다10470',1,false),
(1611,1,'제451조','제4편 재심','O','선서한 당사자의 거짓 진술이 판결의 증거가 된 때에는 재심사유가 된다.','민소 §451',2,false),
(1612,1,'제451조','제4편 재심','O','참칭대표자로 인하여 적법한 대표자가 변론기일통지서를 송달받지 못해 자백간주 판결이 선고된 경우는 민사소송법 제451조 제1항 제3호의 재심사유(대리권 흠)에 해당한다.','대판 98다47290',1,false),
(1613,1,'제451조','제4편 재심','O','제소자가 상대방의 주소를 허위로 기재하여 사위판결을 받고 그 판결정본도 허위주소로 송달처리된 경우, 송달이 무효이므로 상대방은 상소를 제기할 수 있고, 그 판결로 마쳐진 등기의 말소를 별소로 구할 수도 있다.','대판 94다41010',1,false),
(1614,1,'제451조','제4편 재심','O','직권조사사항이라도 당사자가 주장하거나 조사를 촉구한 경우에는 이를 판단하지 아니하면 민소 §451①9호의 판단누락 재심사유에 해당할 수 있다.','민소 §451①9호; 판례',1,true),
(1615,1,'제451조','제4편 재심','O','대법원의 환송판결은 중간판결의 특성을 가져 실질적으로 확정된 종국판결이라 할 수 없으므로 §451① 재심의 대상이 되지 않는다.','대판 93재다27',1,false),
(1616,1,'제451조','제4편 재심','O','판결확정 전에 제기한 재심의 소가 부적법 각하되지 않고 있는 동안 재심대상판결이 나중에 확정되더라도 재심의 소가 적법해지지 않는다.','대판 2016다35123',1,false),
(1617,1,'제451조','제4편 재심','O','재심은 확정 종국판결에 중대한 하자가 있는 경우 예외적으로 법적 안정성을 후퇴시켜 그 하자를 시정하여 구체적 정의를 실현하기 위한 제도이다.','대판 2006다34190',1,false),
(1618,1,'제451조','제4편 재심','O','여러 유죄판결이 재심대상판결의 기초가 된 경우, 그중 어느 한 유죄판결이 효력을 잃고 무죄판결이 확정된 사정은 특별한 사정이 없는 한 별개의 독립된 재심사유가 된다.','대판 2018다300470',1,false),
(1619,1,'제451조','제4편 재심','O','재심의 소에서는 확정된 재심대상판결의 취소 및 본소청구의 기각을 구하는 외에 새로운 청구를 병합할 수 없다.','대판 71다8',1,false),
(1620,1,'제451조','제4편 재심','O','소송대리인이 화해권한 범위를 넘어 소송물 이외의 권리관계를 포함시켜 화해한 사유는 재심사유에 해당하지만, 그 재심의 소는 재심기간의 제한을 받는다.','차상명 해설(2019)',1,false),
(1621,1,'제451조','제4편 재심','O','채권자는 채무자의 재심의 소 제기권을 대위행사할 수 없으므로, 대위권을 행사하여 재심의 소를 제기할 수 없다.','대판(재심 대위)',1,false),
(1622,1,'제451조','제4편 재심','O','재심대상판결의 소송물이 취득시효 완성을 이유로 한 소유권이전등기청구권인 경우, 그 변론종결 후 원고로부터 소유권이전등기를 경료받은 승계인을 상대로 제기한 재심의 소는 부적법하다.','대판(재심 승계인)',1,false),
(1623,1,'제451조','제4편 재심','O','대표자·대리인이 상대방과 통모하여 배임행위 등으로 지급명령에 대한 이의신청을 취하한 경우, 그 취하의 효력이 부정되려면 그 가벌적 행위에 대하여 유죄판결·과태료재판이 확정되거나 증거부족 외의 이유로 그 확정재판을 할 수 없는 때라야 한다.','대판(통모 취하)',1,false),
(1624,1,'제451조','제4편 재심','O','재심의 소에서 각 재심사유는 별개의 청구(소송물)를 구성하므로, 다른 재심사유를 추가하는 것은 공격방법의 추가가 아니라 청구(소)의 추가적 변경에 해당한다.','대판(재심사유 소송물)',1,false),
(1625,1,'제451조','제4편 재심','O','직권조사사항인 소송요건에 관한 피고의 항변에 대하여 판단하지 아니하였더라도 판단누락의 상고이유로 삼을 수 없다.','대판(직권조사 판단누락)',1,false),
(1626,1,'제451조','제4편 재심','O','환송판결은 재심의 대상을 규정한 민소 §451①의 ''확정된 종국판결''에 해당하지 않는다는 것이 판례의 태도이다.','대판 93재다27',1,false),
(1627,1,'제451조','제4편 재심','O','제3자가 원고의 소에서 특정된 피고를 참칭(모용)하여 소송을 진행한 사실을 법원이 알지 못하고 판결을 선고한 경우, 피모용자는 상소 또는 재심의 소로 그 판결의 취소를 구할 수 있다.','대판(성명모용)',1,false),
(1628,1,'제451조','제4편 재심','O','재심사유의 존부는 직권조사사항이므로 변론주의가 적용되지 않고, 그에 관한 자백은 허용되지 않는다.','대판(재심사유 직권)',1,false),
(1629,1,'제451조','제4편 재심','O','전소 판결의 기초가 된 행정처분이 변론종결 후 취소·변경된 것은 §451①8호의 재심사유에 해당하므로, 재심으로 전소판결을 취소하지 않는 한 다시 다투는 것은 기판력에 저촉된다.','대판(판결기초 행정처분 변경)',1,false),
(1630,1,'제451조','제4편 재심','O','직권조사사항에 대한 피고의 다툼은 법원의 직권발동을 촉구하는 데 그치므로, 그 주장에 대하여 판단하지 아니하였다고 하여도 판단누락의 상고이유가 되지 않는다.','대판(직권조사 판단누락)',1,false),
(1631,1,'제451조','제4편 재심','O','재심사유를 달리하는 각 재심의 소는 별개의 소송물이다.','대판(재심사유 소송물)',1,false),
(1632,1,'제451조','제4편 재심','O','당사자가 재심사유가 있는 것을 알았음에도 상소를 제기하지 아니하여 판결이 그대로 확정된 경우에는 재심의 소를 제기할 수 없다.','민소 §451①단서',1,false),
(1633,1,'제451조','제4편 재심','O','항소심에서 사건에 대하여 본안판결을 하였을 때에는 제1심판결에 대하여 재심의 소를 제기하지 못한다.','민소 §451③',1,false),
(1634,1,'제451조','제4편 재심','O','재판권의 부존재를 간과하고 본안판결을 하여 그 판결이 확정된 경우 (그 판결은 무효이므로) 재심청구를 할 수 없다.','대판(재판권 흠 판결)',1,false),
(1635,1,'제451조','제4편 재심','O','판결이 확정되지 않았으므로 재심이 아니라 항소로 불복하여야 한다.','대판 78다1242',1,false),
(1636,1,'제453조','제4편 재심','O','재심의 소는 재심을 제기할 판결을 한 법원의 전속관할에 속한다.','민소 §453',1,false),
(1637,1,'제456조','제4편 재심','O','재심대상판결 확정 후 증인의 거짓 진술에 대한 유죄판결이 확정된 경우 그 사유에 의한 재심의 소는 당사자가 유죄확정 사실을 안 날부터 30일 내에 제기되어야 하고, 그 불변기간 준수 여부는 재심의 소의 적법요건으로 직권조사사항이다.','판례',1,false),
(1638,1,'제456조','제4편 재심','O','재심의 소는 재심사유를 안 날부터 30일 이내, 판결 확정 시부터 5년 이내에 제기하여야 한다.','민소 §456',1,false),
(1639,1,'제456조','제4편 재심','O','소송대리인이 화해권한 범위를 넘어 화해한 것은 재심사유에 해당하나 (대리권 흠과 달리) 재심기간의 제한을 받으므로, 화해일로부터 5년이 지난 뒤에는 준재심의 소를 제기할 수 없다.','대판(화해권한 초과)',1,false),
(1640,1,'제456조','제4편 재심','O','상소기간, 재심기간, 화해권고결정·조정에 갈음한 결정에 대한 이의신청기간은 불변기간이다.','민소 §456② 등',1,false),
(1641,1,'제457조','제4편 재심','O','대리권의 흠 또는 재심을 제기할 판결이 전에 선고한 확정판결에 어긋나는 때를 이유로 하는 재심의 소에는 재심제기기간의 제한이 없다.','민소 §457',1,false),
(1642,1,'제457조','제4편 재심','O','재심을 제기할 판결이 전에 선고한 확정판결에 어긋나는 때(§451①10호)에는, 그 사유를 안 날부터 30일이 지난 뒤에도 재심의 소를 제기할 수 있다.','민소 §457',1,false),
(1643,1,'제459조','제4편 재심','O','재심절차에도 불이익변경금지 원칙이 적용되므로, 재심 전 판결보다 재심원고에게 불리하게 변경할 수 없다.','대판(재심 불이익변경)',1,false),
(1644,1,'제461조','제4편 재심','O','비법인 사단이 당사자로서 청구의 포기·인낙 또는 화해를 하여 조서에 적은 경우, 그 대표자에게 그러한 행위에 필요한 권한 수여에 흠이 있는 때에는 비법인 사단은 그 조서에 대하여 준재심의 소를 제기할 수 있다.','대판(준재심)',1,false),
(1645,1,'제461조','제4편 재심','O','확정된 이행권고결정은 기판력이 없어 준재심의 대상이 되지 않으므로, 재심사유에 해당하는 하자가 있더라도 청구이의의 소로 다툴 수 있을 뿐 준재심의 소를 제기할 수 없다.','대판(이행권고 준재심)',2,false),
(1646,1,'제461조','제4편 재심','O','청구의 포기 또는 인낙에 대하여는 준재심의 소에 의하여 다툴 수 있다.','민소 §461',1,false),
(1647,1,'제462조','제5편 독촉절차','O','사망자를 상대로 한 지급명령은 상속인에게 송달되어 형식적으로 확정되어도 당연무효로서 상속인에 대하여 효력이 없다.','대판 2015그(지급명령)',1,false),
(1648,1,'제462조','제5편 독촉절차','O','지급명령의 대상이 될 수 있는 것은 금전, 그 밖에 대체물이나 유가증권의 일정한 수량의 지급을 목적으로 하는 청구이다.','민소 §462',1,false),
(1649,1,'제462조','제5편 독촉절차','O','보충송달의 방법에 의하여도 지급명령을 (송달)할 수 있다.','대판(지급명령 보충송달)',1,false),
(1650,1,'제462조','제5편 독촉절차','O','채무자가 소재불명인 경우에는 (공시송달을 할 수 없으므로) 지급명령을 할 수 없다.','민소 §462단서',1,false),
(1651,1,'제462조','제5편 독촉절차','O','채무자가 외국에 거주하는 경우에는 지급명령을 할 수 없다.','대판(외국 거주)',1,false),
(1652,1,'제462조','제5편 독촉절차','O','채무자에게 물건의 인도를 구하는 경우에는 (지급명령은 금전·대체물·유가증권 지급 청구에 한하므로) 지급명령을 할 수 없다.','민소 §462',1,false),
(1653,1,'제462조','제5편 독촉절차','O','지급명령은 청구금액의 제한이 없으므로 1억 원을 초과하는 금전의 지급을 구하는 경우에도 할 수 있다.','민소 §462',1,false),
(1654,1,'제462조','제5편 독촉절차','O','지급명령은 대한민국에서 공시송달 외의 방법으로 송달할 수 있는 경우에만 할 수 있다(공시송달에 의하지 아니하고는 송달할 수 없는 경우에는 할 수 없다).','민소 §462단서',1,false),
(1655,1,'제463조','제5편 독촉절차','O','독촉절차는 전속관할이므로 관련재판적(민소 §25)이 적용되지 않아, 乙에 대한 관할이 있더라도 관할 없는 丙에 대한 지급명령신청에까지 관할이 인정되지는 않는다.','민소 §463·§25',1,false),
(1656,1,'제463조','제5편 독촉절차','O','지급명령신청에 관할위반의 사유가 있는 때에는 그 신청을 각하한다.','민소 §465',1,false),
(1657,1,'제463조','제5편 독촉절차','O','독촉절차는 채무자 보통재판적 소재지 또는 제7·8·9·12·18조의 특별재판적 규정에 의한 관할법원의 전속관할이며, 전속관할을 위반한 지급명령신청은 관할법원으로 이송할 것이 아니라 신청을 각하하여야 한다.','민소 §463·§465; 실무제요 Ⅲ8105',3,true),
(1658,1,'제463조','제5편 독촉절차','O','지급명령신청에 관할위반이 있는 경우에는 신청을 각하하여야 하고 관할법원으로 이송할 것이 아니다.','대판(독촉 관할위반)',1,false),
(1659,1,'제465조','제5편 독촉절차','O','지급명령신청을 각하하는 결정에 대하여는 불복할 수 없으나, 지급명령에 대한 이의신청을 각하하는 결정에 대하여는 즉시항고할 수 있다.','민소 §465·§471',1,false),
(1660,1,'제466조','제5편 독촉절차','O','채권자는 법원으로부터 채무자의 주소를 보정하라는 명령을 받은 경우에 소제기신청을 할 수 있다.','민소 §466',2,false),
(1661,1,'제467조','제5편 독촉절차','O','지급명령은 채무자를 심문하지 아니하고 채권자의 주장만을 근거로 하여 발하게 된다.','민소 §467',1,false),
(1662,1,'제467조','제5편 독촉절차','O','지급명령은 채무자를 심문하지 아니하고 한다.','민소 §467',1,false),
(1663,1,'제469조','제5편 독촉절차','O','지급명령에 대한 이의신청은 서면 또는 말로 할 수 있다.','민소 규칙',1,false),
(1664,1,'제470조','제5편 독촉절차','O','채무자가 지급명령을 송달받은 날부터 2주 이내에 이의신청을 한 때에는 지급명령은 그 범위 안에서 효력을 잃고, 위 2주의 기간은 불변기간이다.','민소 §470',1,false),
(1665,1,'제471조','제5편 독촉절차','O','채무자의 이의신청을 각하하는 결정에 대하여는 즉시항고를 할 수 있다.','민소 §471②',1,false),
(1666,1,'제472조','제5편 독촉절차','O','지급명령 사건이 채무자의 이의신청으로 소송으로 이행되는 경우, 그 지급명령에 의한 시효중단의 효과는 소송으로 이행된 때가 아니라 지급명령을 신청한 때에 발생한다.','대판(지급명령 시효중단)',1,false),
(1667,1,'제472조','제5편 독촉절차','O','지급명령 송달 후 이의신청 기간 중 회생절차개시결정 등의 사유가 생기면 이의신청 기간의 진행이 정지된다.','대판(이의기간 정지)',1,false),
(1668,1,'제474조','제5편 독촉절차','O','지급명령이 확정되더라도 기판력은 인정되지 않는다.','대판(지급명령 기판력 부정)',1,false),
(1669,1,'제474조','제5편 독촉절차','O','확정된 지급명령은 기판력이 인정되지 아니하므로, 청구이의의 소로 (지급명령 성립 전후의 사유를 들어) 다툴 수 있다.','대판(지급명령 기판력)',1,false),
(1670,1,'제474조','제5편 독촉절차','O','지급명령은 확정판결과 같은 효력이 있으나 기판력은 인정되지 않는다.','대판(지급명령 기판력)',1,false),
(1671,1,'제474조','제5편 독촉절차','O','지급명령으로 확정된 채권은 단기의 소멸시효에 해당하는 것이라도 소멸시효가 10년으로 연장된다.','대판(확정 지급명령 시효)',1,false),
(1672,1,'제474조','제5편 독촉절차','O','확정된 지급명령은 기판력이 없으므로, 청구이의의 소에서 지급명령 발령 전에 생긴 청구권의 불성립·무효 등의 사유도 주장할 수 있다.','대판(지급명령 청구이의)',1,false),
(1673,1,'제498조','제7편 판결의 확정 및 집행정지','O','상대방이 전부 승소하여 항소의 이익이 없는 경우에는 패소자만 항소포기를 하면 상대방의 항소기간이 만료하지 않았더라도 제1심판결이 확정된다.','판례',1,false),
(1674,1,'제498조','제7편 판결의 확정 및 집행정지','O','상소기각판결은 그것이 확정된 때에 원판결이 확정된다.','민소 §498',1,false),
(1675,1,'제498조','제7편 판결의 확정 및 집행정지','O','원고만이 패소 부분에 항소하고 피고가 불복하지 않은 원고 승소부분은 항소심의 심판대상이 되지 않으므로, 항소심판결 확정시가 아니라 그 부분에 대한 불복 없이 확정된다.','대판(불복 없는 부분 확정시기)',1,false),
(1676,1,'제498조','제7편 판결의 확정 및 집행정지','O','상소각하판결이 확정되면 상소가 없었던 것과 같은 결과가 되므로, 원판결은 그에 대한 상소기간의 만료시에 확정된다.','대판(상소각하 확정)',1,false),
(1677,1,'제498조','제7편 판결의 확정 및 집행정지','O','상소를 제기하였으나 상소를 취하한 때에는 상소기간의 만료시에 판결이 확정된다.','대판(상소취하 확정)',2,false),
(1678,1,'제498조','제7편 판결의 확정 및 집행정지','O','상고심판결은 선고와 동시에 확정된다.','대판(상고심판결 확정)',1,false),
(1679,1,'제498조','제7편 판결의 확정 및 집행정지','O','일부상소에서 불복신청이 없는 부분도 상소불가분에 의하여 이심되어 확정이 차단되고, 상소심 판결이 확정될 때 함께 확정된다(변론종결시가 아니다).','대판(일부불복 확정시기)',1,false),
(1680,1,'제499조','제7편 판결의 확정 및 집행정지','O','당사자가 판결확정증명서를 신청한 때에는 제1심 법원사무관등이 기록에 따라 내어 주고, 소송기록이 상급심에 있는 때에는 상급법원 법원사무관등이 그 확정부분에 대하여만 내어 준다.','민소 §499',2,false),
(1681,1,'제501조','제7편 판결의 확정 및 집행정지','O','강제집행의 일시정지를 명한 재판에 대하여는 불복할 수 없다.','민소 §500·§501',1,false),
(1682,1,'제502조','제7편 판결의 확정 및 집행정지','O','강제집행정지를 위한 공탁담보는 정지로 인하여 채권자에게 생길 손해만을 담보할 뿐이고, 정지의 대상인 기본채권 자체를 담보하는 것은 아니다.','대판(집행정지 담보)',1,false),
(1683,1,'소액 제3조','관련 특별법','O','소액사건은 법령의 위헌·위법 판단 부당뿐만 아니라 대법원의 판례에 상반되는 판단을 한 때에도 상고·재항고할 수 있다.','소액사건심판법 §3',1,false),
(1684,1,'소액 제5조의3','관련 특별법','O','지급명령에 대한 이의신청이 제기되어 소송절차로 이행된 경우에는 이행권고결정을 할 수 없다.','소액사건심판법 §5의3①',1,false),
(1685,1,'소액 제5조의3','관련 특별법','O','이행권고결정은 공시송달은 물론 발송송달의 방법으로도 송달할 수 없고 피고에게 직접 송달되어야 한다.','소액사건심판법 §5의3③',1,false),
(1686,1,'소액 제5조의3','관련 특별법','O','이행권고결정은 그 결정서의 정본이 아니라 등본을 송달한다.','소액사건심판법 §5의3③',1,false),
(1687,1,'소액 제5조의3','관련 특별법','O','소액사건의 이행권고결정에 대한 이의신청사건은 통상의 소송절차로 진행되며 무변론판결의 대상이 되지 않는다.','소액사건심판법',1,false),
(1688,1,'소액 제5조의7','관련 특별법','O','피고가 이행권고결정을 송달받은 날부터 2주일 내에 이의신청을 하지 않으면 이행권고결정은 확정판결과 같은 효력을 갖는다.','소액사건심판법 §5의7',1,false),
(1689,1,'소액 제5조의2','관련 특별법','O','소액사건심판법의 적용을 받을 목적으로 청구를 분할하여 그 일부만을 청구할 수 없고, 이에 위반한 소는 판결로 각하한다.','소액사건심판법 §5의2',1,false),
(1690,1,'소액 제5조의8','관련 특별법','O','확정된 이행권고결정에 기한 강제집행에서는 조건성취·승계집행문의 경우를 제외하고 집행문을 부여받을 필요가 없다.','소액사건심판법 §5의8①',1,false),
(1691,1,'소액 제8조','관련 특별법','O','소액사건에서는 법원의 허가가 없더라도 당사자의 배우자는 소송대리인이 될 수 있다.','소액사건심판법 §8',1,false),
(1692,1,'소액 제9조','관련 특별법','O','법원은 소장·준비서면 기타 소송기록에 의하여 청구가 이유 없음이 명백한 때에는 변론 없이 청구를 기각할 수 있다.','소액사건심판법 §9①',1,false),
(1693,1,'민집 제286조','관련 특별법','O','가압류에 대한 이의신청에 관한 재판도 결정절차에 의한다(판결절차가 아니다).','대판(가압류 이의)',1,false),
(1694,1,'민법 제168조·제170조(판례)','판례·논점','O','보조참가인으로서 적극적으로 다투고 자신의 권리를 주장하며 권리 위에 잠자는 자가 아님을 표명한 경우, 소멸시효 중단사유인 재판상 청구로 볼 수 있다.','판례(시효중단)',1,false),
(1695,1,'-','판례·논점','O','등기의무자(등기명의인·포괄승계인)나 등기상 이해관계 있는 제3자가 아닌 자를 상대로 한 말소등기절차이행청구의 소는 피고적격이 없어 부적법하다.','판례',1,false),
(1696,1,'민집 §227·§229','판례·논점','O','채권에 대한 압류 및 추심명령이 있더라도 채무자는 피압류채권에 관한 이행의 소를 제기할 당사자적격을 상실하지 않는다.','대판(전합) 2025.10.23. 2021다252977',1,false),
(1697,1,'민법 §406','판례·논점','O','사해행위취소의 소의 피고적격은 수익자 또는 전득자에게 있고, 채무자에게는 피고적격이 없다.','통설·판례',1,false),
(1698,1,'-','판례·논점','O','채권자대위소송에서 피보전채권이 인정되지 않으면 당사자적격이 없어 그 소를 각하하여야 한다.','판례',1,false),
(1699,1,'민법 §406·§407','판례·논점','O','채권자취소권의 요건을 갖춘 각 채권자가 동시 또는 이시에 채권자취소 및 원상회복 소송을 제기하더라도 이들 소송은 중복제소에 해당하지 아니한다.','대판 2014.8.20. 2014다28114',1,false),
(1700,1,'민법 §174','판례·논점','O','소송고지로 최고의 효력이 인정되는 경우, 당해 소송이 계속 중인 동안은 최고에 의하여 권리를 행사하고 있는 상태가 지속되는 것으로 보아 민법 제174조의 6월의 기간은 당해 소송이 종료된 때부터 기산한다.','판례',1,false),
(1701,1,'-','판례·논점','O','법무사 등은 법령에 따라 경매신청을 대리할 자격이 있으므로, 변호사가 아니라는 이유만으로 경매신청인을 대리할 자격이 없는 것은 아니다.','법무사법 §2',1,false),
(1702,1,'민법 §272','판례·논점','O','합유물에 관하여 마쳐진 원인무효의 소유권이전등기의 말소를 구하는 소송은 합유물에 관한 보존행위로서 합유자 각자가 할 수 있다.','판례',1,false),
(1703,1,'민법 §269','판례·논점','O','공유물분할청구의 소는 분할을 청구하는 공유자가 원고가 되어 다른 공유자 전부를 공동피고로 하여야 하는 고유필수적 공동소송이다.','판례',1,false),
(1704,1,'법조 §34','판례·논점','O','시·군법원 판결에 관한 청구이의의 소·제3자이의의 소는 시·군법원 관할이나, 배당이의의 소는 배당을 실시한 집행법원(지방법원)의 관할이다.','법원조직법 §34',1,false),
(1705,1,'규칙 §67','판례·논점','O','당사자 일방이 화해조서의 당연무효 사유를 주장하며 기일지정신청을 한 때에는 법원은 무효사유의 존재 여부를 가리기 위하여 기일을 지정·심리한 다음 무효사유가 인정되지 않으면 소송종료선언을 하여야 한다.','판례',1,false),
(1706,1,'규칙 §67','판례·논점','O','소취하 무효 주장 기일지정신청이 이유 없는 경우 법원은 종국''판결''로 소송종료선언을 하여야 한다(결정이 아니다).','민소규칙 §67',1,false),
(1707,1,'규칙 §67','판례·논점','O','소의 취하가 무효라는 것을 주장하며 기일지정신청을 한 경우 심리 결과 신청이 이유 있다고 인정되면 취하 당시의 소송 정도에 따라 필요한 절차를 계속 진행하고 중간판결 또는 종국판결에 그 판단을 표시하여야 한다.','판례',1,false),
(1708,1,'규칙 §67','판례·논점','O','청구의 인낙으로 소송이 종료되었음에도 소송이 진행된 경우 법원은 청구의 인낙으로 인한 소송종료선언을 하여야 한다.','판례',1,false),
(1709,1,'민법 §157','판례·논점','O','기간을 일·주·월 또는 연으로 정한 때에는 그 기간이 오전 0시로부터 시작하지 않는 한 기간의 초일은 산입하지 아니한다.','민법 §157',1,false),
(1710,1,'인지법','판례·논점','O','지급명령에 대하여 적법한 이의신청을 하여 소송으로 이행되는 경우, 지급명령 신청시의 청구금액을 소송목적의 값으로 하여 인지액을 계산함이 원칙이다.','판례',1,false),
(1711,1,'인지법','판례·논점','O','반소가 제기된 경우에는 반소 제기시를 기준으로 반소 자체에 대한 소송목적의 값을 산정함이 원칙이다.','실무',1,false),
(1712,1,'인지법','판례·논점','O','청구의 확장이나 추가적 변경을 내용으로 하는 신청서에는 확장 이후 총 소송목적의 값과 종전 소송목적의 값의 차액에 해당하는 인지를 추가로 붙여야 한다.','실무',1,false),
(1713,1,'인지규칙','판례·논점','O','시효중단을 위한 ''새로운 방식의 확인소송''의 소가는 대상인 전소 판결에서 인정된 권리 가액의 10분의 1로 하고, 그 권리 가액이 3억 원을 초과하는 경우에는 이를 3억 원으로 본다.','실무제요 Ⅰ2847; 인지규칙',1,false),
(1714,1,'소액법','판례·논점','O','소액사건은 판결서에 이유를 기재하지 아니할 수 있는 대신, 판결선고시 주문을 낭독하고 주문이 정당함을 인정할 수 있는 범위에서 이유의 요지를 말로 설명하여야 한다.','소액사건심판법',1,false),
(1715,1,'소액법','판례·논점','O','재심대상사건이 소액사건이면 그 재심절차에도 소액사건심판법이 적용된다.','판례',1,false),
(1716,1,'소액법','판례·논점','O','2개 이상의 소액사건을 병합하여 소송목적의 값의 합산액이 3,000만 원을 초과하게 되는 경우에도 여전히 소액사건에 해당한다.','판례',1,false),
(1717,1,'인지법','판례·논점','O','채무자의 적법한 이의신청으로 지급명령신청이 소송으로 이행되는 경우, 소송기록이 관할법원으로 송부되기 전에 인지 부족액이 보정되지 않은 상태에서 채권자가 청구금액을 감액하는 청구취지 변경서를 제출하는 등 특별한 사정이 있는 경우에는 변경 후 청구의 소가에 따라 인지액을 계산하여야 한다.','판례',1,false),
(1718,1,'민법 §170','판례·논점','O','지급명령에 의한 시효중단의 효과는 지급명령을 신청한 때에 발생한다.','판례',1,false),
(1719,1,'민법 §406','판례·논점','O','사해행위취소소송에서 채무자의 악의는 취소를 주장하는 채권자가 증명하나, 수익자 또는 전득자의 악의에 관하여는 수익자·전득자 자신이 선의라는 사실을 증명할 책임이 있다.','판례',1,false),
(1720,1,'소액법 §5의3','판례·논점','O','이행권고결정은 소액사건의 소가 제기된 경우에 하는 것이고, 독촉·조정에서 소송으로 이행된 사건에 대하여는 할 수 없다.','소액사건심판법',1,false),
(1721,1,'소액법 §5의3','판례·논점','O','이행권고결정서 등본은 피고에게 직접 송달되어야 하며, 발송송달이나 공시송달의 방법으로는 송달할 수 없다.','소액사건심판법',1,false),
(1722,1,'소액법','판례·논점','O','이행권고결정의 이행조항에 ''판결 선고일''까지·그 다음날부터의 이율이 기재된 경우, 그 ''판결 선고일''의 의미는 이행권고결정의 고지일인 ''이행권고결정서 등본의 송달일''로 보아야 한다.','판례',1,false),
(1723,1,'민집 §158','판례·논점','O','배당이의의 소의 원고가 ''첫 변론기일''에 출석하지 아니한 경우에는 소를 취하한 것으로 간주되는데, 여기서의 ''첫 변론기일''에는 ''첫 변론준비기일''은 포함되지 않는다.','판례',1,false),
(1724,1,'민법 §174','판례·논점','O','소송고지의 요건이 갖추어진 경우에 소송고지서에 고지자가 피고지자에 대하여 채무의 이행을 청구하는 의사가 표명되어 있으면 민법 제174조의 최고의 효력이 인정된다.','판례',1,false),
(1725,1,'민법 §174','판례·논점','O','민법 제174조에 의하면 최고는 6월 내에 재판상의 청구 등을 하지 않으면 시효중단의 효력이 없고, 소송고지로 인한 최고의 경우 그 6월의 기간은 당해 소송이 종료된 때부터 기산한다.','판례',1,false),
(1726,1,'인지법','판례·논점','O','소가는 원고가 청구취지로써 구하는 범위 내에서 원고의 입장에서 전부 승소할 경우 직접 받게 될 경제적 이익을 객관적으로 평가하여 금액으로 정함을 원칙으로 한다.','민소 §26',1,false),
(1727,1,'인지규칙','판례·논점','O','1개의 소로 수개의 청구를 하는 경우 그 경제적 이익이 독립한 별개의 것인 때에는 합산하고, 동일하거나 중복되는 때에는 중복 범위에서 흡수되어 가장 다액인 청구의 가액을 소가로 한다.','인지규칙',1,false),
(1728,1,'인지규칙','판례·논점','O','1개의 청구가 다른 청구의 수단에 지나지 않을 때에는 특별한 규정이 있는 경우를 제외하고 그 가액은 소가에 산입하지 아니하나, 수단인 청구의 가액이 주된 청구의 가액보다 다액인 경우에는 그 다액을 소가로 한다.','인지규칙',1,false),
(1729,1,'소액법 §5의4','판례·논점','O','이행권고결정에 대한 이의신청의 취하는 피고가 단독으로 할 수 있고 원고의 동의를 요하지 않는다(제1심 판결선고 전까지).','소액사건심판법',2,false),
(1730,1,'민법 §174','판례·논점','O','소송고지에 의한 최고의 시효중단 효력은 고지자가 법원에 소송고지서를 제출한 때에 발생한다.','민법 §174; 판례',2,false);
insert into atom_traps(atom_id,statement,source_label) values
(18,'사해행위취소의 소에서 의무이행지는 ''취소 대상 법률행위의 의무이행지''이므로, 사해행위취소에 따른 원상회복으로서의 소유권이전등기 말소등기의무의 이행지는 그 등기관서 소재지가 아니라 채권자인 원고의 주소지이다.','2024 문10-2'),
(22,'갑이 을과 소비대차계약을 체결하고 돈을 건네준 장소를 관할하는 법원에 소를 제기할 수 있다.','2013 문02-3'),
(23,'어음·수표에 관한 소를 제기하는 경우에는 지급지의 법원에 제기하여야 한다.','2007a 문08-3'),
(29,'특허권 등의 지식재산권에 관한 소는 서울남부지방법원에 관할이 있다.','2020 문12-3'),
(30,'하나의 소로 여러 피고에 대하여 청구를 하는 경우, 모든 피고에 대하여 관할권이 있어야 한다.','2012 문12-3'),
(32,'하나의 소로 여러 개의 청구를 하는 경우 각 청구가 단독판사 심판사건에 속하더라도, 그 합산 가액이 단독판사 관할의 상한을 초과하면 합의부 심판사건이 된다(설문의 ''1억 초과해도 단독''은 틀림).','2012 문12-2'),
(33,'주채무자와 보증인을 상대로 소를 제기하는 경우 각 청구의 소송목적의 값을 합산한다.','2012 문23-3'),
(34,'지연손해금의 청구가 소송의 부대목적이 되는 경우에 그 값을 합산한다.','2012 문23-4'),
(37,'1개의 소로써 수개의 비재산권을 목적으로 하는 청구를 하는 경우 그 중 가장 다액인 청구의 가액을 소송목적의 값으로 한다.','2011 문12-3'),
(39,'대여금청구의 소송목적의 값은 원금과 지연손해금을 합산하여 산정한다.','2010 문13-2'),
(42,'청구의 선택적 병합의 경우에는 합산하여 소송목적의 값을 산정하나, 예비적 병합의 경우에는 합산하지 않고 다액인 청구가액을 소송목적의 값으로 한다.','2007a 문22-2'),
(48,'관할합의의 효력은 소송물이 채권과 같은 상대권이면 특정승계인에게 미치지 않고, 물권과 같은 절대권이면 특정승계인에게 미친다.','2014 문21-라'),
(52,'원고가 관할권 없는 법원에 제소한 때에 피고가 본안에 관한 답변서를 제출하고 불출석한 경우, 그 답변서가 진술간주되면 변론관할이 생긴다.','2023 문18-1'),
(52,'원고가 관할권 없는 법원에 제소한 때에 피고가 본안에 관한 답변서를 제출한 채 불출석한 경우, 그 답변서가 진술간주되면 변론관할이 생긴다.','2016 문09-3'),
(54,'임의관할 위반과 소송비용의 담보제공 위반의 주장, 중재합의의 항변은 본안에 관한 사실심 변론종결시까지 제출할 수 있다.','2011 문14-1'),
(56,'특정한 법원의 전속관할로 정하여진 소라고 하더라도 합의관할 규정은 적용 가능하다.','2025 문13-4'),
(60,'전속관할에 대한 관할합의의 약정 내지 약관은 유효하다.','2012 문12-1'),
(61,'전속관할에 위반하여 소가 제기된 경우에도 피고가 관할위반이라고 항변하지 않고 본안에 대하여 변론하면 그 법원은 관할권을 가진다.','2010 문13-3'),
(62,'소송목적의 값이 2억 원 이상인 민사사건은 원칙적으로 지방법원 및 지원 합의부가 제1심으로 심판한다.','2016 문01-2'),
(64,'소송목적의 값이 1억 원인 사건은 합의부 관할사건이다.','2014 문21-나'),
(65,'최고가 9,000만 원으로 입찰하였으나 낙찰자로 선정되지 아니한 자가 낙찰자지위확인을 구하는 소는 지방법원 단독판사가 제1심으로 심판한다.','2011 문03-1'),
(66,'10억 원의 대출금채무를 연대보증한 보증인에 대하여 보증금의 지급을 구하는 소(소가 10억 원)는 지방법원 합의부가 제1심으로 심판한다.','2011 문03-3'),
(67,'관할에 관한 사항은 법원의 직권조사사항이 아니다.','2010 문13-4'),
(68,'3억 원의 지급을 구하는 약속어음금 청구사건은 지방법원 합의부의 사물관할에 해당한다.','2009 문12-1'),
(69,'근로자의 업무상 재해에 관한 채무부존재확인사건은 지방법원 합의부의 사물관할에 해당한다.','2009 문12-2'),
(71,'신용보증기금인 원고가 5억 원의 지급을 구하는 구상금 청구사건은(소가 5억 원으로 2억 원을 초과하므로) 지방법원 합의부의 사물관할에 해당한다.','2009 문12-4'),
(73,'소가는 사실심 변론종결 시를 기준으로 산정한다.','2023 문24-2'),
(80,'가정법원의 전속관할에 속하는 소를 민사법원에 제기한 것은 전속관할위반이지만, 가정법원과 민사법원 사이에서는 관할위반에 따른 이송이 인정되지 않으므로 민사법원은 그 소를 각하하여야 한다.','2015 문01-1'),
(85,'전속적 관할합의의 경우 임의관할의 성격을 가지나, 공익상의 필요에 의하여 사건을 다른 관할법원에 이송할 수는 없다.','2020 문20-1'),
(87,'관할위반 이외의 사유에 의한 이송의 경우 당사자에게는 이송신청권이 없으므로 그 이송신청에 대한 재판을 할 필요가 없고, 이송신청을 기각하는 결정에 대하여는 즉시항고도 할 수 없다.','2007b 문16-4'),
(90,'소송을 이송받은 법원은 사건을 다시 다른 법원에 이송하지 못하므로, 심급관할을 위배한 이송결정의 기속력은 이송받은 상급심법원에도 미친다.','2024 문21-2'),
(90,'전속관할 규정을 위배하여 이송한 경우라도 즉시항고 없이 확정된 이상 이송결정의 기속력이 미치나, 심급관할을 위반하여 상급심 법원에 이송된 경우에도 이송결정의 기속력이 미친다.','2022 문08-3'),
(90,'이송결정의 기속력은 전속관할 규정을 위배하여 이송한 경우에도 미치므로, 전속관할인 심급관할을 위배한 이송결정의 기속력은 이송받은 상급심 법원에 미친다.','2020 문20-3'),
(91,'소송을 이송받은 법원은 사건을 다시 다른 법원에 이송할 수 있다.','2009 문23-4'),
(93,'당사자가 이송결정에 대하여 즉시항고를 하지 아니하여 확정되었더라도 전속관할 규정을 위배한 이송결정의 기속력은 원칙적으로 인정되지 않는다.','2007b 문16-2'),
(95,'소송당사자에게 관할위반을 이유로 하는 이송신청권이 있는 것은 아니므로, 법원이 당사자의 신청에 따른 직권발동으로 이송결정을 한 경우에는 즉시항고가 허용되지 않는다.','2025 문07-1'),
(97,'당사자가 관할위반을 이유로 한 이송신청을 하여 법원이 직권발동으로 이송결정을 한 경우 즉시항고가 허용되고, 그 항고심에서 이송결정이 취소되면 재항고도 허용된다.','2020 문20-2'),
(102,'이송결정이 확정되면 이송결정을 한 법원의 법원사무관등은 그 결정의 원본을 소송기록에 붙여 이송받을 법원에 보내야 한다.','2010 문06-4'),
(104,'본안사건의 재판장에 대한 기피신청사건의 재판에 관여한 법관이 그 본안사건에 관여하는 경우, 이는 제척사유인 전심관여에 해당한다.','2025 문24-1'),
(106,'종중 규약을 개정한 종중 총회 결의에 대한 무효확인의 소에서 재판부 구성법관 중 1인이 당해 종중의 구성원이면 당사자와 공동권리자·공동의무자 관계에 있어 제척사유가 된다.','2023 문10-1'),
(109,'청구이의의 소에 있어서 그 대상인 본안의 확정판결도 이전심급의 재판에 해당한다.','2014 문05-2'),
(113,'법관이 다른 법원의 촉탁에 따라 불복사건의 이전심급의 직무를 수행한 경우에는 불복사건의 직무집행에서 제척된다.','2011 문02-4'),
(119,'기피신청은 서면으로 하여야 하므로 법정에서 구두로 기피신청을 한 것만으로는 적법한 기피신청이라고 할 수 없다.','2017 문01-3'),
(123,'법관과 법원사무관등에 대한 제척 또는 기피의 재판은 모두 그 소속 법원 합의부에서 결정으로 하여야 한다.','2020 문23-3'),
(125,'기피신청의 당부의 재판은 기피당한 법관이 스스로 할 수 없고, 그 신청을 받은 법관의 소속법원 합의부에서 결정으로 재판한다.','2016 문05-3'),
(126,'지방법원 단독판사에 대한 제척·기피사건은 지방법원의 다른 단독판사가 제1심으로 심판한다.','2011 문03-2'),
(127,'지방법원 항소부 소속 법관에 대한 제척 또는 기피신청이 제기되어 각하결정이 있는 경우, 그 결정에 대하여는 고등법원에 즉시항고하는 방법으로 다투어야 한다.','2019 문21-3'),
(130,'기피신청이 있으면 소송절차를 정지해야 하므로, 담당 재판부가 절차를 정지하지 않고 종국판결을 선고하였다면 위법하다.','2017 문01-1'),
(134,'참여관(법원주사)과 실무관(법원서기) 등 법원사무관등에 대해서는 기피신청을 할 수 없으므로 그에 대한 기피신청은 부적법하다.','2017 문01-2'),
(135,'법원사무관등에게는 법관의 제척·기피·회피에 관한 규정이 준용되지 아니한다.','2013 문01-3'),
(136,'종중이 비법인사단으로서 당사자능력이 있는지 여부는 소제기시를 기준으로 판단하여야 한다.','2022 문06-1'),
(139,'타인 소유 토지 위 무단 건물을 그 소유자가 임대하여 임차인이 점유하는 경우, 토지소유자의 토지인도청구의 피고적격자는 건물 임차인(점유자)이다.','2020 문02-3'),
(143,'학교는 교육시설의 명칭에 불과해 원칙적으로 당사자능력이 인정되지 않지만, 임시이사 선임신청과 같은 비송사건에서는 민사소송과 달리 당사자능력이 인정된다.','2020 문09-2'),
(150,'근저당권이 양도되어 이전의 부기등기가 마쳐진 경우, 근저당권설정등기의 말소등기청구는 양도인만을 상대로 하면 족하고 양수인은 피고적격이 없다.','2018 문16-4'),
(150,'근저당권이 양도되어 이전의 부기등기가 이루어진 경우, 근저당권설정등기의 말소등기청구는 양도인을 피고적격자로 한다.','2012 문02-4'),
(155,'법인의 이사에 대한 직무집행정지가처분 신청에서는 당해 이사만이 피신청인이 될 수 있고, 이사회결의 부존재확인의 소에서는 그 결의로 선임된 이사 및 당해 법인 모두가 피고가 될 수 있다.','2016 문07-4'),
(156,'제1심이 소송당사자를 제대로 확정하여 판결하였음에도 항소심이 제1심의 당사자표시 변경을 임의적 당사자변경으로 잘못 보아 소송당사자 아닌 자를 당사자로 취급하여 판결한 경우, 진정한 소송당사자는 상고를 제기하여 이를 다툴 수 없다.','2015 문22-1'),
(158,'단체가 변론종결 시점에 이르러서야 법인이 아닌 사단이 되었고 소제기 당시에는 그 실체가 없었다면 그 소는 부적법하다.','2014 문16-3'),
(159,'법원이 피고가 소제기 전에 사망하였음을 간과하고 본안판결을 하였더라도 당연무효는 아니며, 확정 전이면 상소, 확정 후이면 재심에 의한 취소사유가 될 뿐이다.','2013 문03-3'),
(165,'외국법인의 국내 지점은 당사자능력이 있다.','2012 문21-3'),
(167,'사립대학교 졸업자임의 확인을 구하는 확인소송에서 해당 사립대학교는 당사자능력이 있다.','2011 문17-2'),
(168,'부동산을 매수하지 않은 원고가 소유권이전등기청구소송을 제기하면 그 소는 원고적격이 없는 자에 의한 소이므로 법원은 소를 각하하여야 한다.','2010 문16-1'),
(171,'사망한 줄 모르고 사망자를 피고로 표시하여 소를 제기해 사망자를 당사자로 한 판결이 선고·확정된 경우, 그 판결도 확정판결인 이상 기판력을 가진다.','2009 문09-4'),
(172,'이행의 소에서 피고적격은 원고적격을 가지는 자에 의하여 이행의무자라고 주장된 자가 아니라 정당한 이행의무자로 인정된 자가 갖는다.','2008 문20-1'),
(174,'파산관재인은 임의적 소송담당이다.','2007a 문07-2'),
(178,'조합 업무를 집행할 권한을 수여받은 업무집행조합원이라도 조합재산에 관하여 조합원으로부터 임의적 소송신탁을 받아 자신의 이름으로 소송을 수행할 수는 없다는 것이 판례이다.','2007b 문14-3'),
(180,'실종자를 당사자로 한 판결이 확정된 후 실종선고가 확정되어 사망간주 시점이 소 제기 전으로 소급하는 경우에는 그 판결도 소급하여 당사자능력 없는 사망자를 상대로 한 판결이 되어 무효가 된다.','2007b 문15-1'),
(189,'교회의 총유재산에 관한 소송은 교회 자체의 명의로만 할 수 있다.','2010 문16-3'),
(190,'총유재산의 보존을 위한 소는 법인이 아닌 사단의 대표자 개인도 제기할 수 있다.','2009 문04-2'),
(197,'선정당사자가 소의 취하와 같은 소송행위를 하기 위하여는 선정자의 개별적인 동의가 필요하다.','2023 문14-4'),
(199,'등기말소소송의 원고 선정당사자가 피고 측으로부터 돈을 받기로 합의하고 소취하 및 부제소합의까지 한 경우, 선정자들의 개별적인 동의를 받지 아니한 이상 그 합의의 효력은 선정자들에게 미치지 아니한다.','2019 문06-3'),
(203,'선정당사자가 선정자들의 개별적인 동의 없이 체결한 변호사인 소송대리인과의 보수에 관한 약정은 선정자들에게 효력이 미친다.','2017 문03-4'),
(206,'선정당사자 본인에 대한 부분의 소가 취하된 경우에도 선정자가 선정을 취소하지 않는 한 선정당사자의 자격이 당연히 상실되는 것은 아니다.','2014 문24-3'),
(207,'선정당사자의 자격은 서면이나 구술로 증명할 수 있다.','2013 문09-1'),
(209,'선정당사자의 자격은 사망·선정의 취소로 당연히 상실되나, 선정당사자 본인에 대한 부분의 소가 취하된 경우에는 선정당사자의 자격이 당연히 상실되지 않는다.','2010 문03-3'),
(209,'선정당사자 본인에 대한 부분의 소가 취하되더라도 선정당사자는 그 자격을 당연히 상실하지는 아니한다.','2007b 문22-4'),
(213,'선정당사자는 청구의 포기·인낙, 화해 등 판결에 의하지 아니하고 소송을 종결하는 행위는 특별수권이 없으면 하지 못한다.','2007a 문19-3'),
(217,'선정당사자 일부가 사망하거나 자격을 상실한 경우에 소송절차는 중단된다.','2012 문19-2'),
(218,'미성년자는 법정대리인에 의해서만 소송행위를 할 수 있으므로, 미성년자가 독립하여 법률행위를 할 수 있는 경우에도 소송행위는 법정대리인에 의해서 하여야 한다.','2018 문25-1'),
(222,'미성년자의 후견인은 상대방의 소제기에 관하여 소송행위(응소)를 하는 경우에도 친족회의 동의를 받아야 한다.','2011 문07-3'),
(230,'적법한 대표자 자격이 없는 비법인 사단의 대표자가 한 소송행위는 후에 적법한 대표자가 추인하면 행위 시에 소급하여 효력을 가지는데, 이러한 추인은 항소심에서는 가능하나 상고심에서는 할 수 없다.','2021 문02-3'),
(239,'법인 대표자의 자격·대표권 흠으로 특별대리인이 선임된 후 소송 진행 중 그 흠이 보완되었더라도, 특별대리인에 대한 수소법원의 해임결정이 있기 전에는 흠이 보완된 대표자가 유효한 소송행위를 할 수 없다.','2024 문02-3'),
(239,'법인 대표자의 자격·대표권 흠으로 특별대리인이 선임된 후 소송 진행 중 그 흠이 보완되었더라도, 특별대리인에 대한 수소법원의 해임결정이 있기 전에는 그 대표자가 법인을 위하여 유효하게 소송행위를 할 수 없다.','2015 문04-3'),
(241,'의사능력이 없는 사람의 특정후견인 또는 임의후견인은 의사능력이 없는 사람의 소송수행을 위한 특별대리인 선임을 신청할 수 없다.','2022 문13-2'),
(243,'조합장이 공석이고 이사·감사 각 1명씩만 선임된 재건축조합에서 조합 이사 개인이 자기를 위하여 조합을 상대로 소를 제기한 경우, 법원은 피고 조합을 위하여 특별대리인을 선임할 수 있다.','2019 문05-1'),
(252,'법인의 대표자가 사망하였고 달리 법인을 대표할 자도 정하여지지 아니하여 법인에 대하여 송달을 할 수 없는 경우에는 공시송달의 방법에 의할 수밖에 없다.','2023 문17-4'),
(254,'법인 대표권 소멸 후 상대방에게 통지하지 않으면 중단되지 않아 구 대표자의 소취하는 유효하지만, 상대방이 그 대표권 소멸 사실을 이미 알고 있었던 경우에는 그 소취하는 효력이 없다.','2019 문02-1'),
(255,'적법한 대표자 자격이 없는 비법인 사단 대표자의 소송행위는 후에 적법한 대표자가 추인하면 소급하여 효력을 가지나, 이러한 추인은 상고심에서는 할 수 없다.','2017 문10-1'),
(257,'피고가 법인인 경우 법인의 주소지로 소장 부본을 송달하였으나 이사로 송달불능되었다면, 대표자의 주소지로 송달해 보지 않고 주소보정을 명하였다고 하여 잘못이라 할 수는 없다.','2008 문05-4'),
(259,'부진정연대채무 관계에 있는 채무자들을 공동피고로 하여 이행의 소가 제기된 경우, 공동피고에 대한 각 청구는 법률상 양립할 수 없으므로 상소하지 않은 공동소송인에 대하여 상소로 인한 확정차단의 효력이 미친다.','2025 문16-3'),
(259,'부진정연대채무 관계에 있는 채무자들을 공동피고로 하여 이행의 소가 제기된 경우 그 소송은 예비적·선택적 공동소송에 해당한다.','2022 문07-2'),
(262,'타인 소유의 토지 위에 설치된 공작물을 철거할 의무가 있는 수인을 상대로 그 철거를 청구하는 소송은 고유필수적 공동소송이다.','2022 문10-4'),
(265,'통상의 공동소송에서 공동소송인 1인의 항소는 다른 공동소송인 전원을 위하여 효력이 생긴다.','2010 문23-3'),
(268,'A가 소송에서 탈퇴하지 않으면 A의 청구에 대해서도 판결을 하여야 하고, C가 일부 승소하여 B·C만 항소하면 A의 B에 대한 청구는 분리하여 확정된다.','2021 문19-4'),
(272,'민법상 조합인 공동수급체가 경쟁입찰에 참가하였다가 다른 업체가 낙찰자로 선정된 경우, 그 구성원 중 1인이 단독으로 낙찰자 선정 무효확인의 소를 제기하는 것은 부적법하다.','2022 문10-1'),
(273,'공유물분할판결에서 상소기간은 각 공동소송인 개별로 진행되므로, 일부 공유자에 대하여 상소기간이 만료되면 그 공유자에 대한 판결 부분이 분리·확정된다.','2022 문10-2'),
(275,'고유필수적 공동소송인 가운데 한 사람이 한 소취하는 모두에게 효력이 있다.','2019 문15-1'),
(277,'소송목적이 공동소송인 모두에게 합일적으로 확정되어야 할 공동소송에서 공동소송인 가운데 한 사람의 소송행위는 (유·불리를 불문하고) 모두에게 효력을 미친다.','2018 문17-3'),
(280,'비법인사단의 총유재산에 관한 소송을 구성원 전원 명의로 하는 경우 필수적 공동소송이 되나, 총유물의 보존행위에 관한 소송은 구성원 개인이 제기할 수 있다.','2016 문16-3'),
(284,'제3자가 공유자들에 대하여 하는 (지분)이전등기청구는 공유자 전원을 피고로 하는 필수적 공동소송이다.','2012 문15-4'),
(288,'여럿의 합유자가 합유물의 보존을 위하여 제기하는 이전등기말소청구소송은 (고유)필수적 공동소송이다.','2009 문10-2'),
(292,'유사필수적 공동소송의 경우 공동소송인 중 한 사람에게 소송요건의 흠이 있으면 소송 전부를 각하하여야 한다.','2008 문23-4'),
(295,'동일한 특허권에 관하여 2인 이상이 공동으로 특허무효심판을 청구하여 승소한 경우, 특허권자가 공동심판청구인 중 일부만 상대로 심결취소소송을 제기하였다면 그 소송에서 제소되지 않은 나머지 공동심판청구인을 당사자로 추가할 수 있다.','2023 문01-4'),
(299,'필수적 공동소송인 중 일부가 누락된 경우에는 항소심 변론종결시까지 추가할 수 있다.','2011 문08-1'),
(299,'필수적 공동소송에서 공동소송인 중 일부가 누락된 경우 제2심 변론종결일까지 법원의 허가를 받아 누락된 피고를 추가할 수 있다.','2010 문16-2'),
(299,'법원은 필수적 공동소송인 가운데 일부가 누락된 경우 사실심 변론종결시까지 원고의 신청에 따라 결정으로 원고 또는 피고를 추가하도록 허가할 수 있다.','2007a 문05-2'),
(303,'입주자대표회의 구성원 개인을 피고로 한 동대표지위 부존재확인의 소 계속 중 입주자대표회의를 피고로 추가하는 예비적 추가는, 실체법적으로 서로 양립할 수 없는 경우가 아니므로 허용되지 않는다.','2020 문24-3'),
(304,'예비적 공동소송의 경우 주위적 공동소송인에 대한 청구를 받아들이면 예비적 공동소송인에 대한 청구에 대하여는 판단하지 않아도 된다.','2024 문09-1'),
(308,'예비적 공동소송에서 주위적 피고에 대한 청구를 받아들이면 예비적 피고에 대한 청구를 기각하는 판결을 하여야 하고, 법원이 착오로 예비적 피고에 대한 판결을 누락한 경우에는 그 예비적 피고에 대하여 추가판결을 하여야 한다.','2016 문15-4'),
(314,'보조참가(민사소송법 제71조)는 소송중의 소이다.','2007b 문04-3'),
(320,'원고 패소판결에 대하여 보조참가인이 보조참가신청을 하며 항소장을 제출한 경우, 원고는 보조참가인이 제기한 항소를 임의로 포기하거나 취하할 수 없다.','2017 문13-2'),
(322,'보조참가인의 증거신청 행위가 피참가인의 소송행위와 저촉되지 아니하고 그 증거들이 적법한 증거조사를 거쳐 현출되었더라도, 보조참가인은 피참가인에게 불리한 행위를 할 수 없으므로 법원은 그 증거에 터잡아 피참가인에게 불이익한 사실을 인정할 수 없다.','2016 문13-1'),
(322,'보조참가인의 증거신청 행위가 피참가인의 소송행위와 어긋나지 아니하고 그 증거가 적법한 증거조사를 거쳐 현출되었더라도, 법원은 그 증거에 터잡아 피참가인에게 불이익한 사실을 인정할 수 없다.','2013 문10-3'),
(325,'보조참가인은 사실 주장·다툼, 증거신청·상소제기·이의신청 등에 제한이 없으므로, 보조참가인의 상소기간은 피참가인의 상고기간과 별도로 진행한다.','2012 문01-1'),
(327,'보조참가인은 청구의 포기·인낙을 할 수 있다.','2009 문07-1'),
(328,'보조참가인은 소의 취하를 할 수 있다.','2009 문07-2'),
(328,'보조참가인은 소의 변경을 할 수 있다.','2009 문07-4'),
(332,'보조참가인이 변론한 다음에는 피참가인과 상대방의 동의가 없으면 참가신청을 취하할 수 없다.','2007a 문25-3'),
(334,'피참가인이 참가인이 할 수 없는 소송행위를 고의로 하지 아니한 때에는, 과실로 하지 아니한 때와 달리 재판의 효력이 참가인에게 미치지 않는다.','2018 문05-4'),
(335,'보조참가의 참가적 효력은 전소가 확정판결이 아닌 화해권고결정으로 종료된 경우에도 인정된다.','2025 문01-1'),
(335,'보조참가인이 피참가인을 보조하여 공동으로 소송을 수행한 결과 그 소송에서 화해권고결정이 확정되었다면 보조참가인에게 참가적 효력이 인정된다.','2023 문08-ㄱ'),
(335,'보조참가인이 피참가인을 보조하여 공동으로 소송을 수행하였으나 피참가인이 패소한 경우 참가적 효력이 인정되는데, 전소가 확정판결이 아닌 화해권고결정에 의하여 종료된 경우에도 그러한 참가적 효력이 인정된다.','2016 문20-3'),
(336,'보조참가인에 대한 전소 확정판결의 참가적 효력은 피참가인과 참가인 사이뿐만 아니라 피참가인의 상대방과 참가인 사이에도 미친다.','2016 문13-2'),
(340,'참가적효력은 판결주문에 대해서만 미치고, 판결이유 중 패소이유가 되었던 사실상·법률상의 판단에는 미치지 않는다.','2008 문13-4'),
(341,'재심의 소에 공동소송적 보조참가인이 참가한 후에도 피참가인이 재심의 소를 취하하면 공동소송적 보조참가인의 동의가 없어도 효력이 있다.','2018 문02-2'),
(343,'제1심 판결에서 참가인의 독립당사자참가신청을 각하하고 원고의 청구를 기각한 데 대하여 참가인은 항소하지 않고 원고만이 항소한 경우, 위 독립당사자참가신청을 각하한 부분도 항소심으로 이심된다.','2022 문15-3'),
(345,'이미 사망한 자를 채무자로 한 처분금지가처분결정은 당연무효로서 상속인에게 효력이 미치지 않으므로, 상속인은 그 가처분결정에 대한 이의신청으로 취소를 구할 수 없다.','2021 문15-1'),
(346,'甲의 매매 원인 소유권이전등기 본소 계속 중, 그 매매 이후 점유취득시효 완성을 원인으로 丙이 소유권이전등기를 구하는 독립당사자참가는 적법하다.','2020 문17-1'),
(353,'독립당사자참가인이 화해권고결정에 대하여 이의한 경우, 그 이의의 효력은 독립당사자참가인과 원고, 독립당사자참가인과 피고 사이에는 미치지만 원·피고 사이에는 미치지 아니한다.','2015 문23-4'),
(355,'갑·을 사이의 소송이 상고심에 계속 중이라도 병의 독립당사자참가는 가능하다.','2013 문06-1'),
(361,'본소가 취하되거나 각하되는 경우 참가인의 원고 및 피고에 대한 공동소송도 모두 종료한다.','2007a 문06-4'),
(364,'독립당사자참가소송의 진행 중 부득이한 사정이 있는 경우에는 소송절차의 신속을 위하여 변론을 분리하여 진행할 수 있다.','2007b 문23-4'),
(373,'청구이의의 소가 제기되기 전에 그 집행권원에 표시된 청구권을 양수한 사람이 한 승계참가신청은 허용된다.','2019 문09-2'),
(377,'소송계속 중 실체법상 분쟁주체의 지위가 이전된 경우에는 임의적 당사자의 변경을 인정할 실익이 생기게 된다.','2014 문23-4'),
(378,'부동산 매수인이 매도인을 상대로 제기한 소유권이전등기청구 소송 중에 매도인으로부터 그 목적부동산에 대해 등기이전을 받은 제3자는 특정승계인에 포함된다.','2013 문20-2'),
(381,'소송인수신청이 있는 경우 승계적격 흠결이 명백하지 않으면 결정으로 인용하여야 하나, 본안 심리 결과 승계사실이 인정되지 않으면 인수참가신청 자체가 부적법하게 되어 인수참가신청을 각하하는 판결을 하여야 한다.','2021 문17-3'),
(384,'A가 ''C가 B의 승계인''이라며 인수신청을 하여 인수결정이 있은 후 A의 동의로 B가 탈퇴한 경우, 판결의 효력은 A와 C 사이에만 미치고 탈퇴한 B에게는 미치지 않는다.','2014 문04-4'),
(387,'채권자대위소송 계속 중 다른 채권자가 동일한 금전채권을 대위행사하며 공동소송참가신청을 한 경우, 원고와 참가인에게 합일확정 필요성을 인정하기 어려우므로 그 공동소송참가신청은 부적법하다.','2019 문08-2'),
(390,'소송고지는 참가적 효력을 발생시키기 위한 것이므로 제2심까지만 허용된다.','2010 문07-2'),
(391,'소송이 법원에 계속된 때에는 당사자는 참가할 수 있는 제3자에게 소송고지를 할 수 있으나, 소송고지를 받은 사람은 다시 소송고지를 할 수 없다.','2007b 문10-1'),
(404,'단독사건에서 변호사가 아닌 사람이 소송대리를 하려면 소송목적의 값이 제소 당시 또는 청구취지 확장 당시 1억 원 이하인 민사소송사건이어야 한다.','2009 문24-1'),
(413,'가압류사건을 수임받은 변호사의 소송대리권은 본안의 제소명령을 신청할 권한에는 미치나, 상대방의 신청으로 발하여진 제소명령결정을 송달받을 권한에까지는 미치지 않는다.','2022 문18-4'),
(415,'소송대리인은 특별수권을 받지 않는 한 위임을 받은 사건에 관하여 상대방으로부터 변제를 받을 수 없다.','2020 문18-3'),
(421,'소송대리인이 소취하에 동의를 함에 있어서는 본인으로부터 특별한 권한을 따로 받아야 한다.','2016 문02-4'),
(423,'피고가 제기한 반소에 응소하거나 반소를 제기하는 행위는 모두 통상의 대리권의 범위에 속한다.','2012 문17-1'),
(426,'사건이 상소된 후 상급심에서 파기환송되어 다시 원심법원에 계속되더라도 환송 전 원심에서의 소송대리인의 대리권이 부활하지 않는다.','2008 문04-2'),
(430,'소송위임에 의한 소송대리인은 반소·소취하·화해·청구의 포기·인낙은 특별한 권한을 받아야 하지만 상소의 제기와 취하는 특별한 권한이 없어도 할 수 있다.','2007a 문10-4'),
(434,'여러 소송대리인이 있는 때에는 각자가 당사자를 대리하나, 당사자가 이와 다른 약정을 한 경우에는 그러하지 아니하다.','2008 문18-3'),
(436,'당사자가 소송대리인에게 소송위임을 한 다음 소제기 전에 사망하였는데 소송대리인이 이를 모르고 사망한 당사자를 원고로 표시하여 소를 제기하였다면, 그 소의 제기는 부적법하다.','2025 문25-3'),
(437,'당사자가 사망하거나 소송능력을 상실하게 되면 소송대리권은 소멸된다.','2021 문14-2'),
(437,'당사자의 사망 또는 소송능력의 상실, 당사자인 수탁자의 신탁임무 종료의 경우에는 소송대리권이 소멸한다.','2007b 문05-2'),
(438,'당사자가 사망하면 소송위임에 의한 소송대리인의 대리권은 소멸한다.','2014 문10-1'),
(442,'일부 패소의 경우 각 당사자가 부담할 소송비용은 반드시 청구액과 인용액의 비율에 따라 정하여야 한다.','2021 문12-1'),
(445,'소송이 재판에 의하지 않고 완결된 경우 소송종료 당시 사건이 계속된 법원이 관할법원이며, 항소심에서 항소취하가 된 경우에는 제1심을 포함한 총 소송비용에 관하여 항소심 법원에 신청해야 한다.','2024 문07-2'),
(447,'당사자가 법원에서 화해한 경우 화해비용과 소송비용의 부담에 대하여 특별히 정한 바가 없으면 그 비용은 당사자들이 균등하게 부담한다.','2012 문05-1'),
(456,'소송비용부담의 재판이 있은 후에 비용부담 의무자가 사망한 경우에는 승계집행문을 부여받을 필요 없이 그 상속인들을 상대로 소송비용액 확정신청을 할 수 있다.','2018 문14-4'),
(457,'본안재판으로 소송비용부담의 재판이 행하여진 때에 소송비용액 확정절차는 본안재판이 완결될 당시의 법원이 관할한다.','2017 문15-4'),
(459,'소송비용액 확정신청은 소송비용부담재판이 확정되어야 할 수 있다.','2015 문07-1'),
(460,'소송비용액확정결정 신청에 갈음하여 별도의 소를 제기할 수도 있다.','2007a 문12-3'),
(465,'소송비용 담보제공 신청권은 피고에게만 있으므로, 원고가 본안 항소심에서 승소하여 피고가 상고를 제기함에 따라 원고가 피상고인이 된 경우에도 원고에게는 소송비용 담보제공 신청권이 인정되지 않는다.','2021 문09-1'),
(470,'민사소송법은 ''담보제공신청''에 관한 결정에 대하여 즉시항고할 수 있다고 규정하고 있으므로, 법원이 직권으로 한 담보제공명령에 대해서는 즉시항고할 수 없다.','2019 문19-4'),
(476,'무자력 요건과 관련하여, 자연인의 경우 국민기초생활보장법에 의한 수급권자로 한정된다.','2025 문23-4'),
(483,'신청인이 패소할 것이 분명한 경우에는 법원이 소송구조를 할 수 없으므로, 신청인은 승소의 가능성을 적극적으로 진술하고 소명하여야 한다.','2016 문19-1'),
(483,'소송구조를 받으려면 ''패소할 것이 분명한 경우가 아닐 것''을 요하는데, 이 요건에 대해서는 신청인이 적극적으로 진술하고 소명해야 한다.','2012 문22-1'),
(485,'소송구조는 당사자의 신청에 의해서만 할 수 있다.','2012 문22-2'),
(486,'법원은 자금능력이 부족한 사람에 대하여 직권으로 소송구조를 할 경우에는 패소할 것이 분명하더라도 할 수 있다.','2011 문16-3'),
(490,'소송구조는 원칙적으로 이를 받는 사람에게만 효력이 미치므로, 법원이 소송승계인에게 미루어 둔 비용의 납입을 명할 수는 없다.','2018 문20-3'),
(491,'소송구조의 효과는 구조를 받은 사람의 승계인에게도 미친다.','2012 문22-4'),
(494,'소송구조결정의 상대방은 변호사보수의 지급유예의 소송구조결정에 대하여 즉시항고할 수 있다.','2023 문06-4'),
(496,'소송구조에 대한 재판에 대하여는 즉시항고를 할 수 있으나, 소송구조의 상대방은 어떠한 경우에도 불복할 수 없다.','2007a 문03-4'),
(499,'종중이 당사자인 사건에서 그 종중 대표자에게 적법한 대표권이 있는지 여부는 직권조사사항이지만 자백의 대상이 될 수 있다.','2022 문20-2'),
(500,'소송요건 중 부제소합의, 소취하계약, 상소취하계약은 피고의 주장을 기다려 비로소 조사하게 되는 항변사항에 해당한다.','2022 문20-3'),
(502,'채권자대위소송에서 피보전채권이 존재하는지 여부에 관하여 법원은 그 판단의 기초자료인 사실과 증거를 직권으로 탐지할 의무가 있다.','2017 문18-1'),
(504,'결정으로 완결할 사건은 변론이 아니라 심문을 열어 심리를 하여야 한다.','2014 문14-2'),
(508,'소송당사자가 자기의 주장사실을 서면에 기재하여 법원에 제출하였으면 변론에서 진술되지 아니하였더라도 이를 해당 사건의 판단자료로 삼을 수 있다.','2007b 문13-2'),
(511,'법원은 석명권의 행사로서 당사자가 주장하지 아니한 법률효과에 관한 요건사실이나 독립된 공격방어방법을 시사하여 그 제출을 권유할 수 있다.','2021 문08-3'),
(514,'당사자가 어떠한 법률효과를 주장하면서 미처 깨닫지 못하고 그 요건사실 일부를 빠뜨린 경우, 법원이 그 누락사실을 지적하는 것은 변론주의 원칙에 위배되어 석명권 행사의 한계를 일탈하는 것이다.','2017 문19-2'),
(522,'새로운 신청·주장·공격방어방법의 제출을 권유하거나 시사하는 적극적 석명은 변론주의에 위반되므로 일체 허용될 수 없다.','2011 문11-2'),
(526,'당사자는 법원에 대하여 변론의 제한·분리·병합을 신청할 수 있는 권리가 있다.','2007a 문02-2'),
(529,'소송관계를 분명하게 하기 위하여 필요한 진술을 할 수 없는 당사자 또는 대리인이라고 하더라도, 법원이 그 당사자나 대리인의 진술을 금지하는 것은 허용되지 아니한다.','2016 문21-4'),
(531,'화해·조정에 의한 분쟁해결의 지양(止揚)은 민사소송 신모델의 주요 내용이다.','2007a 문20-4'),
(532,'민사소송법은 공격방어방법을 변론종결 전까지 자유롭게 제출하는 수시제출주의를 채택하지 않고, 제출순서를 엄격하게 법으로 정하고 그 순서를 놓치면 실권하게 하는 법정순서주의를 채택하고 있다.','2013 문07-1'),
(533,'수시제출주의는 현행 민사소송법이 채택하고 있는 변론에 관한 원칙이다.','2008 문21-4'),
(535,'공격 또는 방어의 방법은 변론의 종결까지 수시로 제출할 수 있다.','2007b 문13-1'),
(538,'당사자가 재정기간을 지키지 못하고 넘긴 때에는 정당한 사유가 있는 경우에도 그 특정 사항에 관하여 주장을 제출하거나 증거를 신청할 수 없다.','2011 문10-3'),
(541,'불출석 당사자가 준비서면에 서증의 사본을 첨부하였는데 그 준비서면이 진술간주되었다면 그 사본에 의하여 서증도 제출된 것으로 간주된다.','2025 문04-2'),
(541,'당사자가 준비서면에 서증의 사본을 첨부하여 제출한 채 불출석한 경우, 그 준비서면이 진술간주되면 서증의 제출이 있는 것으로 본다.','2016 문09-2'),
(542,'최초 변론기일에 원고가 특별한 사정 없이 불출석하고 피고가 출석하여 원고 주장을 부인하였다면, 법원은 원고의 청구를 기각하여야 한다.','2014 문14-1'),
(544,'당사자가 제출한 소장·답변서, 그 밖의 준비서면에 청구의 포기 또는 인낙의 의사표시가 적혀 있다면 공증사무소의 인증이 없더라도 그 취지에 따라 청구의 포기·인낙이 성립된 것으로 본다.','2013 문13-2'),
(546,'서증이 첨부된 준비서면을 제출한 당사자가 기일에 출석하지 아니하여도 그 기재사항을 진술한 것으로 간주되고, 첨부된 서증도 제출한 것으로 간주된다.','2007a 문09-1'),
(548,'당사자가 고의·중과실로 공격방어방법을 뒤늦게 제출하여 소송 완결을 지연시키는 경우, 법원은 상대방의 신청에 따라 결정으로 각하할 수 있지만 직권으로 각하할 수는 없다.','2022 문05-2'),
(558,'이행불능에 관한 주장은 채무불이행 사실에 관한 진술을 한 것이라고 볼 수 있으므로 그 진술은 자유로이 철회할 수 없고 법원도 이에 구속되어 자백간주의 효과가 발생한다.','2024 문17-3'),
(559,'불출석한 피고가 원고의 주장사실을 모두 인정하는 취지의 답변서 기타 준비서면을 제출하여 진술간주된 경우 원고의 주장사실에 대한 자백간주가 성립한다.','2023 문18-4'),
(562,'자백간주가 성립하면 자백과 마찬가지로 법원과 당사자를 구속하므로, 자백간주의 효과가 발생한 이후에는 이를 번복하여 상대방의 주장사실을 다툴 수 없다.','2019 문18-4'),
(562,'자백간주는 당사자에 대한 구속력이 있기 때문에 그 뒤 사실심에서 그 사실을 다툴 수 없다.','2012 문06-2'),
(563,'일단 제1심에서 자백간주가 있었다면 항소심에서 이를 다투었다 하더라도 자백간주의 효력이 유지된다.','2016 문09-4'),
(568,'원고의 대여 주장에 대하여 아무런 답변을 하지 않는 것은 항변이다.','2008 문12-4'),
(570,'자백간주된 사실은 증명할 필요가 있는 사실이다.','2007b 문17-2'),
(572,'항소 제기기간 계산의 기산점이 되는 판결정본 송달상의 하자는 이에 대한 이의권(책문권)의 상실로 인하여 치유된다.','2017 문22-2'),
(573,'직권조사사항은 당사자의 소송절차에 관한 이의권의 포기·상실의 대상이 된다.','2010 문14-1'),
(575,'법원사무관등은 변론기일에 참여하여 기일마다 조서를 작성하여야 하므로, 변론을 녹음하거나 속기하는 경우에도 법원사무관등을 참여시키지 아니하고 변론기일을 여는 것은 위법하다.','2021 문10-4'),
(579,'조서가 존재하는 경우에 변론의 방식에 관한 규정이 지켜졌다는 것은 조서 또는 이를 작성한 법원사무관등의 증언에 의하여 증명할 수 있다.','2009 문02-2'),
(582,'우리 민사소송법은 형사재판의 배심원제도와 유사한 참심원 제도인 ''전문심리위원제도''를 도입하여, 전문심리위원들로 하여금 재판의 합의에 참여하도록 함으로써 사건의 적정한 해결을 도모하고 있다.','2017 문25-가'),
(583,'전문심리위원이 제출한 서면이나 그 설명·의견진술은 민사소송법상 증거자료가 될 수 없으므로, 법원은 그에 관하여 당사자에게 의견진술의 기회를 줄 필요가 없다.','2017 문25-다'),
(584,'전문심리위원은 설명·의견을 기재한 서면을 제출하거나 기일에 출석하여 설명·의견을 진술할 수 있으며, 당사자들의 동의가 있으면 재판의 합의에 참여할 수 있다.','2015 문24-1'),
(589,'첫 변론기일 또는 첫 변론준비기일을 바꾸는 것은 현저한 사유가 있는 경우에만 허가할 수 있다.','2007a 문01-2'),
(595,'화해권고결정·이행권고결정·지급명령·조정을 갈음하는 결정에 대한 이의신청기간과 소취하간주 시의 기일지정신청기간은 모두 불변기간에 해당한다.','2024 문16-2'),
(599,'지병으로 인한 집중력 저하와 정신과 치료 등의 사유로 상고기간을 도과한 경우, 당사자가 책임질 수 없는 사유에 해당한다.','2023 문04-ㄱ'),
(601,'서울에서 수원으로 배달증명우편으로 발송한 항소장이 4일 만에 배달되어 항소기간을 준수할 수 없었다는 점은 당사자가 책임질 수 없는 사유에 해당하지 아니한다.','2023 문04-ㄹ'),
(603,'조정이 성립되지 아니한 것으로 종결된 후 피신청인이 주소변경 신고를 하지 않은 상태에서 소송으로 이행되어 소송서류가 발송송달·공시송달된 경우, 피신청인이 소송 진행상황을 조사하지 않아 상소기간을 지키지 못하였다면 이를 당사자가 책임질 수 없는 사유라 할 수 없다.','2017 문16-2'),
(606,'허위주소로 소송서류가 송달되어 피고 아닌 원고가 받아 의제자백 형식으로 원고 승소판결이 선고되고 판결정본도 허위주소로 송달처리된 경우에도, 그 판결에 대한 항소기간은 진행되고 단지 소송행위 추완의 문제가 생긴다.','2013 문11-1'),
(613,'화해권고결정에 대한 이의신청기간은 추후보완이 허용되지 않는 기간이다.','2008 문08-3'),
(614,'항소기간은 추후보완이 허용되지 않는 기간이다.','2008 문08-4'),
(616,'피고가 확정판결의 존재를 안 때로부터 2주의 추후보완 기간이 경과하였으므로 항소는 부적법 각하되어야 한다.','2007b 문24-2'),
(630,'국가를 당사자로 하는 소송에서는 국가의 대표자인 법무부장관에게 송달하여야 한다.','2007b 문20-1'),
(631,'여러 사람이 공동으로 대리권을 행사하는 경우의 송달은 이들 모두에게 하여야 한다.','2025 문19-4'),
(631,'여러 사람이 공동으로 대리권을 행사하는 경우의 송달은 공동대리인 모두에게 하여야 한다.','2020 문16-3'),
(634,'재감자의 수감 사실을 알지 못하여 교도소장에게 송달하지 않고 수감 전의 종전 주·거소에 송달하였다.','2016 문04-2'),
(635,'재감자에 대한 송달을 교도소 등의 소장에게 하지 않고 수감되기 전의 종전 주소에 하였다.','2015 문13-1'),
(636,'법인에 대한 송달에서 ''영업소 또는 사무소''에는 당해 법인의 영업소뿐만 아니라 그 대표자가 경영하는 별도의 법인격을 가진 다른 법인의 영업소·사무소도 포함된다.','2019 문10-3'),
(637,'소장에 기재된 주소 등의 장소에 대한 송달을 시도하지 않은 채 곧바로 근무장소로 송달을 하였다.','2015 문13-2'),
(642,'당사자가 송달장소 변경신고의무를 이행하지 아니하고 달리 송달장소를 알 수 없어 화해권고결정을 등기우편(발송송달)의 방법으로 송달하였다.','2016 문04-4'),
